// Keep new surfaces/extensions on these helpers instead of one-off HTML/CSS islands.
const NeoUI = {
  cx(...items) {
    return items.flat().filter(Boolean).join(' ');
  },
  badge(label, variant = '') {
    return `<span class="neo-badge ${escapeAttr(variant)}">${escapeHtml(label)}</span>`;
  },
  badgeRow(items = [], variant = '') {
    const safeItems = Array.isArray(items) ? items.filter((item) => item !== undefined && item !== null && `${item}`.trim() !== '') : [];
    return safeItems.length
      ? `<div class="neo-ui-toolbar neo-badge-row">${safeItems.map((item) => NeoUI.badge(item, variant)).join('')}</div>`
      : NeoUI.emptyState('No items declared yet.', '', 'compact');
  },
  statusBadge(label, status = '') {
    return NeoUI.badge(label, statusClass(status || label));
  },
  metaList(items = [], options = {}) {
    const safeItems = Array.isArray(items) ? items.filter((item) => item !== undefined && item !== null && `${item}`.trim() !== '') : [];
    if (!safeItems.length) return NeoUI.emptyState(options.empty || 'No items declared yet.', '', 'compact');
    const wrapCode = options.code !== false;
    return `<ul class="neo-ui-meta-list">${safeItems.map((item) => `<li>${wrapCode ? `<code>${escapeHtml(item)}</code>` : escapeHtml(item)}</li>`).join('')}</ul>`;
  },
  sectionHeader({ title = '', description = '', badge = '', actions = '' } = {}) {
    return `<div class="neo-ui-section-head">
      <div><strong>${escapeHtml(title)}</strong>${description ? `<p>${escapeHtml(description)}</p>` : ''}</div>
      ${badge || actions ? `<div class="neo-ui-section-side">${badge || ''}${actions || ''}</div>` : ''}
    </div>`;
  },
  card({ title = '', description = '', badge = '', body = '', actions = '', wide = false, className = '', titleHtml = '' } = {}) {
    const header = title || description || badge || titleHtml
      ? NeoUI.sectionHeader({ title, description, badge, actions: '' }).replace(
          title ? `<strong>${escapeHtml(title)}</strong>` : '<strong></strong>',
          titleHtml || (title ? `<strong>${escapeHtml(title)}</strong>` : '')
        )
      : '';
    return `<div class="${NeoUI.cx('neo-ui-card', wide && 'wide', className)}">${header}${body || ''}${actions ? `<div class="neo-ui-toolbar">${actions}</div>` : ''}</div>`;
  },
  fieldGrid(fieldsHtml = '', columns = 2, className = '') {
    return `<div class="${NeoUI.cx('neo-ui-field-grid', columns === 4 ? 'four' : 'two', className)}">${fieldsHtml}</div>`;
  },
  toolbar(itemsHtml = '', className = '') {
    return `<div class="${NeoUI.cx('neo-ui-toolbar', className)}">${itemsHtml}</div>`;
  },
  emptyState(title = 'Nothing here yet.', detail = '', className = '') {
    return `<div class="${NeoUI.cx('neo-ui-empty', className)}"><strong>${escapeHtml(title)}</strong>${detail ? `<p>${escapeHtml(detail)}</p>` : ''}</div>`;
  },
  codeBlock(value, className = '') {
    const text = typeof value === 'string' ? value : JSON.stringify(value, null, 2);
    return `<pre class="${NeoUI.cx('neo-ui-code', className)}">${escapeHtml(text)}</pre>`;
  },
  extensionPanel(contract = {}, options = {}) {
    const panels = Array.isArray(contract.panels) ? contract.panels : [];
    const badges = [contract.panel_type, contract.surface, ...(((contract.mount || {}).workspace_apps) || [])].filter(Boolean);
    const body = panels.length ? panels.map((panel) => {
      const fields = Array.isArray(panel.fields) ? panel.fields : [];
      const fieldHtml = fields.length ? fields.map((field) => `<label><span>${escapeHtml(field.label || field.id || 'Field')}</span><input type="text" disabled placeholder="${escapeAttr(field.type || 'text')}" /></label>`).join('') : NeoUI.emptyState('No shared controls declared.', 'This extension can still expose custom runtime behavior through its backend contract.');
      return NeoUI.card({ title: panel.title || 'Extension panel', description: panel.description || '', body: NeoUI.fieldGrid(fieldHtml), className: 'neo-ui-extension-section' });
    }).join('') : NeoUI.emptyState('No UI contract panels declared.', 'Add fields or panels to the extension manifest UI schema.');
    const validation = contract.validation || {};
    return NeoUI.card({
      title: contract.name || contract.extension_id || 'Extension',
      description: 'Rendered through the shared extension UI contract.',
      badge: NeoUI.statusBadge(validation.ok === false ? 'needs setup' : 'ready'),
      body: `${NeoUI.badgeRow(badges)}${body}${options.showDiagnostics ? NeoUI.codeBlock(validation, 'neo-ui-extension-diagnostics') : ''}`,
      className: 'neo-ui-extension-panel'
    });
  },
  surfaceBlueprintCard(blueprint = {}, options = {}) {
    const subtabs = Array.isArray(blueprint.subtabs) ? blueprint.subtabs : [];
    const areaCounts = blueprint.coverage?.declared_area_counts || {};
    const badges = [
      blueprint.status || 'planned',
      `${subtabs.length} workspaces`,
      ...((blueprint.provider_types || []).slice(0, 3)),
    ].filter(Boolean);
    const anatomy = Object.entries(areaCounts).length
      ? NeoUI.badgeRow(Object.entries(areaCounts).map(([key, value]) => `${key.replaceAll('_', ' ')}: ${value}`))
      : NeoUI.emptyState('No mapped anatomy yet.', 'Declare slots in the surface manifest to show coverage.');
    const subtabList = subtabs.slice(0, options.limit || 4).map((tab) => {
      const missing = tab.coverage?.missing_required_areas || [];
      return `${tab.display_name || tab.subtab_id}: ${tab.coverage?.declared_slot_count || 0} slots${missing.length ? ` · missing ${missing.length}` : ''}`;
    });
    return NeoUI.card({
      title: blueprint.display_name || blueprint.surface_id || 'Surface',
      description: blueprint.description || 'Shared Neo surface blueprint.',
      badge: NeoUI.statusBadge(blueprint.status || 'planned'),
      body: `${NeoUI.badgeRow(badges)}<p class="neo-muted">Canonical anatomy</p>${anatomy}<p class="neo-muted">Workspace map</p>${NeoUI.metaList(subtabList, { code: false, empty: 'No workspaces declared yet.' })}`,
      className: 'neo-ui-surface-blueprint-card',
    });
  },
};

function neoInvokeSurfaceModule(surfaceId, area, payload = {}) {
  const runtime = window.NeoSurfaceRuntime;
  if (!runtime || typeof runtime.invoke !== 'function') return undefined;
  return runtime.invoke(surfaceId, area, {
    ...payload,
    state,
    NeoUI,
    escapeHtml,
    escapeAttr,
    statusClass,
    loadJson,
    render,
    detailMode: state.detailMode,
    assistantState: typeof assistantState === 'function' ? assistantState : undefined,
    assistantActiveProject: typeof assistantActiveProject === 'function' ? assistantActiveProject : undefined,
    assistantFetchJson: typeof assistantFetchJson === 'function' ? assistantFetchJson : undefined,
    assistantBootstrap: typeof assistantBootstrap === 'function' ? assistantBootstrap : undefined,
    assistantCapabilityPills: typeof assistantCapabilityPills === 'function' ? assistantCapabilityPills : undefined,
    assistantGroundedModeControlsHtml: typeof assistantGroundedModeControlsHtml === 'function' ? assistantGroundedModeControlsHtml : undefined,
    assistantStarterCardsHtml: typeof assistantStarterCardsHtml === 'function' ? assistantStarterCardsHtml : undefined,
    assistantMessageCards: typeof assistantMessageCards === 'function' ? assistantMessageCards : undefined,
    assistantProjectOptions: typeof assistantProjectOptions === 'function' ? assistantProjectOptions : undefined,
    assistantSessionListHtml: typeof assistantSessionListHtml === 'function' ? assistantSessionListHtml : undefined,
    assistantEvidenceCardsHtml: typeof assistantEvidenceCardsHtml === 'function' ? assistantEvidenceCardsHtml : undefined,
  });
}


