function selectedImagePromptLibraryRecord() {
  const activeId = state.imagePromptLibrary?.active_id || '';
  return (state.imagePromptLibrary?.records || []).find((item) => item.id === activeId) || null;
}

function imagePromptLibraryOptions() {
  const records = state.imagePromptLibrary?.records || [];
  return [
    { id: '', label: 'Saved prompts…' },
    ...records.map((item) => ({
      id: item.id,
      label: `${item.name || 'Untitled prompt'} · ${item.source_label || item.source || 'Prompt'}`,
      title: item.readonly ? 'Loaded from Prompt Studio. Use Save to copy into Image prompt library.' : 'Image prompt library record',
    })),
  ];
}

function renderImagePromptLibraryBar() {
  const library = state.imagePromptLibrary || { records: [] };
  const active = selectedImagePromptLibraryRecord();
  const sourceBadge = active ? `Selected: ${active.source_label || active.source || 'Prompt'}` : `${Number(library.image_count || 0)} Image · ${Number(library.prompt_studio_count || 0)} Prompt Studio`;
  const status = library.status ? `<small class="neo-preset-status">${escapeHtml(library.status)}</small>` : `<small class="neo-preset-status">Save/load positive + negative prompt pairs. Prompt Studio saved prompts appear here read-only.</small>`;
  return `<div class="neo-ui-preset-bar neo-image-prompt-library-bar" data-schema="neo.image.prompt_library_bar.v25_9_17">
    <label>Prompt Library${optionSelect('imagePromptLibrarySelect', imagePromptLibraryOptions(), library.active_id || '')}</label>
    <div class="neo-ui-preset-actions" aria-label="Image prompt library actions">
      <button class="neo-icon-btn success" id="imagePromptLibrarySaveBtn" type="button" title="Save current positive and negative prompt" aria-label="Save current positive and negative prompt" data-tooltip="Save current positive and negative prompt">💾</button>
      <button class="neo-icon-btn primary" id="imagePromptLibraryLoadBtn" type="button" title="Load selected saved prompt into current positive and negative fields" aria-label="Load selected saved prompt" data-tooltip="Load selected saved prompt">📥</button>
      <button class="neo-icon-btn primary" id="imagePromptLibraryUpdateBtn" type="button" title="Update selected Image prompt pair" aria-label="Update selected Image prompt pair" data-tooltip="Update selected Image prompt pair">🔄</button>
      <button class="neo-icon-btn secondary" id="imagePromptLibraryRenameBtn" type="button" title="Rename selected Image prompt pair" aria-label="Rename selected Image prompt pair" data-tooltip="Rename selected Image prompt pair">✏️</button>
      <button class="neo-icon-btn danger" id="imagePromptLibraryDeleteBtn" type="button" title="Delete selected Image prompt pair" aria-label="Delete selected Image prompt pair" data-tooltip="Delete selected Image prompt pair">🗑️</button>
    </div>
    <div class="neo-badge-row"><span class="neo-badge">${escapeHtml(sourceBadge)}</span></div>
    ${status}
  </div>`;
}

function applyPromptLibraryRecord(record) {
  if (!record) return;
  updateDraftValue('positive_prompt', record.positive_prompt || '');
  updateDraftValue('negative_prompt', record.negative_prompt || '');
  const pos = document.getElementById('imagePositivePrompt');
  const neg = document.getElementById('imageNegativePrompt');
  if (pos) pos.value = state.imageDraft.positive_prompt || '';
  if (neg) neg.value = state.imageDraft.negative_prompt || '';
  state.imagePromptLibrary.status = `Loaded prompt: ${record.name || 'Untitled prompt'}`;
}

async function saveCurrentImagePromptPair() {
  const positive = promptTextForField('positive_prompt');
  const negative = promptTextForField('negative_prompt');
  if (!String(positive || '').trim() && !String(negative || '').trim()) {
    window.alert('Positive and negative prompts are both empty.');
    return;
  }
  const name = window.prompt('Prompt pair name?', 'Image Prompt Pair');
  if (!name) return;
  const response = await fetch('/api/image/prompt-library', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ name, positive_prompt: positive, negative_prompt: negative }),
  });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok || payload.ok === false) throw new Error(payload.detail || (payload.errors || ['Could not save prompt pair']).join(', '));
  await loadImagePromptLibrary();
  state.imagePromptLibrary.active_id = payload.record?.id || '';
  state.imagePromptLibrary.status = `Saved prompt: ${payload.record?.name || name}`;
  render();
}

async function updateSelectedImagePromptPair(extra = {}) {
  const record = selectedImagePromptLibraryRecord();
  if (!record) return;
  if (record.readonly || record.source !== 'image') {
    window.alert('Prompt Studio records are read-only here. Use 💾 to copy the current prompt into the Image prompt library first.');
    return;
  }
  const positive = promptTextForField('positive_prompt');
  const negative = promptTextForField('negative_prompt');
  const response = await fetch(`/api/image/prompt-library/${encodeURIComponent(record.prompt_pair_id || record.id)}`, {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ positive_prompt: positive, negative_prompt: negative, ...extra }),
  });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok || payload.ok === false) throw new Error(payload.detail || (payload.errors || ['Could not update prompt pair']).join(', '));
  await loadImagePromptLibrary();
  state.imagePromptLibrary.active_id = payload.record?.id || record.id;
  state.imagePromptLibrary.status = `Updated prompt: ${payload.record?.name || record.name || 'Prompt'}`;
  render();
}

async function renameSelectedImagePromptPair() {
  const record = selectedImagePromptLibraryRecord();
  if (!record) return;
  if (record.readonly || record.source !== 'image') {
    window.alert('Prompt Studio records are read-only here. Use 💾 to copy the current prompt into the Image prompt library first.');
    return;
  }
  const name = window.prompt('New prompt pair name?', record.name || 'Image Prompt Pair');
  if (!name) return;
  await updateSelectedImagePromptPair({ name });
}

async function deleteSelectedImagePromptPair() {
  const record = selectedImagePromptLibraryRecord();
  if (!record) return;
  if (record.readonly || record.source !== 'image') {
    window.alert('Prompt Studio records are read-only here. Delete them from Prompt Studio if needed.');
    return;
  }
  const ok = window.confirm('Delete this saved Image prompt pair?');
  if (!ok) return;
  const response = await fetch(`/api/image/prompt-library/${encodeURIComponent(record.prompt_pair_id || record.id)}`, { method: 'DELETE' });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok || payload.ok === false) throw new Error(payload.detail || (payload.errors || ['Could not delete prompt pair']).join(', '));
  await loadImagePromptLibrary();
  state.imagePromptLibrary.active_id = '';
  state.imagePromptLibrary.status = 'Deleted Image prompt pair.';
  render();
}

function bindImagePromptLibraryBar() {
  const safeRun = async (fn) => {
    try { await fn(); }
    catch (error) { window.alert(`Prompt library action failed: ${error.message}`); }
  };
  const select = document.getElementById('imagePromptLibrarySelect');
  if (select) select.addEventListener('change', (event) => {
    state.imagePromptLibrary.active_id = event.target.value || '';
    const record = selectedImagePromptLibraryRecord();
    state.imagePromptLibrary.status = record ? `Selected prompt: ${record.name || 'Untitled prompt'}` : '';
    render();
  });
  document.getElementById('imagePromptLibrarySaveBtn')?.addEventListener('click', () => safeRun(saveCurrentImagePromptPair));
  document.getElementById('imagePromptLibraryLoadBtn')?.addEventListener('click', () => { applyPromptLibraryRecord(selectedImagePromptLibraryRecord()); render(); });
  document.getElementById('imagePromptLibraryUpdateBtn')?.addEventListener('click', () => safeRun(() => updateSelectedImagePromptPair()));
  document.getElementById('imagePromptLibraryRenameBtn')?.addEventListener('click', () => safeRun(renameSelectedImagePromptPair));
  document.getElementById('imagePromptLibraryDeleteBtn')?.addEventListener('click', () => safeRun(deleteSelectedImagePromptPair));
}

async function guardImageResultsIntegrity({ selectedResultId = '' } = {}) {
  if (state.imageResultsIntegrityChecked && !selectedResultId) return;
  try {
    const params = new URLSearchParams();
    if (selectedResultId) params.set('selected_result_id', selectedResultId);
    const category = activeImageResultsCategory ? activeImageResultsCategory() : 'all';
    if (category) params.set('category', category);
    const response = await fetch(`/api/image/results-integrity?${params.toString()}`);
    if (!response.ok) throw new Error('Results integrity API failed');
    const payload = await response.json();
    state.imageResultsIntegrityChecked = true;
    if (payload.should_clear_cached_results) {
      state.imageResults = [];
      state.activeResultIndex = 0;
    }
    if (payload.should_clear_selected) {
      state.activeSavedResultIndex = 0;
      state.activeSavedResultMetadata = null;
      state.activeSavedResultReuse = null;
      state.activeSavedOutputFileId = '';
    }
  } catch (error) {
    console.warn('Results integrity guard skipped', error);
  }
}
