    if (includeDiagnostics && imageProfileSupportsCapability('inpaint', profile)) options.push({ id: 'inpaint', label: 'Inpaint · API' });
    if (includeDiagnostics && imageProfileSupportsCapability('outpaint', profile)) options.push({ id: 'outpaint', label: 'Outpaint · API' });
