function videoProgressTimestampMs(value = '') {
  if (!value) return 0;
  const parsed = Date.parse(value);
  return Number.isFinite(parsed) ? parsed : 0;
}

function formatVideoElapsed(ms = 0) {
  const safeMs = Math.max(0, Number(ms || 0));
  const totalSeconds = Math.floor(safeMs / 1000);
  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;
  if (hours > 0) return `${hours}h ${String(minutes).padStart(2, '0')}m ${String(seconds).padStart(2, '0')}s`;
  if (minutes > 0) return `${minutes}m ${String(seconds).padStart(2, '0')}s`;
  return `${seconds}s`;
}

function videoRunElapsedMs(progress = state.videoRunProgress) {
  if (!progress?.started_at) return 0;
  const start = videoProgressTimestampMs(progress.started_at);
  if (!start) return 0;
  const end = videoProgressTimestampMs(progress.completed_at) || Date.now();
  return Math.max(0, end - start);
}

function videoProgressElapsedLabel(progress = state.videoRunProgress) {
  if (!progress?.started_at) return '';
  const prefix = progress.completed_at ? 'total' : 'elapsed';
  return `${prefix} ${formatVideoElapsed(videoRunElapsedMs(progress))}`;
}

function updateVideoProgressDom() {
  const progress = state.videoRunProgress || {};
  const fill = document.getElementById('videoProgressFill');
  const text = document.getElementById('videoProgressLabel');
  const elapsed = document.getElementById('videoProgressElapsed');
  if (fill) fill.style.width = `${videoProgressPercent()}%`;
  if (text) text.textContent = progress.label || 'Ready';
  if (elapsed) elapsed.textContent = videoProgressElapsedLabel(progress);
}

function startVideoElapsedTicker() {
  if (videoElapsedTicker) return;
  videoElapsedTicker = window.setInterval(updateVideoProgressDom, 1000);
}

function stopVideoElapsedTicker() {
  if (videoElapsedTicker) {
    window.clearInterval(videoElapsedTicker);
    videoElapsedTicker = null;
  }
}

function setVideoWorkspaceProgress(label, percent = 0, details = {}) {
  const safePercent = Math.max(0, Math.min(100, Number(percent || 0)));
  const previous = state.videoRunProgress || {};
  const nowIso = new Date().toISOString();
  const resetTiming = details.reset_timing === true;
  const status = details.status || (resetTiming ? 'running' : previous.status) || 'running';
  const terminalStatuses = new Set(['completed', 'failed', 'blocked', 'cancelled', 'waiting']);
  const isTerminal = terminalStatuses.has(status);
  const startedAt = resetTiming ? nowIso : (details.started_at || previous.started_at || (safePercent > 0 && !isTerminal ? nowIso : ''));
  const completedAt = details.completed_at || (startedAt && isTerminal ? nowIso : '');
  state.videoRunProgress = {
    label: label || 'Ready',
    percent: safePercent,
    status,
    result_id: resetTiming ? (details.result_id || state.videoActiveResultId || '') : (details.result_id || previous.result_id || state.videoActiveResultId || ''),
    prompt_id: resetTiming ? (details.prompt_id || '') : (details.prompt_id || previous.prompt_id || ''),
    started_at: startedAt,
    completed_at: completedAt,
    elapsed_ms: startedAt ? videoRunElapsedMs({ started_at: startedAt, completed_at: completedAt }) : 0,
    updated_at: nowIso,
  };
  updateVideoProgressDom();
  if (state.videoRunProgress.started_at && !state.videoRunProgress.completed_at) startVideoElapsedTicker();
  if (state.videoRunProgress.completed_at) stopVideoElapsedTicker();
}

function videoProgressLabel(defaultLabel = 'Ready') {
  return state.videoRunProgress?.label || defaultLabel;
}

function videoProgressPercent() {
  return Math.max(0, Math.min(100, Number(state.videoRunProgress?.percent || 0)));
}

function videoRuntimePreflightBlockSummary(preflight = null, fallback = '') {
  const pf = preflight || state.videoLastRuntimePreflight || null;
  if (!pf) return fallback || 'Runtime preflight blocked queueing';
  const errors = Array.isArray(pf.errors) ? pf.errors.filter(Boolean).map(String) : [];
  const actions = Array.isArray(pf.action_items) ? pf.action_items.filter(Boolean).map(String) : [];
  const first = errors[0] || actions[0] || fallback || 'Runtime preflight blocked queueing';
  return first.length > 96 ? `${first.slice(0, 93)}…` : first;
}

function videoRuntimePreflightBlockRows(preflight = null) {
  const pf = preflight || state.videoLastRuntimePreflight || null;
  if (!pf) return [];
  const rows = [];
  const errors = Array.isArray(pf.errors) ? pf.errors : [];
  const actions = Array.isArray(pf.action_items) ? pf.action_items : [];
  const warnings = Array.isArray(pf.warnings) ? pf.warnings : [];
  errors.slice(0, 6).forEach((item) => { if (item) rows.push(`Block: ${item}`); });
  actions.slice(0, 6).forEach((item) => { if (item) rows.push(`Action: ${item}`); });
  warnings.slice(0, 4).forEach((item) => { if (item) rows.push(`Warning: ${item}`); });
  return rows;
}

function revokeVideoLivePreview() {
  if (state.videoLivePreviewUrl && state.videoLivePreviewUrl.startsWith('blob:')) {
    try { URL.revokeObjectURL(state.videoLivePreviewUrl); } catch (_) {}
  }
  state.videoLivePreviewUrl = '';
  state.videoLivePreviewLabel = '';
}

function setVideoLivePreviewUrl(url, label = 'Video live preview updating…') {
  const img = document.querySelector('.neo-video-live-preview img');
  const placeholder = document.querySelector('[data-testid="video-preview-placeholder"]');
  if (img) {
    img.src = url;
    const labelNode = document.querySelector('.neo-video-live-preview span');
    if (labelNode) labelNode.textContent = label;
  } else if (placeholder) {
    placeholder.outerHTML = `<figure class="neo-video-live-preview"><img src="${escapeAttr(url)}" alt="Video live preview"><span>${escapeHtml(label)}</span></figure>`;
  }
  state.videoLivePreviewUrl = url;
  state.videoLivePreviewLabel = label;
}

function applyVideoPreviewBuffer(buffer) {
  const payload = detectImagePreviewPayload(buffer);
  if (!payload) return;
  const blob = new Blob([buffer.slice(payload.offset)], { type: payload.mime || 'image/jpeg' });
  const url = URL.createObjectURL(blob);
  state.videoLivePreviewFrameCount = Number(state.videoLivePreviewFrameCount || 0) + 1;
  const label = `Video live preview — frame ${state.videoLivePreviewFrameCount}`;
  revokeVideoLivePreview();
  setVideoLivePreviewUrl(url, label);
  setVideoWorkspaceProgress(label, Math.max(35, videoProgressPercent()));
}

function closeVideoProgressSocket() {
  if (state.videoProgressSocket) {
    try { state.videoProgressSocket.close(); } catch (_) {}
  }
  state.videoProgressSocket = null;
}

function startVideoProgressSocket(profileId, clientId) {
  if (!profileId || !clientId) return;
  closeVideoProgressSocket();
  const url = new URL('/api/video/progress/ws', window.location.href);
  url.protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
  url.search = `profile_id=${encodeURIComponent(profileId)}&client_id=${encodeURIComponent(clientId)}`;
  try {
    const socket = new WebSocket(url.toString());
    socket.binaryType = 'arraybuffer';
    state.videoProgressSocket = socket;
    socket.addEventListener('open', () => setVideoWorkspaceProgress('Video live progress connected', 18));
    socket.addEventListener('message', async (event) => {
      try {
        if (typeof event.data === 'string') {
          const msg = JSON.parse(event.data || '{}');
          const type = String(msg.type || '').toLowerCase();
          const data = msg.data || msg;
          if (type === 'progress') {
            const value = Number(data.value ?? msg.value ?? 0);
            const max = Number(data.max ?? msg.max ?? 0);
            if (max > 0) setVideoWorkspaceProgress(`Generating node ${value}/${max}`, Math.min(96, Math.max(20, (value / max) * 100)));
          } else if (type === 'executing') {
            if (data.node === null || data.node === undefined) setVideoWorkspaceProgress('Finalizing video output', 97);
            else setVideoWorkspaceProgress(`Executing video node ${data.node}`, Math.max(35, videoProgressPercent()));
          } else if (type === 'execution_success') {
            setVideoWorkspaceProgress('Comfy job finished — importing result', 99);
          } else if (type === 'error') {
            setVideoWorkspaceProgress(data.message || 'Video live progress error', Math.max(25, videoProgressPercent()), { status: 'warning' });
          }
          return;
        }
        if (event.data instanceof ArrayBuffer) applyVideoPreviewBuffer(event.data);
        else if (event.data instanceof Blob) applyVideoPreviewBuffer(await event.data.arrayBuffer());
      } catch (error) { console.warn('Video live preview message skipped', error); }
    });
    socket.addEventListener('close', () => { if (state.videoProgressSocket === socket) state.videoProgressSocket = null; });
    socket.addEventListener('error', () => setVideoWorkspaceProgress('Video live progress waiting', Math.max(25, videoProgressPercent())));
  } catch (error) { console.warn('Video live preview socket failed', error); }
}

function stopVideoResultPoller() {
  if (state.videoResultPoller) {
    clearInterval(state.videoResultPoller);
    state.videoResultPoller = null;
  }
}

function startVideoResultPoller(resultId) {
  if (!resultId) return;
  stopVideoResultPoller();
  let attempts = 0;
  state.videoResultPoller = setInterval(async () => {
    attempts += 1;
    try {
      state.videoActiveResultId = resultId;
      await refreshActiveVideoResultFromComfy({ renderAfter: false, silent: true });
      await refreshVideoResults({ renderAfter: false });
      const record = activeVideoResultRecord();
      if (videoResultFile(record)?.url) {
        stopVideoResultPoller();
        closeVideoProgressSocket();
        setVideoWorkspaceProgress('Video imported — playback ready', 100, { status: 'completed', result_id: resultId });
        render();
        return;
      }
      if (attempts <= 120) {
        setVideoWorkspaceProgress(`Waiting for Comfy video output… ${attempts}`, Math.min(98, Math.max(55, videoProgressPercent())));
        render();
      } else {
        stopVideoResultPoller();
        setVideoWorkspaceProgress('Import still pending — use Refresh Results / Import', 100, { status: 'waiting' });
        render();
      }
    } catch (error) {
      if (attempts > 3) console.warn('Video result poll skipped', error);
    }
  }, 5000);
}

