    high: { id: 'high', label: 'High VRAM', target: '24GB+ / remote GPU', method: 'rife', multipliers: [2, 4], cache: 16, frameCap: 0, badge: 'Longer clips allowed', warnings: ['Experimental TensorRT/GIMM/VSRFI methods stay diagnostic-only.'] },
