    source_result_id: result?.source_result_id || payload?.source_result_id || videoUpscaleScopedValue(result, 'source_result_id') || '',
    source_file_id: result?.source_file_id || payload?.source_file_id || videoUpscaleScopedValue(result, 'source_file_id') || '',
