function isSurfacePlanned(surface) {
  return ['planned', 'future', 'placeholder'].includes(String(surface?.status || '').toLowerCase());
}

function plannedSurfaceMessage(surface) {
  const id = String(surface?.surface_id || '').toLowerCase();
  if (id === 'voice') return 'Voice workflows are planned for a future Neo Studio V2 update. Generation, cloning, and finishing controls are not active in this preview release.';
  if (id === 'music') return 'Music and audio generation workflows are planned for a future Neo Studio V2 update. This workspace is a placeholder in this preview release.';
  if (id === 'board') return 'Board is planned as a future visual planning workspace for outputs, notes, prompts, and reusable assets.';
  return 'This workspace is planned for a future Neo Studio V2 update.';
}

function renderPlannedSurface(surface) {
  if (el.workspaceHeader) {
    el.workspaceHeader.hidden = true;
    el.workspaceHeader.innerHTML = '';
  }
  el.subtabNav.innerHTML = '';
  el.subtabNav.removeAttribute('aria-label');
  delete el.subtabNav.dataset.navKind;
  el.surfacePanels.className = 'neo-grid';
  el.surfacePanels.innerHTML = `<section class="neo-panel wide neo-planned-surface-panel"><div class="neo-panel-header"><div><span class="neo-kicker">Future planned</span><h2>${escapeHtml(surface.display_name || 'Workspace')}</h2><p>${escapeHtml(plannedSurfaceMessage(surface))}</p></div><span class="neo-badge warning">Planned</span></div><div class="neo-empty-state"><strong>No workflows are active here yet.</strong><span>Use Image, Video, Roleplay, Assistant, Prompt & Captioning, or Admin / Backends in this preview release.</span></div><div class="neo-first-run-actions"><button type="button" class="neo-btn primary" onclick="setActiveSubtab('image','generate')">Open Image</button><button type="button" class="neo-btn secondary" onclick="setActiveSubtab('admin','backends')">Open Backends</button></div></section>`;
}

function renderSurfaceNav() {
  el.surfaceNav.innerHTML = '';
  state.surfaces.forEach((surface) => {
    const button = document.createElement('button');
    button.type = 'button';
    button.className = surface.surface_id === state.activeSurfaceId ? 'active' : '';
    button.innerHTML = `${surface.display_name}<small>${titleCaseStatus(surface.status === 'active' ? 'ready' : surface.status)}</small>`;
    button.addEventListener('click', async () => {
      state.activeSurfaceId = surface.surface_id;
      ensureSurfaceRuntime(surface.surface_id);
      saveUiState();
      const presetLoaded = await loadSurfaceDefaultUiPresetOnce(surface.surface_id).catch((error) => {
        state.uiPresetStatus = `Could not load ${surface.display_name || surface.surface_id} default preset: ${error.message}`;
        return false;
      });
      if (!presetLoaded) render();
      recordMemoryEvent(`${surface.surface_id}.surface.opened`, surface.surface_id, { surface: surface.surface_id, default_preset_loaded: Boolean(presetLoaded) });
    });
    el.surfaceNav.appendChild(button);
  });
}


function renderUiPresetControls(surface) {
  const surfaceId = surface?.surface_id || 'image';
  const payload = state.uiPresetsBySurface?.[surfaceId] || { presets: [], default_preset_id: '' };
  const presets = payload.presets || [];
  const activeId = state.activeUiPresetIds?.[surfaceId] || '';
  const options = [{ id: '', label: 'Manual UI preset…' }, ...presets.map((preset) => ({ id: preset.preset_id, label: `${preset.name}${preset.is_default ? ' ★' : ''}` }))];
  const status = state.uiPresetStatus ? `<small class="neo-preset-status">${escapeHtml(state.uiPresetStatus)}</small>` : '<small class="neo-preset-status">Manual save enabled · autosave disabled</small>';
  return `<div class="neo-ui-preset-bar">
    <label>UI Preset${optionSelect('workspaceUiPreset', options, activeId)}</label>
    <div class="neo-ui-preset-actions" aria-label="UI preset actions">
      <button class="neo-icon-btn success" id="uiPresetSaveBtn" type="button" title="Save new UI preset" aria-label="Save new UI preset" data-tooltip="Save new UI preset">💾</button>
      <button class="neo-icon-btn primary" id="uiPresetUpdateBtn" type="button" title="Update selected UI preset" aria-label="Update selected UI preset" data-tooltip="Update selected UI preset">🔄</button>
      <button class="neo-icon-btn secondary" id="uiPresetRenameBtn" type="button" title="Rename selected UI preset" aria-label="Rename selected UI preset" data-tooltip="Rename selected UI preset">✏️</button>
      <button class="neo-icon-btn secondary" id="uiPresetRemoveBtn" type="button" title="Remove preset from current selection" aria-label="Remove preset from current selection" data-tooltip="Remove preset from current selection">🧹</button>
      <button class="neo-icon-btn danger" id="uiPresetDeleteBtn" type="button" title="Delete selected UI preset file" aria-label="Delete selected UI preset file" data-tooltip="Delete selected UI preset file">🗑️</button>
      <button class="neo-icon-btn warning" id="uiPresetDefaultBtn" type="button" title="Make selected UI preset default" aria-label="Make selected UI preset default" data-tooltip="Make selected UI preset default">⭐</button>
    </div>
    ${status}
  </div>`;
}

function bindUiPresetControls(surface) {
  const surfaceId = surface?.surface_id || 'image';
  const select = document.getElementById('workspaceUiPreset');
  if (select) select.addEventListener('change', async (event) => {
    state.activeUiPresetIds[surfaceId] = event.target.value || '';
    await applySelectedUiPreset(surfaceId, state.activeUiPresetIds[surfaceId]);
    render();
  });
  const safeRun = async (fn) => {
    try { await fn(); }
    catch (error) { window.alert(`UI preset action failed: ${error.message}`); }
  };
  document.getElementById('uiPresetSaveBtn')?.addEventListener('click', () => safeRun(() => createUiPresetFromCurrent(surfaceId)));
  document.getElementById('uiPresetUpdateBtn')?.addEventListener('click', () => safeRun(() => updateSelectedUiPreset(surfaceId)));
  document.getElementById('uiPresetRenameBtn')?.addEventListener('click', () => safeRun(() => renameSelectedUiPreset(surfaceId)));
  document.getElementById('uiPresetRemoveBtn')?.addEventListener('click', () => safeRun(() => removeSelectedUiPreset(surfaceId)));
  document.getElementById('uiPresetDeleteBtn')?.addEventListener('click', () => safeRun(() => deleteSelectedUiPreset(surfaceId)));
  document.getElementById('uiPresetDefaultBtn')?.addEventListener('click', () => safeRun(() => makeSelectedUiPresetDefault(surfaceId)));
}

async function loadSurfaceDefaultUiPresetOnce(surfaceId) {
  const id = String(surfaceId || '').trim();
  if (!id) return false;
  state.uiPresetDefaultsLoadedBySurface = state.uiPresetDefaultsLoadedBySurface || {};
  if (state.uiPresetDefaultsLoadedBySurface[id]) return false;
  const presetId = state.activeUiPresetIds?.[id] || state.uiPresetsBySurface?.[id]?.default_preset_id || '';
  if (!presetId) {
    state.uiPresetDefaultsLoadedBySurface[id] = true;
    return false;
  }
  await applySelectedUiPreset(id, presetId);
  return true;
}


function commandStripShell(surfaceId = '', stripId = '', html = '', extraClass = '') {
  const safeSurface = escapeAttr(surfaceId || 'surface');
  const safeStrip = escapeAttr(stripId || 'command');
  const classes = ['neo-command-strip', extraClass].filter(Boolean).join(' ');
  return `<div class="${classes}" data-command-strip-schema="${COMMAND_STRIP_SCHEMA_ID}" data-dom-id-schema="${STRICT_DOM_ID_SCHEMA_ID}" data-command-surface="${safeSurface}" data-command-strip="${safeStrip}">${html}</div>`;
}

function renderImageCommandStrip(ctx = {}) {
  const activeProfile = ctx.activeProfile || activeImageProfile();
  const subtab = ctx.subtab || null;
  const imageReadiness = ctx.imageReadiness || buildImageGenerationReadiness(activeProfile, subtab);
  const imageCloudMode = isCloudImageProfile(activeProfile);
  const generationRunning = Boolean(state.activeImageJob?.job_id);
  const activeCapabilities = providerFeatureCapabilities(activeProfile);
  const runningCapabilities = state.activeImageJob?.capabilities || activeCapabilities;
  const pauseSupported = Boolean(runningCapabilities.pause || state.activeImageJob?.runtime?.control?.pause_supported);
  const cancelSupported = Boolean(runningCapabilities.cancel || state.activeImageJob?.runtime?.control?.cancel_supported);
  const modeOptions = ctx.modeOptions || imageWorkflowModeOptionsForRoute({ includeDiagnostics: state.detailMode === 'expert' });
  const selectedImageMode = ctx.selectedImageMode || normalizedSelectableImageWorkflowMode(subtab?.subtab_id || getImageWorkflowMode() || 'generate');
  const routeBadgeLine = (ctx.routeBadges || activeRouteRequirementBadges()).length ? `<div class="neo-route-mode-badges" data-testid="workflow-route-badges">${badgeRow(ctx.routeBadges || activeRouteRequirementBadges())}</div>` : '';
  const recovery = imageRecoveryActionState();
  const configHtml = imageCloudMode ? `
      <div class="neo-workspace-row compact-row neo-cloud-workspace-mode-row" data-command-role="image-route">
        <label>Workflow Mode <span class="neo-field-hint">cloud generation type</span>${optionSelect('imageWorkflowMode', modeOptions, selectedImageMode)}</label>
        <span class="neo-muted neo-cloud-mode-note">Model, aspect ratio, resolution, and image count are controlled by the selected API profile/defaults.</span>
      </div>
      ${routeBadgeLine}` : `
      <div class="neo-workspace-row compact-row" data-command-role="image-route">
        <label>Model Family${optionSelect('imageWorkspaceFamily', familyOptionList('image'), state.imageDraft.family || 'sdxl')}</label>
        <label>Main Model Type <span class="neo-field-hint">main file route</span>${optionSelect('imageWorkspaceLoader', loaderOptionList(state.imageDraft.family || 'sdxl'), state.imageDraft.loader || defaultLoaderForFamily(state.imageDraft.family || 'sdxl'))}</label>
        <label>Workflow Mode <span class="neo-field-hint">generation type</span>${optionSelect('imageWorkflowMode', modeOptions, selectedImageMode)}</label>
      </div>
      ${routeBadgeLine}`;
  const actionsHtml = `
        <div class="neo-workspace-actions neo-run-actions" data-command-role="image-run-actions">
          <button class="neo-btn secondary" id="imageValidateBtn" type="button">Validate</button>
          <button class="neo-btn primary" id="imageGenerateBtn" type="button" ${generationRunning || (imageReadiness && !imageReadiness.ready) ? 'disabled' : ''}>${generationRunning ? 'Generating…' : 'Generate'}</button>
          <button class="neo-btn warning" id="imagePauseBtn" type="button" ${generationRunning && pauseSupported ? '' : 'disabled'}>${state.activeImageJob?.paused ? 'Resume' : 'Pause'}</button>
          <button class="neo-btn danger" id="imageStopBtn" type="button" ${generationRunning && cancelSupported ? '' : 'disabled'}>Stop</button>
          ${recovery ? '<button class="neo-btn secondary" id="imageRecoveryBtn" type="button">Recover Output</button>' : ''}
        </div>
        ${recovery ? `<div class="neo-watchdog-recovery" data-testid="image-progress-watchdog-recovery"><strong>Recovery available:</strong> ${escapeHtml(recovery.message || recovery.label || 'Neo stopped waiting for final output import.')} </div>` : ''}
        <div class="neo-progress-wrap" aria-label="Image generation progress" data-command-role="image-progress">
          <div class="neo-progress-meta"><span>Progress</span><span class="neo-progress-status"><span id="imageProgressLabel">${imageProgressLabel('Idle')}</span><span id="imageProgressElapsed" class="neo-progress-elapsed">${imageProgressElapsedLabel()}</span></span></div>
          <div class="neo-progress-track"><span id="imageProgressFill" style="width: ${imageProgressPercent()}%"></span></div>
        </div>`;
  return commandStripShell('image', 'image-generation-command-strip', `${configHtml}${renderImageUiPresetLatentCheckpointBanner()}${renderImageLatePassContinuationBanner()}${renderImageGenerationReadinessPreflight(imageReadiness)}${actionsHtml}`, 'neo-image-command-strip');
}

