function sceneDirectorV054BboxFromRegion(region = {}) {
  const box = sceneDirectorClampCanvasBox(region.bbox || {});
  return [Number(box.x.toFixed(4)), Number(box.y.toFixed(4)), Number(Math.min(1, box.x + box.w).toFixed(4)), Number(Math.min(1, box.y + box.h).toFixed(4))];
}

function sceneDirectorV054Region(region = {}, index = 0, settingsOverride = null) {
  const settings = settingsOverride || sceneDirectorSettings();
  const normalized = sceneDirectorNormalizeRegion(region, index);
  const role = sceneDirectorV054NormalizeRole(normalized.role || normalized.type);
  const item = {
    id: normalized.id,
    role,
    label: normalized.label || `Region ${index + 1}`,
    bbox: sceneDirectorV054BboxFromRegion(normalized),
    prompt: normalized.prompt || '',
    negative: normalized.negative_prompt || '',
    strength: Number(normalized.strength ?? 1),
    priority: normalized.priority || 'reinforce',
    // Keep the execution-facing value top-level for the V053 attention bridge;
    // metadata.mask remains available for inspector/replay compatibility.
    feather: Math.max(0, Math.round(Number(normalized.mask?.feather ?? normalized.feather ?? 8))),
  };
  if (normalized.attach_to) item.attach_to = normalized.attach_to;
  if (normalized.relationship) item.relationship = normalized.relationship;
  if (normalized.target_area) item.target_area = normalized.target_area;
  if (normalized.relationship_prompt) item.relationship_prompt = normalized.relationship_prompt;
  if (normalized.local_prompt_template) item.local_prompt_template = normalized.local_prompt_template;
  if (normalized.negative_guard) item.negative_guard = normalized.negative_guard;
  if (normalized.compiler_override && typeof normalized.compiler_override === 'object' && Object.keys(normalized.compiler_override).length) item.compiler_override = normalized.compiler_override;
  if (normalized.conflict_resolution_prompt) item.conflict_resolution_prompt = normalized.conflict_resolution_prompt;
  if (normalized.conflict_negative_guard) item.conflict_negative_guard = normalized.conflict_negative_guard;
  if (normalized.conflict_override && typeof normalized.conflict_override === 'object' && Object.keys(normalized.conflict_override).length) item.conflict_override = normalized.conflict_override;
  if (SCENE_DIRECTOR_V054_BACKGROUND_ZONE_ROLES.includes(role)) {
    item.zone = normalized.zone || sceneDirectorV054BackgroundZone(normalized);
    if (normalized.background_prompt) item.background_prompt = normalized.background_prompt;
    if (normalized.background_negative_guard) item.background_negative_guard = normalized.background_negative_guard;
    if (normalized.background_override && typeof normalized.background_override === 'object' && Object.keys(normalized.background_override).length) item.background_override = normalized.background_override;
  }
  const lock = { ...(normalized.lock || {}) };
  if (role === 'character') {
    const characterLock = sceneDirectorCharacterLockFromSettings(settings);
    if (characterLock.character !== 'off') lock.character = lock.character || characterLock.character;
    ['gender', 'skin_tone', 'hair', 'build', 'body_height', 'outfit', 'negative'].forEach((key) => {
      if (characterLock[key] && characterLock[key] !== 'off') lock[key] = lock[key] || characterLock[key];
    });
  }
  if (Object.keys(lock).length) item.lock = lock;
  if (role === 'character') {
    item.character_traits = sceneDirectorCharacterTraitsFromRegion(normalized);
    const correction = sceneDirectorCharacterLockCorrectionFromRegion(normalized);
    item.character_lock_correction = {
      schema: 'neo.image.scene_director.character_lock_correction.ui.v1',
      releaseStage: 'ready',
      enabled: correction.enabled,
      gender_family: correction.gender_family,
      positive_text: correction.positive_text,
      negative_text: correction.negative_text,
      denoise: correction.denoise,
      steps: correction.steps,
      source: 'visible_region_fields',
    };
  }
  ['detailer'].forEach((key) => {
    if (normalized[key] && typeof normalized[key] === 'object' && Object.keys(normalized[key]).length) item[key] = normalized[key];
  });
  if (normalized.inpaint && typeof normalized.inpaint === 'object' && Object.keys(normalized.inpaint).length) item.inpaint = sceneDirectorV054InpaintTargetFromRegion(normalized);
  if (normalized.edit_intent && typeof normalized.edit_intent === 'object' && Object.keys(normalized.edit_intent).length) item.edit_intent = sceneDirectorV054EditIntentFromRegion(normalized);
  if (normalized.source_image) item.source_image = normalized.source_image;
  if (normalized.source_region_id) item.source_region_id = normalized.source_region_id;
  if (normalized.control && normalized.control.enabled === true) item.control = normalized.control;
  if (sceneDirectorV054ExtensionRoutesHaveSelection(normalized.extension_routes)) item.extension_routes = sceneDirectorV054ExtensionRoutesFromRegion(normalized);
  if (role === 'text') {
    const textSpec = sceneDirectorV054TextFromRegion(normalized);
    item.text = textSpec.text || normalized.prompt || '';
    item.mode = textSpec.mode || 'composite';
    item.text_mode = item.mode;
    item.font_style = textSpec.font_style;
    if (textSpec.font_family) item.font_family = textSpec.font_family;
    item.font_size = textSpec.font_size;
    item.color = textSpec.color;
    if (textSpec.stroke_color) item.stroke_color = textSpec.stroke_color;
    item.stroke_width = textSpec.stroke_width;
    item.align = textSpec.align;
    item.valign = textSpec.valign;
    item.opacity = textSpec.opacity;
    item.rotation = textSpec.rotation;
  }
  item.metadata = {
    ui_type: normalized.type,
    mask: normalized.mask || {},
    identity: normalized.identity || {},
    ipadapter_enabled: Boolean(normalized.ipadapter),
    lora_enabled: Boolean(normalized.lora),
  };
  return item;
}


function sceneDirectorV054ProviderCapability(route = {}) {
  const familyRaw = String(route.family || route.model_family || 'sdxl').toLowerCase().replace(/[\s-]+/g, '_');
  const loaderRaw = String(route.loader || route.model_loader || 'checkpoint').toLowerCase().replace(/[\s-]+/g, '_');
  const family = ({ sd_xl: 'sdxl', stable_diffusion_xl: 'sdxl', sd1_5: 'sd15', sd_1_5: 'sd15', sd_15: 'sd15', stable_diffusion_1_5: 'sd15', flux1: 'flux', flux_1: 'flux', qwen: 'qwen_image_edit', qwen_image: 'qwen_image_edit', qwenimage: 'qwen_image_edit' })[familyRaw] || familyRaw;
  const loader = ['ckpt', 'safetensors', 'checkpoint_loader', 'checkpointloader'].includes(loaderRaw) ? 'checkpoint' : loaderRaw;
  const profile = family === 'sdxl' && loader === 'checkpoint' ? 'sdxl_checkpoint'
    : family === 'sd15' && loader === 'checkpoint' ? 'sd15_checkpoint_experimental'
    : family === 'flux' ? 'flux_adapter_planned'
    : family === 'qwen_image_edit' ? 'qwen_semantic_edit_adapter'
    : 'unsupported_provider';
  const features = {
    scene_graph_json: true,
    scene_graph_planning: true,
    v054_node: profile === 'sdxl_checkpoint' || profile === 'sd15_checkpoint_experimental',
    regional_conditioning: profile === 'sdxl_checkpoint' ? true : profile === 'sd15_checkpoint_experimental' ? true : profile === 'flux_adapter_planned' ? 'workflow_dependent' : profile === 'qwen_semantic_edit_adapter' ? 'semantic_or_mask_adapter' : false,
    character_lock: profile === 'sdxl_checkpoint' || profile === 'sd15_checkpoint_experimental' ? true : profile === 'qwen_semantic_edit_adapter' ? 'semantic_instruction' : profile === 'flux_adapter_planned' ? 'prompt_or_adapter_dependent' : false,
    regional_controlnet: profile === 'sdxl_checkpoint' ? true : profile === 'sd15_checkpoint_experimental' || profile === 'flux_adapter_planned' ? 'workflow_dependent' : false,
    regional_detailer: ['sdxl_checkpoint', 'sd15_checkpoint_experimental', 'flux_adapter_planned', 'qwen_semantic_edit_adapter'].includes(profile),
    composite_text: true,
    native_text_editing: profile === 'qwen_semantic_edit_adapter' ? true : profile === 'flux_adapter_planned' ? 'composite_or_native' : false,
    img2img_region_reuse: ['sdxl_checkpoint', 'sd15_checkpoint_experimental', 'flux_adapter_planned', 'qwen_semantic_edit_adapter'].includes(profile),
    inpaint_region_targeting: ['sdxl_checkpoint', 'sd15_checkpoint_experimental', 'flux_adapter_planned', 'qwen_semantic_edit_adapter'].includes(profile),
    output_inspector_source_stack: true,
    latent_replay: profile === 'sdxl_checkpoint' || profile === 'sd15_checkpoint_experimental',
    native_semantic_editing: profile === 'qwen_semantic_edit_adapter' ? true : profile === 'flux_adapter_planned' ? 'kontext_if_available' : false,
  };
  const notices = profile === 'sdxl_checkpoint' ? [{ level: 'info', code: 'provider_sdxl_full_v054_locked', message: 'SDXL checkpoint route is the locked full V054 implementation target.' }]
    : profile === 'flux_adapter_planned' ? [{ level: 'warning', code: 'provider_flux_adapter_required', message: 'Flux preserves the V054 scene graph but needs a Flux adapter for regional conditioning.' }]
    : profile === 'qwen_semantic_edit_adapter' ? [{ level: 'warning', code: 'provider_qwen_semantic_adapter', message: 'Qwen should use semantic/mask-adapter instructions instead of the SDXL V054 node path.' }]
    : profile === 'sd15_checkpoint_experimental' ? [{ level: 'warning', code: 'provider_sd15_experimental', message: 'SD1.5 V054 support is experimental and workflow-dependent.' }]
    : [{ level: 'warning', code: 'provider_unsupported_v054', message: 'This provider has no validated V054 execution route.' }];
  return {
    schema: 'neo.image.scene_director.provider_capabilities.v054.v1',
    releaseStage: 'ready',
    legacy_qwen_adapter_anchor: 'SD-V054-20',
    provider_profile: profile,
    route_kind: profile === 'sdxl_checkpoint' ? 'v054_node_workflow' : profile === 'qwen_semantic_edit_adapter' ? 'semantic_edit_adapter' : profile === 'flux_adapter_planned' ? 'flux_adapter_required' : 'planning_only',
    family,
    loader,
    mode: route.workflow_mode || route.mode || 'generate',
    features,
    latent_policy: features.latent_replay ? 'compatible_route_only' : 'disabled_for_provider',
    source_image_policy: 'reusable_across_providers',
    mask_policy: 'requires_size_match',
    flux_adapter_plan: profile === 'flux_adapter_planned' ? sceneDirectorV054FluxAdapterPlan(null, route) : null,
    qwen_adapter_plan: profile === 'qwen_semantic_edit_adapter' ? sceneDirectorV054QwenAdapterPlan(null, route) : null,
    notices,
  };
}

function sceneDirectorV054FluxAdapterPlan(sceneGraph = null, route = {}) {
  const graph = sceneGraph && typeof sceneGraph === 'object' ? sceneGraph : { version: 'v054', regions: [] };
  const regions = Array.isArray(graph.regions) ? graph.regions : [];
  const byId = new Map(regions.map((region) => [String(region.id || ''), region]));
  const regionalInstructions = regions.map((region, index) => {
    const role = String(region.role || region.type || 'custom');
    const id = String(region.id || `region_${index + 1}`);
    const label = String(region.label || region.name || id);
    const parent = region.attach_to ? byId.get(String(region.attach_to)) : null;
    const parentLabel = parent ? String(parent.label || parent.name || parent.id || region.attach_to) : '';
    const prompt = String(region.prompt || region.text || '');
    const relationship = String(region.relationship || '');
    const instruction = parentLabel
      ? `Apply ${label} to ${parentLabel}${relationship ? ` with relationship ${relationship}` : ''}: ${prompt}`
      : role === 'background' || role === 'background_object' || role === 'transition_effect'
        ? `Use ${label} as ${String(region.zone || region.background_zone || 'background zone')}: ${prompt}`
        : role === 'text'
          ? `Text region ${label}: render ${String(region.text || prompt)} using ${String(region.mode || region.text_mode || 'composite')} text handling.`
          : `${label}: ${prompt}`;
    return { id, label, role, bbox: region.bbox || null, attach_to: region.attach_to || null, relationship: relationship || null, instruction, mask_hint: 'region_bbox_or_mask_adapter' };
  });
  const globalBlock = graph.global && typeof graph.global === 'object' ? graph.global : {};
  return {
    schema: 'neo.image.scene_director.flux_adapter_plan.v054.v1',
    releaseStage: 'ready',
    provider_profile: 'flux_adapter_planned',
    route_kind: 'flux_adapter_required',
    status: 'planning_ready',
    adapter_required: true,
    uses_sdxl_v054_node: false,
    scene_graph_json_reused: true,
    global_prompt: String(globalBlock.prompt || ''),
    global_negative: String(globalBlock.negative || ''),
    regional_instructions: regionalInstructions,
    mask_strategy: { mode: 'bbox_or_mask_adapter', requires_size_match: true },
    conditioning_strategy: { route: 'flux_workflow_adapter', regional_conditioning: 'workflow_dependent' },
    controlnet_strategy: { route: 'flux_control_adapter_if_available', regional_controlnet: 'workflow_dependent' },
    detailer_strategy: { route: 'post_generation_detailer_allowed', regional_detailer: true },
    replay_policy: { scene_graph_json: 'reusable', source_image: 'reusable_across_providers', masks: 'requires_size_match', saved_latent: 'disabled_for_provider' },
  };
}

function sceneDirectorV054QwenAdapterPlan(sceneGraph = null, route = {}) {
  const graph = sceneGraph && typeof sceneGraph === 'object' ? sceneGraph : { version: 'v054', regions: [] };
  const regions = Array.isArray(graph.regions) ? graph.regions : [];
  const byId = new Map(regions.map((region) => [String(region.id || ''), region]));
  const regionalInstructions = regions.map((region, index) => {
    const role = String(region.role || region.type || 'custom');
    const id = String(region.id || `region_${index + 1}`);
    const label = String(region.label || region.name || id);
    const parent = region.attach_to ? byId.get(String(region.attach_to)) : null;
    const parentLabel = parent ? String(parent.label || parent.name || parent.id || region.attach_to) : '';
    const prompt = String(region.prompt || region.text || '');
    const relationship = String(region.relationship || '');
    const instruction = parentLabel
      ? `Apply only this local change to ${parentLabel}${relationship ? ` with relationship ${relationship}` : ''}: ${prompt}`
      : role === 'background' || role === 'background_object' || role === 'transition_effect'
        ? `Edit ${String(region.zone || region.background_zone || 'background zone')} to show ${prompt}; keep foreground subjects stable.`
        : role === 'text'
          ? `Render or edit readable text '${String(region.text || prompt)}' using ${String(region.mode || region.text_mode || 'native')} text handling.`
          : `${label}: ${prompt}`;
    return { id, label, role, bbox: region.bbox || null, attach_to: region.attach_to || null, relationship: relationship || null, instruction, mask_hint: 'optional_mask_adapter_or_bbox' };
  });
  const globalBlock = graph.global && typeof graph.global === 'object' ? graph.global : {};
  return {
    schema: 'neo.image.scene_director.qwen_adapter_plan.v054.v1',
    releaseStage: 'ready',
    provider_profile: 'qwen_semantic_edit_adapter',
    route_kind: 'semantic_edit_adapter',
    status: 'planning_ready',
    adapter_required: true,
    uses_sdxl_v054_node: false,
    scene_graph_json_reused: true,
    global_prompt: String(globalBlock.prompt || ''),
    global_negative: String(globalBlock.negative || ''),
    semantic_edit_instruction: [String(globalBlock.prompt || ''), ...regionalInstructions.map((item) => item.instruction)].filter(Boolean).join(' '),
    regional_instructions: regionalInstructions,
    mask_strategy: { mode: 'optional_mask_or_bbox_adapter', requires_size_match: true },
    conditioning_strategy: { route: 'qwen_semantic_instruction_adapter', regional_conditioning: 'semantic_or_mask_adapter' },
    edit_strategy: { route: 'source_image_semantic_edit', native_semantic_editing: true },
    text_strategy: { default: 'native_text_edit_or_composite', native_text_editing: true, composite_fallback: true },
    replay_policy: { scene_graph_json: 'reusable', source_image: 'required_for_image_edit_or_reusable_across_providers', masks: 'requires_size_match', saved_latent: 'disabled_for_provider' },
  };
}

function sceneDirectorV054SdxlFullImplementationLock(providerCapabilities = {}) {
  const features = providerCapabilities && providerCapabilities.features ? providerCapabilities.features : {};
  const required = [
    'scene_graph_json', 'v054_node', 'regional_conditioning', 'character_lock',
    'linked_detail_lanes', 'relationship_compiler', 'prompt_compiler_registry',
    'conflict_resolver', 'complexity_meter', 'mixed_background_regions',
    'regional_controlnet', 'regional_detailer', 'text_regions', 'composite_text',
    'img2img_region_reuse', 'inpaint_region_targeting', 'output_inspector_source_stack',
    'source_image_reuse', 'latent_replay'
  ];
  const missing = required.filter((name) => features[name] !== true);
  const locked = providerCapabilities.provider_profile === 'sdxl_checkpoint';
  return {
    schema: 'neo.image.scene_director.sdxl_full_lock.v054.v1',
    releaseStage: 'ready',
    provider_profile: providerCapabilities.provider_profile || 'sdxl_checkpoint',
    locked_provider: 'sdxl_checkpoint',
    locked,
    ready: locked && missing.length === 0,
    required_features: required,
    missing_features: missing,
    stress_test: { name: 'sdxl_v054_two_subject_portal_stress' }
  };
}

