      if (imageUpscaleModelCatalogState.seedvr2_dit_models.length && !imageUpscaleModelCatalogState.seedvr2_dit_models.includes(current.seedvr2_dit_model)) patch.seedvr2_dit_model = imageUpscaleModelCatalogState.seedvr2_dit_models[0];
