  if (!profile) return;
  const units = ipAdapterNormalizeUiUnits(settings.units || []);
  const targetUid = settings.identity_profile_target_unit || 'primary';
  let targetIndex = units.findIndex((unit) => String(unit.uid) === String(targetUid));
