    ...units[targetIndex],
    enabled: profile.mode !== 'trigger_only',
    mode,
    image_names: profile.reference_images || [],
    image_name: (profile.reference_images || [])[0] || '',
    clip_vision: profile.clip_vision || units[targetIndex].clip_vision || 'auto',
    weight: profile.weight ?? units[targetIndex].weight,
    weight_faceidv2: profile.weight ?? units[targetIndex].weight_faceidv2,
    start_at: profile.start_at ?? units[targetIndex].start_at,
    end_at: profile.end_at ?? units[targetIndex].end_at,
    faceid_lora_strength: profile.faceid_lora_strength ?? units[targetIndex].faceid_lora_strength,
    trigger_words: profile.trigger_words || units[targetIndex].trigger_words || '',
    optional_lora: profile.optional_lora || units[targetIndex].optional_lora || '',
    identity_profile_id: profile.profile_id,
    identity_profile_name: profile.profile_name,
