    controlnet_task: controlNetNormalizeTask(raw.controlnet_task || raw.params?.controlnet_task || 'map_control', workflowMode),
    qwen_controlnet_adapter: controlNetNormalizeQwenAdapter(raw.qwen_controlnet_adapter || raw.params?.qwen_controlnet_adapter || 'auto'),
    flux_controlnet_adapter: controlNetNormalizeFluxAdapter(raw.flux_controlnet_adapter || raw.params?.flux_controlnet_adapter || 'auto'),
