  const replace = document.getElementById('loraPromptReplace');
  if (replace) replace.addEventListener('click', () => appendToPositivePrompt(sample?.value || record?.example_prompt || '', true));
  const prev = document.getElementById('loraPreviewPrev');
  if (prev) prev.addEventListener('click', () => { const current = loraStackSettings().library.selected_preview_index || 0; updateLoraStackSettings({ library: { selected_preview_index: Math.max(0, current - 1) } }); render(); });
  const next = document.getElementById('loraPreviewNext');
  if (next) next.addEventListener('click', () => { const current = loraStackSettings().library.selected_preview_index || 0; updateLoraStackSettings({ library: { selected_preview_index: current + 1 } }); render(); });
  const edit = document.getElementById('loraLibraryEdit');
  if (edit) edit.addEventListener('click', () => { updateLoraStackSettings({ library: { edit_mode: !loraStackSettings().library.edit_mode } }); render(); });
  const civitaiUrl = document.getElementById('loraCivitaiUrl');
