  const settings = wildcardsSettings();
  const mode = document.getElementById('wildcardsImportMode')?.value || 'merge';
  const form = new FormData();
  form.append('file', file);
  const response = await fetch(`/api/extensions/wildcards/import?mode=${encodeURIComponent(mode)}&root=${encodeURIComponent(settings.root || '')}`, { method: 'POST', body: form });
  const result = await response.json().catch(() => ({}));
  if (!response.ok || result.ok === false) throw new Error(result.detail || result.message || 'Wildcard import failed');
