      <div class="neo-wildcards-card"><strong>Values preview</strong><ul>${valuesPreview}</ul><div class="neo-wildcards-actions"><button class="neo-btn primary" type="button" id="wildcardsInsertToken" ${locked || !selected ? 'disabled' : ''}>Insert token</button><button class="neo-btn secondary" type="button" id="wildcardsPreviewResolve" ${locked ? 'disabled' : ''}>Preview resolve</button><button class="neo-btn secondary" type="button" id="wildcardsApplyFirst" ${(settings.last_preview_results || []).length ? '' : 'disabled'}>Apply first result</button></div></div>
