function layerDiffuseValidationPreview(record = {}, appliedOverride = null) {
  const settings = layerDiffuseSettings();
  const applied = appliedOverride === null ? Boolean(settings.enabled) : Boolean(appliedOverride);
  const route = layerDiffuseRouteSnapshot(record);
  const items = [];
  if (!applied) items.push({ extension_id: LAYERDIFFUSE_EXTENSION_ID, level: 'info', field: 'enabled', message: 'LayerDiffuse is disabled.' });
  if (route.route_state !== 'available') items.push({ extension_id: LAYERDIFFUSE_EXTENSION_ID, level: 'warning', field: 'route', message: route.reason || `Route gated: ${route.route_state}` });
  if (settings.output_policy === 'replace' && !settings.replace_target_id) items.push({ extension_id: LAYERDIFFUSE_EXTENSION_ID, level: 'error', field: 'replace_target_id', message: 'Replace output policy requires a target output id.' });
  if (settings.output_policy === 'replace' && !settings.replace_confirmed) items.push({ extension_id: LAYERDIFFUSE_EXTENSION_ID, level: 'error', field: 'replace_confirmed', message: 'Replace output policy requires visible confirmation.' });
  if (Number(settings.layerdiffuse_weight) < 0 || Number(settings.layerdiffuse_weight) > 2) items.push({ extension_id: LAYERDIFFUSE_EXTENSION_ID, level: 'error', field: 'layerdiffuse_weight', message: 'LayerDiffuse weight must be between 0 and 2.' });
  if (Number(settings.sub_batch_size) < 1 || Number(settings.sub_batch_size) > 64) items.push({ extension_id: LAYERDIFFUSE_EXTENSION_ID, level: 'error', field: 'sub_batch_size', message: 'Sub-batch size must be between 1 and 64.' });
  if (applied) {
    layerDiffuseRequiredImageSlots(settings.mode).forEach((requirement) => {
      if (!String(settings[requirement.field] || '').trim()) {
        items.push({ extension_id: LAYERDIFFUSE_EXTENSION_ID, level: 'error', field: requirement.field, message: `${requirement.label} is required for ${layerDiffuseModeLabel(settings.mode)}.` });
      }
    });
  }
  return items;
}
