function adetailerManualTargetMaker(settings, disabled = false) {
  const total = (settings.detailer_passes || []).reduce((sum, pass) => sum + adetailerManualBoxCount(pass.manual_boxes), 0);
  const passOptions = (settings.detailer_passes || []).map((pass, index) => `<option value="${index}">${escapeHtml(`#${index + 1} ${pass.label || pass.mode || 'Pass'}`)}</option>`).join('');
  const mapperActions = `<div class="neo-adetailer-toolbar neo-adetailer-prompt-actionbar neo-adetailer-target-actionbar" aria-label="ADetailer target prompt actions"><button class="btn btn-small" id="adetailerPromptMapDetect" type="button" title="Detect targets on the loaded canvas image/current output" ${disabled ? 'disabled' : ''}>🎯 Detect targets</button><button class="btn btn-small" id="adetailerPromptMapApply" type="button" title="Apply kept target rows and compile their prompts into [SEP] chunks" ${disabled ? 'disabled' : ''}>↪️ Apply [SEP]</button><button class="btn btn-small" id="adetailerPromptMapCopyFirst" type="button" title="Copy target #1 positive/negative prompt into all target rows" ${disabled ? 'disabled' : ''}>1️⃣ Use #1 for all</button><button class="btn btn-small" id="adetailerPromptMapClear" type="button" title="Clear per-target prompt fields, keeping boxes" ${disabled ? 'disabled' : ''}>🧹 Clear prompts</button></div>`;
  return `<section class="neo-adetailer-subpanel neo-adetailer-target-maker"><div class="neo-adetailer-subhead"><div><strong>Visual box drawer + target picker</strong><p class="neo-muted">manual ADetailer target editor. Load/detect targets, keep/remove rows, add per-target prompts, then apply them into the active pass.</p></div><div class="neo-adetailer-toolbar neo-adetailer-canvas-actionbar" aria-label="ADetailer canvas source actions"><button class="btn btn-small" id="adetailerUseSourceImage" type="button" title="Load a source image into the manual target canvas" ${disabled ? 'disabled' : ''}>Use source image</button><button class="btn btn-small" id="adetailerUseCurrentOutput" type="button" title="Load the current output into the manual target canvas" ${disabled ? 'disabled' : ''}>Use current output</button><button class="btn btn-small" id="adetailerPreviewSourceDetections" type="button" title="Preview detections on the selected source image" ${disabled ? 'disabled' : ''}>Preview source detections</button><button class="btn btn-small" id="adetailerPreviewOutputDetections" type="button" title="Preview detections on the current output image" ${disabled ? 'disabled' : ''}>Preview output detections</button></div></div><div class="neo-adetailer-canvas-shell" data-adetailer-canvas-root><input id="adetailerPreviewImageFile" type="file" accept="image/*" style="display:none"><div class="neo-adetailer-canvas-topbar"><label>Active pass<select id="adetailerCanvasPassIndex" ${disabled ? 'disabled' : ''}>${passOptions}</select></label><select id="adetailerPreviewMerge" ${disabled ? 'disabled' : ''}><option value="replace">Replace current targets</option><option value="append">Append to current targets</option></select><select id="adetailerPriorityPreset" ${disabled ? 'disabled' : ''}><option value="respect_pass">Respect pass settings</option><option value="primary_subject">Main subject only</option><option value="primary_plus_secondary">Main + secondary</option><option value="balanced">Balanced</option><option value="crowd_scan">Crowd scan</option></select></div><div class="neo-adetailer-canvas-stage"><canvas id="adetailerManualCanvas" width="960" height="540" aria-label="ADetailer manual target drawing canvas"></canvas><div id="adetailerCanvasEmpty" class="neo-adetailer-canvas-empty">Load/preview an image, then drag on the canvas to create manual ADetailer targets. ${total} manual region${total === 1 ? '' : 's'} currently staged.</div></div>${mapperActions}<div class="neo-adetailer-toolbar"><label class="neo-toggle-row"><input id="adetailerAutoSuppressTiny" type="checkbox" checked ${disabled ? 'disabled' : ''}> <span>Auto-suppress tiny background faces</span></label><label class="neo-toggle-row"><input id="adetailerConfidenceHeat" type="checkbox" checked ${disabled ? 'disabled' : ''}> <span>Confidence heat preview</span></label><button class="btn btn-small" id="adetailerAddManualBox" type="button" ${disabled ? 'disabled' : ''}>＋ Add canvas box</button><button class="btn btn-small" id="adetailerRemoveSelectedBox" type="button" ${disabled ? 'disabled' : ''}>Remove selected</button><button class="btn btn-small" id="adetailerSyncText" type="button" ${disabled ? 'disabled' : ''}>Sync canvas → text</button><button class="btn btn-small" id="adetailerClearBoxes" type="button" ${disabled ? 'disabled' : ''}>Clear boxes</button></div><div class="neo-adetailer-toolbar"><button class="btn btn-small" id="adetailerExportSnapshot" type="button" ${disabled ? 'disabled' : ''}>Export snapshot</button><button class="btn btn-small" id="adetailerImportSnapshot" type="button" ${disabled ? 'disabled' : ''}>Import snapshot</button><button class="btn btn-small" id="adetailerSyncFromText" type="button" ${disabled ? 'disabled' : ''}>Sync text → canvas</button></div><div id="adetailerCanvasBoxList" class="neo-adetailer-box-list"></div></div><p class="neo-muted" id="adetailerPreviewStatus">Upload/select an image, draw/detect targets, edit per-target prompts, then Apply [SEP] or sync to the active pass.</p></section>`;
}
function adetailerLiveReport(settings, route) {
  const passes = settings.detailer_passes || [];
  const enabledPasses = passes.filter((pass, index) => index === 0 || pass.enabled !== false);
  const manualCount = enabledPasses.reduce((sum, pass) => sum + adetailerManualBoxCount(pass.manual_boxes), 0);
  const sepCount = enabledPasses.reduce((sum, pass) => sum + Math.max(adetailerSepParts(pass.positive_prompt).length, adetailerSepParts(pass.negative_prompt).length), 0);
  const lockReady = enabledPasses.filter((pass) => String(pass.reference_lock || 'none') !== 'none' && adetailerReferenceLockDependency(pass).ready).length;
  return `<section class="neo-adetailer-subpanel neo-adetailer-report"><div class="neo-adetailer-subhead"><div><strong>ADetailer report</strong><p class="neo-muted">Live summary of the current repair setup.</p></div><button class="btn btn-small" id="adetailerCopyReport" type="button">Copy report</button></div><div class="neo-badge-row">${badgeRow([`${enabledPasses.length} pass${enabledPasses.length === 1 ? '' : 'es'}`, `${manualCount} manual box${manualCount === 1 ? '' : 'es'}`, `${sepCount} [SEP] chunks`, `${lockReady} reference lock${lockReady === 1 ? '' : 's'} ready`, `route ${route.route_state}`, settings.provider || 'ultralytics'])}</div></section>`;
}
function adetailerPanel(record) {
  const route = adetailerActiveRoute(record);
  const catalogRuntime = ['comfyui', 'comfyui_portable'].includes(route.backend) ? adetailerEnsureModelCatalog() : adetailerModelCatalogState();
  const settings = adetailerSettings();
  const policy = adetailerRouteUiPolicy(route);
  const controlsEnabled = adetailerRouteControlsEnabled(route);
  if (!adetailerRouteVisible(route)) {
    const body = `<section class="neo-adetailer-panel neo-adetailer-panel--route-hidden" data-extension-id="${ADETAILER_EXTENSION_ID}" data-route-state="${escapeAttr(route.route_state)}"><p class="neo-muted">ADetailer is installed and mounted under Image → Finish, but this selected route is unsupported.</p><p class="neo-warn">${escapeHtml(route.reason || 'Unsupported route.')}</p><p class="neo-muted">Use a supported SDXL/SD1.5 checkpoint route or Expert mode for diagnostics.</p></section>`;
    return panel('ADetailer', body, false, 'Unsupported');
  }
  const disabled = !controlsEnabled;
  const compact = state.detailMode === 'compact';
  const guided = state.detailMode !== 'expert';
  const expert = state.detailMode === 'expert';
  const status = adetailerStatusLabel(route, settings);
  const routeBadge = policy.badge || route.route_state;
  const passCards = settings.detailer_passes.map((pass, index) => adetailerPassCard(pass, index, disabled, false)).join('');
  const manualToolsActive = adetailerHasManualTargetMode(settings);
  const manualTargetTools = manualToolsActive ? adetailerManualTargetMaker(settings, disabled) : adetailerManualToolsNotice(settings);
  const promptMapperTools = '';
  const refreshDisabled = disabled || catalogRuntime.loading;
  const refreshLabel = catalogRuntime.loading ? 'Refreshing…' : 'Refresh models';
  const catalogStatusClass = catalogRuntime.error ? 'neo-warn' : 'neo-muted';
  const shared = `<section class="neo-adetailer-subpanel" data-adetailer-catalog-state="${catalogRuntime.loading ? 'loading' : catalogRuntime.error ? 'error' : catalogRuntime.loaded ? 'loaded' : 'idle'}" data-adetailer-catalog-profile="${escapeAttr(adetailerCatalogProfileId())}" data-adetailer-model-scan-state="${catalogRuntime.loading ? 'loading' : catalogRuntime.error ? 'error' : catalogRuntime.loaded ? 'loaded' : 'idle'}" data-adetailer-model-scan-profile="${escapeAttr(adetailerCatalogProfileId())}" aria-busy="${catalogRuntime.loading ? 'true' : 'false'}"><div class="neo-adetailer-subhead"><div><strong>Shared defaults</strong><p class="neo-muted">These affect the whole detailer stack. Per-pass cards below inherit them.</p></div><button class="btn btn-small" id="adetailerRefreshModels" type="button" ${refreshDisabled ? 'disabled' : ''}>${refreshLabel}</button><button class="btn btn-small" id="adetailerDownloadSam" type="button" ${disabled ? 'disabled' : ''}>Download SAM</button></div><div class="neo-cfg-fix-control-grid">
    <label>SAM preset${adetailerOptionSelect('adetailerSamPreset', [{id:'',label:'Pick SAM preset…'}, {id:'vit_b',label:'SAM ViT-B'}, {id:'vit_l',label:'SAM ViT-L'}, {id:'vit_h',label:'SAM ViT-H'}], settings.sam_preset, disabled)}</label>
    <label>Detector provider${adetailerOptionSelect('adetailerProvider', [{id:'ultralytics',label:'Ultralytics'}, {id:'onnx',label:'ONNX'}], settings.provider, disabled)}</label>
    <label>SAM refine model<input id="adetailerSamModel" type="text" value="${escapeAttr(settings.sam_model)}" placeholder="None" list="adetailerSamModelList" ${disabled ? 'disabled' : ''}></label>
    <label>Custom classes / notes<input id="adetailerCustomClasses" type="text" value="${escapeAttr(settings.custom_classes)}" placeholder="person, face, left hand, clothing..." ${disabled ? 'disabled' : ''}></label>
    <label>Confidence<input id="adetailerConfidence" type="number" min="0" max="1" step="0.01" value="${escapeAttr(settings.confidence)}" ${disabled ? 'disabled' : ''}></label>
    <label>Top-K<input id="adetailerTopK" type="number" min="0" step="1" value="${escapeAttr(settings.top_k)}" ${disabled ? 'disabled' : ''}></label>
    <label>BBox grow<input id="adetailerBboxGrow" type="number" step="1" value="${escapeAttr(settings.bbox_grow)}" ${disabled ? 'disabled' : ''}></label>
    <label>Mask blur<input id="adetailerMaskBlur" type="number" min="0" step="1" value="${escapeAttr(settings.mask_blur)}" ${disabled ? 'disabled' : ''}></label>
    <label>Denoise<input id="adetailerDenoise" type="number" min="0" max="1" step="0.01" value="${escapeAttr(settings.denoise)}" ${disabled ? 'disabled' : ''}></label>
    <label>Steps<input id="adetailerSteps" type="number" min="1" step="1" value="${escapeAttr(settings.steps)}" ${disabled ? 'disabled' : ''}></label>
    <label>CFG cap<input id="adetailerCfg" type="number" min="0" max="15" step="0.1" value="${escapeAttr(settings.cfg)}" ${disabled ? 'disabled' : ''}></label>
    <label class="neo-toggle-row"><input id="adetailerUseMainPrompt" type="checkbox" ${settings.use_main_prompt ? 'checked' : ''} ${disabled ? 'disabled' : ''}> <span>Use main prompts</span></label>
    <label class="neo-toggle-row"><input id="adetailerForceInpaint" type="checkbox" ${settings.force_inpaint ? 'checked' : ''} ${disabled ? 'disabled' : ''}> <span>Force inpaint pass</span></label>
  </div><p class="${catalogStatusClass}" id="adetailerCatalogStatus" role="status" aria-live="polite">${escapeHtml(adetailerCatalogStatusSummary())}</p><p class="neo-muted">At queue time Neo verifies the exact detector value against the active Comfy provider. After adding or moving detector files, refresh Comfy nodes and then Refresh models here.</p>${adetailerCatalogDatalist(settings)}</section>`;
  const details = compact ? '' : `<p class="neo-muted">Selective local repair using Impact Pack-style ADetailer nodes, with draft persistence, replay-safe restore, multi-pass execution, and drag-to-draw manual targets.</p>${route.reason && disabled ? `<p class="neo-warn">${escapeHtml(route.reason)}</p>` : ''}`;
  const stagedSource = settings.staged_preview_source || null;
  const stagedSourceLabel = adetailerStagedPreviewSourceLabel();
  const stagedSourceBlock = stagedSource ? `<div class="neo-preview-action-staged-source neo-preview-action-staged-source--adetailer"><span>🩹+ Staged source</span><strong>${escapeHtml(stagedSourceLabel)}</strong><button id="adetailerClearPreviewSource" type="button" class="neo-mini-btn">Clear</button></div>` : '';
  const expertBlock = expert ? `<div class="neo-extension-expert-block"><div class="neo-badge-row">${badgeRow([`Route: ${route.route_key}`, `State: ${route.route_state}`, 'Mount: image.finish.adetailer', 'Workflow hook: active', 'UI controls: ready'])}</div><pre>${escapeHtml(JSON.stringify(adetailerPayloadPreview(record), null, 2))}</pre></div>` : '';
  const body = `<section class="neo-adetailer-panel" data-extension-id="${ADETAILER_EXTENSION_ID}" data-stage="G3" data-route-aware="true" data-route-state="${escapeAttr(route.route_state)}" data-display-mode="${escapeAttr(state.detailMode)}">
    <header class="neo-cfg-fix-panel__header"><div><strong>ADetailer</strong>${!compact ? '<span class="neo-muted">Built-in Finish extension</span>' : ''}</div><div class="neo-extension-status-line">${extensionEnableStateChip(settings.enabled)}<span class="neo-state-pill ${status === 'Enabled' ? 'success' : (status === 'Experimental' ? 'warning' : '')}">${escapeHtml(status)}</span><span class="neo-badge">${escapeHtml(routeBadge)}</span></div></header>
    ${details}
    ${stagedSourceBlock}
    <div class="neo-cfg-fix-toggle-row"><label class="neo-toggle-row"><input id="adetailerEnabled" type="checkbox" ${settings.enabled ? 'checked' : ''} ${disabled ? 'disabled' : ''}> <span>Use ADetailer for this generation</span></label></div>
    ${shared}
    <section class="neo-adetailer-subpanel"><div class="neo-adetailer-subhead"><div><strong>Detailer pass cards</strong><p class="neo-muted">Primary + additional passes. Each card can target faces, hands, people, or custom/manual regions.</p></div><button class="btn btn-small" id="adetailerAddPass" type="button" ${disabled ? 'disabled' : ''}>＋ Add pass</button></div><div id="adetailerPassList" class="neo-adetailer-pass-list">${passCards}</div></section>
    ${manualTargetTools}
    ${adetailerLiveReport(settings, route)}
    ${guided ? `<p class="neo-muted">${escapeHtml(settings.enabled ? `${(settings.detailer_passes || []).length} pass(es) staged · denoise ${settings.denoise} · ${settings.steps} steps` : 'ADetailer is ready. Enable it to add the repair pass to this generation.')}</p>` : ''}
    ${expertBlock}
  </section>`;
  return panel('ADetailer', body, false, status);
}

function builtInExtensionPanel(record) {
// Compatibility marker for existing regression tests: if (extensionId(record) === CFG_FIX_EXTENSION_ID) return cfgFixPanel(record);
  const id = extensionId(record);
  try {
    if (id === CFG_FIX_EXTENSION_ID) return cfgFixPanel(record);
    if (id === CONTROLNET_EXTENSION_ID) return controlNetPanel(record);
    if (id === IP_ADAPTER_EXTENSION_ID) return ipAdapterPanel(record);
    if (id === SCENE_DIRECTOR_EXTENSION_ID) return sceneDirectorPanel(record);
    if (id === HIGH_RES_LAB_EXTENSION_ID) return highResLabPanel(record);
    if (id === IMAGE_UPSCALE_EXTENSION_ID) return imageUpscalePanel(record);
    if (id === BACKGROUND_REMOVAL_EXTENSION_ID) return backgroundRemovalPanel(record);
    if (id === ADETAILER_EXTENSION_ID) return adetailerPanel(record);
    if (id === LORA_STACK_EXTENSION_ID) return loraStackPanels(record);
    if (id === EMBEDDINGS_TI_EXTENSION_ID) return embeddingsTiPanel(record);
    if (id === WILDCARDS_EXTENSION_ID) return wildcardsPanel(record);
    if (id === STYLE_STACK_EXTENSION_ID) return styleStackPanel(record);
    const manifest = record.manifest || {};
    const body = extensionCard(record, { direct: true, collapsible: false });
    const status = extensionWorkflowApplied(record) ? 'Enabled' : 'Disabled';
    return panel(manifest.name || manifest.id || 'Built-in Tool', body, false, status);
  } catch (error) {
    console.error(`Built-in extension panel failed to render (${id || 'unknown'}):`, error);
    const manifest = record?.manifest || {};
    const title = manifest.name || id || 'Built-in Tool';
    const body = `<section class="neo-warning-panel"><p class="neo-muted">This built-in extension could not render, so it was isolated instead of hiding the Generations tab.</p><pre>${escapeHtml(error?.message || String(error))}</pre></section>`;
    return panel(title, body, false, 'Render warning');
  }
}

function imageExtensionManagerSummary(records) {
  const enabled = records.filter(adminExtensionRegistryEnabled).length;
  const disabled = Math.max(records.length - enabled, 0);
  const warnings = records.filter((record) => record.warnings?.length).length;
  const errors = records.filter((record) => record.errors?.length).length;
  return badgeRow([
    `Image extensions: ${records.length}`,
    `Registry enabled: ${enabled}`,
    `Registry disabled: ${disabled}`,
    `Warnings: ${warnings}`,
    `Errors: ${errors}`,
  ]);
}

function imageExtensionManagerCard(record) {
  const manifest = record.manifest || {};
  const extensionIdValue = manifest.id || record.id || 'extension';
  const registryEnabled = adminExtensionRegistryEnabled(record);
  const origin = extensionOrigin(record);
  const backendText = manifest.supported_backends?.length ? manifest.supported_backends.join(', ') : 'backend-neutral';
  const mountText = manifest.mount_slots?.length ? manifest.mount_slots.join(', ') : 'no mount slot declared';
  const requirementText = manifest.required_nodes && Object.keys(manifest.required_nodes).length
    ? Object.entries(manifest.required_nodes).map(([backend, nodes]) => `${backend}: ${(nodes || []).join(', ') || 'none'}`).join(' · ')
    : '';
  const action = registryEnabled ? 'disable' : 'enable';
  const actionLabel = registryEnabled ? 'Disable' : 'Enable';
  const externalActions = origin === 'built_in' ? '<span class="neo-muted">Built-in: enable/disable/check only.</span>' : `<button class="neo-btn secondary" onclick="updateImageAdminExtension('${escapeAttr(extensionIdValue)}')">Update</button><button class="neo-btn danger" onclick="removeImageAdminExtension('${escapeAttr(extensionIdValue)}')">Remove</button>`;
  return `<article class="neo-admin-extension-card neo-admin-image-extension-card" data-extension-id="${escapeAttr(extensionIdValue)}" data-admin-extension-surface="image">
    <div class="neo-admin-extension-head">
      <div>
        <strong>${escapeHtml(manifest.name || extensionIdValue)}</strong>
        <p>${escapeHtml(extensionIdValue)} · v${escapeHtml(manifest.version || '0.1.0')} · ${escapeHtml(adminExtensionKindLabel(record))}</p>
      </div>
      ${adminExtensionRegistryChip(record)}
    </div>
    ${state.detailMode !== 'compact' ? `<p>${escapeHtml(manifest.description || 'No description provided.')}</p>` : ''}
    <div class="neo-chipline">${badgeRow([adminExtensionOriginLabel(record), `Backends: ${backendText}`, `Mounts: ${mountText}`])}</div>
    ${requirementText && state.detailMode === 'expert' ? `<p class="neo-muted">Required nodes: ${escapeHtml(requirementText)}</p>` : ''}
    ${record.errors?.length ? `<p class="neo-error">${record.errors.map(escapeHtml).join(' ')}</p>` : ''}
    ${record.warnings?.length ? `<p class="neo-warn">${record.warnings.map(escapeHtml).join(' ')}</p>` : ''}
    <div class="neo-admin-extension-actions">
      <button class="neo-btn ${registryEnabled ? 'secondary' : 'primary'}" onclick="toggleImageAdminExtension('${escapeAttr(extensionIdValue)}', '${action}')">${actionLabel}</button>
      <button class="neo-btn secondary" onclick="checkImageAdminExtension('${escapeAttr(extensionIdValue)}')">Check Compatibility</button>
      <button class="neo-btn secondary" onclick="setActiveSubtab('image','generate')">Open in Image Workspace</button>
      ${externalActions}
    </div>
    ${state.detailMode === 'expert' ? `<details><summary>Manifest JSON</summary><pre>${escapeHtml(JSON.stringify(manifest, null, 2))}</pre></details>` : ''}
  </article>`;
}

function imageExtensionInstallSources() {
  return `<div class="neo-admin-extension-install">
    <div class="neo-admin-extension-install-row">
      <label>Surface
        <select id="admin-extension-install-surface"><option value="image">Image</option><option value="video">Video</option></select>
      </label>
      <label>GitHub repository URL
        <input id="image-extension-github-url" type="url" placeholder="https://github.com/user/neo-video-extension.git" />
      </label>
      <label>Branch <span class="neo-muted">optional</span>
        <input id="image-extension-github-branch" type="text" placeholder="main" />
      </label>
      <button class="neo-btn primary" onclick="installImageExtensionFromGithub()">Install from GitHub</button>
    </div>
    <div class="neo-admin-extension-install-row">
      <label>Extension ZIP
        <input id="image-extension-zip-file" class="neo-file-input" type="file" accept=".zip,application/zip" />
      </label>
      <button class="neo-btn secondary" onclick="installImageExtensionFromZip()">Install from ZIP</button>
    </div>
    <p class="neo-muted">Packages are installed into <code>neo_data/extensions/&lt;surface&gt;/</code>. Core repo files are not overwritten.</p>
  </div>`;
}

function imageExtensionManagerBody() {
  return imageExtensionManagerBodyWithOptions({});
}

function imageExtensionManagerBodyWithOptions(options = {}) {
  const records = (state.extensions?.extensions || []).filter((record) => adminExtensionSurfaceId(record) === 'image');
  const showInstall = options.showInstall !== false;
  const canonicalNote = options.canonicalAdminLocation
    ? '<p class="neo-muted">Canonical location: <strong>Admin › Extensions › Image</strong>. Registry chips show global enablement, not workflow apply state.</p>'
    : '<p class="neo-muted">Image extensions are Neo-side modules. Node installation and Comfy custom_nodes validation are managed separately.</p>';
  return `<div class="neo-admin-extension-manager neo-admin-image-extension-manager">
    ${showInstall ? imageExtensionInstallSources() : ''}
    ${records.length ? imageExtensionManagerSummary(records) : '<p>No Image extensions installed yet.</p>'}
    ${canonicalNote}
    <div class="neo-admin-extension-list">${records.length ? records.map(imageExtensionManagerCard).join('') : ''}</div>
  </div>`;
}

function adminImageExtensionsManagerBody(center = null) {
  const records = (state.extensions?.extensions || []).filter((record) => adminExtensionSurfaceId(record) === 'image');
  const enabled = records.filter(adminExtensionRegistryEnabled).length;
  const builtIn = records.filter((record) => extensionOrigin(record) === 'built_in').length;
  return `${NeoUI.card({
    title: 'Image extension manager',
    description: 'Registry-level controls for Image extensions. This remains the canonical Admin home for Image extension enable/disable and compatibility checks. External install/update/remove controls live under Admin › Extensions › External / Installed.',
    badge: NeoUI.statusBadge(records.length ? 'ready' : 'empty'),
    body: NeoUI.badgeRow([`Image extensions ${records.length}`, `Registry enabled ${enabled}`, `Registry disabled ${Math.max(records.length - enabled, 0)}`, `Built-in ${builtIn}`, `External ${Math.max(records.length - builtIn, 0)}`]),
    actions: `<button type="button" class="neo-btn primary" onclick="reloadExtensionRegistry().then(render)">Refresh Image extensions</button><button type="button" class="neo-btn secondary" onclick="openAdminExtensionsChildTab('external')">External / Installed</button><button type="button" class="neo-btn secondary" onclick="openAdminExtensionsChildTab('node_manager')">Open Node Manager</button>`
  })}${imageExtensionManagerBodyWithOptions({ canonicalAdminLocation: true, showInstall: false })}`;
}


function surfaceExtensionManagerBody(surfaceId, surfaceAdmin = {}) {
  const extensions = state.extensions?.extensions || [];
  const surfaceExtensions = extensions.filter((record) => record?.manifest?.surface === surfaceId);
  const label = humanize(surfaceId);
  const installed = surfaceExtensions.length;
  const enabled = surfaceExtensions.filter(adminExtensionRegistryEnabled).length;
  const disabled = Math.max(installed - enabled, 0);
  return `<div class="neo-admin-extension-manager neo-surface-extension-manager" data-surface="${escapeAttr(surfaceId)}">
    <div class="neo-admin-extension-summary">${badgeRow([`Installed: ${installed}`, `Registry enabled: ${enabled}`, `Registry disabled: ${disabled}`])}</div>
    <p class="neo-muted">${label} extension management is surface-scoped. Install and update flows use each surface registry; node tools stay under Admin › Extensions › Node Manager.</p>
    <div class="neo-admin-extension-list">${surfaceExtensions.length ? surfaceExtensions.map(adminExtensionRegistryCard).join('') : `<p class="neo-muted">No ${label.toLowerCase()} extensions registered yet.</p>`}</div>
  </div>`;
}


function adminSurfaceExtensionsManagerBody(surfaceId = 'image', label = '') {
  const surface = String(surfaceId || 'image').trim().toLowerCase();
  const surfaceLabel = label || humanize(surface);
  const records = (state.extensions?.extensions || []).filter((record) => adminExtensionSurfaceId(record) === surface);
  const enabled = records.filter(adminExtensionRegistryEnabled).length;
  const builtIn = records.filter((record) => extensionOrigin(record) === 'built_in').length;
  const external = Math.max(records.length - builtIn, 0);
  return `${NeoUI.card({
    title: `${surfaceLabel} extension manager`,
    description: `Registry-level controls for ${surfaceLabel} built-in extensions. External install/update/remove controls live under Admin › Extensions › External / Installed.`,
    badge: NeoUI.statusBadge(records.length ? 'ready' : 'empty'),
    body: NeoUI.badgeRow([`${surfaceLabel} extensions ${records.length}`, `Registry enabled ${enabled}`, `Registry disabled ${Math.max(records.length - enabled, 0)}`, `Built-in ${builtIn}`, `External ${external}`]),
    actions: `<button type="button" class="neo-btn primary" onclick="reloadExtensionRegistry().then(render)">Refresh ${surfaceLabel} extensions</button><button type="button" class="neo-btn secondary" onclick="openAdminExtensionsChildTab('external')">External / Installed</button><button type="button" class="neo-btn secondary" onclick="openAdminExtensionsChildTab('node_manager')">Open Node Manager</button>`
  })}<div class="neo-admin-extension-manager neo-admin-${escapeAttr(surface)}-extension-manager"><p class="neo-muted">Canonical location: <strong>Admin › Extensions › ${escapeHtml(surfaceLabel)}</strong>. Registry chips show global enablement, not workflow apply state.</p><div class="neo-admin-extension-list">${records.length ? records.map(adminExtensionRegistryCard).join('') : `<p class="neo-muted">No ${escapeHtml(surfaceLabel.toLowerCase())} extensions registered yet.</p>`}</div></div>`;
}

function adminVideoExtensionsManagerBody(center = null) {
  return adminSurfaceExtensionsManagerBody('video', 'Video');
}

function adminSurfaceExtensionSummary(surfaceId, label = '') {
  const surfaceLabel = label || humanize(surfaceId || 'surface');
  const extensions = state.extensions?.extensions || [];
  const surfaceExtensions = extensions.filter((record) => record?.manifest?.surface === surfaceId);
  const enabled = surfaceExtensions.filter(adminExtensionRegistryEnabled).length;
  const disabled = Math.max(surfaceExtensions.length - enabled, 0);
  const names = surfaceExtensions.map((record) => {
    const manifest = record?.manifest || {};
    const extensionId = manifest.id || record.id || 'Extension';
    const extensionName = manifest.name || extensionId;
    const status = adminExtensionRegistryEnabled(record) ? 'registry enabled' : 'registry disabled';
    return `${extensionName}: ${status}`;
  });
  return NeoUI.card({
    title: `${surfaceLabel} extension summary`,
    description: 'Extension install, compatibility, and registry actions are managed from Admin > Extensions. This surface view stays read-only and lists every registered extension so hidden extension-count bugs are easier to catch.',
    badge: NeoUI.statusBadge(surfaceExtensions.length ? 'ready' : 'empty'),
    body: `${NeoUI.badgeRow([`Installed ${surfaceExtensions.length}`, `Registry enabled ${enabled}`, `Registry disabled ${disabled}`, `Listed ${names.length}/${surfaceExtensions.length}`])}${names.length ? NeoUI.metaList(names) : NeoUI.emptyState(`No ${surfaceLabel.toLowerCase()} extensions registered yet.`)}`,
    actions: `<button type="button" class="neo-btn primary" onclick="setActiveSubtab('admin','extensions')">Open Extensions</button>`
  });
}

function adminGlobalExtensionActionsHtml() {
  const extensions = state.extensions?.extensions || [];
  const surfaces = Array.from(new Set(extensions.map((record) => record?.manifest?.surface || 'global'))).sort();
  return NeoUI.card({
    title: 'Extension ownership',
    description: 'The global registry is the edit surface. Per-surface Admin pages show summaries and surface-only tools instead of duplicating managers.',
    body: NeoUI.badgeRow([`Registered ${extensions.length}`, `Surfaces ${surfaces.length || 0}`]) + (surfaces.length ? NeoUI.metaList(surfaces.map((surface) => `${humanize(surface)} extensions managed by Admin > Extensions`)) : NeoUI.emptyState('No extension surfaces registered.')),
    actions: '<button type="button" class="neo-btn secondary" onclick="reloadExtensionRegistry().then(render)">Refresh extensions</button>'
  });
}

// Compatibility marker retained for legacy tests: Image Extension Manager · surfaceExtensionManagerBody(id, surfaceAdmin)

async function reloadExtensionRegistry() {
  state.extensions = await loadJson('/api/extensions', { extensions: [] });
}

async function toggleImageAdminExtension(extensionId, action) {
  const endpoint = `/api/admin/image/extensions/${encodeURIComponent(extensionId)}/${action}`;
  const response = await fetch(endpoint, { method: 'POST' });
  if (!response.ok) {
    const text = await response.text();
    window.alert(`Extension ${action} failed: ${text}`);
    return;
  }
  await reloadExtensionRegistry();
  render();
}


async function toggleAdminRegistryExtension(extensionId, action) {
  const endpoint = `/api/extensions/${encodeURIComponent(extensionId)}/${action}`;
  const response = await fetch(endpoint, { method: 'POST' });
  if (!response.ok) {
    const text = await response.text();
    window.alert(`Extension ${action} failed: ${text}`);
    return;
  }
  await reloadExtensionRegistry();
  render();
}

async function checkAdminRegistryExtension(extensionId) {
  const payload = { extension_ids: [extensionId] };
  const response = await fetch('/api/extensions/check-compatibility', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  });
  const result = await response.json();
  window.alert(JSON.stringify(result, null, 2));
}

async function installImageExtensionFromGithub() {
  const surfaceInput = document.getElementById('admin-extension-install-surface');
  const surface = surfaceInput?.value || 'image';
  const repoInput = document.getElementById('image-extension-github-url');
  const branchInput = document.getElementById('image-extension-github-branch');
  const repoUrl = repoInput?.value?.trim() || '';
  const branch = branchInput?.value?.trim() || '';
  if (!repoUrl) {
    window.alert('GitHub repository URL is required.');
    return;
  }
  const response = await fetch(`/api/admin/${encodeURIComponent(surface)}/extensions/install-github`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ repo_url: repoUrl, branch: branch || null }),
  });
  if (!response.ok) {
    window.alert(`GitHub install failed: ${await response.text()}`);
    return;
  }
  if (repoInput) repoInput.value = '';
  if (branchInput) branchInput.value = '';
  await reloadExtensionRegistry();
  render();
}

async function installImageExtensionFromZip() {
  const surfaceInput = document.getElementById('admin-extension-install-surface');
  const surface = surfaceInput?.value || 'image';
  const input = document.getElementById('image-extension-zip-file');
  const file = input?.files?.[0];
  if (!file) {
    window.alert('Select an extension ZIP first.');
    return;
  }
  const formData = new FormData();
  formData.append('file', file);
  const response = await fetch(`/api/admin/${encodeURIComponent(surface)}/extensions/install-zip`, {
    method: 'POST',
    body: formData,
  });
  if (!response.ok) {
    window.alert(`ZIP import failed: ${await response.text()}`);
    return;
  }
  if (input) input.value = '';
  await reloadExtensionRegistry();
  render();
}

async function updateAdminSurfaceExtension(surfaceId, extensionId) {
  const surface = surfaceId || 'image';
  const response = await fetch(`/api/admin/${encodeURIComponent(surface)}/extensions/${encodeURIComponent(extensionId)}/update`, { method: 'POST' });
  if (!response.ok) {
    window.alert(`Extension update failed: ${await response.text()}`);
    return;
  }
  await reloadExtensionRegistry();
  render();
}

async function removeAdminSurfaceExtension(surfaceId, extensionId) {
  const surface = surfaceId || 'image';
  if (!window.confirm(`Remove ${surface} extension ${extensionId}?`)) return;
  const response = await fetch(`/api/admin/${encodeURIComponent(surface)}/extensions/${encodeURIComponent(extensionId)}/remove`, { method: 'POST' });
  if (!response.ok) {
    window.alert(`Extension remove failed: ${await response.text()}`);
    return;
  }
  await reloadExtensionRegistry();
  render();
}

async function updateImageAdminExtension(extensionId) {
  const response = await fetch(`/api/admin/image/extensions/${encodeURIComponent(extensionId)}/update`, { method: 'POST' });
  if (!response.ok) {
    window.alert(`Extension update failed: ${await response.text()}`);
    return;
  }
  await reloadExtensionRegistry();
  render();
}

async function removeImageAdminExtension(extensionId) {
  const response = await fetch(`/api/admin/image/extensions/${encodeURIComponent(extensionId)}/remove`, { method: 'POST' });
  if (!response.ok) {
    window.alert(`Extension remove failed: ${await response.text()}`);
    return;
  }
  await reloadExtensionRegistry();
  render();
}

async function checkImageAdminExtension(extensionId) {
  const payload = { surface: 'image', extension_ids: [extensionId] };
  const response = await fetch('/api/extensions/check-compatibility', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  });
  const result = await response.json();
  window.alert(JSON.stringify(result, null, 2));
}



function nodeManagerSummary(payload = {}) {
  const summary = payload.summary || {};
  const python = payload.python || {};
  return badgeRow([
    `On disk: ${summary.disk || 0}`,
    `Tracked: ${summary.tracked || 0}`,
    `Untracked: ${summary.untracked || 0}`,
    `Missing: ${summary.missing || 0}`,
    `Warnings: ${summary.warnings || 0}`,
    python.ok ? `Python: ${python.version || 'valid'}` : 'Python: not configured',
  ]);
}

function imageNodeManagerNodeCard(node) {
  const status = node.status || (node.tracked_by_neo ? 'tracked' : 'untracked');
  const statusClass = status === 'missing_from_disk' ? 'danger' : (node.tracked_by_neo ? 'success' : '');
  const activeOperation = imageNodeManagerActiveOperation();
  const busy = Boolean(activeOperation);
  const git = node.git || {};
  const chips = [
    status === 'missing_from_disk' ? 'Missing from disk' : 'Installed on disk',
    node.tracked_by_neo ? 'Tracked by Neo' : 'Untracked folder',
    git.is_repo ? 'Git repo' : 'No git repo',
    node.requirements_txt ? 'requirements.txt' : '',
    node.pyproject_toml ? 'pyproject.toml' : '',
  ].filter(Boolean);
  return `<article class="neo-admin-extension-card neo-node-manager-card">
    <div class="neo-admin-extension-head">
      <div><strong>${escapeHtml(node.name || node.folder_name || 'Unknown node')}</strong><p>${escapeHtml(node.path || '')}</p></div>
      <span class="neo-state-pill ${statusClass}">${escapeHtml(status)}</span>
    </div>
    <div class="neo-chipline">${badgeRow(chips)}</div>
    ${git.remote ? `<p class="neo-muted">Remote: <code>${escapeHtml(git.remote)}</code>${git.branch ? ` · Branch: ${escapeHtml(git.branch)}` : ''}</p>` : ''}
    ${node.install_hint ? `<p class="neo-muted">${escapeHtml(node.install_hint)}</p>` : ''}
    <div class="neo-admin-extension-actions">
      <button class="neo-btn secondary" type="button" onclick="updateImageNode('${escapeAttr(node.name || node.folder_name || '')}')" ${git.is_repo && !busy ? '' : 'disabled'}>${activeOperation?.kind === 'update' && activeOperation?.folder_name === (node.name || node.folder_name) ? 'Updating…' : 'Update'}</button>
      <button class="neo-btn secondary" type="button" onclick="installImageNodeRequirements('${escapeAttr(node.name || node.folder_name || '')}')" ${node.requirements_txt && !busy ? '' : 'disabled'}>${activeOperation?.kind === 'requirements' && activeOperation?.folder_name === (node.name || node.folder_name) ? 'Installing…' : 'Install requirements'}</button>
    </div>
  </article>`;
}

function imageNodeManagerActiveOperation() {
  const op = state.imageNodeManagerInstall || null;
  return op && op.active ? op : null;
}

function imageNodeManagerInstallStatusHtml() {
  const op = state.imageNodeManagerInstall || null;
  if (!op) {
    return `<div id="image-node-install-status" class="neo-node-install-status idle" role="status" aria-live="polite">Ready. Install actions will show progress here.</div>`;
  }
  const level = op.level || (op.active ? 'working' : 'info');
  const label = op.label || 'Node Manager action';
  const message = op.message || (op.active ? 'Working…' : 'Ready.');
  const repo = op.repo_url ? `<span class="neo-node-install-repo">${escapeHtml(op.repo_url)}</span>` : '';
  const logLines = Array.isArray(op.logs) ? op.logs.slice(-6) : [];
  const logHtml = logLines.length ? `<details class="neo-node-install-log" ${op.active || level === 'error' ? 'open' : ''}><summary>Install log</summary><pre>${escapeHtml(logLines.join('\n'))}</pre></details>` : '';
  const progress = op.active ? '<span class="neo-node-install-progress"><i></i></span>' : '';
  return `<div id="image-node-install-status" class="neo-node-install-status ${escapeAttr(level)}" role="status" aria-live="polite"><div><span class="neo-node-install-spinner" aria-hidden="true"></span><strong>${escapeHtml(label)}</strong><span>${escapeHtml(message)}</span>${repo}</div>${progress}${logHtml}</div>`;
}

function imageNodeManagerSetOperation(partial) {
  state.imageNodeManagerInstall = { ...(state.imageNodeManagerInstall || {}), ...(partial || {}) };
  render();
}

function imageNodeManagerClearOperationSoon(delay = 3500) {
  window.setTimeout(() => {
    if (state.imageNodeManagerInstall && !state.imageNodeManagerInstall.active) {
      state.imageNodeManagerInstall = null;
      render();
    }
  }, delay);
}

function imageNodeManagerBody() {
  const payload = state.imageNodeManager || {};
  const settings = payload.settings || {};
  const nodes = Array.isArray(payload.nodes) ? payload.nodes : [];
  const warnings = Array.isArray(payload.warnings) ? payload.warnings : [];
  const activeOperation = imageNodeManagerActiveOperation();
  const busyAttr = activeOperation ? 'disabled aria-busy="true"' : '';
  return `<div class="neo-admin-extension-manager neo-node-manager">
    <div class="neo-admin-extension-install">
      <div class="neo-admin-extension-install-row">
        <label>ComfyUI root path
          <input id="image-node-comfy-root" type="text" placeholder="Select the ComfyUI root folder" value="${escapeAttr(settings.comfy_root_path || '')}" />
        </label>
        <label>custom_nodes path
          <input id="image-node-custom-path" type="text" placeholder="Select the custom_nodes folder" value="${escapeAttr(settings.custom_nodes_path || '')}" />
        </label>
        <label>Comfy Python path
          <input id="image-node-python-path" type="text" placeholder="Select the Comfy Python executable" value="${escapeAttr(settings.python_path || '')}" />
        </label>
        <button class="neo-btn primary" type="button" onclick="saveImageNodeManagerSettings()">Save Paths</button>
      </div>
      <div class="neo-admin-extension-actions">
        <button class="neo-btn secondary" type="button" onclick="detectImageNodePythonPath()">Auto-detect Python</button>
        <button class="neo-btn secondary" type="button" onclick="validateImageNodePythonPath()">Validate Python</button>
        <span class="neo-muted">${escapeHtml((payload.python && (payload.python.version || (payload.python.errors || []).join(' '))) || 'Python path not validated yet.')}</span>
      </div>
      <div class="neo-admin-extension-install-row">
        <label>GitHub custom node URL
          <input id="image-node-github-url" type="url" placeholder="https://github.com/user/ComfyUI-node.git" />
        </label>
        <label>Branch <span class="neo-muted">optional</span>
          <input id="image-node-github-branch" type="text" placeholder="main" />
        </label>
        <label>Folder name <span class="neo-muted">optional</span>
          <input id="image-node-folder-name" type="text" placeholder="auto from repo" />
        </label>
        <button id="image-node-install-button" class="neo-btn primary neo-node-install-button ${activeOperation ? 'is-installing' : ''}" type="button" onclick="installImageNodeFromGithub()" ${busyAttr}>${activeOperation ? '<span class="neo-node-btn-spinner" aria-hidden="true"></span>Installing…' : 'Install Node'}</button>
      </div>
      <div class="neo-admin-extension-actions">
        <button class="neo-btn secondary" type="button" onclick="scanImageNodeManagerDisk()" ${busyAttr}>Scan Disk</button>
        <button class="neo-btn secondary" type="button" onclick="openImageCustomNodesFolder()" ${busyAttr}>Open custom_nodes</button>
      </div>
      ${imageNodeManagerInstallStatusHtml()}
      <p class="neo-muted">Node Manager checks the actual ComfyUI <code>custom_nodes</code> folder, then compares disk folders against Neo records.</p>
    </div>
    ${nodeManagerSummary(payload)}
    ${warnings.length ? `<p class="neo-warn">${warnings.map(escapeHtml).join(' ')}</p>` : ''}
    <div class="neo-admin-extension-list">${nodes.length ? nodes.map(imageNodeManagerNodeCard).join('') : '<p class="neo-muted">No disk scan loaded yet. Set paths, then click Scan Disk.</p>'}</div>
  </div>`;
}

async function reloadImageNodeManager(scan = false) {
  state.imageNodeManager = await loadJson(`/api/admin/image/node-manager/state${scan ? '?scan=true' : ''}`, { nodes: [], settings: {}, summary: {} });
}

function getImageNodeManagerFormValues() {
  return {
    comfy_root_path: document.getElementById('image-node-comfy-root')?.value?.trim() || '',
    custom_nodes_path: document.getElementById('image-node-custom-path')?.value?.trim() || '',
    python_path: document.getElementById('image-node-python-path')?.value?.trim() || '',
  };
}

async function saveImageNodeManagerSettings({ rerender = true, scan = true } = {}) {
  const values = getImageNodeManagerFormValues();
  const response = await fetch('/api/admin/image/node-manager/settings', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(values),
  });
  if (!response.ok) {
    window.alert(`Node Manager settings failed: ${await response.text()}`);
    return false;
  }
  state.imageNodeManager = await response.json();
  if (scan) await reloadImageNodeManager(true);
  if (rerender) render();
  return true;
}


async function detectImageNodePythonPath() {
  const comfyRoot = document.getElementById('image-node-comfy-root')?.value?.trim() || '';
  const response = await fetch('/api/admin/image/node-manager/detect-python', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ comfy_root_path: comfyRoot || null }),
  });
  const result = await response.json();
  if (!response.ok || !result.python_path) {
    window.alert(`Python auto-detect failed: ${JSON.stringify(result)}`);
    return;
  }
  const field = document.getElementById('image-node-python-path');
  if (field) field.value = result.python_path;
  await saveImageNodeManagerSettings({ rerender: true, scan: false });
}

async function validateImageNodePythonPath() {
  const pythonPath = document.getElementById('image-node-python-path')?.value?.trim() || '';
  const response = await fetch('/api/admin/image/node-manager/validate-python', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ python_path: pythonPath }),
  });
  if (!response.ok) {
    window.alert(`Python validation failed: ${await response.text()}`);
    return;
  }
  const result = await response.json();
  window.alert(`Python OK: ${result.version || result.python_path}`);
  await reloadImageNodeManager(false);
  render();
}

async function scanImageNodeManagerDisk() {
  const values = getImageNodeManagerFormValues();
  const response = await fetch('/api/admin/image/node-manager/scan-disk', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(values),
  });
  if (!response.ok) {
    window.alert(`Node Manager disk scan failed: ${await response.text()}`);
    return;
  }
  state.imageNodeManager = await response.json();
  const warnings = Array.isArray(state.imageNodeManager?.warnings) ? state.imageNodeManager.warnings : [];
  if (!Array.isArray(state.imageNodeManager?.nodes) || state.imageNodeManager.nodes.length === 0) {
    console.info('Node Manager scan returned no nodes.', { settings: state.imageNodeManager?.settings, warnings });
  }
  render();
}

async function installImageNodeFromGithub() {
  if (imageNodeManagerActiveOperation()) return;
  const repoUrl = document.getElementById('image-node-github-url')?.value?.trim() || '';
  const branch = document.getElementById('image-node-github-branch')?.value?.trim() || '';
  const folderName = document.getElementById('image-node-folder-name')?.value?.trim() || '';
  if (!repoUrl) {
    window.alert('GitHub custom node URL is required.');
    return;
  }
  imageNodeManagerSetOperation({
    active: true,
    kind: 'install',
    level: 'working',
    label: 'Installing node',
    message: 'Cloning repository into ComfyUI custom_nodes. Keep this page open.',
    repo_url: repoUrl,
    logs: [`git clone ${repoUrl}`, 'Waiting for installer response…'],
  });
  try {
    const response = await fetch('/api/admin/image/node-manager/install', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ repo_url: repoUrl, branch: branch || null, folder_name: folderName || null }),
    });
    const text = await response.text();
    let result = null;
    try { result = text ? JSON.parse(text) : null; } catch (_) { result = null; }
    if (!response.ok || result?.ok === false) {
      const detail = result?.detail || result?.errors || text || 'Node install failed.';
      throw new Error(Array.isArray(detail) ? detail.join(' ') : String(detail));
    }
    await reloadImageNodeManager(true);
    imageNodeManagerSetOperation({
      active: false,
      kind: 'install',
      level: 'success',
      label: 'Node installed',
      message: `${result?.installed || folderName || 'Custom node'} installed. Restart ComfyUI if the node does not appear yet.`,
      repo_url: repoUrl,
      logs: ['Install completed.', result?.path ? `Path: ${result.path}` : 'Disk scan refreshed.'].filter(Boolean),
    });
    imageNodeManagerClearOperationSoon();
  } catch (error) {
    imageNodeManagerSetOperation({
      active: false,
      kind: 'install',
      level: 'error',
      label: 'Node install failed',
      message: error?.message || 'Node install failed.',
      repo_url: repoUrl,
      logs: [`Error: ${error?.message || error}`],
    });
  }
}

async function updateImageNode(folderName) {
  if (!folderName || imageNodeManagerActiveOperation()) return;
  imageNodeManagerSetOperation({ active: true, kind: 'update', folder_name: folderName, level: 'working', label: 'Updating node', message: `Running git pull for ${folderName}…`, logs: [`git pull ${folderName}`] });
  try {
    const response = await fetch('/api/admin/image/node-manager/update', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ folder_name: folderName }),
    });
    const text = await response.text();
    let result = null;
    try { result = text ? JSON.parse(text) : null; } catch (_) { result = null; }
    if (!response.ok || result?.ok === false) {
      const detail = result?.detail || result?.errors || text || 'Node update failed.';
      throw new Error(Array.isArray(detail) ? detail.join(' ') : String(detail));
    }
    await reloadImageNodeManager(true);
    imageNodeManagerSetOperation({ active: false, kind: 'update', folder_name: folderName, level: 'success', label: 'Node updated', message: `${folderName} updated. Restart ComfyUI if needed.`, logs: [(result?.output || 'Update completed.')] });
    imageNodeManagerClearOperationSoon();
  } catch (error) {
    imageNodeManagerSetOperation({ active: false, kind: 'update', folder_name: folderName, level: 'error', label: 'Node update failed', message: error?.message || 'Node update failed.', logs: [`Error: ${error?.message || error}`] });
  }
}


async function installImageNodeRequirements(folderName) {
  if (!folderName || imageNodeManagerActiveOperation()) return;
  imageNodeManagerSetOperation({ active: true, kind: 'requirements', folder_name: folderName, level: 'working', label: 'Installing requirements', message: `Running pip install for ${folderName}. This can take a few minutes.`, logs: [`pip install -r ${folderName}/requirements.txt`] });
  try {
    const response = await fetch('/api/admin/image/node-manager/install-requirements', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ folder_name: folderName }),
    });
    const text = await response.text();
    let result = null;
    try { result = text ? JSON.parse(text) : null; } catch (_) { result = null; }
    if (!response.ok || result?.ok === false) {
      const detail = result?.detail || result?.errors || text || 'Requirements install failed.';
      throw new Error(Array.isArray(detail) ? detail.join(' ') : String(detail));
    }
    await reloadImageNodeManager(true);
    imageNodeManagerSetOperation({ active: false, kind: 'requirements', folder_name: folderName, level: 'success', label: 'Requirements installed', message: `${folderName} requirements installed. Restart ComfyUI if the node needs reload.`, logs: [(result?.output || 'Requirements install completed.').slice(0, 4000)] });
    imageNodeManagerClearOperationSoon();
  } catch (error) {
    imageNodeManagerSetOperation({ active: false, kind: 'requirements', folder_name: folderName, level: 'error', label: 'Requirements install failed', message: error?.message || 'Requirements install failed.', logs: [`Error: ${error?.message || error}`] });
  }
}

async function openImageCustomNodesFolder() {
  const response = await fetch('/api/admin/image/node-manager/open-folder', { method: 'POST' });
  if (!response.ok) window.alert(`Open folder failed: ${await response.text()}`);
}


function beginTwoColumnWorkspace() {
  el.surfacePanels.innerHTML = '';
  el.surfacePanels.className = 'neo-universal-workspace';
  const left = document.createElement('section');
  left.className = 'neo-universal-column neo-universal-left';
  const right = document.createElement('section');
  right.className = 'neo-universal-column neo-universal-right';
  el.surfacePanels.appendChild(left);
  el.surfacePanels.appendChild(right);
  return { left, right };
}

function appendBalanced(columns, node, index) {
  (index % 2 === 0 ? columns.left : columns.right).appendChild(node);
}


function adminEngineBadge(value, label) {
  const ok = Boolean(value);
  return `<span class="neo-badge ${ok ? 'success' : ''}">${escapeHtml(label)}: ${ok ? 'ready' : 'planned'}</span>`;
}

