function adminProviderOptions(current, configured, canonical) {
  const merged = [];
  [...(configured || []), ...(canonical || []), current].forEach((item) => {
    const value = String(item || '').trim();
    if (value && !merged.includes(value)) merged.push(value);
  });
  return merged;
}

function adminProviderLabel(provider) {
  const labels = {
    qwen3_reranker: 'qwen3_reranker (Qwen3 native)',
    local_reranker: 'local_reranker',
    cross_encoder: 'cross_encoder',
    bge_reranker: 'bge_reranker',
    lexical_overlap: 'lexical_overlap fallback',
    none: 'none',
  };
  return labels[provider] || provider;
}

