function adminSemanticEngineStatusHtml() {
  const busy = Boolean(state.adminSemanticEngineBusy);
  const test = state.adminSemanticEngineTest || null;
  const manual = state.adminSemanticEngineStatus || '';
  const status = busy ? 'testing' : (test?.status || (manual ? 'working' : 'idle'));
  const badgeClass = status === 'passed' ? 'success' : status === 'warning' ? 'warn' : status === 'failed' ? 'danger' : busy ? 'warn' : '';
  const message = busy ? 'Testing semantic engine… loading/warming embedding and reranker models if needed.' : (test?.message || manual || 'No semantic engine test run yet.');
  const rows = [];
  if (test?.embedding) rows.push(`Embedding: ${test.embedding.mode || 'unknown'} · provider ${test.embedding.provider || 'unknown'} · dim ${test.sample_dimension || test.embedding.dimension || 0}`);
  if (test?.reranker) rows.push(`Reranker: ${test.reranker.mode || 'none'} · provider ${test.reranker.provider || 'unknown'}${test.reranker.fallback_used ? ' · fallback used' : ''}`);
  if (test?.reranker?.provider_note) rows.push(`Provider note: ${test.reranker.provider_note}`);
  if (Array.isArray(test?.warnings)) test.warnings.forEach((warning) => rows.push(`Warning: ${warning}`));
  return `<div class="admin-semantic-status neo-ui-card ${busy ? 'is-running' : ''}">
    <div class="neo-ui-section-head admin-engine-row-between"><div><strong>Semantic engine test status</strong><p>${escapeHtml(message)}</p></div><span class="neo-badge ${badgeClass}">${escapeHtml(status)}</span></div>
    ${busy ? '<div class="admin-semantic-progress"><span></span></div>' : ''}
    ${rows.length ? listItems(rows) : ''}
  </div>`;
}

function adminEngineIndexJobsHtml(engine) {
  const queue = state.adminIndexJobs || engine?.index_jobs || {};
  const jobs = queue.jobs || [];
  const summary = queue.summary || {};
  const rows = jobs.length ? jobs.slice(0, 8).map((job) => {
    const status = job.status || 'queued';
    const good = status === 'completed';
    const bad = status === 'failed' || status === 'cancelled';
    const badgeClass = good ? 'success' : bad ? 'danger' : status === 'running' ? 'warn' : '';
    const percent = Math.max(0, Math.min(100, Number(job.progress || 0)));
    return `<div class="neo-ui-record-card admin-engine-record-card compact admin-index-job-card">
      <div class="neo-ui-section-head admin-engine-row-between"><div><strong>${escapeHtml(job.title || job.job_type || 'Index job')}</strong><small>${escapeHtml(job.job_id || '')} · ${escapeHtml(job.mode || 'changed_only')}</small></div><span class="neo-badge ${badgeClass}">${escapeHtml(status)}</span></div>
      <div class="admin-index-progress"><span style="width:${percent}%"></span></div>
      ${listItems([`Progress: ${percent}%`, `Limit: ${job.limit ?? 500}`, `Scope: ${job.scope_id || 'all'}`, `Message: ${job.message || ''}`, `Indexed: ${(job.result || {}).indexed_count ?? 'n/a'} · skipped: ${(job.result || {}).skipped_count ?? 'n/a'}`])}
      <div class="neo-ui-toolbar admin-engine-badge-row"><button type="button" class="neo-btn admin-engine-btn small" onclick="cancelAdminIndexJob('${escapeAttr(job.job_id || '')}')">Cancel</button><button type="button" class="neo-btn admin-engine-btn small" onclick="loadAdminIndexJobLog('${escapeAttr(job.job_id || '')}')">Log</button></div>
    </div>`;
  }).join('') : `<div class="neo-ui-empty admin-engine-empty"><strong>No indexing jobs yet.</strong><p>Create a background job to index Roleplay memory vectors without blocking the UI.</p></div>`;
  const log = state.adminIndexJobLog || {};
  return `
    <div class="neo-ui-grid two admin-engine-grid two">
      <div class="neo-ui-card admin-engine-card wide">
        <div class="neo-ui-section-head admin-engine-row-between"><div><strong>Background indexing job queue</strong><p>Queue Roleplay memory vector indexing from Memory Engine. This keeps large indexes away from blocking Scene/Studio interactions.</p></div><span class="neo-badge ${queue.status === 'ready' ? 'success' : ''}">${escapeHtml(queue.status || 'ready')}</span></div>
        ${listItems([`Total: ${summary.total ?? 0}`, `Running: ${summary.running ?? 0}`, `Pending: ${summary.pending ?? 0}`, `Completed: ${summary.completed ?? 0}`, `Failed: ${summary.failed ?? 0}`, `Cancelled: ${summary.cancelled ?? 0}`])}
      </div>
      <div class="neo-ui-card admin-engine-card">
        <strong>Create index job</strong>
        <div class="neo-ui-field-grid two compact admin-engine-form-grid two compact">
          <div><label>Job type</label><select id="admin-index-job-type"><option value="roleplay_memory_vectors">Roleplay memory vectors</option></select></div>
          <div><label>Mode</label><select id="admin-index-job-mode"><option value="changed_only">Changed only</option><option value="force_reindex">Force reindex</option></select></div>
          <div><label>Limit</label><input id="admin-index-job-limit" type="number" value="500"></div>
          <div><label>Scope ID</label><input id="admin-index-job-scope" placeholder="optional scene/story/runtime scope"></div>
        </div>
        <div class="neo-ui-toolbar admin-engine-badge-row"><button type="button" class="neo-btn primary admin-engine-btn" onclick="createAdminIndexJob()">Queue index job</button><button type="button" class="neo-btn admin-engine-btn" onclick="reloadAdminIndexJobs()">Refresh jobs</button></div>
      </div>
      <div class="neo-ui-card admin-engine-card wide"><strong>Jobs</strong><div class="neo-ui-record-list admin-engine-record-list compact">${rows}</div></div>
      ${log.job_id ? `<div class="neo-ui-card admin-engine-card wide"><strong>Job log · ${escapeHtml(log.job_id || '')}</strong><pre class="neo-ui-code admin-engine-code">${escapeHtml((log.lines || []).join('\n'))}</pre></div>` : ''}
      ${state.detailMode === 'expert' ? `<div class="neo-ui-card admin-engine-card wide"><strong>Raw index queue</strong><pre class="neo-ui-code admin-engine-code">${escapeHtml(JSON.stringify(queue, null, 2))}</pre></div>` : ''}
    </div>`;
}

