const ADMIN_DASHBOARD_CHILD_TABS = [
  { id: 'cockpit', label: 'Cockpit', description: 'Admin cockpit groups and high-level control center status.' },
  { id: 'attention', label: 'Attention', description: 'Current items that need review before deeper changes.' },
  { id: 'system_summary', label: 'System Summary', description: 'Control Center summary for providers, extensions, surfaces, memory, and records.' },
  { id: 'quick_launch', label: 'Quick Launch', description: 'Shortcuts into repaired Admin workspaces.' },
  { id: 'activity', label: 'Activity', description: 'Operations map and recent Admin cockpit activity.' },
  { id: 'diagnostics', label: 'Diagnostics', description: 'Links and status cards for Health, Diagnostics, Logs, and Records.' },
];

function adminDashboardActiveChildTab() {
  const allowed = ADMIN_DASHBOARD_CHILD_TABS.map((tab) => tab.id);
  const active = allowed.includes(state.adminDashboardChildTab) ? state.adminDashboardChildTab : 'cockpit';
  state.adminDashboardChildTab = active;
  return active;
}

function setAdminDashboardChildTab(tabId) {
  const allowed = ADMIN_DASHBOARD_CHILD_TABS.map((tab) => tab.id);
  state.adminDashboardChildTab = allowed.includes(tabId) ? tabId : 'cockpit';
  render();
}

function adminDashboardChildTabs() {
  const active = adminDashboardActiveChildTab();
  return `<nav class="neo-subtabs neo-admin-dashboard-child-tabs" aria-label="Admin Dashboard child tabs">${ADMIN_DASHBOARD_CHILD_TABS.map((tab) => `<button type="button" class="${tab.id === active ? 'active' : ''}" title="${escapeAttr(tab.description)}" onclick="setAdminDashboardChildTab('${escapeAttr(tab.id)}')">${escapeHtml(tab.label)}</button>`).join('')}</nav>`;
}

