function adminDashboardChildTabBody(center) {
  const active = adminDashboardActiveChildTab();
  if (active === 'cockpit') return adminCockpitHtml(center);
  if (active === 'attention') return adminAttentionHtml(center);
  if (active === 'system_summary') return adminControlSummaryHtml(center);
  if (active === 'quick_launch') return adminDashboardQuickLaunchBody(center);
  if (active === 'activity') return adminDashboardActivityBody(center);
  if (active === 'diagnostics') return adminDashboardDiagnosticsBody(center);
  return adminCockpitHtml(center);
}

