function adminStoragePathCards(paths, filterFn = null) {
  const items = (Array.isArray(paths) ? paths : []).filter((item) => (filterFn ? filterFn(item) : true));
  return items.length ? `<div class="neo-ui-record-list admin-storage-list">${items.map((item) => NeoUI.card({
    title: item.key || 'path',
    description: item.path || '',
    badge: NeoUI.statusBadge(item.exists ? 'ready' : 'missing'),
    body: NeoUI.badgeRow([item.exists ? 'exists' : 'missing', item.kind || 'storage path']),
    className: 'neo-ui-record-card admin-storage-card',
  })).join('')}</div>` : NeoUI.emptyState('No matching storage paths declared.', 'Configure storage paths in Admin config first.');
}

function adminStorageHtml(center) {
  const paths = center?.storage?.paths || [];
  return adminStoragePathCards(paths);
}

function adminStorageStats(center) {
  const storage = center?.storage || {};
  const paths = Array.isArray(storage.paths) ? storage.paths : [];
  const runtime = center?.runtime_hardening || state.runtimeHardening || {};
  const checks = Array.isArray(runtime.checks) ? runtime.checks : [];
  const existing = paths.filter((item) => item.exists).length;
  const missing = Math.max(paths.length - existing, 0);
  const outputPaths = paths.filter((item) => /output|project/i.test(String(item.key || '')));
  const cachePaths = paths.filter((item) => /cache|temp/i.test(String(item.key || '')));
  const logPaths = paths.filter((item) => /log/i.test(String(item.key || '')));
  const dataPaths = paths.filter((item) => !/output|project|cache|temp|log/i.test(String(item.key || '')));
  const requiredFailures = Number(runtime.required_failure_count || 0);
  const warningCount = Number(runtime.warning_count || 0);
  return { storage, paths, runtime, checks, existing, missing, outputPaths, cachePaths, logPaths, dataPaths, requiredFailures, warningCount };
}

