    badge: NeoUI.statusBadge(queue.status || workflow.status || 'ready'),
    body: `${NeoUI.badgeRow([`${summary.pending_count || summary.pending_reviews || 0} pending`, `${summary.client_review_count || summary.client_reviews || 0} client review`, `${summary.revision_requested_count || summary.revision_requests || 0} revisions`, `${summary.approved_count || summary.approved_reviews || 0} approved`])}<div class="neo-ui-field-grid"><div><label>Review title</label><input id="project-review-title" placeholder="Client review: first cut / Internal approval: prompt pack"></div><div><label>Linked deliverable</label><select id="project-review-deliverable"><option value="">None / custom</option>${deliverableOptions}</select></div><div><label>Review scope</label><select id="project-review-scope"><option value="internal">Internal</option><option value="client">Client</option><option value="creative">Creative</option><option value="technical">Technical</option></select></div><div><label>Priority</label><select id="project-review-priority"><option value="normal">Normal</option><option value="high">High</option><option value="urgent">Urgent</option><option value="low">Low</option></select></div><div><label>Due date</label><input id="project-review-due" placeholder="YYYY-MM-DD"></div><div class="wide"><label>Review notes</label><textarea id="project-review-summary" rows="2" placeholder="What needs review, what approval means, revision notes..."></textarea></div><div><label>Decision target</label><select id="project-review-target"><option value="">Select review item</option>${itemOptions}</select></div><div><label>Decision</label><select id="project-review-decision"><option value="start_review">Start review</option><option value="approve">Approve</option><option value="request_revision">Request revision</option><option value="reject">Reject</option><option value="resolve">Resolve</option><option value="archive">Archive</option><option value="reopen">Reopen</option></select></div><div class="wide"><label>Decision notes</label><textarea id="project-review-decision-notes" rows="2" placeholder="Approval note, revision request, or blocker explanation..."></textarea></div></div><div class="neo-ui-toolbar"><button type="button" class="neo-btn" onclick="saveProjectReviewItem()">Save review item</button><button type="button" class="neo-btn primary" onclick="applyProjectReviewDecision()">Apply decision</button><button type="button" class="neo-btn" onclick="loadProjectReviewQueue()">Refresh review queue</button></div><div class="neo-project-activity-grid"><div><h4>Review queue</h4>${itemRows.length ? NeoUI.metaList(itemRows) : NeoUI.emptyState('No explicit review items yet.')}</div><div><h4>Auto candidates</h4>${candidateRows.length ? NeoUI.metaList(candidateRows) : NeoUI.emptyState('No ready-for-review candidates detected.')}</div><div><h4>Approval blockers</h4>${blockerRows.length ? NeoUI.metaList(blockerRows) : NeoUI.emptyState('No approval blockers detected.')}</div></div>${state.projectWorkspace?.lastReviewSave ? `<p class="neo-muted">Last review item: ${escapeHtml(state.projectWorkspace.lastReviewSave.review_item?.title || 'saved')}</p>` : ''}${state.projectWorkspace?.lastReviewDecision ? `<p class="neo-muted">Last decision: ${escapeHtml(state.projectWorkspace.lastReviewDecision.review_item?.decision || 'applied')}</p>` : ''}`,
    className: 'neo-project-review-queue-card',
