function projectBriefVersionHistoryHtml() {
  const briefsPayload = state.projectWorkspace?.briefs || state.adminControlCenter?.project_briefs || {};
  const briefs = Array.isArray(briefsPayload.briefs) ? briefsPayload.briefs : [];
  const versionsPayload = state.projectWorkspace?.briefVersions || {};
  const versions = Array.isArray(versionsPayload.versions) ? versionsPayload.versions : [];
  const compare = state.projectWorkspace?.briefCompare || null;
  const briefOptions = briefs.map((brief) => `<option value="${escapeAttr(brief.brief_id || '')}">${escapeHtml(brief.title || brief.brief_id || 'Project brief')} · v${escapeHtml(String(brief.version_number || 1))}${brief.is_final ? ' · final' : ''}</option>`).join('');
  const versionOptions = versions.map((brief) => `<option value="${escapeAttr(brief.brief_id || '')}">v${escapeHtml(String(brief.version_number || 1))} · ${escapeHtml(brief.title || brief.brief_id || 'Project brief')}${brief.is_final ? ' · final' : ''}</option>`).join('');
  const versionRows = versions.slice(0, 12).map((brief) => `${brief.is_final ? 'Final · ' : ''}v${brief.version_number || 1}: ${brief.title || brief.brief_id} · ${brief.created_at || ''}`);
  const diffBlock = compare ? `<div class="neo-ui-code"><pre>${escapeHtml(compare.diff || 'No diff output.')}</pre></div>` : NeoUI.emptyState('No brief comparison loaded.', 'Select two versions and compare them.');
  return NeoUI.card({
    title: 'Project Brief Version History + Compare',
    description: 'Review saved brief versions, compare differences, restore a previous version, or mark a version as final.',
    badge: NeoUI.statusBadge(versionsPayload.ok ? 'ready' : 'idle'),
    body: `<div class="neo-ui-field-grid"><div><label>Brief family</label><select id="project-brief-version-select"><option value="">Select saved brief</option>${briefOptions}</select></div><div><label>Version action target</label><select id="project-brief-version-action"><option value="">Select loaded version</option>${versionOptions}</select></div><div><label>Compare left</label><select id="project-brief-compare-left"><option value="">Older / base</option>${versionOptions}</select></div><div><label>Compare right</label><select id="project-brief-compare-right"><option value="">Newer / changed</option>${versionOptions}</select></div></div><div class="neo-ui-toolbar"><button type="button" class="neo-btn" onclick="loadProjectBriefVersions()">Load versions</button><button type="button" class="neo-btn" onclick="compareProjectBriefVersions()">Compare</button><button type="button" class="neo-btn" onclick="restoreProjectBriefVersion()">Restore as new version</button><button type="button" class="neo-btn primary" onclick="finalizeProjectBriefVersion()">Mark final</button></div>${versionRows.length ? NeoUI.metaList(versionRows) : NeoUI.emptyState('No versions loaded yet.', 'Choose a saved brief and load its version history.')}${compare ? `<p class="neo-muted">Compared ${escapeHtml(compare.left_brief?.brief_id || '')} → ${escapeHtml(compare.right_brief?.brief_id || '')} · +${escapeHtml(String(compare.summary?.added_lines || 0))} / -${escapeHtml(String(compare.summary?.removed_lines || 0))}</p>` : ''}${diffBlock}${state.projectWorkspace?.lastBriefRestore ? `<p class="neo-muted">Last restored: ${escapeHtml(state.projectWorkspace.lastBriefRestore.brief?.brief_id || 'restored')}</p>` : ''}${state.projectWorkspace?.lastBriefFinalize ? `<p class="neo-muted">Final brief: ${escapeHtml(state.projectWorkspace.lastBriefFinalize.brief_id || 'finalized')}</p>` : ''}`,
    className: 'neo-project-brief-version-card',
  });
}

function projectActivityIntelligenceHtml() {
  const activity = state.projectWorkspace?.activityIntelligence || state.adminControlCenter?.project_activity_intelligence || {};
  const summary = activity.summary || {};
  const groups = activity.groups || {};
  const workflowGroups = Array.isArray(groups.workflow_groups) ? groups.workflow_groups : [];
  const important = Array.isArray(activity.important_events) ? activity.important_events : [];
  const assistant = Array.isArray(activity.assistant_decisions) ? activity.assistant_decisions : [];
  const roleplay = Array.isArray(activity.roleplay_milestones) ? activity.roleplay_milestones : [];
  const workflowRows = workflowGroups.slice(0, 8).map((group) => `${group.workflow_key}: ${group.count} event(s) · ${group.important_count || 0} important`);
  const importantRows = important.slice(0, 6).map((event) => `${event.title || event.event_type}: ${event.surface || 'unknown'} · ${event.resource_type || 'activity'}`);
  const decisionRows = assistant.slice(0, 5).map((event) => `${event.title || event.event_type}: ${event.summary || ''}`);
  const roleplayRows = roleplay.slice(0, 5).map((event) => `${event.title || event.event_type}: ${event.summary || ''}`);
  return NeoUI.card({
    title: 'Project Timeline + Activity Intelligence',
    description: 'Groups project history by surface, workflow, resource type, important events, Assistant decisions, and Roleplay milestones.',
    badge: NeoUI.statusBadge(activity.status || 'ready'),
    body: `${NeoUI.badgeRow([`${summary.timeline_count || 0} timeline`, `${summary.handoff_count || 0} handoffs`, `${summary.workflow_group_count || 0} workflows`, `${summary.important_event_count || 0} important`])}<p class="neo-muted">${escapeHtml(summary.progress_summary || 'No project activity summary yet.')}</p>${Array.isArray(summary.recommended_focus) && summary.recommended_focus.length ? `<div class="neo-project-activity-focus">${summary.recommended_focus.slice(0, 4).map((item) => `<span>${escapeHtml(item)}</span>`).join('')}</div>` : ''}<div class="neo-ui-toolbar"><button type="button" class="neo-btn" onclick="loadProjectActivityIntelligence()">Refresh activity intelligence</button></div><div class="neo-project-activity-grid"><div><h4>Workflow groups</h4>${workflowRows.length ? NeoUI.metaList(workflowRows) : NeoUI.emptyState('No workflow groups yet.')}</div><div><h4>Important events</h4>${importantRows.length ? NeoUI.metaList(importantRows) : NeoUI.emptyState('No important events detected.')}</div><div><h4>Assistant decisions</h4>${decisionRows.length ? NeoUI.metaList(decisionRows) : NeoUI.emptyState('No Assistant decisions linked yet.')}</div><div><h4>Roleplay milestones</h4>${roleplayRows.length ? NeoUI.metaList(roleplayRows) : NeoUI.emptyState('No Roleplay milestones linked yet.')}</div></div>`
  });
}

async function sendProjectWorkspaceHandoff() {
  const projectId = document.getElementById('admin-project-workspace-active')?.value || state.projectWorkspace?.active?.active_project_id || 'general';
  const sourceSurface = document.getElementById('project-handoff-source')?.value || state.activeSurface || 'assistant';
  const resourceType = document.getElementById('project-handoff-type')?.value || 'handoff';
  const title = document.getElementById('project-handoff-title')?.value || 'Project handoff';
  const ref = document.getElementById('project-handoff-ref')?.value || '';
  const content = document.getElementById('project-handoff-content')?.value || '';
  const response = await fetch('/api/projects/workspace/handoff', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ project_id: projectId, source_surface: sourceSurface, target_surface: 'project_workspace', resource_type: resourceType, title, ref_id: ref, content, tags: [sourceSurface, resourceType] }),
  });
  if (!response.ok) { window.alert(`Project handoff failed: ${await response.text()}`); return; }
  state.projectWorkspace.lastHandoff = await response.json();
  state.projectWorkspace.assetTray = await loadJson(`/api/projects/workspace/asset-tray?project_id=${encodeURIComponent(projectId)}&limit=40`, state.projectWorkspace.assetTray || null);
  state.projectWorkspace.context = await loadJson(`/api/projects/workspace/context?project_id=${encodeURIComponent(projectId)}&limit=30`, state.projectWorkspace.context || null);
  state.memory = await loadJson('/api/memory/status', state.memory || null);
  render();
}

function adminToolRegistryHtml(center) {
  const registry = center?.tool_registry || state.toolRegistry?.registry || {};
  const profilesPayload = center?.tool_permission_profiles || state.toolRegistry?.profiles || {};
  const tools = Array.isArray(registry.tools) ? registry.tools : [];
  const profiles = Array.isArray(profilesPayload.profiles) ? profilesPayload.profiles : [];
  const activeProfile = registry.active_profile_id || profilesPayload.active_profile_id || 'guided';
  const counts = registry.counts || {};
  const categoryRows = Object.entries(registry.by_category || {}).map(([category, stats]) => `${category}: ${stats.allow || 0} allow / ${stats.confirm || 0} confirm / ${stats.block || 0} block`);
  const profileOptions = profiles.map((profile) => `<option value="${escapeHtml(profile.profile_id || '')}" ${String(profile.profile_id || '') === String(activeProfile) ? 'selected' : ''}>${escapeHtml(profile.label || profile.profile_id || '')}</option>`).join('');
  const toolCards = tools.slice(0, 18).map((tool) => NeoUI.card({
    title: tool.label || tool.tool_id,
    description: tool.description || tool.tool_id,
    badge: NeoUI.statusBadge(tool.permission_mode || 'confirm'),
    body: `${NeoUI.badgeRow([tool.category || 'tool', tool.risk_level || 'risk', tool.tool_id || ''])}${tool.endpoints?.length ? `<p class="neo-muted">${escapeHtml((tool.endpoints || []).join(' · '))}</p>` : ''}`,
    className: 'neo-ui-record-card admin-tool-registry-card',
  })).join('');
  return `${NeoUI.card({
    title: 'Assistant Tool Registry + Permission Profiles',
    description: 'Central source of truth for tools, risk classes, read/write/external permissions, and Assistant/Operator availability.',
    badge: NeoUI.statusBadge(registry.status || 'ready'),
    body: `${NeoUI.badgeRow([`Profile: ${activeProfile}`, `${counts.total || tools.length} tools`, `${counts.allow || 0} allowed`, `${counts.confirm || 0} confirm`, `${counts.block || 0} blocked`])}<div class="neo-ui-field-grid"><div><label>Active permission profile</label><select id="admin-tool-profile-select">${profileOptions}</select></div></div><div class="neo-ui-toolbar"><button type="button" class="neo-btn primary" onclick="saveToolPermissionProfile()">Save profile</button><button type="button" class="neo-btn" onclick="refreshToolRegistry()">Refresh tools</button></div>${categoryRows.length ? NeoUI.metaList(categoryRows) : ''}`
  })}<div class="neo-ui-grid two admin-tool-registry-grid">${toolCards || NeoUI.emptyState('No tools registered yet.', 'Refresh the tool registry from Admin.')}</div>`;
}


function adminToolLedgerHtml(center) {
  const ledger = center?.tool_execution_ledger || state.toolLedger?.status || {};
  const events = ledger.recent_events || state.toolLedger?.events?.events || [];
  const statusRows = Object.entries(ledger.status_counts || {}).map(([key, value]) => `${key}: ${value}`);
  const riskRows = Object.entries(ledger.risk_counts || {}).map(([key, value]) => `${key}: ${value}`);
  const eventCards = (events || []).slice(0, 12).map((event) => NeoUI.card({
    title: `${event.tool_label || event.tool_id || 'Tool event'} · ${event.status || 'recorded'}`,
    description: event.result_summary || event.action_type || event.ledger_id,
    badge: NeoUI.statusBadge(event.blocked ? 'blocked' : (event.status || 'recorded')),
    body: `${NeoUI.badgeRow([event.category || 'tool', event.risk_level || 'risk', event.actor || 'neo', event.permission_profile || 'profile'])}${event.memory_trace_id ? `<p class="neo-muted">Trace: ${escapeHtml(event.memory_trace_id)}</p>` : ''}<p class="neo-muted">${escapeHtml(event.created_at || '')}</p>`,
    className: 'neo-ui-record-card admin-tool-ledger-card',
  })).join('');
  return `${NeoUI.card({
    title: 'Tool Execution Ledger + Audit Timeline',
    description: 'Central audit trail for Assistant, Operator, Voice, Internet/API, and permission-gated tool actions.',
    badge: NeoUI.statusBadge(ledger.status || 'ready'),
    body: `${NeoUI.badgeRow([`${ledger.event_count || 0} events`, `Profile: ${ledger.active_permission_profile || 'guided'}`, ledger.db_path || 'tool ledger'])}<div class="neo-ui-toolbar"><button type="button" class="neo-btn" onclick="refreshToolLedger()">Refresh ledger</button></div>${statusRows.length ? NeoUI.metaList(statusRows) : ''}${riskRows.length ? NeoUI.metaList(riskRows) : ''}`
  })}<div class="neo-ui-record-list admin-tool-ledger-list">${eventCards || NeoUI.emptyState('No tool execution events yet.', 'Run an Assistant Action Review, Operator command, or safe tool plan to populate the ledger.')}</div>`;
}

