function adminMemoryInspectorHtml(center) {
  const inspector = state.memoryInspector || {};
  const chunks = inspector.results?.chunks || [];
  const selected = inspector.selectedChunk?.chunk || null;
  const trace = inspector.selectedTrace?.trace || null;
  const resultLines = chunks.slice(0, 12).map((chunk) => {
    const label = `${chunk.source_id || 'source'} · ${chunk.memory_state || 'active'} · ${chunk.approval_state || 'not_required'} · ${chunk.title || chunk.chunk_id}`;
    return `<button type="button" class="neo-ui-record-card admin-memory-inspector-result" onclick="selectMemoryInspectorChunk('${escapeAttr(chunk.chunk_id)}')"><strong>${escapeHtml(label)}</strong><span>${escapeHtml(chunk.source_path || '')}${chunk.start_line ? `:${chunk.start_line}` : ''}</span><small>${escapeHtml(chunk.snippet || '')}</small></button>`;
  }).join('');
  const selectedBody = selected ? `${NeoUI.badgeRow([selected.source_id || 'source', selected.memory_state || 'active', selected.trust_level || 'confirmed', selected.approval_state || 'not_required', selected.retention_scope || 'project'])}${NeoUI.metaList([`Path: ${selected.source_path || ''}${selected.start_line ? `:${selected.start_line}-${selected.end_line || selected.start_line}` : ''}`, `Chunk: ${selected.chunk_id}`, `Policy score: ${selected.policy_score ?? 0.5}`, `Updated: ${selected.updated_at || ''}`])}<pre class="neo-ui-code admin-memory-inspector-code">${escapeHtml(selected.content || '')}</pre><div class="neo-ui-toolbar"><button type="button" class="neo-btn" onclick="reviewMemoryInspectorChunk('approve')">Approve</button><button type="button" class="neo-btn" onclick="reviewMemoryInspectorChunk('mark_canon')">Mark canon</button><button type="button" class="neo-btn" onclick="reviewMemoryInspectorChunk('mark_draft')">Mark draft</button><button type="button" class="neo-btn" onclick="reviewMemoryInspectorChunk('flag_conflict')">Flag conflict</button><button type="button" class="neo-btn danger" onclick="reviewMemoryInspectorChunk('deprecate')">Deprecate</button></div>` : NeoUI.emptyState('No memory chunk selected.', 'Search indexed memory and select a chunk to review its source, policy, and content.');
  const traceBody = trace ? `${NeoUI.badgeRow([trace.profile || 'smart', trace.consumer || 'assistant', `${(trace.results || []).length} result(s)`])}${NeoUI.metaList([`Trace: ${trace.trace_id}`, `Query: ${trace.query || ''}`, `Sources: ${(trace.sources || []).join(', ')}`])}${NeoUI.codeBlock(trace.metadata || {}, 'admin-memory-trace-code')}` : NeoUI.emptyState('No trace selected.', 'Open a trace ID from retrieval diagnostics or paste one later.');
  return `${NeoUI.card({
    title: 'Memory Inspector + Review Tools',
    description: 'Search indexed memory chunks, inspect source path/line ranges, and review policy state without touching raw databases.',
    badge: NeoUI.statusBadge('ready'),
    body: `<div class="neo-ui-field-grid"><div><label>Search indexed memory</label><input id="neo-memory-inspector-query" value="${escapeAttr(inspector.query || '')}" placeholder="Search records, code, Assistant, or Roleplay memory"></div><div><label>Source</label><input id="neo-memory-inspector-source" value="${escapeAttr(inspector.sourceId || '')}" placeholder="system_records / neo_codebase / roleplay_memory"></div><div><label>Memory state</label><input id="neo-memory-inspector-state" value="${escapeAttr(inspector.memoryState || '')}" placeholder="active / draft / canon / conflicting"></div><div><label>Approval</label><input id="neo-memory-inspector-approval" value="${escapeAttr(inspector.approvalState || '')}" placeholder="approved / pending / rejected"></div></div><div class="neo-ui-toolbar"><button type="button" class="neo-btn primary" onclick="searchMemoryInspector()">Search memory</button><button type="button" class="neo-btn" onclick="searchMemoryInspector('policy_alerts')">Show review items</button></div>${inspector.lastReview ? `<p class="neo-muted">Last review: ${escapeHtml(inspector.lastReview.status || '')} · ${escapeHtml(inspector.lastReview.action || '')}</p>` : ''}`
  })}${NeoUI.card({ title: 'Inspector Results', description: `${inspector.results?.total ?? 0} matching chunk(s).`, body: resultLines || NeoUI.emptyState('No inspector results yet.', 'Run a memory search or index sources first.') })}${NeoUI.card({ title: 'Selected Memory Chunk', description: 'Review content, source path, trust, canon/draft state, and approval.', body: selectedBody })}${NeoUI.card({ title: 'Retrieval Trace Detail', description: 'Trace detail shows how a memory query chose and rejected context.', body: traceBody })}`;
}

async function searchMemoryInspector(mode = '') {
  const query = document.getElementById('neo-memory-inspector-query')?.value || '';
  const sourceId = document.getElementById('neo-memory-inspector-source')?.value || '';
  const memoryState = document.getElementById('neo-memory-inspector-state')?.value || '';
  const approvalState = document.getElementById('neo-memory-inspector-approval')?.value || '';
  state.memoryInspector.query = query;
  state.memoryInspector.sourceId = sourceId;
  state.memoryInspector.memoryState = mode === 'policy_alerts' ? (memoryState || 'draft') : memoryState;
  state.memoryInspector.approvalState = approvalState;
  const params = new URLSearchParams();
  if (query) params.set('query', query);
  if (sourceId) params.set('source_id', sourceId);
  if (state.memoryInspector.memoryState) params.set('memory_state', state.memoryInspector.memoryState);
  if (approvalState) params.set('approval_state', approvalState);
  params.set('limit', '25');
  const response = await fetch(`/api/memory/inspect/chunks?${params.toString()}`);
  if (!response.ok) { window.alert(`Memory inspector search failed: ${await response.text()}`); return; }
  state.memoryInspector.results = await response.json();
  render();
}

async function selectMemoryInspectorChunk(chunkId) {
  if (!chunkId) return;
  const response = await fetch(`/api/memory/inspect/chunks/${encodeURIComponent(chunkId)}`);
  if (!response.ok) { window.alert(`Memory chunk load failed: ${await response.text()}`); return; }
  state.memoryInspector.selectedChunk = await response.json();
  render();
}

async function reviewMemoryInspectorChunk(action) {
  const chunkId = state.memoryInspector?.selectedChunk?.chunk?.chunk_id;
  if (!chunkId) { window.alert('Select a memory chunk first.'); return; }
  const response = await fetch('/api/memory/inspect/review', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ chunk_id: chunkId, action }) });
  if (!response.ok) { window.alert(`Memory review failed: ${await response.text()}`); return; }
  state.memoryInspector.lastReview = await response.json();
  state.memoryInspector.selectedChunk = { ok: true, chunk: state.memoryInspector.lastReview.chunk };
  state.memoryDiagnostics = await loadJson('/api/memory/diagnostics', state.memoryDiagnostics || null);
  state.memoryObservability = await loadJson('/api/memory/observability/status', state.memoryObservability || null);
  state.memory = await loadJson('/api/memory/status', state.memory || null);
  render();
}



function adminMemoryConflictResolverHtml(center) {
  const conflicts = state.memoryConflicts || {};
  const groups = conflicts.groups?.groups || [];
  const selected = conflicts.selectedGroup?.group || null;
  const canonItems = conflicts.canon?.items || [];
  const groupCards = groups.slice(0, 10).map((group) => {
    const label = `${group.severity || 'normal'} · ${group.conflict_type || 'candidate'} · ${group.title || group.group_id}`;
    return `<button type="button" class="neo-ui-record-card admin-memory-conflict-result" onclick="selectMemoryConflictGroup('${escapeAttr(group.group_id)}')"><strong>${escapeHtml(label)}</strong><span>${escapeHtml(group.source_id || '')} · ${group.chunk_count || 0} chunk(s)</span><small>${escapeHtml((group.source_paths || []).join(', '))}</small></button>`;
  }).join('');
  const selectedChunks = selected ? (selected.chunks || []).map((chunk) => `<button type="button" class="neo-ui-record-card" onclick="selectMemoryInspectorChunk('${escapeAttr(chunk.chunk_id)}')"><strong>${escapeHtml(chunk.memory_state || 'active')} · ${escapeHtml(chunk.title || chunk.chunk_id)}</strong><span>${escapeHtml(chunk.source_path || '')}${chunk.start_line ? `:${chunk.start_line}` : ''}</span><small>${escapeHtml(chunk.snippet || chunk.content || '')}</small></button>`).join('') : '';
  const selectedBody = selected ? `${NeoUI.badgeRow([selected.conflict_type || 'candidate', selected.severity || 'normal', selected.source_id || 'source', `${selected.chunk_count || 0} chunk(s)`])}${NeoUI.metaList([`Group: ${selected.group_id}`, `Key: ${selected.canon_key || ''}`, `States: ${(selected.states || []).join(', ')}`, `Trust: ${(selected.trust_levels || []).join(', ')}`])}<div class="neo-ui-record-list">${selectedChunks}</div><div class="neo-ui-toolbar"><button type="button" class="neo-btn primary" onclick="resolveMemoryConflict('promote_canonical')">Promote first as canon</button><button type="button" class="neo-btn" onclick="resolveMemoryConflict('mark_all_canon')">Mark all canon</button><button type="button" class="neo-btn" onclick="resolveMemoryConflict('flag_group_conflict')">Flag all conflict</button><button type="button" class="neo-btn danger" onclick="resolveMemoryConflict('archive_group')">Archive group</button></div>` : NeoUI.emptyState('No conflict group selected.', 'Scan memory conflicts and select a group to review canon/draft collisions.');
  const canonBody = canonItems.length ? canonItems.slice(0, 10).map((item) => `<button type="button" class="neo-ui-record-card" onclick="selectMemoryInspectorChunk('${escapeAttr(item.chunk_id)}')"><strong>${escapeHtml(item.memory_state || 'active')} · ${escapeHtml(item.title || item.chunk_id)}</strong><span>${escapeHtml(item.source_id || '')} · ${escapeHtml(item.approval_state || '')}</span><small>${escapeHtml(item.snippet || '')}</small></button>`).join('') : NeoUI.emptyState('No canon/candidate items loaded.', 'Load the Canon Manager to review canon, draft, pending, and conflicting memories.');
  return `${NeoUI.card({
    title: 'Memory Conflict Resolver + Canon Manager',
    description: 'Detect canon/draft collisions, review conflicting chunks, promote approved memory to canon, and keep Roleplay/Assistant memory clean.',
    badge: NeoUI.statusBadge('ready'),
    body: `<div class="neo-ui-field-grid"><div><label>Search conflicts</label><input id="neo-memory-conflict-query" value="${escapeAttr(conflicts.query || '')}" placeholder="character name, feature, source path, canon key"></div><div><label>Source</label><input id="neo-memory-conflict-source" value="${escapeAttr(conflicts.sourceId || '')}" placeholder="roleplay_memory / assistant_memory / system_records"></div></div><div class="neo-ui-toolbar"><button type="button" class="neo-btn primary" onclick="loadMemoryConflictGroups()">Scan conflicts</button><button type="button" class="neo-btn" onclick="loadMemoryCanonManager()">Load Canon Manager</button></div>${conflicts.lastResolution ? `<p class="neo-muted">Last resolution: ${escapeHtml(conflicts.lastResolution.status || '')} · ${escapeHtml(conflicts.lastResolution.action || '')} · ${escapeHtml(String(conflicts.lastResolution.updated_count || 0))} updated</p>` : ''}`
  })}${NeoUI.card({ title: 'Conflict Groups', description: `${conflicts.groups?.total ?? 0} group(s) needing review.`, body: groupCards || NeoUI.emptyState('No conflict groups loaded.', 'Scan conflicts after indexing Roleplay, Assistant, records, or codebase memory.') })}${NeoUI.card({ title: 'Selected Conflict Group', description: 'Review grouped memory and apply explicit resolution actions.', body: selectedBody })}${NeoUI.card({ title: 'Canon Manager', description: `${conflicts.canon?.total ?? 0} canon/candidate memory item(s).`, body: canonBody })}`;
}

async function loadMemoryConflictGroups() {
  const query = document.getElementById('neo-memory-conflict-query')?.value || '';
  const sourceId = document.getElementById('neo-memory-conflict-source')?.value || '';
  state.memoryConflicts.query = query;
  state.memoryConflicts.sourceId = sourceId;
  const params = new URLSearchParams();
  if (query) params.set('query', query);
  if (sourceId) params.set('source_id', sourceId);
  params.set('limit', '25');
  const response = await fetch(`/api/memory/conflicts?${params.toString()}`);
  if (!response.ok) { window.alert(`Memory conflict scan failed: ${await response.text()}`); return; }
  state.memoryConflicts.groups = await response.json();
  render();
}

async function selectMemoryConflictGroup(groupId) {
  if (!groupId) return;
  const response = await fetch(`/api/memory/conflicts/${encodeURIComponent(groupId)}`);
  if (!response.ok) { window.alert(`Memory conflict group load failed: ${await response.text()}`); return; }
  state.memoryConflicts.selectedGroup = await response.json();
  render();
}

async function resolveMemoryConflict(action) {
  const group = state.memoryConflicts?.selectedGroup?.group;
  if (!group?.group_id) { window.alert('Select a conflict group first.'); return; }
  const canonical = (group.chunks || []).find((chunk) => chunk.memory_state === 'canon') || (group.chunks || [])[0] || {};
  const response = await fetch('/api/memory/conflicts/resolve', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ group_id: group.group_id, action, canonical_chunk_id: canonical.chunk_id || '' }) });
  if (!response.ok) { window.alert(`Memory conflict resolution failed: ${await response.text()}`); return; }
  state.memoryConflicts.lastResolution = await response.json();
  state.memoryConflicts.selectedGroup = await loadJson(`/api/memory/conflicts/${encodeURIComponent(group.group_id)}`, state.memoryConflicts.selectedGroup || null);
  state.memoryDiagnostics = await loadJson('/api/memory/diagnostics', state.memoryDiagnostics || null);
  state.memoryObservability = await loadJson('/api/memory/observability/status', state.memoryObservability || null);
  state.memory = await loadJson('/api/memory/status', state.memory || null);
  render();
}

async function loadMemoryCanonManager() {
  const query = document.getElementById('neo-memory-conflict-query')?.value || state.memoryConflicts?.query || '';
  const sourceId = document.getElementById('neo-memory-conflict-source')?.value || state.memoryConflicts?.sourceId || '';
  state.memoryConflicts.query = query;
  state.memoryConflicts.sourceId = sourceId;
  const params = new URLSearchParams();
  if (query) params.set('query', query);
  if (sourceId) params.set('source_id', sourceId);
  params.set('include_candidates', 'true');
  params.set('limit', '50');
  const response = await fetch(`/api/memory/canon?${params.toString()}`);
  if (!response.ok) { window.alert(`Canon Manager load failed: ${await response.text()}`); return; }
  state.memoryConflicts.canon = await response.json();
  render();
}


function adminMemoryConsolidationHtml(center) {
  const stateBlock = state.memoryConsolidation || {};
  const groups = stateBlock.plan?.groups || [];
  const selected = groups.find((group) => group.group_id === stateBlock.selectedGroupId) || groups[0] || null;
  const groupCards = groups.slice(0, 10).map((group) => `<button type="button" class="neo-ui-record-card admin-memory-consolidation-result" onclick="selectMemoryConsolidationGroup('${escapeAttr(group.group_id)}')"><strong>${escapeHtml(group.title || group.group_id)}</strong><span>${escapeHtml(group.source_id || '')} · ${group.chunk_count || 0} chunk(s) · ${escapeHtml(group.recommended_action || '')}</span><small>${escapeHtml((group.chunks || []).map((chunk) => chunk.source_path).filter(Boolean).slice(0, 3).join(', '))}</small></button>`).join('');
  const selectedChunks = selected ? (selected.chunks || []).map((chunk) => `<button type="button" class="neo-ui-record-card" onclick="selectMemoryInspectorChunk('${escapeAttr(chunk.chunk_id)}')"><strong>${escapeHtml(chunk.memory_state || 'active')} · ${escapeHtml(chunk.title || chunk.chunk_id)}</strong><span>${escapeHtml(chunk.source_path || '')}${chunk.start_line ? `:${chunk.start_line}` : ''}</span><small>${escapeHtml(chunk.snippet || '')}</small></button>`).join('') : '';
  const selectedBody = selected ? `${NeoUI.badgeRow([selected.source_id || 'source', `${selected.chunk_count || 0} chunks`, selected.recommended_action || 'review', `confidence ${selected.confidence ?? 0}`])}${NeoUI.metaList([`Group: ${selected.group_id}`, `States: ${Object.entries(selected.state_counts || {}).map(([k, v]) => `${k}:${v}`).join(', ')}`, `Approval: ${Object.entries(selected.approval_counts || {}).map(([k, v]) => `${k}:${v}`).join(', ')}`])}<div class="neo-ui-record-list">${selectedChunks}</div><div class="neo-ui-toolbar"><button type="button" class="neo-btn primary" onclick="runMemoryConsolidation('create_summary')">Create summary</button><button type="button" class="neo-btn danger" onclick="runMemoryConsolidation('create_summary_archive_originals')">Create summary + archive originals</button></div>` : NeoUI.emptyState('No consolidation group selected.', 'Plan consolidation after indexing memory sources.');
  const last = stateBlock.lastRun;
  return `${NeoUI.card({
    title: 'Memory Consolidation + Summarization',
    description: 'Create durable reviewed summaries from related memory chunks. Originals stay auditable unless explicitly archived.',
    badge: NeoUI.statusBadge('ready'),
    body: `<div class="neo-ui-field-grid"><div><label>Search memory groups</label><input id="neo-memory-consolidation-query" value="${escapeAttr(stateBlock.query || '')}" placeholder="project, character, feature, source path"></div><div><label>Source</label><input id="neo-memory-consolidation-source" value="${escapeAttr(stateBlock.sourceId || '')}" placeholder="assistant_memory / roleplay_memory / system_records"></div></div><div class="neo-ui-toolbar"><button type="button" class="neo-btn primary" onclick="planMemoryConsolidation()">Plan consolidation</button></div>${last ? `<p class="neo-muted">Last consolidation: ${escapeHtml(last.status || '')} · ${escapeHtml(last.summary_chunk_id || '')}</p>` : ''}`
  })}${NeoUI.card({ title: 'Consolidation Candidates', description: `${stateBlock.plan?.total ?? 0} group(s) found.`, body: groupCards || NeoUI.emptyState('No consolidation groups loaded.', 'Index memory sources, then plan consolidation.') })}${NeoUI.card({ title: 'Selected Consolidation Group', description: 'Review source chunks before creating a durable summary.', body: selectedBody })}`;
}

async function planMemoryConsolidation() {
  const query = document.getElementById('neo-memory-consolidation-query')?.value || '';
  const sourceId = document.getElementById('neo-memory-consolidation-source')?.value || '';
  state.memoryConsolidation.query = query;
  state.memoryConsolidation.sourceId = sourceId;
  const response = await fetch('/api/memory/consolidation/plan', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ query, source_id: sourceId, min_group_size: 2, limit: 25 }) });
  if (!response.ok) { window.alert(`Memory consolidation plan failed: ${await response.text()}`); return; }
  state.memoryConsolidation.plan = await response.json();
  state.memoryConsolidation.selectedGroupId = state.memoryConsolidation.plan?.groups?.[0]?.group_id || '';
  render();
}

function selectMemoryConsolidationGroup(groupId) {
  state.memoryConsolidation.selectedGroupId = groupId || '';
  render();
}

async function runMemoryConsolidation(action) {
  const groups = state.memoryConsolidation?.plan?.groups || [];
  const group = groups.find((item) => item.group_id === state.memoryConsolidation.selectedGroupId) || groups[0];
  if (!group) { window.alert('Plan consolidation and select a group first.'); return; }
  const response = await fetch('/api/memory/consolidation/run', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ action, chunk_ids: group.chunk_ids || [], title: `Summary: ${group.title || group.group_id}`, note: 'Created from Admin Memory Consolidation.' }) });
  if (!response.ok) { window.alert(`Memory consolidation failed: ${await response.text()}`); return; }
  state.memoryConsolidation.lastRun = await response.json();
  state.memoryDiagnostics = await loadJson('/api/memory/diagnostics', state.memoryDiagnostics || null);
  state.memoryObservability = await loadJson('/api/memory/observability/status', state.memoryObservability || null);
  state.memory = await loadJson('/api/memory/status', state.memory || null);
  render();
}


function adminMemoryRetentionHtml(center) {
  const retention = state.memoryRetention || {};
  const plan = retention.plan || {};
  const candidates = plan.candidates || [];
  const selected = new Set(retention.selectedIds || []);
  const rows = candidates.slice(0, 12).map((item) => {
    const checked = selected.has(item.chunk_id) ? ' checked' : '';
    const label = `${item.source_id || 'source'} · ${item.recommended_action || 'review'} · ${item.memory_state || 'active'} · ${item.age_days ?? '?'}d`;
    return `<label class="neo-ui-record-card admin-memory-retention-result"><input type="checkbox" onchange="toggleMemoryRetentionCandidate('${escapeAttr(item.chunk_id)}', this.checked)"${checked}><strong>${escapeHtml(label)}</strong><span>${escapeHtml(item.title || item.chunk_id || '')}</span><small>${escapeHtml((item.retention_reasons || []).join(', '))}</small></label>`;
  }).join('');
  const actionCounts = Object.entries(plan.action_counts || {}).map(([key, value]) => `${key}: ${value}`);
  const last = retention.lastRun || null;
  return `${NeoUI.card({
    title: 'Memory Decay + Retention Automation',
    description: 'Find stale temporary/session memory, external/API memory that needs recheck, low-trust chunks, and source-backed records that need refresh. Actions are Admin-reviewed only.',
    badge: NeoUI.statusBadge(plan.status || 'review ready'),
    body: `<div class="neo-ui-field-grid"><div><label>Search retention candidates</label><input id="neo-memory-retention-query" value="${escapeAttr(retention.query || '')}" placeholder="external, draft, old scene, project"></div><div><label>Source</label><input id="neo-memory-retention-source" value="${escapeAttr(retention.sourceId || '')}" placeholder="internet_external / assistant_memory / roleplay_memory"></div><div><label>Max age days</label><input id="neo-memory-retention-age" type="number" min="1" value="${escapeAttr(plan.max_age_days || 30)}"></div></div><div class="neo-ui-toolbar"><button type="button" class="neo-btn primary" onclick="planMemoryRetention()">Plan retention review</button><button type="button" class="neo-btn" onclick="runMemoryRetention('mark_for_review')">Mark selected for review</button><button type="button" class="neo-btn" onclick="runMemoryRetention('archive_temporary')">Archive selected</button><button type="button" class="neo-btn danger" onclick="runMemoryRetention('deprecate_stale_external')">Deprecate stale external</button></div>${actionCounts.length ? NeoUI.badgeRow(actionCounts) : ''}${last ? `<p class="neo-muted">Last retention action: ${escapeHtml(last.status || '')} · ${escapeHtml(last.action || '')} · ${last.updated_count || 0} updated</p>` : ''}`
  })}${NeoUI.card({ title: 'Retention Candidates', description: `${plan.total ?? 0} candidate(s). Select chunks before running a retention action.`, body: rows || NeoUI.emptyState('No retention candidates loaded.', 'Plan retention review after indexing memory sources.') })}`;
}

function toggleMemoryRetentionCandidate(chunkId, checked) {
  const ids = new Set(state.memoryRetention?.selectedIds || []);
  if (checked) ids.add(chunkId); else ids.delete(chunkId);
  state.memoryRetention.selectedIds = Array.from(ids);
}

async function planMemoryRetention() {
  const query = document.getElementById('neo-memory-retention-query')?.value || '';
  const sourceId = document.getElementById('neo-memory-retention-source')?.value || '';
  const maxAgeDays = Number(document.getElementById('neo-memory-retention-age')?.value || 30);
  state.memoryRetention.query = query;
  state.memoryRetention.sourceId = sourceId;
  const response = await fetch('/api/memory/retention/plan', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ query, source_id: sourceId, max_age_days: maxAgeDays, limit: 50 }) });
  if (!response.ok) { window.alert(`Memory retention plan failed: ${await response.text()}`); return; }
  state.memoryRetention.plan = await response.json();
  state.memoryRetention.selectedIds = [];
  render();
}

async function runMemoryRetention(action) {
  const chunkIds = state.memoryRetention?.selectedIds || [];
  if (!chunkIds.length) { window.alert('Select one or more retention candidates first.'); return; }
  const response = await fetch('/api/memory/retention/run', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ action, chunk_ids: chunkIds, note: 'Applied from Admin Memory Retention review.' }) });
  if (!response.ok) { window.alert(`Memory retention action failed: ${await response.text()}`); return; }
  state.memoryRetention.lastRun = await response.json();
  state.memoryRetention.selectedIds = [];
  await planMemoryRetention();
}

function adminMemoryPoliciesHtml(center) {
  const payload = center?.memory_engine?.memory_policies || state.memory?.memory_policies || {};
  const allowed = payload.allowed || {};
  const defaults = payload.source_defaults || {};
  const counts = payload.counts?.chunk_policy_counts || [];
  const defaultCards = Object.entries(defaults).slice(0, 10).map(([sourceId, policy]) => NeoUI.card({
    title: sourceId.replaceAll('_', ' '),
    description: policy.notes || 'Memory policy defaults.',
    badge: NeoUI.statusBadge(policy.memory_state || 'active'),
    body: `${NeoUI.badgeRow([policy.retention_scope || 'project', policy.visibility || 'expert', policy.trust_level || 'confirmed', policy.importance || 'normal'])}${NeoUI.metaList([`Approval: ${policy.approval_state || 'not_required'}`, `Policy score: ${policy.policy_score ?? 0.5}`, `Decay: ${policy.decay_policy || 'none'}`])}`,
    className: 'neo-ui-record-card admin-memory-policy-card',
  })).join('');
  const countLines = counts.slice(0, 12).map((item) => `${item.source_id || 'source'} · ${item.memory_state || 'active'} · ${item.trust_level || 'confirmed'} · ${item.count || 0} chunk(s)`);
  return `${NeoUI.card({
    title: 'Memory Policies',
    description: 'Controls trust, canon/draft state, retention scope, visibility, approval, importance, and memory rejection rules before context reaches Assistant or Roleplay.',
    badge: NeoUI.statusBadge(payload.status || 'ready'),
    body: `${NeoUI.badgeRow([`${(allowed.retention_scopes || []).length} retention scopes`, `${(allowed.memory_states || []).length} memory states`, `${(allowed.trust_levels || []).length} trust levels`, `${(allowed.visibility_levels || []).length} visibility levels`])}${NeoUI.metaList(countLines.length ? countLines : ['No indexed policy counts yet. Index memory sources first.'])}`
  })}<div class="neo-ui-record-list admin-memory-policy-list">${defaultCards || NeoUI.emptyState('No memory policy defaults registered.')}</div>`;
}

function adminMemoryRetrievalProfilesHtml(center) {
  const payload = center?.retrieval_profiles || center?.memory_engine?.retrieval_profiles || {};
  const profiles = Array.isArray(payload.profiles) ? payload.profiles : [];
  const traces = Array.isArray(payload.recent_traces) ? payload.recent_traces : (center?.memory_engine?.recent_traces || []);
  const profileCards = profiles.map((profile) => NeoUI.card({
    title: profile.label || profile.profile_id,
    description: profile.description || 'Memory Engine retrieval profile.',
    badge: NeoUI.statusBadge(profile.profile_id === (payload.default_profile_id || 'smart') ? 'default' : 'ready'),
    body: `${NeoUI.badgeRow([`keyword ${profile.keyword_weight ?? 0}`, `vector ${profile.vector_weight ?? 0}`, `min ${profile.min_score ?? 0}`, profile.rerank ? 'rerank' : 'no rerank'])}${NeoUI.metaList([`Sources: ${(profile.sources || []).join(', ') || 'auto'}`, `Low-confidence rejection: ${profile.low_confidence_rejection ? 'on' : 'off'}`])}`,
    className: 'neo-ui-record-card admin-memory-profile-card',
  })).join('');
  const traceList = traces.slice(0, 6).map((trace) => `${trace.profile || 'smart'} · ${trace.query || 'empty query'} · ${(trace.results || []).length} result(s)`).join('') ? NeoUI.metaList(traces.slice(0, 6).map((trace) => `${trace.profile || 'smart'} · ${trace.query || 'empty query'} · ${(trace.results || []).length} result(s)`)) : NeoUI.emptyState('No retrieval traces yet.', 'Run a Memory Engine search to create a trace.');
  return `${NeoUI.card({ title: 'Hybrid Retrieval Profiles', description: 'Profiles combine keyword, vector, recency, importance, reranker, and low-confidence rejection rules.', badge: NeoUI.statusBadge(payload.status || 'ready'), body: `${NeoUI.badgeRow([`${profiles.length} profiles`, `Default: ${payload.default_profile_id || 'smart'}`])}` })}<div class="neo-ui-record-list admin-memory-profile-list">${profileCards || NeoUI.emptyState('No retrieval profiles registered.')}</div>${NeoUI.card({ title: 'Recent Retrieval Traces', description: 'Inspectable trace trail for Memory Engine recall decisions.', body: traceList })}`;
}

async function indexMemorySource(sourceId = 'system_records') {
  const response = await fetch('/api/memory/index', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ source_id: sourceId }) });
  if (!response.ok) { window.alert(`Memory indexing failed: ${await response.text()}`); return; }
  const result = await response.json();
  state.memory = await loadJson('/api/memory/status', state.memory || null);
  state.memoryDiagnostics = await loadJson('/api/memory/diagnostics', state.memoryDiagnostics || null);
  state.memoryObservability = await loadJson('/api/memory/observability/status', state.memoryObservability || null);
  state.adminControlCenter = await loadJson('/api/admin/control-center', state.adminControlCenter || {});
  render();
  window.alert(`Memory indexed: ${result.indexed_documents || 0} documents · ${result.indexed_chunks || 0} chunks`);
}


function adminMemorySearchUxHtml(center) {
  const search = state.memorySearch || {};
  const results = search.results?.results || [];
  const citation = search.selectedCitation || null;
  const related = search.related?.chunks || [];
  const comparison = search.comparison || null;
  const resultCards = results.slice(0, 12).map((item) => {
    const cite = item.citation || {};
    const label = cite.label || `${item.source_path || ''}:${item.start_line || ''}`;
    return `<button type="button" class="neo-ui-record-card admin-memory-search-result" onclick="openMemoryCitation('${escapeAttr(item.chunk_id)}')"><strong>${escapeHtml(item.title || item.chunk_id || 'Memory result')}</strong><span>${escapeHtml(label)}</span><small>${escapeHtml(item.snippet || '')}</small>${NeoUI.badgeRow([item.source_id || 'source', item.memory_state || 'active', item.trust_level || 'confirmed', `score ${item.score ?? 0}`])}</button>`;
  }).join('');
  const citationLines = citation?.lines || [];
  const citationBody = citation ? `${NeoUI.badgeRow([citation.citation?.source_id || citation.chunk?.source_id || 'source', citation.source_available ? 'source file' : 'stored chunk', citation.citation?.memory_state || citation.chunk?.memory_state || 'active'])}${NeoUI.metaList([`Citation: ${citation.citation?.label || citation.source_path || ''}`, `Chunk: ${citation.chunk?.chunk_id || ''}`, `Range: ${citation.requested_range?.start_line || 1}-${citation.requested_range?.end_line || 1}`])}<pre class="neo-ui-code admin-memory-source-viewer-code">${escapeHtml(citationLines.map((line) => `${line.highlight ? '›' : ' '} ${String(line.line).padStart(4, ' ')}  ${line.text}`).join('\n') || citation.fallback_content || '')}</pre><div class="neo-ui-toolbar"><button type="button" class="neo-btn" onclick="loadRelatedMemoryChunks('${escapeAttr(citation.chunk?.chunk_id || '')}')">Show related chunks</button><button type="button" class="neo-btn" onclick="compareConsolidatedMemory('${escapeAttr(citation.chunk?.chunk_id || '')}')">Compare summary sources</button></div>` : NeoUI.emptyState('No citation selected.', 'Run a memory search and open a result to view source lines or stored chunk content.');
  const relatedBody = related.length ? related.slice(0, 8).map((item) => `<button type="button" class="neo-ui-record-card" onclick="openMemoryCitation('${escapeAttr(item.chunk_id)}')"><strong>${escapeHtml(item.title || item.chunk_id)}</strong><span>${escapeHtml(item.source_path || '')}${item.start_line ? `:${item.start_line}` : ''}</span><small>${escapeHtml(item.snippet || '')}</small></button>`).join('') : NeoUI.emptyState('No related chunks loaded.', 'Open a citation, then show related chunks.');
  const comparisonBody = comparison?.ok ? `${NeoUI.badgeRow([`${(comparison.sources || []).length} source chunks`, comparison.summary_chunk?.source_id || 'memory_consolidation'])}${NeoUI.metaList((comparison.sources || []).slice(0, 8).map((item) => `${item.chunk_id} · ${item.source_path || ''}${item.start_line ? `:${item.start_line}-${item.end_line || item.start_line}` : ''}`))}` : NeoUI.emptyState('No summary comparison loaded.', 'Use this on consolidated summary chunks to audit their original source chunks.');
  return `${NeoUI.card({
    title: 'Memory Search + Source Citations',
    description: 'Search Memory Engine with citations, source path/line viewer, related chunks, retrieval trace linkage, and summary-source comparison.',
    badge: NeoUI.statusBadge('ready'),
    body: `<div class="neo-ui-field-grid"><div><label>Search memory</label><input id="neo-memory-search-query" value="${escapeAttr(search.query || '')}" placeholder="Search records, code, canon, Assistant memory..."></div><div><label>Profile</label><input id="neo-memory-search-profile" value="${escapeAttr(search.profile || 'smart')}" placeholder="smart / code_audit / roleplay_runtime"></div><div><label>Source filter</label><input id="neo-memory-search-source" value="${escapeAttr(search.sourceId || '')}" placeholder="system_records / neo_codebase / roleplay_memory"></div></div><div class="neo-ui-toolbar"><button type="button" class="neo-btn primary" onclick="runMemorySearchUx()">Search with citations</button><button type="button" class="neo-btn" onclick="runMemorySearchUx('code_audit')">Code audit search</button><button type="button" class="neo-btn" onclick="runMemorySearchUx('roleplay_runtime')">Roleplay memory search</button></div>${search.results ? `<p class="neo-muted">Trace: ${escapeHtml(search.results.trace_id || '')} · ${escapeHtml(search.results.backend_used || '')} · ${(search.results.results || []).length} result(s)</p>` : ''}`
  })}${NeoUI.card({ title: 'Search Results', description: `${search.results?.results?.length ?? 0} cited result(s).`, body: resultCards || NeoUI.emptyState('No cited results yet.', 'Index sources and run a search.') })}${NeoUI.card({ title: 'Source Citation Viewer', description: 'Shows source file lines when available; generated/virtual memory falls back to stored chunk content.', body: citationBody })}${NeoUI.card({ title: 'Related Chunks', description: 'Nearby or title-related memory chunks for context expansion.', body: relatedBody })}${NeoUI.card({ title: 'Consolidated Summary Comparison', description: 'For memory_consolidation summaries, show the original source chunk list.', body: comparisonBody })}`;
}

async function runMemorySearchUx(forceProfile = '') {
  const query = document.getElementById('neo-memory-search-query')?.value || '';
  const profile = forceProfile || document.getElementById('neo-memory-search-profile')?.value || 'smart';
  const sourceId = document.getElementById('neo-memory-search-source')?.value || '';
  state.memorySearch.query = query;
  state.memorySearch.profile = profile;
  state.memorySearch.sourceId = sourceId;
  const payload = { query, profile, limit: 12, consumer: 'admin_memory_search_ux' };
  if (sourceId) payload.sources = [sourceId];
  const response = await fetch('/api/memory/search-ux', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
  if (!response.ok) { window.alert(`Memory search failed: ${await response.text()}`); return; }
  state.memorySearch.results = await response.json();
  state.memorySearch.selectedCitation = null;
  state.memorySearch.related = null;
  state.memorySearch.comparison = null;
  render();
}

async function openMemoryCitation(chunkId) {
  if (!chunkId) return;
  const response = await fetch(`/api/memory/citations/${encodeURIComponent(chunkId)}`);
  if (!response.ok) { window.alert(`Citation load failed: ${await response.text()}`); return; }
  state.memorySearch.selectedCitation = await response.json();
  render();
}

async function loadRelatedMemoryChunks(chunkId) {
  if (!chunkId) return;
  const response = await fetch(`/api/memory/related-chunks/${encodeURIComponent(chunkId)}?limit=8`);
  if (!response.ok) { window.alert(`Related chunks failed: ${await response.text()}`); return; }
  state.memorySearch.related = await response.json();
  render();
}

async function compareConsolidatedMemory(chunkId) {
  if (!chunkId) return;
  const response = await fetch(`/api/memory/consolidation/compare/${encodeURIComponent(chunkId)}`);
  if (!response.ok) { window.alert(`Summary comparison failed: ${await response.text()}`); return; }
  state.memorySearch.comparison = await response.json();
  render();
}


function adminMemoryDiagnosticsHtml(center) {
  const diag = center?.memory_diagnostics || state.memoryDiagnostics || {};
  const summary = diag.summary || {};
  const checks = Array.isArray(diag.checks) ? diag.checks : [];
  const sourceHealth = Array.isArray(diag.source_health) ? diag.source_health : [];
  const traces = Array.isArray(diag.recent_retrieval_traces) ? diag.recent_retrieval_traces : [];
  const alerts = Array.isArray(diag.policy_alerts) ? diag.policy_alerts : [];
  const checkCards = checks.map((check) => NeoUI.card({
    title: check.label || check.id,
    description: check.detail || '',
    badge: NeoUI.statusBadge(check.status || 'unknown'),
    className: 'neo-ui-check-card admin-memory-diagnostic-check',
  })).join('');
  const sourceLines = sourceHealth.slice(0, 10).map((source) => `${source.source_id || 'source'} · ${source.status || 'unknown'} · ${source.document_count || 0} docs · ${source.chunk_count || 0} chunks${source.age_days != null ? ` · ${source.age_days}d old` : ''}`);
  const traceLines = traces.slice(0, 8).map((trace) => `${trace.profile || 'smart'} · ${trace.consumer || 'assistant'} · ${trace.result_count || 0} result(s) · ${trace.rejected_count || 0} rejected · ${trace.query || ''}`);
  const alertLines = alerts.slice(0, 8).map((alert) => `${alert.memory_state || 'active'} · ${alert.trust_level || 'confirmed'} · ${alert.approval_state || 'not_required'} · ${alert.count || 0} chunk(s)`);
  return `${NeoUI.card({
    title: 'Memory Health Dashboard',
    description: 'Read-only diagnostics for indexing, retrieval quality, policies, Operator, Voice input, Internet/API gating, and Roleplay continuity.',
    badge: NeoUI.statusBadge(diag.status || 'ready'),
    body: `${NeoUI.badgeRow([`${summary.document_count || 0} docs`, `${summary.chunk_count || 0} chunks`, `${summary.ready_source_count || 0} ready sources`, `${summary.stale_source_count || 0} stale`, `${summary.policy_alert_count || 0} policy alerts`, `internet ${summary.internet_mode || 'disabled'}`])}`,
    actions: '<button type="button" class="neo-btn primary" onclick="reloadAdminControlCenter()">Refresh diagnostics</button>',
  })}<div class="neo-ui-record-list admin-memory-diagnostics-checks">${checkCards || NeoUI.emptyState('No diagnostic checks loaded.', 'Refresh diagnostics.')}</div>${NeoUI.card({ title: 'Source Index Health', description: 'Shows which Memory Engine sources are ready, stale, or need their first index pass.', body: sourceLines.length ? NeoUI.metaList(sourceLines) : NeoUI.emptyState('No source health loaded.') })}${NeoUI.card({ title: 'Retrieval Quality Snapshot', description: 'Recent retrieval traces, rejected candidates, and backend usage.', body: traceLines.length ? NeoUI.metaList(traceLines) : NeoUI.emptyState('No retrieval traces yet.', 'Run Assistant, Operator, or Memory retrieval to create traces.') })}${NeoUI.card({ title: 'Policy Alerts', description: 'Memory chunks that may need review because they are draft, conflicting, deprecated, pending, or rejected.', badge: NeoUI.statusBadge(alerts.length ? 'needs review' : 'ready'), body: alertLines.length ? NeoUI.metaList(alertLines) : NeoUI.emptyState('No policy alerts.', 'Memory policies look clean.') })}`;
}


