function adminAssistantBrainWorkspaceHtml(center) {
  const migrated = neoInvokeSurfaceModule('admin', 'assistantBrainWorkspaceHtml', { center });
  if (typeof migrated === 'string') return migrated;
  const brain = state.assistantBrain || {};
  const status = brain.status || center?.assistant_brain || {};
  const dashboard = brain.dashboard || {};
  const workspaces = Array.isArray(dashboard.workspaces) ? dashboard.workspaces : (Array.isArray(brain.workspaces?.workspaces) ? brain.workspaces.workspaces : []);
  const active = dashboard.active_workspace || workspaces.find((item) => item.workspace_id === brain.activeWorkspaceId) || workspaces[0] || {};
  const preview = Array.isArray(dashboard.memory_preview) ? dashboard.memory_preview : [];
  const traces = Array.isArray(dashboard.recent_traces) ? dashboard.recent_traces : [];
  const workspaceButtons = workspaces.map((workspace) => {
    const selected = active.workspace_id === workspace.workspace_id;
    const stats = workspace.memory_stats || {};
    return `<button type="button" class="neo-ui-record-card ${selected ? 'selected' : ''}" onclick="selectAssistantBrainWorkspace('${escapeAttr(workspace.workspace_id || '')}')"><strong>${escapeHtml(workspace.name || workspace.workspace_id || 'Workspace')}</strong><span>${escapeHtml(workspace.surface || 'assistant')} · ${escapeHtml(workspace.project_id || 'project')} · ${stats.fragments || 0} fragments</span><small>${escapeHtml((workspace.memory_lanes || []).slice(0, 4).join(', '))}</small></button>`;
  }).join('');
  const memoryLines = preview.slice(0, 8).map((item) => `${item.memory_type || 'memory'} · ${item.title || item.fragment_id || ''} · ${item.content_preview || ''}`);
  const traceLines = traces.slice(0, 6).map((trace) => `${trace.intent || 'intent'} · ${trace.context_count || 0} ctx · ${trace.status || 'status'} · ${trace.created_at || ''}`);
  const lastContext = brain.lastContext || {};
  return `${NeoUI.card({
    title: 'Assistant Brain Workspace',
    description: 'Workspace-aware Assistant routing: built-in surface projects, scoped memory lanes, and Control Center handoff before backend generation.',
    badge: NeoUI.statusBadge(status.status || 'ready'),
    body: `${NeoUI.badgeRow([`workspaces ${status.workspace_count || workspaces.length || 0}`, `active ${active.name || 'none'}`, `surface ${active.surface || 'assistant'}`])}<div class="neo-ui-toolbar"><button type="button" class="neo-btn primary" onclick="reloadAssistantBrainWorkspace()">Refresh brain workspaces</button><button type="button" class="neo-btn" onclick="activateAssistantBrainWorkspace()">Set active Assistant project</button><button type="button" class="neo-btn" onclick="buildAssistantBrainContext()">Build context preview</button></div>`
  })}<div class="neo-ui-grid two"><div>${NeoUI.card({ title: 'Built-in workspaces', description: 'Each workspace is a sandboxed Assistant project mapped to a Neo surface.', body: workspaceButtons || NeoUI.emptyState('No Assistant brain workspaces loaded yet.', 'Refresh brain workspaces.') })}</div><div>${NeoUI.card({ title: active.name || 'Active workspace', description: active.description || 'Workspace details and scoped memory preview.', body: `${NeoUI.metaList([`Workspace: ${active.workspace_id || 'none'}`, `Project: ${active.project_id || 'none'}`, `Surface: ${active.surface || 'assistant'}`, `Memory lanes: ${(active.memory_lanes || []).join(', ') || 'none'}`])}${NeoUI.card({ title: 'Memory preview', description: 'Recent unified memory fragments available to this workspace.', body: memoryLines.length ? NeoUI.metaList(memoryLines) : NeoUI.emptyState('No memory fragments in this workspace yet.') })}${NeoUI.card({ title: 'Recent Assistant Control traces', description: 'Latest Control Center traces for this workspace.', body: traceLines.length ? NeoUI.metaList(traceLines) : NeoUI.emptyState('No traces for this workspace yet.') })}${lastContext.trace_id ? NeoUI.card({ title: 'Last context preview', description: 'Prompt/control brief generated for the selected workspace.', body: `${NeoUI.metaList([`Trace: ${lastContext.trace_id || ''}`, `Project: ${lastContext.diagnostics?.project_id || ''}`, `Surface: ${lastContext.diagnostics?.surface || ''}`])}${state.detailMode === 'expert' ? NeoUI.codeBlock(lastContext.prompt_block || '', 'assistant-brain-context-preview') : ''}` }) : ''}` })}</div></div>`;
}

async function reloadAssistantBrainWorkspace() {
  if (await neoTryAdminAction('reloadAssistantBrainWorkspace')) return;
  state.assistantBrain.status = await loadJson('/api/assistant/brain/status', state.assistantBrain.status || null);
  state.surfaceModules.status = await loadJson('/api/surfaces/modules/status', state.surfaceModules.status || null);
  state.surfaceStatus.status = await loadJson('/api/surfaces/status/status', state.surfaceStatus.status || null);
  state.modernUi.status = await loadJson('/api/ui/modern/status', state.modernUi.status || null);
  state.assistantBrain.workspaces = await loadJson('/api/assistant/brain/workspaces', state.assistantBrain.workspaces || null);
  const workspaceId = state.assistantBrain.activeWorkspaceId || state.assistantBrain.workspaces?.workspaces?.[0]?.workspace_id || '';
  const response = await fetch('/api/assistant/brain/dashboard', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ workspace_id: workspaceId, limit: 8 }) });
  if (!response.ok) { window.alert(`Assistant Brain refresh failed: ${await response.text()}`); return; }
  state.assistantBrain.dashboard = await response.json();
  if (state.assistantBrain.dashboard?.active_workspace?.workspace_id) state.assistantBrain.activeWorkspaceId = state.assistantBrain.dashboard.active_workspace.workspace_id;
  render();
}

async function selectAssistantBrainWorkspace(workspaceId) {
  if (await neoTryAdminAction('selectAssistantBrainWorkspace', { workspaceId })) return;
  state.assistantBrain.activeWorkspaceId = workspaceId || '';
  const response = await fetch('/api/assistant/brain/dashboard', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ workspace_id: state.assistantBrain.activeWorkspaceId, limit: 8 }) });
  if (!response.ok) { window.alert(`Assistant Brain workspace load failed: ${await response.text()}`); return; }
  state.assistantBrain.dashboard = await response.json();
  render();
}

async function activateAssistantBrainWorkspace() {
  if (await neoTryAdminAction('activateAssistantBrainWorkspace')) return;
  const workspaceId = state.assistantBrain.activeWorkspaceId || state.assistantBrain.dashboard?.active_workspace?.workspace_id || '';
  if (!workspaceId) { window.alert('No Assistant Brain workspace selected.'); return; }
  const response = await fetch('/api/assistant/brain/activate', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ workspace_id: workspaceId }) });
  if (!response.ok) { window.alert(`Assistant Brain activation failed: ${await response.text()}`); return; }
  state.assistantBrain.lastActivation = await response.json();
  await reloadAssistantBrainWorkspace();
}

async function buildAssistantBrainContext() {
  if (await neoTryAdminAction('buildAssistantBrainContext')) return;
  const workspaceId = state.assistantBrain.activeWorkspaceId || state.assistantBrain.dashboard?.active_workspace?.workspace_id || '';
  const response = await fetch('/api/assistant/brain/context', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ workspace_id: workspaceId, query: 'Build Assistant Brain workspace context preview.', limit: 8 }) });
  if (!response.ok) { window.alert(`Assistant Brain context failed: ${await response.text()}`); return; }
  state.assistantBrain.lastContext = await response.json();
  await reloadAssistantBrainWorkspace();
}

function adminControlCenterReviewHtml(center) {
  const migrated = neoInvokeSurfaceModule('admin', 'controlCenterReviewHtml', { center });
  if (typeof migrated === 'string') return migrated;
  const review = state.controlCenterReview || {};
  const status = review.status || center?.control_center_review || {};
  const dashboard = review.dashboard || {};
  const traces = Array.isArray(dashboard.traces) ? dashboard.traces : (status.recent_traces || []);
  const selected = dashboard.selected_trace || null;
  const filters = review.filters || {};
  const traceButtons = traces.slice(0, 12).map((trace) => {
    const active = selected?.trace_id === trace.trace_id || review.selectedTraceId === trace.trace_id;
    const safety = trace.safety_guard || {};
    const label = `${trace.controller || 'controller'} · ${trace.intent || 'intent'} · ${trace.context_count || 0} ctx · ${trace.prompt_contract_id || 'contract'}`;
    const sub = `${trace.status || 'recorded'} · ${trace.created_at || ''}${safety.rejected_count ? ` · blocked ${safety.rejected_count}` : ''}`;
    return `<button type="button" class="neo-ui-record-card ${active ? 'selected' : ''}" onclick="selectControlCenterReviewTrace('${escapeAttr(trace.trace_id)}')"><strong>${escapeHtml(label)}</strong><span>${escapeHtml(sub)}</span><small>${escapeHtml(trace.user_preview || trace.trace_id || '')}</small></button>`;
  }).join('');
  const selectedContext = selected?.selected_context || {};
  const selectedItems = Array.isArray(selectedContext.items) ? selectedContext.items : [];
  const contextLines = selectedItems.slice(0, 8).map((item) => `${item.memory_type || 'memory'} · ${item.title || item.fragment_id || ''} · score ${item.score ?? 'n/a'} · ${item.trust_level || 'trust?'}`);
  const related = selected?.related || {};
  const writebacks = Array.isArray(related.writebacks) ? related.writebacks : [];
  const violations = Array.isArray(related.safety_violations) ? related.safety_violations : [];
  const retrievalAccess = Array.isArray(related.retrieval_access) ? related.retrieval_access : [];
  const hints = Array.isArray(selected?.review_hints) ? selected.review_hints : [];
  const hintLines = hints.map((hint) => `${hint.level || 'info'} · ${hint.message || ''}`);
  const selectedBody = selected ? `${NeoUI.badgeRow([selected.controller, selected.surface, selected.intent, selected.prompt_contract_id, selected.status])}
    ${NeoUI.metaList([
      `Trace: ${selected.trace_id}`,
      `Project: ${selected.project_id || 'none'}`,
      `Scope: ${selected.scope_id || 'none'}`,
      `Backend: ${selected.backend_profile_id || 'not set'}`,
      `Selection: ${selectedContext.selection_mode || 'unknown'} · ${(selectedContext.item_count ?? selectedItems.length) || 0} item(s)`,
      `Retrieval trace: ${selectedContext.retrieval_trace_id || 'none'}`,
    ])}
    ${NeoUI.card({ title: 'Review hints', description: 'What the cockpit thinks you should inspect first.', body: NeoUI.metaList(hintLines) })}
    ${NeoUI.card({ title: 'Selected context', description: 'The exact compact memory context selected by Control Center after retrieval/rerank/safety.', body: contextLines.length ? NeoUI.metaList(contextLines) : NeoUI.emptyState('No selected context reached the prompt.', 'This is a likely cause of generic or hallucinated answers.') })}
    ${NeoUI.card({ title: 'Retrieval diagnostics', description: 'Related retrieval access records and reranker trace linkage.', body: retrievalAccess.length ? NeoUI.metaList(retrievalAccess.slice(0, 6).map((item) => `${item.consumer || 'consumer'} · ${item.query || 'query'} · ${(item.result_ids || []).length} result(s) · ${item.created_at || ''}`)) : NeoUI.emptyState('No related retrieval access records found.') })}
    ${NeoUI.card({ title: 'Safety guard', description: 'Sandbox/cross-scope blocks related to this trace.', badge: NeoUI.statusBadge(violations.length ? 'needs review' : 'ready'), body: violations.length ? NeoUI.metaList(violations.slice(0, 6).map((item) => `${item.severity || 'warn'} · ${item.check_type || 'check'} · ${item.message || ''}`)) : NeoUI.emptyState('No related safety violations.') })}
    ${NeoUI.card({ title: 'Prompt contract + validation', description: 'The behavior contract selected before backend generation.', body: `${NeoUI.metaList([`Contract: ${selected.prompt_contract_id || 'none'}`, `Validation: ${selected.validation?.status || 'planned'}`, `Checks: ${(selected.validation?.checks || []).join(', ') || 'none'}`])}${state.detailMode === 'expert' ? NeoUI.codeBlock(selected.prompt_contract || {}, 'admin-control-center-review-contract') : ''}` })}
    ${NeoUI.card({ title: 'Writeback candidates', description: 'Memory evolution candidates linked to this trace.', body: writebacks.length ? NeoUI.metaList(writebacks.slice(0, 8).map((item) => `${item.status || 'queued'} · ${item.risk_level || 'risk'} · ${item.memory_type || 'memory'} · ${item.title || item.writeback_id}`)) : NeoUI.emptyState('No writeback candidates linked yet.') })}
    ${NeoUI.card({ title: 'Review decision', description: 'Record an Admin review note without mutating memory content.', actions: `<button type="button" class="neo-btn" onclick="reviewControlCenterTrace('good')">Mark good</button><button type="button" class="neo-btn" onclick="reviewControlCenterTrace('needs_fix')">Needs fix</button><button type="button" class="neo-btn" onclick="reviewControlCenterTrace('scope_issue')">Scope issue</button><button type="button" class="neo-btn" onclick="reviewControlCenterTrace('memory_gap')">Memory gap</button>`, body: selected.latest_review ? NeoUI.metaList([`Latest review: ${selected.latest_review.decision || 'reviewed'}`, `Note: ${selected.latest_review.note || ''}`, `At: ${selected.latest_review.created_at || ''}`]) : NeoUI.emptyState('No review recorded for this trace.') })}` : NeoUI.emptyState('No Control Center trace selected.', 'Run Assistant or Roleplay, then refresh the cockpit.');
  return `${NeoUI.card({
    title: 'Control Center Trace Review Cockpit',
    description: 'Inspect what Control Center selected, blocked, contracted, and planned before backend generation.',
    badge: NeoUI.statusBadge(status.status || dashboard.status || 'ready'),
    body: `${NeoUI.badgeRow([`traces ${status.trace_count || dashboard.summary?.trace_count || traces.length || 0}`, `reviews ${status.review_count || 0}`, `open safety ${status.open_safety_violations || 0}`, `writebacks ${status.writeback_count || 0}`])}<div class="neo-ui-field-grid"><div><label>Controller</label><select id="neo-cc-review-controller"><option value="">All</option><option value="assistant" ${filters.controller === 'assistant' ? 'selected' : ''}>Assistant</option><option value="roleplay" ${filters.controller === 'roleplay' ? 'selected' : ''}>Roleplay</option></select></div><div><label>Surface</label><input id="neo-cc-review-surface" value="${escapeAttr(filters.surface || '')}" placeholder="assistant / roleplay / image"></div><div><label>Search traces</label><input id="neo-cc-review-query" value="${escapeAttr(filters.query || '')}" placeholder="intent, contract, user text"></div></div>`,
    actions: '<button type="button" class="neo-btn primary" onclick="reloadControlCenterReview()">Refresh cockpit</button>'
  })}<div class="neo-ui-grid two"><div>${NeoUI.card({ title: 'Trace queue', description: 'Latest Control Center traces. Select one to inspect the full route.', body: traceButtons || NeoUI.emptyState('No traces yet.', 'Run Assistant or Roleplay to create traces.') })}</div><div>${selectedBody}</div></div>`;
}

async function reloadControlCenterReview() {
  if (await neoTryAdminAction('reloadControlCenterReview')) return;
  const controller = document.getElementById('neo-cc-review-controller')?.value || state.controlCenterReview?.filters?.controller || '';
  const surface = document.getElementById('neo-cc-review-surface')?.value || state.controlCenterReview?.filters?.surface || '';
  const query = document.getElementById('neo-cc-review-query')?.value || state.controlCenterReview?.filters?.query || '';
  state.controlCenterReview.filters = { controller, surface, query };
  state.controlCenterReview.status = await loadJson('/api/control-center/review/status', state.controlCenterReview.status || null);
  state.assistantBrain.status = await loadJson('/api/assistant/brain/status', state.assistantBrain.status || null);
  state.surfaceModules.status = await loadJson('/api/surfaces/modules/status', state.surfaceModules.status || null);
  state.modernUi.status = await loadJson('/api/ui/modern/status', state.modernUi.status || null);
  const response = await fetch('/api/control-center/review/dashboard', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ controller, surface, query, trace_id: state.controlCenterReview.selectedTraceId || '', limit: 20 }) });
  if (!response.ok) { window.alert(`Control Center cockpit refresh failed: ${await response.text()}`); return; }
  state.controlCenterReview.dashboard = await response.json();
  if (state.controlCenterReview.dashboard?.selected_trace?.trace_id) state.controlCenterReview.selectedTraceId = state.controlCenterReview.dashboard.selected_trace.trace_id;
  render();
}

async function selectControlCenterReviewTrace(traceId) {
  if (await neoTryAdminAction('selectControlCenterReviewTrace', { traceId })) return;
  state.controlCenterReview.selectedTraceId = traceId || '';
  await reloadControlCenterReview();
}

async function reviewControlCenterTrace(decision) {
  if (await neoTryAdminAction('reviewControlCenterTrace', { decision })) return;
  const traceId = state.controlCenterReview?.selectedTraceId || state.controlCenterReview?.dashboard?.selected_trace?.trace_id || '';
  if (!traceId) { window.alert('No Control Center trace selected.'); return; }
  const note = window.prompt('Review note for this trace?', decision || 'reviewed') || '';
  const response = await fetch('/api/control-center/review/decision', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ trace_id: traceId, decision, note }) });
  if (!response.ok) { window.alert(`Trace review failed: ${await response.text()}`); return; }
  state.controlCenterReview.lastReview = await response.json();
  await reloadControlCenterReview();
}

function adminMemoryHtml(center) {
  const memory = center?.memory || state.memory || {};
  const overview = center?.overview || {};
  return `${NeoUI.card({ title: 'Memory service', description: 'Central memory service status and optional semantic layers.', badge: NeoUI.statusBadge(memory.status || memory.mode || 'available'), body: `${NeoUI.badgeRow(overview.memory_namespaces || [])}${state.detailMode === 'expert' ? NeoUI.codeBlock(memory, 'admin-control-code') : ''}` })}`;
}


function adminMemoryStats(center) {
  const memory = center?.memory || state.memory || {};
  const overview = center?.overview || {};
  const inspector = state.memoryInspector || {};
  const conflicts = state.memoryConflicts || {};
  const consolidation = state.memoryConsolidation || {};
  const retention = state.memoryRetention || {};
  const diagnostics = state.memoryDiagnostics || {};
  const namespaces = overview.memory_namespaces || memory.namespaces || [];
  const chunks = inspector.results?.total ?? inspector.results?.chunks?.length ?? 0;
  const conflictsCount = conflicts.groups?.total ?? conflicts.groups?.groups?.length ?? 0;
  const canonCount = conflicts.canon?.total ?? conflicts.canon?.items?.length ?? 0;
  const consolidationGroups = consolidation.plan?.total ?? consolidation.plan?.groups?.length ?? 0;
  const retentionGroups = retention.plan?.total ?? retention.plan?.items?.length ?? 0;
  const diagnosticWarnings = diagnostics.warnings?.length ?? diagnostics.warning_count ?? 0;
  const status = memory.status || memory.mode || diagnostics.status || 'available';
  return { memory, overview, namespaces, chunks, conflictsCount, canonCount, consolidationGroups, retentionGroups, diagnosticWarnings, status };
}

function adminMemoryOverviewPanel(center) {
  const stats = adminMemoryStats(center);
  const chips = [
    `Status ${stats.status}`,
    `Namespaces ${stats.namespaces.length}`,
    `Inspector ${stats.chunks}`,
    `Conflicts ${stats.conflictsCount}`,
    `Canon ${stats.canonCount}`,
    `Consolidation ${stats.consolidationGroups}`,
    `Retention ${stats.retentionGroups}`,
    `Warnings ${stats.diagnosticWarnings}`,
  ];
  const namespaceBody = stats.namespaces.length ? NeoUI.badgeRow(stats.namespaces) : NeoUI.emptyState('No memory namespaces reported.', 'Refresh Admin or open Diagnostics if the memory status endpoint is unavailable.');
  const modeRows = [
    `Memory mode: ${stats.memory.mode || stats.memory.status || 'available'}`,
    `SQLite/vector internals live in Admin → Memory Engine`,
    `Records, review, policies, conflicts, consolidation, and retention live here`,
  ];
  return `<div class="neo-admin-smart-split-overview neo-admin-memory-overview-left">${NeoUI.card({
    title: 'Memory overview',
    description: 'Admin summary for memory records, review workflows, policy controls, and lifecycle tasks. Engine internals stay under Memory Engine.',
    badge: NeoUI.statusBadge(stats.status),
    body: `${NeoUI.badgeRow(chips)}${NeoUI.metaList(modeRows)}`,
    actions: `<button type="button" class="neo-btn primary" onclick="reloadAdminControlCenter()">Refresh Memory</button><button type="button" class="neo-btn secondary" onclick="setAdminMemoryChildTab('diagnostics')">Open Diagnostics</button>`
  })}${NeoUI.card({ title: 'Memory namespaces', description: 'Namespaces reported by the control center/memory status payload.', body: namespaceBody })}${NeoUI.card({ title: 'Smart split boundary', description: 'This tab manages memory content and governance. Use Memory Engine for SQLite, vector, embeddings, reranker, indexes, and source plumbing.', body: NeoUI.metaList(['Memory = records, review, policies, conflicts, consolidation, retention, citations', 'Memory Engine = SQLite, vector store, embeddings, reranker, indexes, retrieval profiles']) })}</div>`;
}

const ADMIN_MEMORY_CHILD_TABS = [
  { id: 'inspector', label: 'Inspector', description: 'Inspect memory chunks, traces, source lines, and provenance.' },
  { id: 'search', label: 'Search + Citations', description: 'Search memory with source-grounded citation previews.' },
  { id: 'policies', label: 'Policies', description: 'Review write, approval, decay, and surface memory policies.' },
  { id: 'conflicts', label: 'Conflicts + Canon', description: 'Resolve canon/draft collisions and promote reviewed memory.' },
  { id: 'consolidation', label: 'Consolidation', description: 'Plan and run memory consolidation/summarization.' },
  { id: 'retention', label: 'Retention', description: 'Plan retention, decay, archival, and lifecycle automation.' },
  { id: 'diagnostics', label: 'Diagnostics', description: 'Memory health, route, and runtime diagnostics for records/governance.' },
];

function adminMemoryActiveChildTab() {
  const allowed = ADMIN_MEMORY_CHILD_TABS.map((tab) => tab.id);
  const active = allowed.includes(state.adminMemoryChildTab) ? state.adminMemoryChildTab : 'inspector';
  state.adminMemoryChildTab = active;
  return active;
}

function setAdminMemoryChildTab(tabId) {
  const allowed = ADMIN_MEMORY_CHILD_TABS.map((tab) => tab.id);
  state.adminMemoryChildTab = allowed.includes(tabId) ? tabId : 'inspector';
  render();
}

function adminMemoryChildTabs() {
  const active = adminMemoryActiveChildTab();
  return `<nav class="neo-subtabs neo-admin-memory-child-tabs" aria-label="Admin Memory child tabs">${ADMIN_MEMORY_CHILD_TABS.map((tab) => `<button type="button" class="${tab.id === active ? 'active' : ''}" title="${escapeAttr(tab.description)}" onclick="setAdminMemoryChildTab('${escapeAttr(tab.id)}')">${escapeHtml(tab.label)}</button>`).join('')}</nav>`;
}

function adminMemoryChildTabBody(center) {
  const active = adminMemoryActiveChildTab();
  if (active === 'inspector') return adminMemoryInspectorHtml(center);
  if (active === 'search') return adminMemorySearchUxHtml(center);
  if (active === 'policies') return adminMemoryPoliciesHtml(center);
  if (active === 'conflicts') return adminMemoryConflictResolverHtml(center);
  if (active === 'consolidation') return adminMemoryConsolidationHtml(center);
  if (active === 'retention') return adminMemoryRetentionHtml(center);
  if (active === 'diagnostics') return adminMemoryDiagnosticsHtml(center);
  return adminMemoryInspectorHtml(center);
}

function adminMemoryPanel(center) {
  return `<div class="neo-admin-memory-shell neo-admin-smart-split-right" data-child-tab="${escapeAttr(adminMemoryActiveChildTab())}">${adminMemoryChildTabs()}<div class="neo-admin-memory-child-panel">${adminMemoryChildTabBody(center)}</div></div>`;
}

function backendProviderName(providerId) {
  const providers = state.providers?.providers || [];
  const match = providers.find((item) => item.provider_id === providerId || item.id === providerId);
  return match?.display_name || providerId || 'provider';
}

function backendSurfaceProfiles(surfaceId) {
  const aliases = {
    text: ['text', 'prompt_captioning', 'assistant', 'roleplay'],
    image: ['image'],
    video: ['video'],
    voice: ['voice'],
    audio: ['audio'],
  };
  const allowed = new Set(aliases[surfaceId] || [surfaceId]);
  return (state.backendProfiles?.profiles || []).filter((profile) => allowed.has(profile.surface));
}

function adminBackendsStats(center) {
  const providers = center?.backends?.providers || state.providers?.providers || [];
  const profiles = center?.backends?.profiles || state.backendProfiles?.profiles || [];
  const defaults = state.backendProfiles?.defaults || {};
  const surfaces = ['text', 'image', 'video', 'voice', 'audio'];
  const surfaceCounts = Object.fromEntries(surfaces.map((surface) => [surface, backendSurfaceProfiles(surface).length]));
  const enabled = profiles.filter((profile) => profile.enabled !== false).length;
  const disabled = Math.max(profiles.length - enabled, 0);
  const defaultsList = surfaces.map((surface) => `${humanize(surface)}: ${defaults[surface] || 'none'}`);
  return { providers, profiles, defaults, surfaces, surfaceCounts, enabled, disabled, defaultsList };
}

function adminBackendsHtml(center) {
  const stats = adminBackendsStats(center);
  const surfaceChips = stats.surfaces.map((surface) => `${humanize(surface)} ${stats.surfaceCounts[surface] || 0}`);
  const providerLabels = stats.providers.map((item) => item.display_name || item.provider_id || item.id).filter(Boolean);
  const profileRows = stats.profiles.slice(0, 12).map((item) => `${humanize(item.surface || 'global')} · ${item.display_name || item.profile_id || 'profile'} · ${backendProviderName(item.provider_id)}`);
  return `${NeoUI.card({
    title: 'Backend overview',
    description: 'Admin summary for all runtime backend profiles. Detailed profile editing lives in the child tabs on the right.',
    badge: NeoUI.statusBadge(stats.profiles.length ? 'ready' : 'needs setup'),
    body: `${NeoUI.badgeRow([`Providers ${stats.providers.length}`, `Profiles ${stats.profiles.length}`, `Enabled ${stats.enabled}`, `Disabled ${stats.disabled}`, ...surfaceChips])}${NeoUI.metaList(stats.defaultsList)}`,
    actions: `<button type="button" class="neo-btn primary" onclick="reloadAdminControlCenter()">Refresh Backends</button><button type="button" class="neo-btn secondary" onclick="setAdminBackendsChildTab('diagnostics')">Open Diagnostics</button>`
  })}${NeoUI.card({ title: 'Provider registry', description: 'Registered provider families available to Neo backend profiles.', body: providerLabels.length ? NeoUI.badgeRow(providerLabels) : NeoUI.emptyState('No providers registered.') })}${NeoUI.card({ title: 'Recent backend profiles', description: 'Compact profile list. Use the right-side child tabs for editing.', body: profileRows.length ? NeoUI.metaList(profileRows) : NeoUI.emptyState('No backend profiles saved yet.') })}`;
}

