function adminExtensionsDiagnosticsManifestCard(center = null) {
  const diag = adminExtensionsDiagnosticsPayload(center);
  const issues = [];
  diag.manifestErrors.forEach((record) => issues.push(`${record.manifest?.id || record.id}: errors · ${(record.errors || []).join(' · ')}`));
  diag.manifestWarnings.forEach((record) => issues.push(`${record.manifest?.id || record.id}: warnings · ${(record.warnings || []).join(' · ')}`));
  diag.missingMountSlots.forEach((record) => issues.push(`${record.manifest?.id || record.id}: no mount_slots / mount_targets declared`));
  diag.missingBackendModules.forEach((record) => issues.push(`${record.manifest?.id || record.id}: no backend module declared`));
  return NeoUI.card({
    title: 'Manifest health',
    description: 'Manifest parse, dependency, mount-slot, and backend declaration visibility across loaded extensions.',
    badge: NeoUI.statusBadge(issues.length ? 'review' : 'ready'),
    body: issues.length ? NeoUI.metaList(issues) : NeoUI.emptyState('No manifest issues detected.', 'Loaded manifests have no recorded errors or warnings.'),
    actions: '<button type="button" class="neo-btn secondary" onclick="setAdminExtensionsChildTab(\'image\')">Open Image Extensions</button>'
  });
}

