  state.extensions = await loadJson('/api/extensions', state.extensions || { extensions: [] });
  state.memory = await loadJson('/api/memory/status', state.memory || null);
  state.memoryDiagnostics = await loadJson('/api/memory/diagnostics', state.memoryDiagnostics || null);
  state.memoryObservability = await loadJson('/api/memory/observability/status', state.memoryObservability || null);
  state.controlCenterReview.status = await loadJson('/api/control-center/review/status', state.controlCenterReview.status || null);
  state.assistantBrain.status = await loadJson('/api/assistant/brain/status', state.assistantBrain.status || null);
  state.surfaceModules.status = await loadJson('/api/surfaces/modules/status', state.surfaceModules.status || null);
  state.modernUi.status = await loadJson('/api/ui/modern/status', state.modernUi.status || null);
  state.operator.status = await loadJson('/api/operator/status', state.operator.status || null);
  state.voiceInput.status = await loadJson('/api/voice/input/status', state.voiceInput.status || null);
  state.internetAccess.status = await loadJson('/api/internet/access/status', state.internetAccess.status || null);
