function adminDiagnosticsStats(center) {
  const surfaceArchitecture = state.surfaceModules?.audit || state.surfaceModules?.status || center?.surface_module_architecture || {};
  const surfaceStatus = state.surfaceStatus?.audit || state.surfaceStatus?.status || center?.surface_status || center?.surface_module_status || {};
  const modernUi = state.modernUi?.audit?.modern_ui || state.modernUi?.status || center?.modern_ui || {};
  const memoryObservability = state.memoryObservability || center?.memory_observability || {};
  const runtime = center?.runtime_hardening || state.runtimeHardening || {};
  const release = center?.release_candidate || state.releaseCandidate || {};
  const controls = center?.surface_controls || center?.surface_map || center?.admin?.surface_controls || {};
  const runtimeChecks = Array.isArray(runtime.checks) ? runtime.checks : [];
  const releaseSummary = release.summary || {};
  const statusSummary = surfaceStatus.summary || surfaceStatus.audit_summary || {};
  const uiSummary = modernUi.summary || modernUi;
  const architectureSummary = surfaceArchitecture.summary || surfaceArchitecture;
  const warnings = [
    Number(runtime.warning_count || 0),
    Number(runtime.required_failure_count || 0),
    Number(releaseSummary.failure_count || 0),
    Number(releaseSummary.warning_count || 0),
  ].reduce((total, value) => total + (Number.isFinite(value) ? value : 0), 0);
  return { surfaceArchitecture, surfaceStatus, modernUi, memoryObservability, runtime, release, controls, runtimeChecks, releaseSummary, statusSummary, uiSummary, architectureSummary, warnings };
}

