function adminModelsPacksBody() {
  const packsPayload = ensureAdminModelsState().packs || {};
  const packs = Array.isArray(packsPayload.packs) ? packsPayload.packs : [];
  const body = packs.map((pack) => NeoUI.card({
    title: pack.display_name || pack.id,
    description: pack.description || '',
    badge: NeoUI.statusBadge(pack.status || 'pack'),
    body: `${NeoUI.badgeRow([pack.category, pack.base_model, ...(pack.backend_targets || [])].filter(Boolean))}${NeoUI.metaList((pack.items || []).map((item) => `${item.required ? 'Required' : 'Optional'} · ${item.catalog_id}${item.variant_required ? ' · variant required' : ''}`), { code: false })}`,
  })).join('');
  return `<div class="neo-admin-models-packs">${body || NeoUI.emptyState('No recommended packs loaded yet.', 'Refresh the Model Guide.')}</div>`;
}

function adminModelsWorkspacesBody() {
  const workspacePayload = ensureAdminModelsState().workspaces || {};
  const workspaces = Array.isArray(workspacePayload.workspaces) ? workspacePayload.workspaces : [];
  const body = workspaces.map((workspace) => NeoUI.card({
    title: workspace.display_name || workspace.id,
    description: workspace.description || '',
    badge: NeoUI.statusBadge(workspace.status || 'workspace'),
    body: `${NeoUI.badgeRow([workspace.surface, workspace.backend, workspace.base_model].filter(Boolean))}${NeoUI.metaList([`Guide filter: ${JSON.stringify(workspace.guide_filter || {})}`, `Packs: ${(workspace.model_pack_ids || []).join(', ') || 'none'}`], { code: false })}`,
  })).join('');
  return `<div class="neo-admin-models-workspaces">${body || NeoUI.emptyState('No workspace requirements loaded yet.', 'Refresh the Model Guide.')}</div>`;
}

function adminModelsDownloadsBody() {
  const jobsPayload = ensureAdminModelsState().downloadJobs || {};
  const jobs = Array.isArray(jobsPayload.jobs) ? jobsPayload.jobs : [];
  const plans = ensureAdminModelsState().downloadPlans || {};
  const planCards = Object.entries(plans).map(([catalogId, plan]) => NeoUI.card({
    title: `Plan · ${catalogId}`,
    description: plan.ok ? `${plan.file?.filename || 'file'} → ${plan.target?.final_path || plan.target?.target_folder || 'target'}` : 'Download plan needs attention.',
    badge: NeoUI.statusBadge(plan.status || (plan.ok ? 'ready' : 'needs attention')),
    body: `${plan.errors?.length ? `<p class="neo-error-text">${escapeHtml(plan.errors.join(' · '))}</p>` : ''}${NeoUI.metaList([`Provider: ${plan.source?.provider || 'unknown'}`, `Backend: ${plan.target?.backend || 'unknown'}`, `Target: ${plan.target?.final_path || 'not resolved'}`], { code: false })}`,
    actions: plan.ok ? `<button type="button" class="neo-btn primary" onclick="startAdminModelDownload('${escapeAttr(catalogId)}')">Download</button><button type="button" class="neo-btn" onclick="startAdminModelDryRun('${escapeAttr(catalogId)}')">Dry-run job</button>` : '',
  })).join('');
  const jobRows = jobs.map((job) => {
    const progress = job.progress || {};
    const percent = Number(progress.percent ?? job.progress_percent ?? 0);
    const downloaded = adminModelFormatBytes(progress.bytes_downloaded);
    const total = adminModelFormatBytes(progress.size_bytes || job.file?.size_bytes);
    const speed = adminModelFormatBytes(progress.speed_bytes_per_second);
    const eta = adminModelFormatDuration(progress.eta_seconds);
    const elapsed = adminModelFormatDuration(progress.elapsed_seconds || job.metrics?.elapsed_seconds);
    const active = ['queued', 'downloading', 'cancelling'].includes(String(job.status || '').toLowerCase());
    const cancelAction = active ? `<button type="button" class="neo-btn small danger" onclick="cancelAdminModelDownload('${escapeAttr(job.job_id)}')">Cancel</button>` : '';
    return `<article class="neo-ui-record-card"><div class="neo-ui-section-head"><div><strong>${escapeHtml(job.display_name || job.catalog_id || job.job_id)}</strong><p>${escapeHtml(job.paths?.final_path || job.source?.download_url || '')}</p></div>${NeoUI.statusBadge(job.status || 'job')}</div>${NeoUI.badgeRow([job.provider, job.dry_run ? 'dry-run' : '', percent ? `${percent}%` : '', speed ? `${speed}/s` : '', eta ? `ETA ${eta}` : ''].filter(Boolean))}<progress value="${escapeAttr(String(Math.min(Math.max(percent, 0), 100)))}" max="100" style="width:100%;height:12px;"></progress>${NeoUI.metaList([downloaded || total ? `Progress: ${downloaded || '0 B'}${total ? ` / ${total}` : ''}` : '', speed ? `Speed: ${speed}/s` : '', eta ? `Estimated time left: ${eta}` : '', elapsed ? `Elapsed: ${elapsed}` : ''].filter(Boolean), { code: false })}<div class="neo-ui-toolbar">${cancelAction}</div></article>`;
  }).join('');
  return `<div class="neo-admin-models-downloads">${NeoUI.card({ title: 'Download jobs', description: 'Download manager state with progress, speed, ETA, and cancel support.', badge: NeoUI.statusBadge(jobsPayload.status || 'ready'), body: NeoUI.badgeRow([`Jobs ${jobs.length}`, `Active ${jobsPayload.summary?.active_count || 0}`, `Completed ${jobsPayload.summary?.completed_count || 0}`, `Failed ${jobsPayload.summary?.failed_count || 0}`]), actions: '<button type="button" class="neo-btn primary" onclick="refreshAdminModelDownloadJobs()">Refresh jobs</button>' })}${planCards || NeoUI.emptyState('No download plans yet.', 'Open Sources and click Plan.')}${jobRows ? `<div class="neo-ui-record-list">${jobRows}</div>` : ''}</div>`;
}

function adminModelsRawBody() {
  const models = ensureAdminModelsState();
  if (state.detailMode !== 'expert') return NeoUI.emptyState('Raw payloads are hidden in Guided/Compact mode.', 'Switch the top-right detail mode to Expert.');
  return `${NeoUI.card({ title: 'Catalog payload', body: NeoUI.codeBlock(models.catalog || {}) })}${NeoUI.card({ title: 'Paths payload', body: NeoUI.codeBlock(models.paths || {}) })}${NeoUI.card({ title: 'Installed payload', body: NeoUI.codeBlock(models.installed || {}) })}`;
}

function adminModelsChildTabBody() {
  const active = adminModelsActiveChildTab();
  if (active === 'sources') return adminModelsSourcesBody();
  if (active === 'installed') return adminModelsInstalledBody();
  if (active === 'paths') return adminModelsPathsBody();
  if (active === 'packs') return adminModelsPacksBody();
  if (active === 'workspaces') return adminModelsWorkspacesBody();
  if (active === 'downloads') return adminModelsDownloadsBody();
  if (active === 'raw') return adminModelsRawBody();
  return adminModelsSourcesBody();
}

function adminModelsPanel() {
  const models = ensureAdminModelsState();
  if (!models.catalog && !state.adminModelsLoading) setTimeout(() => reloadAdminModelsState(), 0);
  if (state.adminModelsLoading && !models.catalog) return NeoUI.card({ title: 'Loading Models…', description: 'Reading public model manifests and local model path state.', body: NeoUI.emptyState('Loading Admin Models.', 'This should only take a moment.') });
  return `<div class="neo-admin-models-shell" data-child-tab="${escapeAttr(adminModelsActiveChildTab())}">${adminModelsChildTabs()}<div class="neo-admin-models-child-panel">${models.catalog ? adminModelsChildTabBody() : NeoUI.emptyState('Models are not loaded yet.', 'Click Refresh Models.', 'compact')}</div></div>`;
}


function renderAdminPanels(subtab) {
  const columns = beginTwoColumnWorkspace();
  const admin = state.admin || {};
  const id = subtab?.subtab_id || 'overview';
  const center = adminControlCenter();
  const global = admin.global || {};

  if (id === 'overview' || id === 'system' || id === 'global') {
    columns.left.appendChild(panel('Dashboard Overview', adminDashboardOverviewPanel(center), true, 'ready'));
    columns.right.appendChild(panel('Dashboard Tools', adminDashboardPanel(center), true, 'ready'));
    return;
  }

  if (id === 'backends') {
    columns.left.appendChild(panel('Backends Overview', adminBackendsOverviewPanel(center), true, 'ready'));
    columns.right.appendChild(panel('Backend Profile Tools', adminBackendsPanel(center), true, 'backend-profiles'));
    return;
  }

  if (id === 'models') {
    columns.left.appendChild(panel('Models Overview', adminModelsOverviewPanel(), true, 'models'));
    columns.right.appendChild(panel('Model Guide Tools', adminModelsPanel(), true, 'models'));
    return;
  }

  if (id === 'extensions') {
    columns.left.appendChild(panel('Extensions Overview', adminExtensionsOverviewPanel(center), true, 'ready'));
    columns.right.appendChild(panel('Extension Tools', adminExtensionsPanel(center), true, 'ready'));
    return;
  }

  if (id === 'memory') {
    columns.left.appendChild(panel('Memory Overview', adminMemoryOverviewPanel(center), true, 'ready'));
    columns.right.appendChild(panel('Memory Tools', adminMemoryPanel(center), true, 'ready'));
    return;
  }

  if (id === 'engine') {
    renderAdminEnginePanels(columns);
    return;
  }


  if (id === 'projects') {
    columns.left.appendChild(panel('Projects Overview', adminProjectsOverviewPanel(center), true, 'ready'));
    columns.right.appendChild(panel('Project Tools', adminProjectsPanel(center), true, 'ready'));
    return;
  }

  if (id === 'assistant_operator') {
    columns.left.appendChild(panel('Assistant / Operator Overview', adminAssistantOperatorOverviewPanel(center), true, 'ready'));
    columns.right.appendChild(panel('Assistant / Operator Tools', adminAssistantOperatorPanel(center), true, 'ready'));
    return;
  }

  if (id === 'diagnostics') {
    columns.left.appendChild(panel('Diagnostics Overview', adminDiagnosticsOverviewPanel(center), true, 'ready'));
    columns.right.appendChild(panel('Diagnostics Tools', adminDiagnosticsPanel(center), true, 'active'));
    return;
  }

  if (id === 'libraries') {
    columns.left.appendChild(panel('Libraries Overview', adminLibrariesOverviewPanel(center), true, 'ready'));
    columns.right.appendChild(panel('Library Tools', adminLibrariesPanel(center), true, 'ready'));
    return;
  }

  if (id === 'storage') {
    columns.left.appendChild(panel('Storage Overview', adminStorageOverviewPanel(center), true, 'ready'));
    columns.right.appendChild(panel('Storage Tools', adminStoragePanel(center), true, 'ready'));
    return;
  }

  if (id === 'health') {
    columns.left.appendChild(panel('Health Overview', adminHealthOverviewPanel(center), true, 'health'));
    columns.right.appendChild(panel('Health Tools', adminHealthPanel(center), true, 'ready'));
    return;
  }

  if (id === 'logs') {
    columns.left.appendChild(panel('Logs Overview', adminLogsOverviewPanel(center), true, 'logs'));
    columns.right.appendChild(panel('Log Tools', adminLogsPanel(center), true, 'ready'));
    return;
  }

  if (id === 'records') {
    columns.left.appendChild(panel('Records Overview', adminRecordsOverviewPanel(center), true, 'ready'));
    columns.right.appendChild(panel('Records Tools', adminRecordsPanel(center), true, 'ready'));
    return;
  }

  const surfaces = admin.surfaces || {};
  const surfaceAdmin = surfaces[id];
  if (!surfaceAdmin) {
    columns.left.appendChild(panel('Admin Section Setup', `<p>${subtab?.description || 'No control panel has been connected for this section yet.'}</p>`));
    columns.right.appendChild(panel('Admin Workspace', '<p>This section is ready for mapped controls from Admin configuration.</p>', false, 'muted'));
    return;
  }

  if (id === 'image') {
    columns.left.appendChild(panel('Image Backend Summary', adminSurfaceBackendSummary('image', 'Image'), false, 'ready'));
    columns.right.appendChild(panel('Image Extension Shortcuts', adminImageExtensionShortcutsBody(center), false, 'relocated'));
    return;
  }

  if (id === 'text') {
    columns.left.appendChild(panel('Text Backend Summary', adminTextBackendSummary(), false, 'ready'));
    columns.right.appendChild(panel('Text Extension Summary', adminSurfaceExtensionSummary('text', 'Text'), false, 'ready'));
  } else {
    columns.left.appendChild(panel(`${humanize(id)} Backend Summary`, adminSurfaceBackendSummary(id, humanize(id)), false, 'ready'));
    columns.right.appendChild(panel(`${humanize(id)} Extension Summary`, adminSurfaceExtensionSummary(id, humanize(id)), false, 'ready'));
  }
  if (id === 'video') {
    columns.right.appendChild(panel('Shared Node Manager', '<p class="neo-muted">Video workflows use the shared Comfy custom node manager under <strong>Admin › Extensions › Node Manager</strong>. No duplicate node manager is created here.</p>', false, 'muted'));
  }
}


function activeImageResultsCategory() {
  return state.imageResultsFilterCategory || 'all';
}

function imageResultImageUrl(file, item) {
  if (!file?.url) return '';
  const stamp = encodeURIComponent(item?.created_at || item?.result_id || Date.now());
  return `${file.url}${file.url.includes('?') ? '&' : '?'}v=${stamp}`;
}

function imageResultsFilterControls() {
  const settings = state.imageOutputSettings || {};
  const categories = Array.isArray(settings.categories) ? settings.categories : [];
  const activeCategory = activeImageResultsCategory();
  const sort = state.imageResultsSort || 'newest';
  const categoryOptions = ['all', ...categories].filter((item, index, arr) => item && arr.indexOf(item) === index);
  return `
    <div class="neo-results-filter-row">
      <label>Category
        <select id="imageResultsCategoryFilter">
          ${categoryOptions.map((item) => `<option value="${escapeAttr(item)}" ${item === activeCategory ? 'selected' : ''}>${escapeHtml(item === 'all' ? 'All categories' : item)}</option>`).join('')}
        </select>
      </label>
      <label>Date
        <select id="imageResultsSortFilter">
          <option value="newest" ${sort === 'newest' ? 'selected' : ''}>New to old</option>
          <option value="oldest" ${sort === 'oldest' ? 'selected' : ''}>Old to new</option>
        </select>
      </label>
    </div>`;
}

function activeSavedResultSummary() {
  const visibleResults = visibleImageSavedResults();
  return visibleResults[state.activeSavedResultIndex] || visibleResults[0] || null;
}

function visibleImageSavedResults() {
  const broken = new Set(state.imageBrokenResultIds || []);
  return (state.imageSavedResults || []).filter((item) => item?.result_id && !broken.has(item.result_id));
}

function basename(value) {
  const text = `${value || ''}`.replaceAll('\\', '/');
  return text.split('/').filter(Boolean).pop() || text || '';
}

function formatMaybeNumber(value) {
  const number = Number(value);
  return Number.isFinite(number) ? `${Math.round(number * 1000) / 1000}` : `${value ?? ''}`;
}

function outputRunTimingLabel(runTiming = {}) {
  if (!runTiming || typeof runTiming !== 'object') return '';
  const explicit = `${runTiming.elapsed_label || ''}`.trim();
  if (explicit) return explicit.startsWith('total ') || explicit.startsWith('elapsed ') ? explicit : `total ${explicit}`;
  const seconds = Number(runTiming.elapsed_seconds ?? 0);
  if (Number.isFinite(seconds) && seconds > 0) return `total ${formatVideoElapsed(seconds * 1000)}`;
  const ms = Number(runTiming.elapsed_ms ?? 0);
  if (Number.isFinite(ms) && ms > 0) return `total ${formatVideoElapsed(ms)}`;
  return '';
}


function outputCleanupSummary(metadata = {}) {
  const cleanup = metadata?.cleanup || metadata?.persistence?.asset_cleanup || {};
  if (!cleanup || typeof cleanup !== 'object') return { label: '', detail: '' };
  const outputs = Array.isArray(cleanup.backend_outputs_deleted) ? cleanup.backend_outputs_deleted.length : 0;
  const inputs = Array.isArray(cleanup.backend_inputs_deleted) ? cleanup.backend_inputs_deleted.length : 0;
  const skipped = Array.isArray(cleanup.skipped) ? cleanup.skipped.length : 0;
  const errors = Array.isArray(cleanup.errors) ? cleanup.errors.length : 0;
  if (!outputs && !inputs && !skipped && !errors) return { label: '', detail: '' };
  const label = `Cleanup · ${outputs} output / ${inputs} input`;
  const detail = `${outputs} backend output duplicate(s), ${inputs} Comfy input handoff(s), ${skipped} skipped, ${errors} error(s)`;
  return { label, detail };
}

function outputExtensionTimingLabel(item = {}) {
  const timing = item?.timing && typeof item.timing === 'object' ? item.timing : {};
  if (!timing || !Object.keys(timing).length) return '';
  const label = `${timing.elapsed_label || ''}`.trim();
  if (label) return label;
  const seconds = Number(timing.individual_elapsed_seconds ?? timing.run_elapsed_seconds ?? 0);
  return Number.isFinite(seconds) && seconds > 0 ? formatVideoElapsed(seconds * 1000) : '';
}

function metadataValue(path, fallback = '') {
  let current = state.activeSavedResultMetadata || {};
  for (const part of path) {
    if (!current || typeof current !== 'object') return fallback;
    current = current[part];
  }
  return current ?? fallback;
}

function resultPromptBlock(label, value, emptyText) {
  const text = `${value || ''}`.trim();
  return `
    <div class="neo-output-prompt-block">
      <div class="neo-output-prompt-label">${escapeHtml(label)}</div>
      <div class="neo-output-prompt-copy">${text ? escapeHtml(text) : `<span class="neo-muted">${escapeHtml(emptyText)}</span>`}</div>
    </div>`;
}

function resultMetaTile(label, value) {
  const text = value === undefined || value === null || value === '' ? '—' : `${value}`;
  return `<div class="neo-output-meta-tile"><span>${escapeHtml(label)}</span><strong>${escapeHtml(text)}</strong></div>`;
}



function outputExtensionDetailBlock(title = 'Extension', chips = [], body = '', attrs = '') {
  const cleanTitle = title || 'Extension';
  const chipHtml = outputChipRow((Array.isArray(chips) ? chips : []).filter(Boolean));
  return `
    <div class="neo-output-extension-detail" ${attrs || ''}>
      <div class="neo-output-extension-name">${escapeHtml(cleanTitle)}</div>
      ${chipHtml}
      ${body || ''}
    </div>`;
}

function outputValidationNoteList(notes = [], extraClass = '') {
  const list = (Array.isArray(notes) ? notes : []).filter(Boolean);
  if (!list.length) return '';
  const cls = extraClass ? ` ${extraClass}` : '';
  return `<div class="neo-output-chip-row neo-output-chip-row--notes${cls}">${list.map((note) => `<span class="neo-output-chip neo-output-chip--note">${escapeHtml(note)}</span>`).join('')}</div>`;
}


function styleStackOutputInspectorDetails(payloads = {}, patches = [], validation = []) {
  const block = payloads[STYLE_STACK_EXTENSION_ID];
  if (!block || typeof block !== 'object') return '';
  const inputs = block.inputs && typeof block.inputs === 'object' ? block.inputs : {};
  const assets = block.assets && typeof block.assets === 'object' ? block.assets : {};
  const params = block.params && typeof block.params === 'object' ? block.params : {};
  const metadata = block.metadata && typeof block.metadata === 'object' ? block.metadata : {};
  const styleNames = Array.isArray(metadata.style_names) && metadata.style_names.length
    ? metadata.style_names
    : (Array.isArray(assets.style_names) && assets.style_names.length ? assets.style_names : (Array.isArray(inputs.active_styles) ? inputs.active_styles : []));
  const missingNames = Array.isArray(metadata.missing_style_names) ? metadata.missing_style_names : [];
  const target = metadata.target || params.target || 'both';
  const applied = Boolean(metadata.applied || metadata.runtime_merge_status || styleNames.length || inputs.manual_positive || inputs.manual_negative);
  const status = block.enabled ? (applied ? 'Applied' : 'Enabled') : 'Disabled / gated';
  const positiveParts = metadata.positive_parts_added ?? '';
  const negativeParts = metadata.negative_parts_added ?? '';
  const manualPositive = Boolean(metadata.manual_positive || String(inputs.manual_positive || '').trim());
  const manualNegative = Boolean(metadata.manual_negative || String(inputs.manual_negative || '').trim());
  const chips = [
    `Status · ${status}`,
    `Styles · ${styleNames.length}`,
    `Target · ${target}`,
    positiveParts !== '' ? `Positive parts · ${formatMaybeNumber(positiveParts)}` : '',
    negativeParts !== '' ? `Negative parts · ${formatMaybeNumber(negativeParts)}` : '',
    manualPositive ? 'Manual positive' : '',
    manualNegative ? 'Manual negative' : '',
    'Prompt-only',
    metadata.provider_graph_mutation === false ? 'Provider-neutral' : '',
  ].filter(Boolean);
  const styleChips = styleNames.slice(0, 12).map((name, index) => `Style ${index + 1} · ${name}`);
  if (styleNames.length > 12) styleChips.push(`+${styleNames.length - 12} more styles`);
  const missingChips = missingNames.slice(0, 6).map((name) => `Missing · ${name}`);
  const positivePreview = sceneDirectorOutputPromptPreview(metadata.style_positive_prompt || '', 220);
  const negativePreview = sceneDirectorOutputPromptPreview(metadata.style_negative_prompt || '', 220);
  const promptRows = [
    positivePreview ? `<div class="neo-output-mini-note"><strong>Style positive:</strong> ${escapeHtml(positivePreview)}</div>` : '',
    negativePreview ? `<div class="neo-output-mini-note"><strong>Style negative:</strong> ${escapeHtml(negativePreview)}</div>` : '',
  ].filter(Boolean).join('');
  const validationNotes = validation
    .filter((item) => item && item.extension_id === STYLE_STACK_EXTENSION_ID && item.message)
    .slice(0, 3)
    .map((item) => item.message);
  const body = `${outputChipRow(styleChips, 'items')}${outputChipRow(missingChips, 'items')}${promptRows}${outputValidationNoteList(validationNotes)}`;
  return outputExtensionDetailBlock('Style Stack', chips, body, `data-extension-id="${STYLE_STACK_EXTENSION_ID}"`);
}

function cfgFixOutputInspectorDetails(payloads = {}, patches = [], validation = []) {
  const block = payloads[CFG_FIX_EXTENSION_ID];
  if (!block || typeof block !== 'object') return '';
  const params = block.params && typeof block.params === 'object' ? block.params : {};
  const metadata = block.metadata && typeof block.metadata === 'object' ? block.metadata : {};
  const patch = Array.isArray(patches) ? patches.find((item) => item && item.extension_id === CFG_FIX_EXTENSION_ID) : null;
  const applied = Boolean(patch?.applied);
  const status = block.enabled ? (applied ? 'Applied' : 'Validated') : 'Disabled / gated';
  const node = metadata.node || patch?.node || patch?.node_class || (params.mode === 'full' ? 'DynamicThresholdingFull' : 'DynamicThresholdingSimple');
  const reason = metadata.reason || patch?.reason || '';
  const chips = [
    `Status · ${status}`,
    params.preset ? `Preset · ${params.preset}` : '',
    params.mode ? `Mode · ${params.mode}` : '',
    params.mimic_scale !== undefined ? `Mimic · ${formatMaybeNumber(params.mimic_scale)}` : '',
    params.threshold_percentile !== undefined ? `Threshold · ${formatMaybeNumber(params.threshold_percentile)}` : '',
    node ? `Node · ${node}` : '',
    applied ? 'Workflow patched' : '',
  ].filter(Boolean);
  const validationNotes = validation
    .filter((item) => item && item.extension_id === CFG_FIX_EXTENSION_ID && item.message)
    .slice(0, 3)
    .map((item) => item.message);
  const body = `${reason ? `<div class="neo-output-mini-note">${escapeHtml(reason)}</div>` : ''}${outputValidationNoteList(validationNotes)}`;
  return outputExtensionDetailBlock('CFG Fix', chips, body, `data-extension-id="${CFG_FIX_EXTENSION_ID}"`);
}


function loraStackOutputInspectorDetails(payloads = {}, patches = [], validation = []) {
  const block = payloads[LORA_STACK_EXTENSION_ID];
  if (!block || typeof block !== 'object') return '';
  const params = block.params && typeof block.params === 'object' ? block.params : {};
  const metadata = block.metadata && typeof block.metadata === 'object' ? block.metadata : {};
  const rows = Array.isArray(params.loras) ? params.loras : [];
  const patch = Array.isArray(patches) ? patches.find((item) => item && item.extension_id === LORA_STACK_EXTENSION_ID) : null;
  const applied = Boolean(patch?.applied);
  const status = block.enabled ? (applied ? 'Applied' : 'Validated') : 'Disabled / gated';
  const reason = metadata.reason || patch?.reason || '';
  const node = patch?.node || patch?.node_class || (applied ? 'LoraLoader' : '');
  const chips = [
    `Status · ${status}`,
    `Rows · ${rows.length}`,
    applied ? `Patched · ${patch?.lora_count || rows.length}` : '',
    node ? `Node · ${node}` : '',
    patch?.route?.family ? `Family · ${patch.route.family}` : '',
    patch?.route?.loader ? `Loader · ${patch.route.loader}` : '',
  ].filter(Boolean);
  const rowChips = rows.slice(0, 6).flatMap((row, index) => {
    const name = row?.name;
    if (!name) return [];
    return [`LoRA ${index + 1} · ${basename(name)}`, row?.strength !== undefined ? `Strength · ${formatMaybeNumber(row.strength)}` : '', row?.target ? `Target · ${row.target}` : '', 'Region assignment · Scene Director'].filter(Boolean);
  });
  const validationNotes = validation
    .filter((item) => item && item.extension_id === LORA_STACK_EXTENSION_ID && item.message)
    .slice(0, 3)
    .map((item) => item.message);
  const body = `${reason ? `<div class="neo-output-mini-note">${escapeHtml(reason)}</div>` : ''}${outputChipRow(rowChips, 'items')}${outputValidationNoteList(validationNotes)}`;
  return outputExtensionDetailBlock('LoRA Stack', chips, body, `data-extension-id="${LORA_STACK_EXTENSION_ID}"`);
}


function embeddingsTiOutputInspectorDetails(payloads = {}, patches = [], validation = []) {
  const block = payloads[EMBEDDINGS_TI_EXTENSION_ID];
  if (!block || typeof block !== 'object') return '';
  const params = block.params && typeof block.params === 'object' ? block.params : {};
  const metadata = block.metadata && typeof block.metadata === 'object' ? block.metadata : {};
  const items = Array.isArray(params.items) ? params.items : [];
  const status = block.enabled ? 'Validated' : 'Disabled / gated';
  const reason = metadata.reason || '';
  const chips = [
    `Status · ${status}`,
    `Chips · ${items.length}`,
    metadata.family ? `Family · ${metadata.family}` : '',
    metadata.loader ? `Loader · ${metadata.loader}` : '',
  ].filter(Boolean);
  const tokenChips = items.slice(0, 6).flatMap((item, index) => {
    if (!item?.token) return [];
    return [`Token ${index + 1} · ${embeddingsTiTokenLabel(item.token, item.strength)}`, `Target · ${embeddingsTiTargetLabel(item.target)}`];
  });
  const validationNotes = validation
    .filter((item) => item && item.extension_id === EMBEDDINGS_TI_EXTENSION_ID && item.message)
    .slice(0, 3)
    .map((item) => item.message);
  const body = `${reason ? `<div class="neo-output-mini-note">${escapeHtml(reason)}</div>` : ''}${outputChipRow(tokenChips, 'items')}${outputValidationNoteList(validationNotes)}`;
  return outputExtensionDetailBlock('Embeddings / TI', chips, body, `data-extension-id="${EMBEDDINGS_TI_EXTENSION_ID}"`);
}


function controlNetOutputUnitChips(unit = {}, imageBucket = {}, mapBucket = {}) {
  const uid = unit.uid || 'unit';
  const source = mapBucket[uid] || imageBucket[uid] || mapBucket.default || imageBucket.default || '';
  const sourceLabel = typeof source === 'object' ? (source.filename || source.ref || source.path || source.asset_id || source.map_id || '') : source;
  const chips = [
    uid,
    unit.unit ? `Control · ${unit.unit}` : '',
    unit.preprocessor ? `Preprocessor · ${unit.preprocessor}` : 'Preprocessor · none',
    unit.model ? `Model · ${basename(unit.model)}` : '',
    unit.strength !== undefined ? `Strength · ${formatMaybeNumber(unit.strength)}` : '',
    unit.start_percent !== undefined ? `Start · ${formatMaybeNumber(unit.start_percent)}` : '',
    unit.end_percent !== undefined ? `End · ${formatMaybeNumber(unit.end_percent)}` : '',
    sourceLabel ? `Preview · ${basename(sourceLabel)}` : '',
  ].filter(Boolean);
  return `<div class="neo-output-extension-unit-card" data-extension-unit="${escapeAttr(uid)}">${outputChipRow(chips, 'unit')}</div>`;
}

function controlNetOutputInspectorDetails(payloads = {}, patches = [], validation = []) {
  const block = payloads[CONTROLNET_EXTENSION_ID];
  if (!block || typeof block !== 'object') return '';
  const inputs = block.inputs && typeof block.inputs === 'object' ? block.inputs : {};
  const assets = block.assets && typeof block.assets === 'object' ? block.assets : {};
  const metadata = block.metadata && typeof block.metadata === 'object' ? block.metadata : {};
  const units = Array.isArray(inputs.units) ? inputs.units : [];
  const activeUnits = units.filter((unit) => unit && unit.enabled !== false);
  const patch = Array.isArray(patches) ? patches.find((item) => item && item.extension_id === CONTROLNET_EXTENSION_ID) : null;
  const applied = Boolean(patch?.applied || patch?.mutated);
  const status = block.enabled ? (applied ? 'Applied' : 'Validated / gated') : 'Disabled / gated';
  const reason = metadata.reason || patch?.reason || '';
  const chips = [
    `Status · ${status}`,
    `Units · ${activeUnits.length}`,
    patch?.node || patch?.node_class ? `Node · ${patch.node || patch.node_class}` : '',
    patch?.route?.family ? `Family · ${patch.route.family}` : '',
    patch?.route?.loader ? `Loader · ${patch.route.loader}` : '',
    applied ? 'Workflow patched' : '',
  ].filter(Boolean);
  const imageBucket = assets.control_images && typeof assets.control_images === 'object' ? assets.control_images : {};
  const mapBucket = assets.generated_maps && typeof assets.generated_maps === 'object' ? assets.generated_maps : {};
  const unitRows = activeUnits.length
    ? `<div class="neo-output-extension-units">${activeUnits.slice(0, 6).map((unit) => controlNetOutputUnitChips(unit, imageBucket, mapBucket)).join('')}</div>`
    : '';
  const validationNotes = validation
    .filter((item) => item && item.extension_id === CONTROLNET_EXTENSION_ID && item.message)
    .slice(0, 3)
    .map((item) => item.message);
  const body = `${reason ? `<div class="neo-output-mini-note">${escapeHtml(reason)}</div>` : ''}${unitRows}${outputValidationNoteList(validationNotes)}`;
  return outputExtensionDetailBlock('ControlNet', chips, body, `data-extension-id="${CONTROLNET_EXTENSION_ID}"`);
}


function outputChipRow(chips = [], extraClass = '') {
  const clean = (Array.isArray(chips) ? chips : []).filter(Boolean);
  if (!clean.length) return '';
  const cls = extraClass ? ` neo-output-chip-row--${extraClass}` : '';
  return `<div class="neo-output-chip-row${cls}">${clean.map((chip) => `<span class="neo-output-chip">${escapeHtml(chip)}</span>`).join('')}</div>`;
}

function ipAdapterOutputUnitChips(unit = {}, imageBucket = {}) {
  const uid = unit.uid || 'unit';
  const refs = Array.isArray(imageBucket[uid]) ? imageBucket[uid] : [];
  const firstRef = refs[0] || {};
  const sourceLabel = typeof firstRef === 'object' ? (firstRef.filename || firstRef.ref || firstRef.path || firstRef.asset_id || '') : firstRef;
  const mode = String(unit.mode || 'standard') === 'faceid' ? 'FaceID' : 'Standard';
  const model = mode === 'FaceID' ? (unit.faceid_model || unit.faceid_preset || '') : (unit.model || '');
  const chips = [
    uid,
    `Mode · ${mode}`,
    model ? `Model · ${basename(model)}` : '',
    unit.clip_vision ? `CLIP · ${basename(unit.clip_vision)}` : '',
    `Weight · ${formatMaybeNumber(unit.weight ?? '')}`,
    mode === 'FaceID' && unit.weight_faceidv2 !== undefined ? `FaceID v2 · ${formatMaybeNumber(unit.weight_faceidv2)}` : '',
    unit.weight_type ? `Type · ${unit.weight_type}` : '',
    refs.length ? `Refs · ${refs.length}` : 'Refs · 0',
    sourceLabel ? `Preview · ${basename(sourceLabel)}` : '',
  ].filter(Boolean);
  return `<div class="neo-output-extension-unit-card" data-extension-unit="${escapeAttr(uid)}">${outputChipRow(chips, 'unit')}</div>`;
}


function ipAdapterOutputInspectorDetails(payloads = {}, patches = [], validation = []) {
  const block = payloads[IP_ADAPTER_EXTENSION_ID];
  if (!block || typeof block !== 'object') return '';
  const inputs = block.inputs && typeof block.inputs === 'object' ? block.inputs : {};
  const assets = block.assets && typeof block.assets === 'object' ? block.assets : {};
  const metadata = block.metadata && typeof block.metadata === 'object' ? block.metadata : {};
  const params = block.params && typeof block.params === 'object' ? block.params : {};
  const units = Array.isArray(inputs.units) ? inputs.units : [];
  const activeUnits = units.filter((unit) => unit && unit.enabled !== false);
  const faceidCount = activeUnits.filter((unit) => String(unit.mode || 'standard') === 'faceid').length;
  const standardCount = activeUnits.length - faceidCount;
  const patch = Array.isArray(patches) ? patches.find((item) => item && item.extension_id === IP_ADAPTER_EXTENSION_ID) : null;
  const applied = Boolean(patch?.applied || patch?.mutated);
  const status = block.enabled ? (applied ? 'Applied' : 'Validated / gated') : 'Disabled / gated';
  const reason = metadata.reason || patch?.reason || '';
  const nodeClasses = Array.isArray(patch?.node_classes) ? patch.node_classes.join(', ') : (patch?.node || patch?.node_class || '');
  const identity = params.identity && typeof params.identity === 'object' ? params.identity : {};
  const chips = [
    `Status · ${status}`,
    `Units · ${activeUnits.length}`,
    `Standard · ${standardCount}`,
    `FaceID · ${faceidCount}`,
    identity.goal && identity.goal !== 'off' ? `Identity · ${identity.goal}` : '',
    nodeClasses ? `Nodes · ${nodeClasses}` : '',
    patch?.route?.family ? `Family · ${patch.route.family}` : metadata.family ? `Family · ${metadata.family}` : '',
    patch?.route?.loader ? `Loader · ${patch.route.loader}` : metadata.loader ? `Loader · ${metadata.loader}` : '',
    applied ? 'Workflow patched' : '',
  ].filter(Boolean);
  const imageBucket = assets.reference_images && typeof assets.reference_images === 'object' ? assets.reference_images : {};
  const unitRows = activeUnits.length
    ? `<div class="neo-output-extension-units">${activeUnits.slice(0, 6).map((unit) => ipAdapterOutputUnitChips(unit, imageBucket)).join('')}</div>`
    : '';
  const validationNotes = validation
    .filter((item) => item && item.extension_id === IP_ADAPTER_EXTENSION_ID && item.message)
    .slice(0, 3)
    .map((item) => item.message);
  const body = `${reason ? `<div class="neo-output-mini-note">${escapeHtml(reason)}</div>` : ''}${unitRows}${outputValidationNoteList(validationNotes)}`;
  return outputExtensionDetailBlock('IP Adapter', chips, body, `data-extension-id="${IP_ADAPTER_EXTENSION_ID}"`);
}


function sceneDirectorOutputPromptPreview(text = '', maxLength = 180) {
  const value = String(text || '').replace(/\s+/g, ' ').trim();
  if (!value) return '';
  return value.length > maxLength ? `${value.slice(0, Math.max(0, maxLength - 1)).trim()}…` : value;
}

function sceneDirectorOutputRegionChips(region = {}) {
  const bbox = region.bbox && typeof region.bbox === 'object' ? region.bbox : {};
  const mask = region.mask && typeof region.mask === 'object' ? region.mask : {};
  const positivePrompt = sceneDirectorOutputPromptPreview(region.prompt || region.positive_prompt || region.positive || '');
  const negativePrompt = sceneDirectorOutputPromptPreview(region.negative_prompt || region.negative || '');
  const chips = [
    region.label || region.id || 'Region',
    region.type ? `Type · ${region.type}` : '',
    positivePrompt ? 'Prompt' : region.has_prompt ? 'Prompt' : '',
    negativePrompt ? 'Negative' : region.has_negative_prompt ? 'Negative' : '',
    region.has_identity_reference ? 'Identity/ref' : '',
    region.strength !== undefined ? `Strength · ${formatMaybeNumber(region.strength)}` : '',
    bbox.w !== undefined && bbox.h !== undefined ? `Box · ${formatMaybeNumber(bbox.x || 0)}, ${formatMaybeNumber(bbox.y || 0)}, ${formatMaybeNumber(bbox.w)}, ${formatMaybeNumber(bbox.h)}` : '',
    mask.feather !== undefined ? `Feather · ${mask.feather}` : '',
    mask.refine_requested ? 'Mask refine' : '',
  ].filter(Boolean);
  const promptRows = [
    positivePrompt ? `<div class="neo-output-mini-note"><strong>Positive:</strong> ${escapeHtml(positivePrompt)}</div>` : '',
    negativePrompt ? `<div class="neo-output-mini-note"><strong>Negative:</strong> ${escapeHtml(negativePrompt)}</div>` : '',
  ].filter(Boolean).join('');
  return `<div class="neo-output-extension-unit-card" data-extension-unit="${escapeAttr(region.id || '')}">${outputChipRow(chips, 'unit')}${promptRows}</div>`;
}

function sceneDirectorOutputInspectorDetails(payloads = {}, patches = [], validation = [], memoryEvents = {}) {
  const block = payloads[SCENE_DIRECTOR_EXTENSION_ID];
  if (!block || typeof block !== 'object') return '';
  const inputs = block.inputs && typeof block.inputs === 'object' ? block.inputs : {};
  const assets = block.assets && typeof block.assets === 'object' ? block.assets : {};
  const metadata = block.metadata && typeof block.metadata === 'object' ? block.metadata : {};
  const regions = Array.isArray(inputs.regions) ? inputs.regions : [];
  const activeRegions = regions.filter((region) => region && region.enabled !== false && region.visible !== false);
  const ipBindings = Array.isArray(assets.ipadapter_bindings) ? assets.ipadapter_bindings : [];
  const loraBindings = Array.isArray(assets.lora_bindings) ? assets.lora_bindings : [];
  const identityUnits = Array.isArray(assets.identity_units) ? assets.identity_units : [];
  const patch = Array.isArray(patches) ? patches.find((item) => item && item.extension_id === SCENE_DIRECTOR_EXTENSION_ID) : null;
  const applied = Boolean(patch?.applied || patch?.mutated || metadata.workflow_patch_applied);
  const status = block.enabled ? (applied ? 'Applied' : 'Validated / gated') : 'Disabled / gated';
  const reason = metadata.gated_reason || metadata.reason || patch?.reason || '';
  const nodeStatus = patch?.node_status || metadata.node_status || metadata.node_readiness || {};
  const node = patch?.node || patch?.node_class || nodeStatus?.selected_node || '';
  const subjectCount = metadata.subject_count ?? patch?.subject_count ?? activeRegions.filter((region) => String(region.type || '') === 'character').length;
  const detailCount = metadata.detail_region_count ?? patch?.detail_region_count ?? activeRegions.filter((region) => String(region.type || '') !== 'character').length;
  const chips = [
    `Status · ${status}`,
    `Regions · ${activeRegions.length}`,
    `Subjects · ${subjectCount}`,
    `Details · ${detailCount}`,
    ipBindings.length ? `IPAdapter · ${ipBindings.length}` : '',
    loraBindings.length ? `LoRA · ${loraBindings.length}` : '',
    identityUnits.length ? `Identity · ${identityUnits.length}` : '',
    node ? `Node · ${node}` : (block.enabled ? 'Node · backend checked' : ''),
    metadata.route_state ? `Route · ${metadata.route_state}` : patch?.route_state ? `Route · ${patch.route_state}` : '',
    applied ? 'Workflow patched' : '',
  ].filter(Boolean);
  const memory = memoryEvents && typeof memoryEvents === 'object' ? memoryEvents[SCENE_DIRECTOR_EXTENSION_ID] : null;
  const regionSummary = memory?.region_summary && Array.isArray(memory.region_summary) ? memory.region_summary : [];
  const activeRegionById = new Map(activeRegions.map((region) => [String(region?.id || ''), region]).filter(([key]) => Boolean(key)));
  const inspectorRegions = regionSummary.length
    ? regionSummary.slice(0, 6).map((summaryRegion, index) => {
        const liveRegion = activeRegionById.get(String(summaryRegion?.id || '')) || activeRegions[index] || {};
        return {
          ...summaryRegion,
          prompt: liveRegion.prompt || summaryRegion.prompt || summaryRegion.positive_prompt || '',
          positive_prompt: liveRegion.positive_prompt || liveRegion.prompt || summaryRegion.positive_prompt || summaryRegion.prompt || '',
          negative_prompt: liveRegion.negative_prompt || liveRegion.negative || summaryRegion.negative_prompt || summaryRegion.negative || '',
          negative: liveRegion.negative || liveRegion.negative_prompt || summaryRegion.negative || summaryRegion.negative_prompt || '',
          has_prompt: Boolean(liveRegion.prompt || liveRegion.positive_prompt || summaryRegion.has_prompt),
          has_negative_prompt: Boolean(liveRegion.negative_prompt || liveRegion.negative || summaryRegion.has_negative_prompt),
        };
      })
    : activeRegions.slice(0, 6).map((region, index) => ({ id: region.id, label: region.label || `Region ${index + 1}`, type: region.type, prompt: region.prompt || region.positive_prompt || '', positive_prompt: region.positive_prompt || region.prompt || '', negative_prompt: region.negative_prompt || region.negative || '', negative: region.negative || region.negative_prompt || '', has_prompt: Boolean(region.prompt || region.positive_prompt), has_negative_prompt: Boolean(region.negative_prompt || region.negative), strength: region.strength, bbox: region.bbox, mask: region.mask, has_identity_reference: Boolean(region.identity?.reference_image || (Array.isArray(region.identity?.image_names) && region.identity.image_names.length)) }));
  const regionRows = inspectorRegions.length
    ? `<div class="neo-output-extension-units">${inspectorRegions.map((region) => sceneDirectorOutputRegionChips(region)).join('')}</div>`
    : '';
  const identityBindingChips = identityUnits.slice(0, 4).map((unit) => {
    const label = unit.profile_name || unit.profile_id || unit.uid || 'Identity profile';
    const region = unit.region_id || (unit.region_index ? `Region ${unit.region_index}` : 'regional mask');
    const mode = String(unit.mode || 'identity').toUpperCase();
    const weight = unit.weight !== undefined ? ` · W ${formatMaybeNumber(unit.weight)}` : '';
    return `${mode} · ${label} → ${region}${weight}`;
  });
  const bindingChips = [
    ...identityBindingChips,
    ...ipBindings.slice(0, 4).map((item) => `IP slot ${item.slot} · ${item.region_id || `Region ${item.region_index || ''}`}`),
    ...loraBindings.slice(0, 4).map((item) => `LoRA slot ${item.slot} · ${item.region_id || `Region ${item.region_index || ''}`}`),
  ];
  const validationNotes = validation
    .filter((item) => item && item.extension_id === SCENE_DIRECTOR_EXTENSION_ID && item.message)
    .slice(0, 3)
    .map((item) => item.message);
  const summary = metadata.assistant_summary || memory?.assistant_summary || '';
  const body = `${reason ? `<div class="neo-output-mini-note">${escapeHtml(reason)}</div>` : ''}${summary ? `<div class="neo-output-mini-note">${escapeHtml(summary)}</div>` : ''}${regionRows}${outputChipRow(bindingChips, 'items')}${outputValidationNoteList(validationNotes)}`;
  return outputExtensionDetailBlock('Scene Director', chips, body, `data-extension-id="${SCENE_DIRECTOR_EXTENSION_ID}"`);
}



function adetailerOutputInspectorDetails(payloads = {}, patches = [], validation = [], memoryEvents = {}) {
  const block = payloads[ADETAILER_EXTENSION_ID];
  if (!block || typeof block !== 'object') return '';
  const params = block.params && typeof block.params === 'object' ? block.params : {};
  const metadata = block.metadata && typeof block.metadata === 'object' ? block.metadata : {};
  const patch = Array.isArray(patches) ? patches.find((item) => item && item.extension_id === ADETAILER_EXTENSION_ID) : null;
  const event = memoryEvents && typeof memoryEvents === 'object' ? memoryEvents[ADETAILER_EXTENSION_ID] : null;
  const multi = metadata.multi_pass && typeof metadata.multi_pass === 'object'
    ? metadata.multi_pass
    : (event?.multi_pass && typeof event.multi_pass === 'object' ? event.multi_pass : {});
  const passSummaries = Array.isArray(multi.pass_summaries) ? multi.pass_summaries : (Array.isArray(patch?.pass_summaries) ? patch.pass_summaries : []);
  const skippedPasses = Array.isArray(multi.skipped_passes) ? multi.skipped_passes : (Array.isArray(patch?.skipped_passes) ? patch.skipped_passes : []);
  const patchPaths = Array.isArray(multi.patch_paths) ? multi.patch_paths : (Array.isArray(patch?.patch_paths) ? patch.patch_paths : []);
  const applied = Boolean(patch?.applied || patch?.mutated);
  const status = block.enabled ? (applied ? 'Applied' : 'Validated / gated') : 'Disabled / gated';
  const reason = metadata.reason || patch?.reason || event?.gated_reason || '';
  const nodeStatus = patch?.node_status || event?.node_availability || {};
  const optional = patch?.optional_capabilities || nodeStatus.capabilities || {};
  const normalization = metadata.normalization && typeof metadata.normalization === 'object' ? metadata.normalization : {};
  const runtimeUnits = Number(multi.runtime_unit_count || patch?.runtime_unit_count || passSummaries.length || 0);
  const enabledCards = Number(multi.enabled_detailer_pass_count || patch?.enabled_detailer_pass_count || normalization.enabled_detailer_pass_count || 0);
  const totalCards = Number(multi.detailer_pass_count || patch?.detailer_pass_count || normalization.detailer_pass_count || 0);
  const manualUnits = Number(multi.manual_unit_count || passSummaries.filter((item) => item?.manual_box_index).length || 0);
  const sepUnits = Number(multi.sep_unit_count || passSummaries.filter((item) => item?.sep_target_total).length || 0);
  const faceUnits = Number(multi.face_detailer_unit_count || passSummaries.filter((item) => item?.patch_path === 'face_detailer').length || 0);
  const segsUnits = Number(multi.segs_detailer_unit_count || passSummaries.filter((item) => ['segs_detailer', 'manual_mask_to_segs'].includes(item?.patch_path)).length || 0);
  const chips = [
    `Status · ${status}`,
    totalCards ? `Cards · ${enabledCards}/${totalCards} enabled` : '',
    runtimeUnits ? `Runtime units · ${runtimeUnits}` : '',
    patchPaths.length ? `Paths · ${patchPaths.map((item) => String(item).replaceAll('_', ' ')).join(' + ')}` : (patch?.patch_path ? `Path · ${String(patch.patch_path).replaceAll('_', ' ')}` : ''),
    faceUnits ? `FaceDetailer · ${faceUnits}` : '',
    segsUnits ? `SEGSDetailer · ${segsUnits}` : '',
    manualUnits ? `Manual boxes · ${manualUnits}` : '',
    sepUnits ? `[SEP] units · ${sepUnits}` : '',
    params.detector_model ? `Primary detector · ${basename(params.detector_model)}` : '',
    params.denoise !== undefined ? `Denoise · ${formatMaybeNumber(params.denoise)}` : '',
    params.steps !== undefined ? `Steps · ${params.steps}` : '',
    params.cfg !== undefined && params.cfg !== null ? `CFG · ${formatMaybeNumber(params.cfg)}` : '',
    params.sam_model ? `SAM · ${basename(params.sam_model)}` : '',
    nodeStatus.ready !== undefined ? `Node readiness · ${nodeStatus.ready ? 'ready' : 'blocked'}` : '',
    applied ? 'Workflow patched' : '',
  ].filter(Boolean);
  const passCards = passSummaries.slice(0, 12).map((item, index) => {
    const label = item?.label || item?.pass_id || `Pass ${index + 1}`;
    const unitChips = [
      `#${index + 1}`,
      item?.patch_path ? `Path · ${String(item.patch_path).replaceAll('_', ' ')}` : '',
      item?.detector_model ? `Detector · ${basename(item.detector_model)}` : '',
      item?.target_mode ? `Target · ${item.target_mode}` : '',
      item?.manual_box_index ? `Box · ${item.manual_box_index}` : '',
      item?.sep_target_index ? `[SEP] · ${item.sep_target_index}/${item.sep_target_total || '?'}` : '',
      item?.patched_image_ref ? `Image ref · ${Array.isArray(item.patched_image_ref) ? item.patched_image_ref.join(':') : item.patched_image_ref}` : '',
    ].filter(Boolean);
    return `<div class="neo-output-extension-unit-card" data-adetailer-runtime-unit="${escapeAttr(String(index + 1))}">
      <div class="neo-output-extension-name">${escapeHtml(label)}</div>
      ${outputChipRow(unitChips, 'unit')}
    </div>`;
  }).join('');
  const skippedCards = skippedPasses.slice(0, 8).map((item, index) => {
    const label = item?.label || item?.pass_id || `Skipped ${index + 1}`;
    const unitChips = [
      `Skipped · ${label}`,
      item?.reason ? `Reason · ${item.reason}` : '',
    ].filter(Boolean);
    return `<div class="neo-output-extension-unit-card neo-output-extension-unit-card--muted" data-adetailer-skipped="${escapeAttr(String(index + 1))}">${outputChipRow(unitChips, 'unit')}</div>`;
  }).join('');
  const targetChips = [
    normalization.sep_target_count ? `[SEP] targets · ${normalization.sep_target_count}` : '',
    normalization.manual_box_count ? `Manual boxes parsed · ${normalization.manual_box_count}` : '',
    params.custom_classes ? `Classes · ${params.custom_classes}` : '',
    params.target_order ? `Order · ${params.target_order}` : '',
  ].filter(Boolean);
  const optionalChips = Object.entries(optional || {}).slice(0, 8).map(([key, value]) => `${key.replaceAll('_', ' ')} · ${value === true || value?.available !== false ? 'available' : 'gated'}`);
  const validationNotes = validation
    .filter((item) => item && item.extension_id === ADETAILER_EXTENSION_ID && item.message)
    .slice(0, 4)
    .map((item) => item.message);
  const summary = metadata.assistant_summary || patch?.assistant_summary || event?.assistant_summary || '';
  const body = `${reason ? `<div class="neo-output-mini-note">${escapeHtml(reason)}</div>` : ''}${summary ? `<div class="neo-output-mini-note">${escapeHtml(summary)}</div>` : ''}${outputChipRow(targetChips, 'items')}${passCards ? `<div class="neo-output-extension-unit-list">${passCards}</div>` : ''}${skippedCards ? `<div class="neo-output-extension-unit-list">${skippedCards}</div>` : ''}${outputChipRow(optionalChips, 'items')}${outputValidationNoteList(validationNotes)}`;
  return outputExtensionDetailBlock('Image · ADetailer', chips, body, `data-extension-id="${ADETAILER_EXTENSION_ID}" data-adetailer-multipass="true"`);
}

