function restoreAdetailerSettingsFromReuse(reuse = {}) {
  const extensions = reuse.extensions && typeof reuse.extensions === 'object' ? reuse.extensions : {};
  const payloads = extensions.payloads && typeof extensions.payloads === 'object' ? extensions.payloads : {};
  const replayPayloads = extensions.replay_payloads && typeof extensions.replay_payloads === 'object' ? extensions.replay_payloads : {};
  let block = replayPayloads[ADETAILER_EXTENSION_ID] || payloads[ADETAILER_EXTENSION_ID] || null;
  if (!block && replayPayloads.extensions && replayPayloads.extensions[ADETAILER_EXTENSION_ID]) block = replayPayloads.extensions[ADETAILER_EXTENSION_ID];
  if (!block && payloads.extensions && payloads.extensions[ADETAILER_EXTENSION_ID]) block = payloads.extensions[ADETAILER_EXTENSION_ID];
  if (!block || typeof block !== 'object') return false;

  const params = block.params && typeof block.params === 'object' ? block.params : {};
  const inputs = block.inputs && typeof block.inputs === 'object' ? block.inputs : {};
  const assets = block.assets && typeof block.assets === 'object' ? block.assets : {};
  const metadata = block.metadata && typeof block.metadata === 'object' ? block.metadata : {};
  const routeState = metadata.route_state || '';
  const routeEnabled = !routeState || ADETAILER_ACTIVE_ROUTE_STATES.includes(routeState);
  const cleaned = adetailerCleanParams({ ...ADETAILER_DEFAULTS, ...params });
  const restored = adetailerNormalizeSettings({
    ...adetailerSettings(),
    ...cleaned,
    enabled: false,
    detection_snapshot: inputs.detection_snapshot || metadata.detection_snapshot || null,
    canvas_snapshot: inputs.canvas_snapshot || metadata.canvas_snapshot || null,
    preview_action_source: inputs.preview_action_source || metadata.preview_action_source || null,
    restored_from_output: reuse.result_id || '',
    restore_policy: metadata.restore_policy || extensions.extension_restore_policies?.[ADETAILER_EXTENSION_ID] || 'restore_disabled_until_route_nodes_detector_models_pass_cards_manual_boxes_and_impact_pack_validate',
    restore_state: routeEnabled ? 'restored_disabled_pending_revalidation' : 'restored_gated_for_review',
    revalidation_required: true,
    ready_to_auto_enable: false,
    restored_assets: assets,
  });
  state.imageDraft[ADETAILER_EXTENSION_ID] = restored;
  setWorkflowExtensionApplied(ADETAILER_EXTENSION_ID, false);
  return true;
}

function buildImageBranchRestoreContext(activeMetadata = {}, restorePoint = '', resultId = '', options = {}) {
  if (!IMAGE_REPLAY_LATENT_RESTORE_POINTS.includes(restorePoint)) return null;
  const support = imageReplayRestoreSupport(activeMetadata, restorePoint);
  if (restorePoint === 'base_generation_only') {
    if (support.state !== 'available') return null;
    return {
      schema_version: 'neo.image.branch_restore.v1',
      source_result_id: resultId || activeMetadata?.result_id || '',
      restore_point: restorePoint,
      restore_point_label: support.label || 'Base generation only',
      artifact_id: '',
      artifact_path: '',
      artifact_format: 'metadata_recipe',
      provider_id: '',
      backend: '',
      provider_owned: false,
      source_filename: '',
      source_subfolder: '',
      source_type: '',
      comfy_load_name: '',
      no_png_reencode: true,
      resume_policy: 'metadata_base_generation_branch_strip_finish_extensions',
      state: 'branch_draft_loaded_metadata_base_ready',
      requires_provider_resume: false,
      provider_resume_supported: true,
      enhancement_extensions_stripped: [HIGH_RES_LAB_EXTENSION_ID, ADETAILER_EXTENSION_ID, IMAGE_UPSCALE_EXTENSION_ID, LAYERDIFFUSE_EXTENSION_ID],
    };
  }
  const artifact = imageReplayLatentArtifact(activeMetadata, restorePoint);
  if (!artifact || support.state !== 'available') return null;
  const latePassContinuation = options.latePassContinuation === true;
  const allowedPasses = latePassContinuation ? imageLatePassAllowedPasses(restorePoint) : [];
  const providerReference = artifact.provider_reference && typeof artifact.provider_reference === 'object' ? artifact.provider_reference : {};
  return {
    schema_version: 'neo.image.branch_restore.v1',
    source_result_id: resultId || activeMetadata?.result_id || '',
    restore_point: restorePoint,
    restore_point_label: support.label || artifact.label || restorePoint,
    artifact_id: artifact.artifact_id || '',
    artifact_path: artifact.path || '',
    artifact_format: artifact.format || '',
    provider_id: artifact.provider_id || '',
    backend: artifact.backend || '',
    provider_owned: artifact.provider_owned === true,
    source_filename: artifact.source_filename || '',
    source_subfolder: artifact.source_subfolder || '',
    source_type: artifact.source_type || '',
    comfy_load_name: artifact.comfy_load_name || '',
    provider_reference: {
      filename: providerReference.filename || artifact.source_filename || '',
      subfolder: providerReference.subfolder || artifact.source_subfolder || '',
      type: providerReference.type || artifact.source_type || 'output',
      load_name: providerReference.load_name || artifact.comfy_load_name || '',
    },
    no_png_reencode: true,
    resume_policy: restorePoint === 'final_latent' ? 'provider_owned_load_latent_no_png_reencode' : (restorePoint === 'before_high_res_fix' ? 'provider_owned_pre_high_res_latent_continue_no_png_reencode' : (restorePoint === 'after_high_res_fix' ? 'provider_owned_post_high_res_latent_continue_no_png_reencode' : (restorePoint === 'before_adetailer' ? 'provider_owned_pre_adetailer_latent_continue_no_png_reencode' : 'provider_owned_latent_only_no_png_reencode'))),
    state: (restorePoint === 'final_latent' || restorePoint === 'before_high_res_fix' || restorePoint === 'after_high_res_fix' || restorePoint === 'before_adetailer') ? 'branch_draft_loaded_provider_resume_ready' : 'branch_draft_loaded_provider_resume_pending',
    requires_provider_resume: !(restorePoint === 'final_latent' || restorePoint === 'before_high_res_fix' || restorePoint === 'after_high_res_fix' || restorePoint === 'before_adetailer'),
    provider_resume_supported: restorePoint === 'final_latent' || restorePoint === 'before_high_res_fix' || restorePoint === 'after_high_res_fix' || restorePoint === 'before_adetailer',
    activation_scope: latePassContinuation ? 'explicit_late_pass_continuation' : 'legacy_branch_restore',
    late_pass_only: latePassContinuation,
    allowed_passes: allowedPasses,
    enabled_passes: [],
  };
}

function stripEnhancementExtensionsForBaseGenerationBranch(resultId = '') {
  if (!state.imageDraft || typeof state.imageDraft !== 'object') state.imageDraft = {};
  const stripped = [HIGH_RES_LAB_EXTENSION_ID, ADETAILER_EXTENSION_ID, IMAGE_UPSCALE_EXTENSION_ID, LAYERDIFFUSE_EXTENSION_ID];
  state.imageDraft[HIGH_RES_LAB_EXTENSION_ID] = { ...highResLabSettings(), enabled: false, restored_from_output: resultId, restore_state: 'stripped_for_base_generation_branch' };
  state.imageDraft[ADETAILER_EXTENSION_ID] = adetailerNormalizeSettings({ ...adetailerSettings(), enabled: false, restored_from_output: resultId, restore_state: 'stripped_for_base_generation_branch', revalidation_required: true, ready_to_auto_enable: false });
  state.imageDraft[IMAGE_UPSCALE_EXTENSION_ID] = { ...imageUpscaleSettings(), enabled: false, restored_from_output: resultId, restore_state: 'stripped_for_base_generation_branch' };
  state.imageDraft[LAYERDIFFUSE_EXTENSION_ID] = { ...layerDiffuseSettings(), enabled: false, restored_from_output: resultId, restore_state: 'stripped_for_base_generation_branch' };
  stripped.forEach((extensionId) => setWorkflowExtensionApplied(extensionId, false));
  delete state.imageDraft._preview_action_force_workflow_mode;
  delete state.imageDraft._preview_action_run_label;
  delete state.imageDraft._preview_action_finish_pass;
  state.imageDraft._base_generation_branch = {
    schema_version: 'neo.image.base_generation_branch.v1',
    source_result_id: resultId || '',
    stripped_extensions: stripped,
    policy: 'metadata_recipe_branch_no_latent_claim_no_finish_pass_replay',
    loaded_at: new Date().toISOString(),
  };
}

function prepareImageLatePassContinuationDraft(branchRestore = {}, resultId = '') {
  if (!state.imageDraft || typeof state.imageDraft !== 'object') state.imageDraft = {};
  const continuationMarker = {
    source_result_id: resultId || branchRestore.source_result_id || '',
    restore_point: branchRestore.restore_point || '',
    restore_point_label: branchRestore.restore_point_label || imageLatePassRestorePointLabel(branchRestore.restore_point || ''),
    activation_scope: 'explicit_late_pass_continuation',
  };
  state.imageDraft[HIGH_RES_LAB_EXTENSION_ID] = {
    ...highResLabSettings(),
    enabled: false,
    restored_from_output: resultId,
    restore_state: 'late_pass_continuation_loaded_disabled_for_explicit_selection',
    late_pass_continuation: continuationMarker,
  };
  state.imageDraft[ADETAILER_EXTENSION_ID] = adetailerNormalizeSettings({
    ...adetailerSettings(),
    enabled: false,
    restored_from_output: resultId,
    restore_state: 'late_pass_continuation_loaded_disabled_for_explicit_selection',
    revalidation_required: true,
    ready_to_auto_enable: false,
    late_pass_continuation: continuationMarker,
  });
  state.imageDraft[IMAGE_UPSCALE_EXTENSION_ID] = {
    ...imageUpscaleSettings(),
    enabled: false,
    restored_from_output: resultId,
    restore_state: 'disabled_for_latent_late_pass_continuation',
  };
  state.imageDraft[LAYERDIFFUSE_EXTENSION_ID] = {
    ...layerDiffuseSettings(),
    enabled: false,
    restored_from_output: resultId,
    restore_state: 'disabled_for_latent_late_pass_continuation',
  };
  [HIGH_RES_LAB_EXTENSION_ID, ADETAILER_EXTENSION_ID, IMAGE_UPSCALE_EXTENSION_ID, LAYERDIFFUSE_EXTENSION_ID].forEach((extensionId) => setWorkflowExtensionApplied(extensionId, false));
  delete state.imageDraft._preview_action;
  delete state.imageDraft._preview_action_force_workflow_mode;
  delete state.imageDraft._preview_action_run_label;
  delete state.imageDraft._preview_action_finish_pass;
  state.imageDraft.output_policy = 'append_derived';
}

function applyImageResultReusePayload(reuse = {}, options = {}) {
  const prompt = reuse.prompt || {};
  const params = reuse.params || {};
  const model = reuse.model || {};
  const resultId = reuse.result_id || options.resultId || activeSavedResultSummary()?.result_id || '';
  const activeMetadata = options.activeMetadata || state.activeSavedResultMetadata || {};
  const replaySource = options.replaySource || options.replayKind || 'full_recipe';
  const latePassContinuation = options.latePassContinuation === true;
  const branchRestore = buildImageBranchRestoreContext(activeMetadata, replaySource, resultId, { latePassContinuation });
  const replayMetadata = activeMetadata?.replay || {};
  const availableRestorePoints = Array.isArray(replayMetadata.available_restore_points) ? replayMetadata.available_restore_points : ['full_recipe', 'final_output_as_source'];
  const latePassRestorePoints = Array.isArray(replayMetadata.late_pass_restore_points)
    ? replayMetadata.late_pass_restore_points
    : (Array.isArray(replayMetadata.latent_restore_points) ? replayMetadata.latent_restore_points : []);
  const gatedRestorePoints = Array.isArray(replayMetadata.gated_restore_points) ? replayMetadata.gated_restore_points : ['base_generation_only', 'before_high_res_fix', 'after_high_res_fix', 'before_adetailer', 'final_latent'];
  state.imageDraft = {
    ...state.imageDraft,
    ...params,
    positive_prompt: prompt.positive || state.imageDraft.positive_prompt,
    negative_prompt: prompt.negative || state.imageDraft.negative_prompt,
    family: model.family || state.imageDraft.family,
    loader: model.loader || state.imageDraft.loader,
    model: model.model || state.imageDraft.model,
    vae: model.vae || state.imageDraft.vae,
    _replay_context: {
      schema_version: 'neo.image.replay_draft.v1',
      source_result_id: resultId,
      replay_kind: latePassContinuation ? 'late_pass_continuation' : (branchRestore ? 'latent_branch' : (options.replayKind || replaySource || 'full_recipe')),
      replay_source: latePassContinuation ? 'none' : replaySource,
      source_is_output_image: false,
      loaded_at: new Date().toISOString(),
      trigger: options.trigger || 'reuse_prompt_params',
      available_restore_points: availableRestorePoints,
      latent_restore_points: latePassRestorePoints,
      late_pass_restore_points: latePassRestorePoints,
      gated_restore_points: gatedRestorePoints,
      branch_restore: branchRestore,
      late_pass_continuation: latePassContinuation && branchRestore ? {
        schema_version: 'neo.image.late_pass_continuation.v1',
        source_result_id: resultId,
        restore_point: branchRestore.restore_point,
        restore_point_label: branchRestore.restore_point_label,
        artifact_id: branchRestore.artifact_id,
        provider_id: branchRestore.provider_id,
        backend: branchRestore.backend,
        provider_reference: branchRestore.provider_reference,
        allowed_passes: branchRestore.allowed_passes || [],
        enabled_passes: [],
        activation_scope: 'explicit_late_pass_continuation',
        state: 'loaded_waiting_for_explicit_pass_selection',
        loaded_at: new Date().toISOString(),
        no_png_reencode: true,
      } : null,
      auto_run: false,
    },
  };
  const restoredIpAdapter = restoreIpAdapterSettingsFromReuse(reuse);
  const restoredSceneDirector = restoreSceneDirectorSettingsFromReuse(reuse);
  const isBaseGenerationBranch = replaySource === 'base_generation_only';
  const restoredHighResLab = restoreHighResLabSettingsFromReuse(reuse);
  const restoredAdetailer = restoreAdetailerSettingsFromReuse(reuse);
  if (isBaseGenerationBranch) stripEnhancementExtensionsForBaseGenerationBranch(resultId);
  if (latePassContinuation && branchRestore) prepareImageLatePassContinuationDraft(branchRestore, resultId);
  state.activeSavedResultReuse = reuse;
  saveUiState();
  const baseBranchLabel = isBaseGenerationBranch ? 'Base branch: finish extensions stripped' : '';
  const restoredHighResLabLabel = restoredHighResLab ? 'High-Res Lab settings' : '';
  const restoredAdetailerLabel = restoredAdetailer ? 'ADetailer settings' : '';
  const restoredLabels = [restoredIpAdapter ? 'IP Adapter settings' : '', restoredSceneDirector ? 'Scene Director regions' : '', isBaseGenerationBranch ? '' : restoredHighResLabLabel, isBaseGenerationBranch ? '' : restoredAdetailerLabel, baseBranchLabel].filter(Boolean).join(' + ');
  return { restoredLabels };
}

async function fetchActiveImageResultReusePayload() {
  const summary = activeSavedResultSummary();
  if (!summary?.result_id) return null;
  const category = activeImageResultsCategory();
  const response = await fetch(`/api/image/results/${encodeURIComponent(summary.result_id)}/reuse?category=${encodeURIComponent(category)}`, { method: 'POST' });
  if (!response.ok) throw new Error('Result reuse API failed');
  return response.json();
}

async function loadActiveImageReplayDraft() {
  const summary = activeSavedResultSummary();
  if (!summary?.result_id) return;
  try {
    const activeFile = activeInspectorOutputFile() || summary.active_file || {};
    const sourceOption = selectedImageReplaySourceOption(summary, state.activeSavedResultMetadata || {}, activeFile);
    const replaySource = sourceOption?.id || 'none';
    if (replaySource === 'none') {
      setWorkspaceStatus('Choose a replay source before loading a replay draft.', 'warning');
      render();
      return;
    }
    const reuse = await fetchActiveImageResultReusePayload();
    const applied = applyImageResultReusePayload(reuse || {}, { trigger: 'load_replay_draft', replayKind: 'full_recipe', replaySource, resultId: summary.result_id, activeMetadata: state.activeSavedResultMetadata || {} });
    const previewSource = activeSavedPreviewActionSource();
    if (previewActionHasSource(previewSource)) {
      stageSavedOutputAsCurrentImagePreview(previewSource, { replaySource });
    }
    const restoredSuffix = applied.restoredLabels ? ` + ${applied.restoredLabels}` : '';
    const branch = state.imageDraft?._replay_context?.branch_restore;
    const sourceSuffix = branch ? ` · branch draft from ${branch.restore_point_label || branch.restore_point}` : '';
    setWorkspaceProgress(`${branch ? 'Branch Draft' : 'Replay Draft'} loaded for review${sourceSuffix}${restoredSuffix}`, 100);
    render();
  } catch (error) {
    state.imageResultsError = error.message || 'Could not load replay draft.';
    render();
  }
}

async function loadActiveImageLatePassContinuation() {
  const summary = activeSavedResultSummary();
  if (!summary?.result_id) return;
  try {
    const activeMetadata = state.activeSavedResultMetadata || {};
    const selected = selectedImageLatePassContinuationOption(activeMetadata);
    if (!selected || selected.id === 'none' || !selected.enabled) {
      setWorkspaceStatus('Choose an available saved latent restore point first.', 'warning');
      render();
      return;
    }
    const reuse = await fetchActiveImageResultReusePayload();
    const applied = applyImageResultReusePayload(reuse || {}, {
      trigger: 'load_late_pass_continuation',
      replayKind: 'late_pass_continuation',
      replaySource: selected.id,
      resultId: summary.result_id,
      activeMetadata,
      latePassContinuation: true,
    });
    const continuation = activeImageLatePassContinuation();
    if (!continuation) throw new Error('The saved latent could not be activated for late-pass continuation.');
    state.imageResultsReplaySource = 'none';
    setSurfaceWorkspaceAppId('image', 'finish');
    setImageWorkflowMode('generate');
    state.imageDraft.workflow_mode = 'generate';
    saveUiState();
    const restoredSuffix = applied.restoredLabels ? ` Recipe restored: ${applied.restoredLabels}.` : '';
    setWorkspaceProgress(`Late-Pass Continuation loaded from ${continuation.restore_point_label || imageLatePassRestorePointLabel(continuation.restore_point)}.${restoredSuffix} Choose High-Res Fix or ADetailer before generating.`, 100, { allowBackwards: true });
    render();
  } catch (error) {
    state.imageResultsError = error.message || 'Could not load the saved latent for late-pass continuation.';
    render();
  }
}

async function reuseActiveImageResult() {
  const summary = activeSavedResultSummary();
  if (!summary?.result_id) return;
  try {
    const reuse = await fetchActiveImageResultReusePayload();
    const applied = applyImageResultReusePayload(reuse || {}, { trigger: 'reuse_prompt_params', replayKind: 'full_recipe', replaySource: 'full_recipe', resultId: summary.result_id, activeMetadata: state.activeSavedResultMetadata || {} });
    const restoredSuffix = applied.restoredLabels ? ` + ${applied.restoredLabels}` : '';
    setWorkspaceProgress(`Reused saved result prompt + params${restoredSuffix}`, 100);
    render();
  } catch (error) {
    state.imageResultsError = error.message || 'Could not reuse saved result.';
    render();
  }
}


function imageDeleteManifestCount(preview = {}, key = '') {
  const items = Array.isArray(preview?.[key]) ? preview[key] : [];
  return items.length;
}

function imageDeleteManifestRows(preview = {}) {
  const rows = [
    ['Generated image output(s)', imageDeleteManifestCount(preview, 'output_files')],
    ['Metadata sidecar(s)', imageDeleteManifestCount(preview, 'metadata_files')],
    ['Latent checkpoint / restore file(s)', imageDeleteManifestCount(preview, 'latent_files')],
    ['Image job context file(s)', imageDeleteManifestCount(preview, 'job_context_files')],
    ['Unique linked input/control asset(s)', imageDeleteManifestCount(preview, 'input_assets_unique')],
  ];
  return rows.map(([label, count]) => `<li><span>${escapeHtml(label)}</span><strong>${Number(count || 0)}</strong></li>`).join('');
}

function imageDeleteSharedRows(preview = {}) {
  const shared = Array.isArray(preview?.input_assets_shared) ? preview.input_assets_shared : [];
  if (!shared.length) return '';
  return `
    <div class="neo-delete-modal-skipped">
      <strong>Skipped shared assets</strong>
      <ul>${shared.slice(0, 8).map((item) => `<li>${escapeHtml(item.label || item.filename || item.path || 'Shared asset')} <span class="neo-muted">${escapeHtml((item.referenced_by_result_ids || []).join(', ') || 'referenced elsewhere')}</span></li>`).join('')}</ul>
      ${shared.length > 8 ? `<p class="neo-muted">+${shared.length - 8} more shared asset(s)</p>` : ''}
    </div>`;
}

function imageDeleteSkippedRows(preview = {}) {
  const skipped = Array.isArray(preview?.skipped) ? preview.skipped : [];
  if (!skipped.length) return '';
  return `
    <div class="neo-delete-modal-skipped">
      <strong>Other skipped items</strong>
      <ul>${skipped.slice(0, 6).map((item) => `<li>${escapeHtml(item.label || item.path || item.reason || 'Skipped item')} <span class="neo-muted">${escapeHtml(item.reason || '')}</span></li>`).join('')}</ul>
      ${skipped.length > 6 ? `<p class="neo-muted">+${skipped.length - 6} more skipped item(s)</p>` : ''}
    </div>`;
}

function closeImageDeleteModal() {
  state.imageDeleteModal = { open: false, loading: false, deleting: false, error: '', preview: null, resultId: '', filename: '' };
  renderImageDeleteModal();
}

function renderImageDeleteModal() {
  let host = document.getElementById('imageDeleteModalHost');
  if (!host) {
    host = document.createElement('div');
    host.id = 'imageDeleteModalHost';
    document.body.appendChild(host);
  }
  const modal = state.imageDeleteModal || {};
  if (!modal.open) {
    host.innerHTML = '';
    if (!state.imageZoomModal?.open && !state.imageMaskEditor?.open) document.body.classList.remove('neo-modal-open');
    return;
  }
  document.body.classList.add('neo-modal-open');
  const preview = modal.preview || {};
  const summary = preview.summary || {};
  const fullCount = Number(summary.full_delete_count || 0);
  const outputOnlyCount = Number(summary.output_only_delete_count || 0);
  const uniqueInputs = Number(summary.unique_input_assets || 0);
  const latentCount = Number(summary.latent_files || 0);
  const jobCount = Number(summary.job_context_files || 0);
  const fullHasExtra = Boolean(uniqueInputs || latentCount || jobCount);
  const filename = modal.filename || modal.resultId || 'selected output';
  host.innerHTML = `
    <div class="neo-image-delete-modal" role="dialog" aria-modal="true" aria-label="Delete saved image output">
      <div class="neo-image-zoom-backdrop" data-delete-close="true"></div>
      <div class="neo-delete-modal-window">
        <div class="neo-delete-modal-head">
          <div>
            <strong>Delete this saved output?</strong>
            <p class="neo-muted">${escapeHtml(filename)}</p>
          </div>
          <button class="neo-btn secondary" id="imageDeleteModalCloseBtn" type="button">Close</button>
        </div>
        ${modal.loading ? `<div class="neo-empty-state"><strong>Building delete preview…</strong><p>Scanning linked output files, metadata, latents, job context, and source assets.</p></div>` : ''}
        ${modal.error ? `<p class="neo-error-text">${escapeHtml(modal.error)}</p>` : ''}
        ${!modal.loading && preview?.schema_version ? `
          <div class="neo-delete-modal-body">
            <p>This action uses a Neo_Data-only path guard. Shared source/control/reference assets are skipped unless they are unique to this result.</p>
            <ul class="neo-delete-count-list">${imageDeleteManifestRows(preview)}</ul>
            ${imageDeleteSharedRows(preview)}
            ${imageDeleteSkippedRows(preview)}
          </div>
          <div class="neo-delete-modal-actions">
            <button class="neo-btn secondary" id="imageDeleteOutputOnlyBtn" type="button" ${modal.deleting || !outputOnlyCount ? 'disabled' : ''}>Delete output only</button>
            <button class="neo-btn danger" id="imageDeleteFullCascadeBtn" type="button" ${modal.deleting || !fullCount ? 'disabled' : ''}>Delete full linked assets${fullHasExtra ? '' : ' (same as output only)'}</button>
          </div>` : ''}
      </div>
    </div>`;
  bindImageDeleteModal();
}

function bindImageDeleteModal() {
  document.querySelectorAll('[data-delete-close]').forEach((node) => node.addEventListener('click', closeImageDeleteModal));
  const closeBtn = document.getElementById('imageDeleteModalCloseBtn');
  if (closeBtn) closeBtn.addEventListener('click', closeImageDeleteModal);
  const outputOnly = document.getElementById('imageDeleteOutputOnlyBtn');
  if (outputOnly) outputOnly.addEventListener('click', () => performImageResultDelete('output_only'));
  const full = document.getElementById('imageDeleteFullCascadeBtn');
  if (full) full.addEventListener('click', () => performImageResultDelete('full'));
}

async function openImageDeletePreview() {
  const summary = activeSavedResultSummary();
  if (!summary?.result_id) return;
  const category = activeImageResultsCategory();
  state.imageDeleteModal = {
    open: true,
    loading: true,
    deleting: false,
    error: '',
    preview: null,
    resultId: summary.result_id,
    filename: summary.active_file?.filename || summary.result_id,
  };
  renderImageDeleteModal();
  try {
    const response = await fetch(`/api/image/results/${encodeURIComponent(summary.result_id)}/delete-preview?category=${encodeURIComponent(category)}`);
    const payload = await response.json().catch(() => ({}));
    if (!response.ok || payload.ok === false) throw new Error(payload.detail || payload.message || 'Could not build delete preview');
    state.imageDeleteModal = { ...state.imageDeleteModal, loading: false, preview: payload, error: '' };
  } catch (error) {
    state.imageDeleteModal = { ...state.imageDeleteModal, loading: false, error: error.message || 'Could not build delete preview.' };
  }
  renderImageDeleteModal();
}

async function performImageResultDelete(cascade = 'output_only') {
  const resultId = state.imageDeleteModal?.resultId || activeSavedResultSummary()?.result_id || '';
  if (!resultId) return;
  const category = activeImageResultsCategory();
  state.imageDeleteModal = { ...state.imageDeleteModal, deleting: true, error: '' };
  renderImageDeleteModal();
  try {
    const response = await fetch(`/api/image/results/${encodeURIComponent(resultId)}?category=${encodeURIComponent(category)}&cascade=${encodeURIComponent(cascade)}`, { method: 'DELETE' });
    const payload = await response.json().catch(() => ({}));
    if (!response.ok || payload.ok === false) throw new Error(payload.detail || payload.message || 'Delete failed');
    state.imageSavedResults = state.imageSavedResults.filter((item) => item?.result_id !== resultId);
    state.activeSavedResultIndex = Math.min(state.activeSavedResultIndex, Math.max(0, state.imageSavedResults.length - 1));
    state.activeSavedResultMetadata = null;
    state.activeSavedResultReuse = null;
    state.activeSavedOutputFileId = '';
    state.imageResultsLoadedCategory = null;
    state.imageResultsLoadedSort = null;
    state.imageResultsError = '';
    closeImageDeleteModal();
    setWorkspaceProgress(cascade === 'full' ? 'Deleted saved output + unique linked assets' : 'Deleted saved output', 100);
    await loadImageResults({ force: true });
  } catch (error) {
    state.imageDeleteModal = { ...state.imageDeleteModal, deleting: false, error: error.message || 'Could not delete saved output.' };
    renderImageDeleteModal();
  }
}

async function deleteActiveImageResult() {
  await openImageDeletePreview();
}



function resetImageZoomModal() {
  state.imageZoomModal.scale = 1;
  state.imageZoomModal.offsetX = 0;
  state.imageZoomModal.offsetY = 0;
}

function openImageZoomModal(src, label = 'Image preview') {
  if (!src) return;
  state.imageZoomModal = {
    open: true,
    src,
    label,
    scale: 1,
    offsetX: 0,
    offsetY: 0,
    dragging: false,
    dragStartX: 0,
    dragStartY: 0,
  };
  renderImageZoomModal();
}

function closeImageZoomModal() {
  state.imageZoomModal.open = false;
  state.imageZoomModal.dragging = false;
  renderImageZoomModal();
}

function imageZoomTransform() {
  const zoom = state.imageZoomModal || {};
  return `translate(${Number(zoom.offsetX || 0)}px, ${Number(zoom.offsetY || 0)}px) scale(${Number(zoom.scale || 1)})`;
}

function renderImageZoomModal() {
  let host = document.getElementById('imageZoomModalHost');
  if (!host) {
    host = document.createElement('div');
    host.id = 'imageZoomModalHost';
    document.body.appendChild(host);
  }
  const zoom = state.imageZoomModal || {};
  if (!zoom.open || !zoom.src) {
    host.innerHTML = '';
    document.body.classList.remove('neo-modal-open');
    return;
  }
  document.body.classList.add('neo-modal-open');
  host.innerHTML = `
    <div class="neo-image-zoom-modal" role="dialog" aria-modal="true" aria-label="Image zoom preview">
      <div class="neo-image-zoom-backdrop" data-zoom-close="true"></div>
      <div class="neo-image-zoom-window">
        <div class="neo-image-zoom-toolbar">
          <strong>${escapeHtml(zoom.label || 'Image preview')}</strong>
          <span class="neo-muted">Mouse wheel zoom · drag to pan · double-click reset</span>
          <button class="neo-btn secondary" id="imageZoomResetBtn" type="button">Reset</button>
          <button class="neo-btn secondary" id="imageZoomCloseBtn" type="button">Close</button>
        </div>
        <div class="neo-image-zoom-stage" id="imageZoomStage">
          <img id="imageZoomImg" src="${escapeAttr(zoom.src)}" alt="${escapeAttr(zoom.label || 'Zoomed image preview')}" style="transform:${escapeAttr(imageZoomTransform())}">
        </div>
      </div>
    </div>`;
  bindImageZoomModal();
}

function updateImageZoomTransform() {
  const img = document.getElementById('imageZoomImg');
  if (img) img.style.transform = imageZoomTransform();
}

function bindImageZoomModal() {
  document.querySelectorAll('[data-zoom-close]').forEach((node) => node.addEventListener('click', closeImageZoomModal));
  const closeBtn = document.getElementById('imageZoomCloseBtn');
  if (closeBtn) closeBtn.addEventListener('click', closeImageZoomModal);
  const resetBtn = document.getElementById('imageZoomResetBtn');
  if (resetBtn) resetBtn.addEventListener('click', () => { resetImageZoomModal(); updateImageZoomTransform(); });
  const stage = document.getElementById('imageZoomStage');
  if (!stage) return;
  stage.addEventListener('wheel', (event) => {
    event.preventDefault();
    const zoom = state.imageZoomModal;
    const delta = event.deltaY < 0 ? 0.12 : -0.12;
    zoom.scale = Math.max(0.25, Math.min(6, Number(zoom.scale || 1) + delta));
    updateImageZoomTransform();
  }, { passive: false });
  stage.addEventListener('dblclick', () => { resetImageZoomModal(); updateImageZoomTransform(); });
  stage.addEventListener('pointerdown', (event) => {
    const zoom = state.imageZoomModal;
    zoom.dragging = true;
    zoom.dragStartX = event.clientX - Number(zoom.offsetX || 0);
    zoom.dragStartY = event.clientY - Number(zoom.offsetY || 0);
    stage.setPointerCapture?.(event.pointerId);
    stage.classList.add('dragging');
  });
  stage.addEventListener('pointermove', (event) => {
    const zoom = state.imageZoomModal;
    if (!zoom.dragging) return;
    zoom.offsetX = event.clientX - Number(zoom.dragStartX || 0);
    zoom.offsetY = event.clientY - Number(zoom.dragStartY || 0);
    updateImageZoomTransform();
  });
  const stopDrag = (event) => {
    state.imageZoomModal.dragging = false;
    stage.releasePointerCapture?.(event.pointerId);
    stage.classList.remove('dragging');
  };
  stage.addEventListener('pointerup', stopDrag);
  stage.addEventListener('pointercancel', stopDrag);
}

function bindImageZoomTriggers() {
  document.querySelectorAll('[data-zoom-src]').forEach((node) => {
    node.addEventListener('click', (event) => {
      if (node.hasAttribute('data-output-file-id')) return;
      event.preventDefault();
      openImageZoomModal(node.getAttribute('data-zoom-src'), node.getAttribute('data-zoom-label') || 'Image preview');
    });
  });
}

function bindImageResultsWorkspace() {
  document.querySelectorAll('[data-saved-result-index]').forEach((button) => {
    button.addEventListener('click', async () => {
      const index = Number(button.dataset.savedResultIndex || 0);
      state.activeSavedResultIndex = Number.isFinite(index) ? index : 0;
      state.activeSavedOutputFileId = '';
      state.activeSavedInspectorMediaId = '';
      const summary = activeSavedResultSummary();
      await loadImageResultDetail(summary?.result_id);
    });
  });
  document.querySelectorAll('[data-output-file-id]').forEach((button) => {
    button.addEventListener('click', () => {
      state.activeSavedOutputFileId = button.getAttribute('data-output-file-id') || '';
      state.activeSavedInspectorMediaId = state.activeSavedOutputFileId ? `output:${state.activeSavedOutputFileId}` : '';
      saveUiState();
      render();
    });
  });
  document.querySelectorAll('[data-output-input-asset-id]').forEach((button) => {
    button.addEventListener('click', () => {
      const assetId = button.getAttribute('data-output-input-asset-id') || '';
      state.activeSavedInspectorMediaId = assetId ? `asset:${assetId}` : '';
      saveUiState();
      render();
    });
  });
  document.querySelectorAll('[data-output-extension-asset-id]').forEach((button) => {
    button.addEventListener('click', () => {
      const assetId = button.getAttribute('data-output-extension-asset-id') || '';
      state.activeSavedInspectorMediaId = assetId ? `extension_asset:${assetId}` : '';
      saveUiState();
      render();
    });
  });
  document.querySelectorAll('[data-result-thumb]').forEach((img) => {
    img.addEventListener('error', () => {
      const resultId = img.getAttribute('data-result-thumb');
      if (!resultId) return;
      const broken = new Set(state.imageBrokenResultIds || []);
      broken.add(resultId);
      state.imageBrokenResultIds = Array.from(broken);
      img.closest('.neo-output-card')?.remove();
      const visibleResults = visibleImageSavedResults();
      state.activeSavedResultIndex = Math.min(state.activeSavedResultIndex, Math.max(0, visibleResults.length - 1));
      if (!visibleResults.length) {
        state.activeSavedResultMetadata = null;
        state.activeSavedResultReuse = null;
      }
      state.imageResultsError = visibleResults.length
        ? 'A missing output thumbnail was hidden from this Results view.'
        : 'No available saved outputs found in Neo_Data.';
      // Do not invalidate loaded category/sort or call render() here. Broken image
      // events can fire during render; re-rendering from the error handler creates
      // a refresh loop if metadata exists but the image file was deleted manually.
    }, { once: true });
  });
  const refresh = document.getElementById('imageResultsRefreshBtn');
  if (refresh) refresh.addEventListener('click', () => loadImageResults({ force: true }));
  const categoryFilter = document.getElementById('imageResultsCategoryFilter');
  if (categoryFilter) categoryFilter.addEventListener('change', () => {
    state.imageResultsFilterCategory = categoryFilter.value || 'all';
    state.activeSavedResultIndex = 0;
    state.imageResultsLoadedCategory = null;
    state.imageResultsIntegrityChecked = false;
    loadImageResults({ force: true });
  });
  const sortFilter = document.getElementById('imageResultsSortFilter');
  if (sortFilter) sortFilter.addEventListener('change', () => {
    state.imageResultsSort = sortFilter.value || 'newest';
    state.activeSavedResultIndex = 0;
    state.imageResultsLoadedSort = null;
    state.imageResultsIntegrityChecked = false;
    loadImageResults({ force: true });
  });
  const replaySourceSelect = document.getElementById('imageResultReplaySourceSelect');
  if (replaySourceSelect) replaySourceSelect.addEventListener('change', () => {
    state.imageResultsReplaySource = replaySourceSelect.value || 'none';
    render();
  });
  const replayDraft = document.getElementById('imageResultLoadReplayDraftBtn');
  if (replayDraft) replayDraft.addEventListener('click', () => loadActiveImageReplayDraft());
  const latePassRestoreSelect = document.getElementById('imageResultLatePassRestoreSelect');
  if (latePassRestoreSelect) latePassRestoreSelect.addEventListener('change', () => {
    state.imageResultsLatePassRestorePoint = latePassRestoreSelect.value || 'none';
    render();
  });
  const loadLatePassBtn = document.getElementById('imageResultLoadLatePassBtn');
  if (loadLatePassBtn) loadLatePassBtn.addEventListener('click', () => loadActiveImageLatePassContinuation());
  const exitLatePassBtn = document.getElementById('imageResultExitLatePassBtn');
  if (exitLatePassBtn) exitLatePassBtn.addEventListener('click', () => {
    clearImageLatePassContinuation({ renderAfter: true, statusMessage: 'Late-Pass Continuation exited. The current recipe remains loaded.' });
  });
  document.querySelectorAll('[data-output-postfix-action]').forEach((button) => {
    button.addEventListener('click', () => {
      if (button.disabled) return;
      Promise.resolve(handleOutputInspectorPostFixAction(button.getAttribute('data-output-postfix-action') || '')).catch((error) => {
        setWorkspaceStatus(error.message || 'Could not run this post-fix action.', 'warning');
        alert(`Post-fix action failed: ${error.message || error}`);
      });
    });
  });
  const deleteBtn = document.getElementById('imageResultDeleteBtn');
  if (deleteBtn) deleteBtn.addEventListener('click', () => deleteActiveImageResult());
  const folder = document.getElementById('imageResultFolderBtn');
  if (folder) folder.addEventListener('click', () => openImageOutputFolder());
  const saveDetails = document.getElementById('imageOutputSaveSettingsBtn');
  if (saveDetails) saveDetails.addEventListener('click', () => saveImageOutputSettings());
  const addCategory = document.getElementById('imageOutputAddCategoryBtn');
  if (addCategory) addCategory.addEventListener('click', () => addImageOutputCategory());
  const storageRefresh = document.getElementById('imageReplayStorageRefreshBtn');
  if (storageRefresh) storageRefresh.addEventListener('click', () => loadImageReplayStorage({ renderAfter: true }));
  const storageCleanup = document.getElementById('imageReplayStorageCleanupOrphansBtn');
  if (storageCleanup) storageCleanup.addEventListener('click', () => cleanupImageReplayStorageOrphans());
  ['imageOutputCategory', 'imageOutputPrefix', 'imageOutputPadding', 'imageOutputCleanupNative'].forEach((id) => {
    const node = document.getElementById(id);
    if (node) node.addEventListener('change', () => saveImageOutputSettings());
  });
}


function renderQwenSourcePreviewSlot(lane, primaryPreview = '') {
  const label = sourceImageLaneLabel(lane);
  const url = sourceImageLaneUrl(lane);
  const defaultRoleLabel = lane === 1 ? 'Main subject' : lane === 2 ? 'Secondary subject' : 'Composition guide';
  if (lane === 1) {
    return `
      <div class="neo-source-stack-slot is-primary" data-testid="qwen-source-preview-slot-1">
        <div class="neo-source-stack-slot-head"><strong>Image 1</strong><span>${escapeHtml(defaultRoleLabel)}</span></div>
        <div class="neo-source-preview-wrap" data-neo-image-dropzone="true" data-neo-image-kind="source" data-neo-image-lane="1" data-neo-image-input="imageSourceFile">${primaryPreview}</div>
      </div>`;
  }
  const preview = url
    ? `<button class="neo-qwen-source-thumb neo-zoomable-preview" type="button" data-neo-image-dropzone="true" data-neo-image-kind="reference" data-neo-image-lane="${lane}" data-neo-image-input="imageQwenRef${lane}File" data-zoom-src="${escapeAttr(url)}" data-zoom-label="${escapeAttr(label)}" title="Open source image ${lane} zoom"><img src="${escapeAttr(url)}" alt="Selected source image ${lane}"></button>`
    : `<label class="neo-qwen-source-empty" data-neo-image-dropzone="true" data-neo-image-kind="reference" data-neo-image-lane="${lane}" data-neo-image-input="imageQwenRef${lane}File"><span>Drop image ${lane} here</span><small>or click to choose</small></label>`;
  return `
    <div class="neo-source-stack-slot" data-testid="qwen-source-preview-slot-${lane}">
      <div class="neo-source-stack-slot-head"><strong>Image ${lane}</strong><span>${escapeHtml(defaultRoleLabel)}</span></div>
      ${preview}
      <div class="neo-source-stack-slot-meta">${escapeHtml(label)}</div>
    </div>`;
}

function renderQwenSourcePreviewStack(primaryPreview) {
  const lanes = [1, 2, 3].filter((lane) => lane === 1 || qwenVisibleSourceSlotCount() >= lane);
  return `<div class="neo-source-preview-stack-multi" data-testid="qwen-source-preview-stack">${lanes.map((lane) => renderQwenSourcePreviewSlot(lane, primaryPreview)).join('')}</div>`;
}

function renderQwenSourceCard(lane) {
  const hasImage = Boolean(sourceImageLanePath(lane) || sourceImageLaneUrl(lane));
  const label = sourceImageLaneLabel(lane);
  const defaultRole = lane === 2 ? 'secondary_subject' : 'composition_guide';
  const roleKey = `source_image_${lane}_role`;
  return `
    <article class="neo-qwen-source-card" data-testid="qwen-source-card-${lane}">
      <div class="neo-qwen-source-card-head">
        <strong>Source Image ${lane}</strong>
        <button class="neo-btn ghost" id="imageRemoveQwenRef${lane}Btn" type="button">Remove</button>
      </div>
      <div class="neo-qwen-source-fields">
        <label class="neo-source-file-label">Role
          ${optionSelect(`imageQwenSourceRole${lane}`, qwenSourceRoleOptions(lane), state.imageDraft[roleKey] || defaultRole)}
        </label>
        <div class="neo-source-actions">
          <label class="neo-source-file-label neo-file-action">Replace
            <input id="imageQwenRef${lane}File" type="file" accept="image/png,image/jpeg,image/webp,image/bmp">
          </label>
          <button class="neo-btn secondary" id="imageClearQwenRef${lane}Btn" type="button" ${hasImage ? '' : 'disabled'}>Clear</button>
        </div>
        <div class="neo-source-meta"><span class="neo-badge">${escapeHtml(label)}</span></div>
      </div>
    </article>`;
}


function imageInpaintTargetLabel(value) {
  if (value === 'not_masked_area') return 'Inpaint not masked';
  if (value === 'masked_area') return 'Inpaint masked area';
  return 'Route default';
}

function imageInpaintContextLabel(value) {
  if (value === 'full_image_context') return 'Full image context';
  if (value === 'masked_region_focus') return 'Masked region focus';
  return 'Route default';
}

function renderImageSourceMaskWorkflowCard({ hasSource = false, hasMask = false } = {}) {
  if (!imageNeedsMaskPanel()) return '';
  const targetVisible = shouldShowProfileField('inpaint_selection_target');
  const contextVisible = shouldShowProfileField('inpaint_context_mode');
  const targetLabel = targetVisible ? imageInpaintTargetLabel(state.imageDraft.inpaint_selection_target || 'masked_area') : 'Route default';
  const contextLabel = contextVisible ? imageInpaintContextLabel(state.imageDraft.inpaint_context_mode || 'masked_region_focus') : 'Route default';
  const sourceState = hasSource ? 'ready' : 'missing';
  const maskState = hasMask ? 'ready' : 'not painted';
  const editHint = hasSource
    ? (hasMask ? 'Mask overlay is saved on this source. Re-open Edit Mask to refine it.' : 'Paint white where the image should change, then click Use Mask.')
    : 'Add a source image before painting the mask.';
  return `<div class="neo-source-mask-workflow" data-testid="image-source-mask-workflow">
    <div class="neo-source-mask-workflow-head">
      <strong>Inpaint source + mask</strong>
      <span class="neo-badge ${hasSource && hasMask ? 'success' : 'warning'}">${hasSource && hasMask ? 'Ready' : 'Needs input'}</span>
    </div>
    <div class="neo-source-mask-steps" aria-label="Inpaint source and mask readiness">
      <span class="neo-source-step ${hasSource ? 'is-ready' : 'is-blocked'}"><strong>1</strong> Source ${escapeHtml(sourceState)}</span>
      <span class="neo-source-step ${hasMask ? 'is-ready' : 'is-blocked'}"><strong>2</strong> Mask ${escapeHtml(maskState)}</span>
      <span class="neo-source-step is-info"><strong>3</strong> Target: ${escapeHtml(targetLabel)}</span>
      <span class="neo-source-step is-info"><strong>4</strong> Context: ${escapeHtml(contextLabel)}</span>
    </div>
    <p class="neo-muted">${escapeHtml(editHint)} Black preserves; white edits. Target/context selectors stay in Params so route profiles remain honest.</p>
  </div>`;
}


function renderImageSourcePanelBody() {
  const hasSource = Boolean(state.imageDraft.source_image || state.imageDraft.source_image_url);
  const isInpaint = imageNeedsMaskPanel();
  const isOutpaint = imageNeedsOutpaintCanvas();
  const hasMask = Boolean(state.imageDraft.mask_image || state.imageDraft.mask_image_url);
  const maskPreviewUrl = state.imageDraft.mask_image_preview_url || state.imageDraft.mask_image_url || '';
  const outpaintBadge = isOutpaint && outpaintHasPadding()
    ? `<span class="neo-source-mask-chip neo-outpaint-chip">Outpaint ${Number(state.imageDraft.outpaint_left || 0)}/${Number(state.imageDraft.outpaint_top || 0)}/${Number(state.imageDraft.outpaint_right || 0)}/${Number(state.imageDraft.outpaint_bottom || 0)}</span>`
    : '';
  const renderPrimarySourcePreview = () => state.imageDraft.source_image_url
    ? `<button class="neo-source-preview neo-zoomable-preview ${isInpaint && hasMask ? 'has-mask-preview' : ''} ${isOutpaint && outpaintHasPadding() ? 'has-outpaint-preview' : ''}" type="button" data-zoom-src="${escapeAttr(state.imageDraft.source_image_url)}" data-zoom-label="${escapeAttr(sourceImageLabel())}" title="Open source image zoom"><span class="neo-source-preview-stack"><img src="${escapeAttr(state.imageDraft.source_image_url)}" alt="Selected source image" data-image-source-dim-probe="1">${isInpaint && hasMask && maskPreviewUrl ? `<img class="neo-source-mask-preview" src="${escapeAttr(maskPreviewUrl)}" alt="Saved inpaint mask overlay"><span class="neo-source-mask-chip">Mask overlay</span>` : ''}${outpaintBadge}</span></button>`
    : `<div class="neo-source-empty"><strong>No source image selected</strong><span>Upload an image or send one from Output Inspector.</span></div>`;
  const preview = renderPrimarySourcePreview();
  const maskStatus = isInpaint
    ? `<div class="neo-source-meta neo-mask-inline-status"><span class="neo-badge ${hasMask ? 'success' : 'warning'}">Mask: ${hasMask ? 'ready' : 'not painted'}</span>${hasMask ? `<span class="neo-badge">${escapeHtml(maskImageLabel())}</span>` : ''}</div>`
    : '';
  const maskWorkflow = isInpaint ? renderImageSourceMaskWorkflowCard({ hasSource, hasMask }) : '';
  const maskActions = isInpaint
    ? `<button class="neo-btn primary" id="imageOpenMaskEditorBtn" type="button" ${hasSource ? '' : 'disabled'} title="${hasSource ? 'Paint or refine the inpaint mask on this source image' : 'Select a source image before painting a mask'}">Edit Mask</button><button class="neo-btn secondary" id="imageClearMaskBtn" type="button" ${hasMask ? '' : 'disabled'} title="Clear the saved mask attached to this source image">Clear Mask</button>`
    : '';
  const outpaintActions = isOutpaint
    ? `<button class="neo-btn primary" id="imageOpenOutpaintEditorBtn" type="button" ${hasSource ? '' : 'disabled'}>Outpaint Canvas</button><button class="neo-btn secondary" id="imageResetOutpaintBtn" type="button" ${outpaintHasPadding() ? '' : 'disabled'}>Reset Padding</button>`
    : '';
  const multiReferenceActive = imageMultiReferenceActive();
  const multiReferenceLabel = imageMultiReferenceLabel();
  const qwenRefs = multiReferenceActive
    ? `<div class="neo-source-qwen-stack ${cloudMultiImageEditActive() ? 'neo-cloud-multi-source-stack' : ''}" data-testid="image-multi-reference-panel">
        <div class="neo-source-stack-header">
          <div>
            <strong>Source Images</strong>
            <p class="neo-muted">Image 1 is the anchor. Add image 2 and image 3 only when they have a clear role in the edit/composition.</p>
          </div>
          <span class="neo-badge">${escapeHtml(multiReferenceLabel)}</span>
        </div>
        <label class="neo-source-file-label">Image 1 Role
          ${optionSelect('imageQwenSourceRole1', qwenSourceRoleOptions(1), state.imageDraft.source_image_1_role || 'main_subject')}
        </label>
        ${[2, 3].filter((lane) => qwenVisibleSourceSlotCount() >= lane).map((lane) => renderQwenSourceCard(lane)).join('')}
        ${qwenVisibleSourceSlotCount() < 3 ? `<button class="neo-btn secondary neo-add-source-btn" id="imageQwenAddSourceBtn" type="button">+ Add source image</button>` : ''}
        <p class="neo-muted">${escapeHtml(imageMultiReferenceHelpText())}</p>
      </div>`
    : '';
  const imagePreparation = `<details class="neo-source-image-preparation" data-testid="image-preparation-section">
      <summary><strong>Image Preparation</strong><span class="neo-muted">Crop or align an image/mask before Inpaint, Outpaint, or Stitch</span></summary>
      <p class="neo-muted">Open Image → Finish → Remove Background → Mask & Object Utilities and choose <strong>Image Crop</strong> or <strong>Image + Mask Resize</strong>. The original source stays unchanged; the derived PNG becomes a selectable Neo result for the next route.</p>
      <div class="neo-badge-row"><span class="neo-badge">Image Crop</span><span class="neo-badge">Image + Mask Resize</span><span class="neo-badge">Mask alignment preserved</span></div>
      <button class="neo-btn secondary" id="imageOpenPreparationUtilitiesBtn" type="button">Open Image Preparation Utilities</button>
    </details>`;
  return `
    <div class="neo-source-panel ${hasSource ? 'has-source' : ''} ${isInpaint ? 'neo-unified-inpaint-source' : ''}">
      ${multiReferenceActive ? renderQwenSourcePreviewStack(preview) : `<div class="neo-source-preview-wrap" data-neo-image-dropzone="true" data-neo-image-kind="source" data-neo-image-lane="1" data-neo-image-input="imageSourceFile">${preview}</div>`}
      <div class="neo-source-controls">
        <label class="neo-source-file-label neo-file-action">Replace Source
          <input id="imageSourceFile" type="file" accept="image/png,image/jpeg,image/webp,image/bmp,.png,.jpg,.jpeg,.webp,.bmp">
        </label>
        <div class="neo-source-meta">
          <span class="neo-badge">Mode: ${escapeHtml(getImageWorkflowMode() || 'generate')}</span>
          <span class="neo-badge">${escapeHtml(sourceImageLabel())}</span>
        </div>
        ${maskStatus}
        ${maskWorkflow}
        ${state.imageDraft.source_image ? `<div class="neo-source-path">${escapeHtml(state.imageDraft.source_image)}</div>` : ''}
        <div class="neo-source-actions neo-source-actions-grid">
          <button class="neo-btn secondary" id="imageClearSourceBtn" type="button" ${hasSource ? '' : 'disabled'}>Clear Source</button>
          ${maskActions}
          ${outpaintActions}
        </div>
        ${isInpaint ? '<p class="neo-muted">Use the same source image for masking. Mask controls stay attached to the source preview. Changing or clearing the source also clears the saved mask to avoid mismatched inpaint inputs.</p>' : ''}
        ${isOutpaint ? '<p class="neo-muted">Use the same source image as the center canvas. Click <strong>Outpaint Canvas</strong> to expand sides.</p>' : ''}
        ${qwenRefs}
        ${imagePreparation}
        ${renderQwenStitchSection()}
      </div>
    </div>`;
}

function renderImageMaskPanelBody() {
  return panel('Inpaint Mask Editor', '<p class="neo-muted">Inpaint uses the shared Source Image panel. Click <strong>Edit Mask</strong> there to paint a black/white mask on the same image.</p>');
}

function imageFieldDraftKey(fieldId) {
  const map = {
    checkpoint: 'checkpoint',
    diffusion_model: 'diffusion_model',
    gguf_model: 'gguf_model',
    vae: 'vae',
    sampler: 'sampler',
    scheduler: 'scheduler',
    width: 'width',
    height: 'height',
    steps: 'steps',
    seed: 'seed',
    batch_count: 'batch_count',
    cfg: 'cfg',
    clip_skip: 'clip_skip',
    flux_guidance: 'flux_guidance',
    flux_variant: 'flux_variant',
    text_encoder_1: 'text_encoder_1',
    text_encoder_2: 'text_encoder_2',
    qwen_text_encoder: 'qwen_text_encoder',
    qwen3_text_encoder: 'qwen3_text_encoder',
    qwen_mmproj: 'qwen_mmproj',
  };
  return map[fieldId] || fieldId;
}
// Regression guard: const samplerOptions = profileModelOptions('samplers'); const schedulerOptions = profileModelOptions('schedulers');
const IMAGE_MODEL_FIELD_CATALOGS = Object.freeze({
  checkpoint: 'models',
  qwen_rapid_aio_checkpoint: 'models',
  diffusion_model: 'diffusion_models',
  gguf_model: 'gguf_models',
  text_encoder_1: 'text_encoders',
  text_encoder_2: 'text_encoders',
  qwen_text_encoder: 'qwen_text_encoders',
  qwen3_text_encoder: 'qwen_text_encoders',
});
function imageModelCatalogForField(fieldId) {
  return IMAGE_MODEL_FIELD_CATALOGS[fieldId] || '';
}
// Regression guard: if (fieldId === 'diffusion_model') return profileModelOptions('diffusion_models');
function imageOptionsForField(fieldId) {
  if (isImageGgufRuntimeActive()) {
    if (fieldId === 'text_encoder_1') return profileModelOptions('gguf_text_encoder_primary');
    if (fieldId === 'text_encoder_2') return profileModelOptions('gguf_text_encoder_secondary');
    if (['qwen_text_encoder', 'qwen3_text_encoder'].includes(fieldId)) return profileModelOptions('gguf_text_encoders');
  }
  const modelCatalog = imageModelCatalogForField(fieldId);
  if (modelCatalog) {
    const options = profileModelOptions(modelCatalog);
    if (options.length || !['qwen_text_encoder', 'qwen3_text_encoder'].includes(fieldId)) return options;
    return profileModelOptions('text_encoders');
  }
  if (fieldId === 'vae') return isImageGgufRuntimeActive() ? profileModelOptions('gguf_vaes') : profileModelOptions('vaes');
  if (fieldId === 'sampler') return profileModelOptions('samplers');
  if (fieldId === 'scheduler') return profileModelOptions('schedulers');
  if (fieldId === 'text_encoder_1') return isImageGgufRuntimeActive() ? profileModelOptions('gguf_text_encoder_primary') : profileModelOptions('text_encoders');
  if (fieldId === 'text_encoder_2') return isImageGgufRuntimeActive() ? profileModelOptions('gguf_text_encoder_secondary') : profileModelOptions('text_encoders');
  if (fieldId === 'qwen_text_encoder') return isImageGgufRuntimeActive() ? profileModelOptions('gguf_text_encoders') : profileModelOptions('text_encoders');
  if (fieldId === 'qwen3_text_encoder') return isImageGgufRuntimeActive() ? profileModelOptions('gguf_text_encoders') : profileModelOptions('text_encoders');
  if (fieldId === 'qwen_mmproj') return profileModelOptions('mmproj');
  if (fieldId === 'hidream_variant') return [
    { id: 'HiDream-I1', label: 'HiDream-I1' },
    { id: 'HiDream-E1', label: 'HiDream-E1' },
    { id: 'HiDream-O1', label: 'HiDream-O1' },
  ];
  if (fieldId === 'flux_variant') return [
    { id: 'dev', label: 'Dev' },
    { id: 'schnell', label: 'Schnell' },
    { id: 'fill', label: 'Fill / Inpaint' },
    { id: 'kontext', label: 'Kontext' },
    { id: 'krea', label: 'Krea' },
    { id: 'klein_4b', label: 'FLUX.2 Klein 4B' },
    { id: 'klein_9b', label: 'FLUX.2 Klein 9B' },
  ];
  if (fieldId === 'outpaint_source_resolution_mode') return imageOutpaintSourceResolutionOptions();
  if (fieldId === 'inpaint_selection_target') return [
    { id: 'masked_area', label: 'Inpaint masked area' },
    { id: 'not_masked_area', label: 'Inpaint not masked' },
  ];
  if (fieldId === 'inpaint_context_mode') return [
    { id: 'full_image_context', label: 'Full image context' },
    { id: 'masked_region_focus', label: 'Masked region focus' },
  ];
  return [];
}

function renderImageParameterField(field, p) {
  const fieldId = field.field_id;
  if (['positive_prompt', 'negative_prompt', 'source_image', 'mask_image', 'outpaint_padding', 'width', 'height'].includes(fieldId)) return '';
  const key = imageFieldDraftKey(fieldId);
  const id = `imageParam_${fieldId}`;
  const value = p[key] ?? field.default ?? '';
  const label = escapeHtml(field.label || humanize(fieldId));
  const helpText = field.help_text && state.detailMode !== 'compact' ? `<small class="neo-muted">${escapeHtml(field.help_text)}</small>` : '';
  const required = field.required ? '<span class="neo-state-pill warning">Required</span>' : '';
  if (field.control_type === 'status') {
    const statusValue = fieldId === 'gguf_loader_status'
      ? `${state.imageDraft.loader === 'gguf' ? 'GGUF loader selected' : 'Waiting for GGUF loader'}`
      : `${label} tracked by readiness validator`;
    return `<label class="neo-param-field neo-param-status"><span>${label}</span><span class="neo-badge">${escapeHtml(statusValue)}</span>${required}${helpText}</label>`;
  }
  if (field.control_type === 'select') {
    const options = imageOptionsForField(fieldId);
    const select = optionSelect(id, options, value);
    return `<label class="neo-param-field" data-profile-field="${escapeAttr(fieldId)}"><span>${label}</span>${select}${required}${helpText}</label>`;
  }
  const step = fieldId === 'flux_guidance' || fieldId === 'cfg' ? '0.1' : '1';
  const inputType = field.control_type === 'slider' || field.control_type === 'number' ? 'number' : 'text';
  return `<label class="neo-param-field" data-profile-field="${escapeAttr(fieldId)}"><span>${label}</span><input id="${id}" type="${inputType}" step="${step}" value="${escapeAttr(value)}" aria-label="${escapeAttr(label)}">${required}${helpText}</label>`;
}
const IMAGE_COMPONENT_PARAMETER_FIELD_IDS = new Set([
  'text_encoder_1',
  'text_encoder_2',
  'qwen_text_encoder',
  'qwen3_text_encoder',
  'flux_guidance',
  'hidream_variant',
]);

function activeImageComponentParameterFields() {
  const loader = state.imageDraft.loader || imageCommandValue('loader') || 'checkpoint';
  if (!['diffusion_model', 'unet'].includes(loader)) return [];
  const hidden = activeParameterProfileHiddenFields();
  return activeImageParameterFields().filter((field) => (
    IMAGE_COMPONENT_PARAMETER_FIELD_IDS.has(field.field_id)
    && !hidden.has(field.field_id)
  ));
}

function renderImageComponentParameterRows(p = {}) {
  const fields = activeImageComponentParameterFields();
  if (!fields.length) return '';
  const fieldHtml = fields.map((field) => renderImageParameterField(field, p)).filter(Boolean).join('');
  if (!fieldHtml) return '';
  return `<div class="neo-parameter-profile-card neo-component-asset-card" data-testid="image-safetensors-component-assets">
    <div class="neo-ui-section-head"><div><strong>Required Model Components</strong><p class="neo-muted">Select the exact ComfyUI text encoder and route-specific component values. Neo does not guess installed filenames.</p></div><span class="neo-badge">Safetensors / Components</span></div>
    <div class="neo-parameter-row neo-dynamic-profile-row">${fieldHtml}</div>
  </div>`;
}

function renderDynamicImageParameterRows(p) {
  const profile = activeImageParameterProfile();
  const rawFields = activeImageParameterFields();
  const ggufActive = isImageGgufRuntimeActive();
  const fields = ggufActive ? rawFields.filter((field) => !GGUF_RUNTIME_FIELD_IDS.has(field.field_id)) : rawFields;
  if (!profile || (!fields.length && !ggufActive)) return '';
  const hidden = profile.hidden_fields || [];
  const disabled = profile.disabled_fields || [];
  const readiness = profile.readiness_fields || [];
  const fieldHtml = fields.map((field) => renderImageParameterField(field, p)).filter(Boolean).join('');
  const ggufRuntime = renderGgufRuntimeCard(p);
  const profileBadges = [
    `Profile: ${profile.display_name || profile.profile_id}`,
    `Family: ${state.imageDraft.family || 'sdxl'}`,
    `Main Model Type: ${imageMainModelTypeLabel(state.imageDraft.loader || 'checkpoint')}`,
    `Mode: ${activeImageMode()}`,
  ];
  return `<div class="neo-parameter-profile-card">
    ${state.detailMode !== 'compact' ? badgeRow(profileBadges) : ''}
    ${fieldHtml ? `<div class="neo-parameter-row neo-dynamic-profile-row">${fieldHtml}</div>` : ''}
    ${ggufRuntime}
    ${state.detailMode !== 'compact' && !ggufActive && hidden.length ? `<p class="neo-muted">Hidden by profile: ${escapeHtml(hidden.join(', '))}</p>` : ''}
    ${state.detailMode !== 'compact' && !ggufActive && disabled.length ? `<p class="neo-muted">Disabled by profile: ${escapeHtml(disabled.join(', '))}</p>` : ''}
    ${state.detailMode !== 'compact' && !ggufActive && readiness.length ? `<p class="neo-muted">Readiness fields: ${escapeHtml(readiness.join(', '))}</p>` : ''}
  </div>`;
}


function cfgDisabledPlaceholderLabel() {
  const family = state.imageDraft.family || imageCommandValue('family') || '';
  const loader = state.imageDraft.loader || imageCommandValue('loader') || '';
  if (['flux', 'flux2_klein'].includes(family) && loader === 'gguf') return 'CFG handled by Flux Guidance';
  if (family === 'flux') return 'CFG handled by Flux Guidance';
  return 'CFG unavailable for selected route';
}

function activeParameterProfileHiddenFields() {
  const profile = activeImageParameterProfile();
  return new Set(profile?.hidden_fields || []);
}
function shouldShowProfileField(fieldId) {
  if (isCloudImageProfile()) return false;
  return routeUsesParameterField(fieldId) && !activeParameterProfileHiddenFields().has(fieldId);
}

function renderImageOutpaintSourceResolutionRow(p = {}) {
  if (!imageNeedsOutpaintCanvas() || !shouldShowProfileField('outpaint_padding')) return '';
  const policy = imageOutpaintSourceResolutionPolicy({ ...state.imageDraft, ...p });
  const mode = policy.mode || 'auto';
  const maxLongEdge = Number(state.imageDraft.outpaint_source_max_long_edge || p.outpaint_source_max_long_edge || policy.max_long_edge || 1536);
  const maxMegapixels = Number(state.imageDraft.outpaint_source_max_megapixels || p.outpaint_source_max_megapixels || policy.max_megapixels || 4);
  const source = policy.source_size || {};
  const sourceMeta = source.width && source.height ? `Original: ${source.width}×${source.height} · ${source.megapixels} MP` : 'Original size unknown until source preview loads';
  return `<div class="neo-parameter-row neo-outpaint-source-resolution-row" data-testid="image-outpaint-source-resolution-controls">
    <label>Source Resolution${optionSelect('imageOutpaintSourceResolutionMode', imageOutpaintSourceResolutionOptions(), mode)}</label>
    <label>Max Long Edge<input id="imageOutpaintSourceMaxLongEdge" type="number" min="512" max="4096" step="64" value="${escapeAttr(maxLongEdge)}" aria-label="Outpaint source max long edge"></label>
    <label>Max Canvas MP<input id="imageOutpaintSourceMaxMegapixels" type="number" min="0.25" max="16" step="0.25" value="${escapeAttr(maxMegapixels)}" aria-label="Outpaint source max megapixels"></label>
    <span class="neo-muted neo-param-note"><strong>${escapeHtml(imageOutpaintSourceResolutionSummary(policy))}</strong><br>${escapeHtml(sourceMeta)} · ${escapeHtml(policy.reason || '')}</span>
  </div>`;
}

function renderImageInpaintVisibilityRow(p = {}) {
  const targetVisible = shouldShowProfileField('inpaint_selection_target');
  const contextVisible = shouldShowProfileField('inpaint_context_mode');
  const fluxKontextActive = state.imageDraft.family === 'flux'
    && state.imageDraft.loader === 'diffusion_model'
    && String(state.imageDraft.flux_variant || '').toLowerCase() === 'kontext'
    && activeImageMode() === 'inpaint';
  if (!targetVisible && !contextVisible && !fluxKontextActive) return '';
  const targetValue = p.inpaint_selection_target || state.imageDraft.inpaint_selection_target || 'masked_area';
  const contextValue = p.inpaint_context_mode || state.imageDraft.inpaint_context_mode || 'masked_region_focus';
  const contextLatentCard = fluxKontextActive ? `<div class="neo-context-latent-card" data-testid="image-context-latent-controls">
    <div class="neo-ui-section-head"><div><strong>RMBG Context + Latent Assist</strong><p class="neo-muted">Experimental Flux Kontext route. Reuses Image 1 latent context and the existing inpaint mask through the live Reference Latent Mask node.</p></div><span class="neo-badge">Live-gated</span></div>
    <label class="neo-check-row"><input id="imageContextLatentEnabled" type="checkbox" ${state.imageDraft.context_latent_enabled ? 'checked' : ''}> Enable Reference Latent Mask</label>
    <div class="neo-parameter-row"><label>Mask Expand<input id="imageContextLatentExpand" type="number" min="-64" max="64" step="1" value="${escapeAttr(state.imageDraft.context_latent_expand ?? 5)}"></label><label>Mask Blur<input id="imageContextLatentBlur" type="number" min="0" max="64" step="0.1" value="${escapeAttr(state.imageDraft.context_latent_blur ?? 3)}"></label><label class="neo-check-row"><input id="imageContextLatentMaskOnly" type="checkbox" ${state.imageDraft.context_latent_mask_only !== false ? 'checked' : ''}> Mask-only latent</label></div>
    <p class="neo-muted">The run is blocked if the exact live AILab_ReferenceLatentMask contract or an inpaint mask is unavailable. No fallback route is used.</p>
  </div>` : '';
  return `<div class="neo-parameter-row neo-inpaint-visibility-row" data-testid="image-inpaint-visibility-controls">
    ${targetVisible ? `<label>Inpaint Target${optionSelect('imageParam_inpaint_selection_target', imageOptionsForField('inpaint_selection_target'), targetValue)}</label>` : ''}
    ${contextVisible ? `<label>Inpaint Context${optionSelect('imageParam_inpaint_context_mode', imageOptionsForField('inpaint_context_mode'), contextValue)}</label>` : ''}
    <span class="neo-muted neo-param-note">Shown only when the active route profile exposes masked/not-masked area controls.</span>
  </div>${contextLatentCard}`;
}

function checkpointModelValue(p = {}) {
  // Loader-specific guardrail: checkpoint routes must not inherit stale diffusion/GGUF model selections.
  const draftModel = String(state.imageDraft.model || '');
  const rejectsStaleGguf = !draftModel.toLowerCase().endsWith('.gguf');
  void rejectsStaleGguf;
  return state.imageDraft.checkpoint || p.checkpoint || 'provider_default';
}
function imageModelComponentRouteNote() {
  const family = state.imageDraft.family || imageCommandValue('family') || 'sdxl';
  const loader = state.imageDraft.loader || imageCommandValue('loader') || defaultLoaderForFamily(family);
  if (loader === 'checkpoint_aio') return family === 'qwen_rapid_aio' ? 'Qwen Rapid AIO bundled route. Main model contains the needed AIO parts; extra encoder/VAE fields stay hidden unless Advanced Override enables them.' : 'Bundled model route. Extra encoder/VAE fields stay hidden unless Advanced Override enables them.';
  if (loader === 'diffusion_model' || loader === 'unet') return family === 'flux2_klein' ? 'Flux 2 Klein component route. P4 enables native img2img/edit/inpaint/outpaint with one Qwen3 encoder, Flux2 VAE, and Image 1 latent-anchor mask/canvas workflows.' : (family === 'flux1_fill' ? 'Flux 1 Fill is now an internal Flux 1 fill route. Use a FLUX.1 Fill-dev compatible model for inpaint/outpaint.' : (family === 'qwen_image_edit_2509' ? 'Qwen Image Edit 2509 component route. P3 promotes Image 1 plus optional Image 2/Image 3 for multi-source img2img/edit; inpaint/outpaint use single-source mask/canvas.' : 'Component route. Encoder and AE/VAE fields appear only when this family needs them.'));
  if (loader === 'gguf') return family === 'flux2_klein' ? 'Flux 2 Klein GGUF route. Single Qwen3 encoder; Image 1 plus optional Image 2/Image 3 appear for image-conditioned modes.' : (family === 'qwen_rapid_aio' ? 'Qwen Rapid AIO GGUF route. Uses one Qwen text encoder; MMProj appears for image-conditioned routes; Image 2/Image 3 appear only for img2img/edit.' : (family === 'qwen_image_edit_2509' ? 'Qwen Image Edit 2509 GGUF route. Supports Image 1 plus optional Image 2/Image 3 for multi-source edit modes; MMProj appears for image-conditioned routes.' : 'GGUF route. Neo resolves backend architecture automatically from family + model type.')); 
  return 'Checkpoint route. Extra model components stay hidden unless this family needs them.';
}

function renderImagePrimaryModelRow(p) {
  if (isCloudImageProfile()) return '';
  if (isImageGgufRuntimeActive()) return '';
  const fieldId = imagePrimaryModelFieldId();
  const label = 'Main Model';
  const value = fieldId === 'checkpoint'
    ? checkpointModelValue(p)
    : fieldId === 'diffusion_model'
      ? (state.imageDraft.diffusion_model || p.diffusion_model || 'provider_default')
      : (state.imageDraft[fieldId] || state.imageDraft.model || p.model || 'provider_default');
  const bundledCheckpoint = (state.imageDraft.loader || imageCommandValue('loader')) === 'checkpoint_aio';
  const vaeField = bundledCheckpoint
    ? ''
    : `<label>VAE${optionSelect('imageVae', imageOptionsForField('vae'), p.vae || 'automatic')}</label>`;
  return `<div class="neo-parameter-row neo-model-vae-row${bundledCheckpoint ? ' neo-model-bundled-row' : ''}">
    <label>${label}${optionSelect(fieldId === 'model' ? 'imageModel' : `imageParam_${fieldId}`, imageOptionsForField(fieldId), value)}</label>
    ${vaeField}
    <span class="neo-muted neo-param-note">${escapeHtml(imageModelComponentRouteNote())}</span>
  </div>`;
}
function renderProfileCapabilitySummary() {
  const profile = activeImageParameterProfile();
  if (!profile || state.detailMode === 'compact') return '';
  const hidden = profile.hidden_fields || [];
  const hiddenText = hidden.length ? ` · Hidden: ${hidden.join(', ')}` : '';
  return `<p class="neo-muted">Parameters are resolved from selected family + main model type + workflow mode.${escapeHtml(hiddenText)}</p>`;
}

function imageLatentCaptureOptions() {
  return [
    { id: 'off', label: 'Off' },
    { id: 'final_latent', label: 'Final latent only' },
    { id: 'milestone_checkpoints', label: 'Milestone checkpoints' },
    { id: 'full_debug_checkpoints', label: 'Full debug checkpoints' },
  ];
}

function imageLatentCaptureRequestedRestorePoints(mode) {
  if (mode === 'final_latent') return ['final_latent'];
  if (mode === 'milestone_checkpoints' || mode === 'full_debug_checkpoints') return ['base_generation_only', 'before_high_res_fix', 'after_high_res_fix', 'before_adetailer', 'final_latent'];
  return [];
}

function imageLatentCaptureHelp(mode) {
  if (mode === 'final_latent') return 'Requests provider capture of the final latent before VAE decode. Resume stays disabled until the provider returns an artifact.';
  if (mode === 'milestone_checkpoints') return 'Requests key restore points for later branch/regenerate work. Requires provider-owned latent hooks.';
  if (mode === 'full_debug_checkpoints') return 'Heavy debug request for future provider hooks. Use carefully; storage can grow fast.';
  return 'Off. Neo saves replay metadata only.';
}

function imageSectionBody(section, imageSetup, surface, subtab) {
  const workspaceExtensions = activeWorkspaceExtensions('image', activeWorkspaceApp().id, subtab.subtab_id);
  const activeProviders = (state.providers?.providers || []).filter((provider) => provider.surfaces?.includes('image'));
  const help = state.detailMode === 'compact' ? '' : `<p>${section.description}</p>`;
  const expert = state.detailMode === 'expert' ? `<p>Slot: <code>${section.slot}</code></p>${listItems(section.fields)}` : '';

  if (section.section_id === 'backend') {
    return `${help}<label>Backend</label>${optionSelect('imageBackend', activeProviders.map((provider) => ({ id: provider.provider_id, label: provider.display_name })), 'comfyui_portable')}${badgeRow(activeProviders.map((provider) => `${provider.provider_id}: ${provider.status}`))}${expert}`;
  }
  if (section.section_id === 'model') {
    const selectedFamily = state.imageDraft.family || 'sdxl';
    const selectedLoader = state.imageDraft.loader || 'checkpoint';
    const family = modelFamilyMeta(selectedFamily);
    const familyInfo = family && state.detailMode !== 'compact' ? `<div class="neo-family-summary">${badgeRow([`Default model type: ${imageMainModelTypeLabel(family.default_loader, family.default_loader)}`, `Status: ${family.status}`, ...family.supported_backends.map((backend) => `Backend: ${backend}`)])}<p class="neo-muted">${family.description}</p></div>` : '';
    return `${help}<label>Model Family</label>${optionSelect('imageFamily', familyOptionList('image'), selectedFamily)}<label>Main Model Type</label>${optionSelect('imageLoader', loaderOptionList(selectedFamily), selectedLoader)}${familyInfo}${expert}`;
  }
  if (section.section_id === 'prompt') {
    const negativeVisible = !isCloudImageProfile() || imageProfileSupportsCapability('negative_prompt');
    const negativeBlock = negativeVisible
      ? `<label>Negative Prompt</label><textarea id="imageNegativePrompt" placeholder="Things to avoid...">${escapeHtml(state.imageDraft.negative_prompt)}</textarea>`
      : `<p class="neo-muted neo-cloud-hidden-note">Negative prompt is hidden because the selected cloud image profile does not expose a native negative prompt field.</p>`;
    const libraryBar = renderImagePromptLibraryBar();
    return `${help}${libraryBar}<label>Positive Prompt</label><textarea id="imagePositivePrompt" placeholder="Describe the image...">${escapeHtml(state.imageDraft.positive_prompt)}</textarea>${negativeBlock}${state.detailMode !== 'compact' ? badgeRow(['Prompt Assist', 'Style chips', isCloudImageProfile() ? 'Cloud profile gated' : 'Saved prompt pairs']) : ''}${expert}`;
  }
  if (section.section_id === 'source') {
    return `${help}${renderImageSourcePanelBody()}${expert}`;
  }
  if (section.section_id === 'mask') {
    return `${help}${renderImageMaskPanelBody()}${expert}`;
  }
  if (section.section_id === 'instruction') {
    return `${help}<label>Edit Instruction</label><textarea placeholder="Tell the model what to change..."></textarea>${expert}`;
  }
  if (section.section_id === 'params') {
    applyQwenRapidAioRuntimeDefaultsIfNeeded();
    const p = { ...(imageSetup.default_params || {}), ...state.imageDraft };
    if (isCloudImageProfile()) return `${help}${renderCloudImageParameterRows(p)}${expert}`;
    const presets = imageSizePresetOptions();
    const ggufRuntime = renderGgufRuntimeCard(p);
    const primaryModelRow = renderImagePrimaryModelRow(p);
    const componentParameterRows = renderImageComponentParameterRows(p);
    const cfgVisible = shouldShowProfileField('cfg');
    const clipSkipVisible = shouldShowProfileField('clip_skip');
    const denoiseVisible = shouldShowProfileField('denoise');
    const clampOptions = [
      { id: 'raw', label: 'Raw' },
      { id: 'soft_clamp', label: 'Soft Clamp' },
      { id: 'balanced', label: 'Balanced' },
    ];
    return `${help}<div class="neo-parameter-stack">
      ${primaryModelRow}
      ${componentParameterRows}
      ${ggufRuntime}
      <div class="neo-parameter-row neo-sampler-scheduler-row">
        <label>Sampler${optionSelect('imageSampler', imageOptionsForField('sampler'), p.sampler || 'provider_default')}</label>
        <label>Scheduler${optionSelect('imageScheduler', imageOptionsForField('scheduler'), p.scheduler || 'provider_default')}</label>
      </div>
      <div class="neo-parameter-row neo-size-row">
        <label>Width<input id="imageWidth" type="number" value="${p.width}" aria-label="Width"></label>
        <label>Height<input id="imageHeight" type="number" value="${p.height}" aria-label="Height"></label>
        <div class="neo-size-helper-control" aria-label="Size helper controls">
          <button class="neo-icon-btn icon" id="imageSwapSizeBtn" type="button" title="Swap width and height" aria-label="Swap width and height" data-tooltip="Swap width and height">🔁</button>
          <label class="neo-size-scale-control" title="Scale width and height together, preserving the current ratio"><span class="neo-size-scale-icon" aria-hidden="true">📐</span><input id="imageAspectScale" type="range" min="0.5" max="1.5" step="0.01" value="1" aria-label="Scale width and height together"></label>
        </div>
        <label class="neo-size-preset-control">Size Preset<div class="neo-inline-control">${optionSelect('imageSizePreset', presets, p.size_preset || 'square_1024')}<button class="neo-icon-btn icon" id="imageSaveSizePresetBtn" type="button" title="Save current width and height as a custom size preset" aria-label="Save current width and height as a custom size preset" data-tooltip="Save current width and height as a custom size preset">💾</button></div></label>
      </div>
      <div class="neo-parameter-row neo-generation-row ${cfgVisible ? 'has-cfg' : 'no-cfg'}">
        <label>Steps<input id="imageSteps" type="number" value="${p.steps}" aria-label="Steps"></label>
        ${cfgVisible ? `<label>CFG<input id="imageCfg" type="number" step="0.1" value="${p.cfg}" aria-label="CFG"></label>` : `<label class="neo-param-disabled">CFG<input id="imageCfgDisplay" type="text" value="${escapeAttr(cfgDisabledPlaceholderLabel())}" aria-label="CFG disabled for selected profile" disabled></label>`}
        <label class="neo-seed-control">Seed<div class="neo-inline-control"><input id="imageSeed" value="${p.seed}" aria-label="Seed">${iconButton('🔒', 'Lock seed so future generations reuse it', 'icon', 'data-image-seed-action="lock"')}${iconButton('🎲', 'Randomize seed for every generation', 'icon', 'data-image-seed-action="randomize"')}${iconButton('♻️', 'Reuse previous resolved seed', 'icon', 'data-image-seed-action="reuse"')}${iconButton('📋', 'Copy current seed', 'icon', 'data-image-seed-action="copy"')}</div></label>
        <label>Batch Count<input id="imageBatchCount" type="number" min="1" max="16" step="1" value="${p.batch_count || 1}" aria-label="Batch Count"></label>
      </div>
      <div class="neo-parameter-row neo-advanced-sampler-row">
        ${denoiseVisible ? `<label>Denoise<input id="imageDenoise" type="number" min="0" max="1" step="0.01" value="${p.denoise}" aria-label="Denoise"></label>` : ''}
        ${clipSkipVisible ? `<label>Clip Skip<input id="imageClipSkip" type="number" min="1" max="12" step="1" value="${p.clip_skip || 1}" aria-label="Clip Skip"></label>` : ''}
        <label>Prompt Conditioning${optionSelect('imageClamp', clampOptions, p.prompt_conditioning_mode || p.clamp || 'raw')}</label>
      </div>
      <div class="neo-parameter-row neo-latent-capture-row" data-testid="image-latent-capture-foundation">
        <label>Latent Capture${optionSelect('imageLatentCaptureMode', imageLatentCaptureOptions(), p.latent_capture_mode || 'off')}</label>
        <span class="neo-muted neo-param-note">${escapeHtml(imageLatentCaptureHelp(p.latent_capture_mode || 'off'))}</span>
      </div>
      ${renderImageInpaintVisibilityRow(p)}
      ${(shouldShowProfileField('mask_grow') || shouldShowProfileField('mask_blur')) ? `<div class="neo-parameter-row neo-inpaint-mask-row">
        ${shouldShowProfileField('mask_grow') ? `<label>Mask Grow<input id="imageMaskGrow" type="number" min="0" max="128" step="1" value="${p.mask_grow ?? 6}" aria-label="Mask grow"></label>` : ''}
        ${shouldShowProfileField('mask_blur') ? `<label>Mask Blur<input id="imageMaskBlur" type="number" min="0" max="128" step="1" value="${p.mask_blur ?? 0}" aria-label="Mask blur"></label>` : ''}
        <span class="neo-muted neo-param-note">Mask tuning stays profile-owned and only appears on inpaint routes that declare mask growth/blur fields.</span>
      </div>` : ''}
      ${renderImageOutpaintSourceResolutionRow(p)}
      ${shouldShowProfileField('outpaint_padding') ? `<div class="neo-parameter-row neo-outpaint-row">
        <div class="neo-outpaint-padding-grid" data-testid="outpaint-padding-grid">
          <label>Left<input id="imageOutpaintLeft" type="number" min="0" step="8" value="${p.outpaint_left || 0}" aria-label="Outpaint left"></label>
          <label>Right<input id="imageOutpaintRight" type="number" min="0" step="8" value="${p.outpaint_right || 0}" aria-label="Outpaint right"></label>
          <label>Top<input id="imageOutpaintTop" type="number" min="0" step="8" value="${p.outpaint_top || 0}" aria-label="Outpaint top"></label>
          <label>Bottom<input id="imageOutpaintBottom" type="number" min="0" step="8" value="${p.outpaint_bottom || 0}" aria-label="Outpaint bottom"></label>
        </div>
        <label class="neo-outpaint-feather-field">Feather<input id="imageOutpaintFeather" type="number" min="0" max="256" step="1" value="${p.outpaint_feather ?? 32}" aria-label="Outpaint feather"></label>
      </div>` : ''}
    </div>${renderProfileCapabilitySummary()}${expert}`;
  }

  if (section.section_id === 'extensions') {
    const externalTitle = neoFeatureTitleCard('Image Extensions', 'External Extensions', 'Workspace-mounted extension panels from installed extension packages.', ['external', 'workspace scoped', `${workspaceExtensions.external.length} mounted`], { testId: 'image-external-extensions-feature-title-card', extraClass: 'neo-image-feature-title-card' });
    const externalCards = workspaceExtensions.external.map((record) => {
      const gate = imageExtensionAllowedForActiveProfile(record);
      return gate.allowed ? extensionCard(record, { collapsible: true }) : renderProviderGatedExtensionPanel(record, gate.reason);
    }).join('');
    return `${help}${externalTitle}${workspaceExtensions.external.length ? externalCards : '<p>No external extensions mounted into this workspace yet.</p>'}${expert}`;
  }
  if (section.section_id === 'run') {
    return `${help}<div class="neo-run-readiness-note" data-testid="image-run-actions-cleaned"><strong>Generation actions</strong><p>Use the main Generate button in the Image header. Queue, board, and cancel controls stay hidden until real handlers exist.</p></div>${expert}`;
  }
  if (section.section_id === 'preview') {
    const activeOutput = state.imageResults[state.activeResultIndex];
    const liveSourceContext = buildLivePreviewActionSource(activeOutput || {});
    const preview = activeOutput?.url
      ? `<div class="neo-preview-action-wrap"><button class="neo-result-preview neo-zoomable-preview" type="button" data-zoom-src="${escapeAttr(activeOutput.url)}" data-zoom-label="${escapeAttr(activeOutput.filename || `Result ${state.activeResultIndex + 1}`)}" title="Open zoom preview"><img src="${escapeAttr(activeOutput.url)}" alt="Generated result preview"><span>${escapeHtml(activeOutput.filename || `Result ${state.activeResultIndex + 1}`)}</span></button>${renderPreviewActionToolbar(liveSourceContext, { placement: 'live_preview' })}</div>`
      : `<div class="neo-preview-action-wrap is-empty"><div class="neo-result-placeholder" id="imageResultPlaceholder">Preview</div>${renderPreviewActionToolbar(liveSourceContext, { placement: 'live_preview' })}</div>`;
    const outputs = state.imageResults.length ? state.imageResults : [];
    const batchThumbs = outputs.length
      ? outputs.map((item, index) => `<button class="neo-batch-thumb ${index === state.activeResultIndex ? 'active' : ''}" type="button" title="Set batch result ${index + 1} as main preview" aria-label="Set batch result ${index + 1} as main preview" data-tooltip="Set batch result ${index + 1} as main preview" data-result-index="${index}">${item.url ? `<img src="${escapeAttr(item.url)}" alt="Batch result ${index + 1}">` : ''}<span>${escapeHtml(item.filename || `Result ${index + 1}`)}</span></button>`).join('')
      : [1, 2, 3, 4].map((index) => `<button class="neo-batch-thumb" type="button" title="Batch result ${index}" aria-label="Batch result ${index}" data-tooltip="Batch result ${index}"><span>Preview ${index}</span></button>`).join('');
    return `${help}${preview}<div class="neo-batch-preview-strip"><div class="neo-batch-preview-head"><strong>Batch Thumbnails</strong><span class="neo-muted">Click a thumbnail to make it the main preview.</span></div><div class="neo-batch-thumbs">${batchThumbs}</div></div>${expert}`;
  }
  if (section.section_id === 'filters' || section.section_id === 'reuse') {
    return `${help}${badgeRow(section.fields)}${expert}`;
  }
  return `${help}${badgeRow(section.fields)}${expert}`;
}

function renderImageBasePanels(surface, subtab) {
  el.surfacePanels.innerHTML = '';
  el.surfacePanels.className = 'neo-workspace-split image-workspace';
  const contract = imageSubtabSetup(subtab.subtab_id);
  if (!contract) {
    el.surfacePanels.className = 'neo-grid';
    el.surfacePanels.appendChild(panel('Image Setup Missing', '<p>Image base contract is not available for this workflow mode.</p>', true));
    return;
  }

  const app = activeWorkspaceApp();
  const left = document.createElement('section');
  left.className = 'neo-workspace-column neo-workspace-left';
  const right = document.createElement('section');
  right.className = 'neo-workspace-column neo-workspace-right';

  const context = activeImageWorkspaceWorkflowSummary(subtab);
  appendNeoFirstRunPanel(left, 'image', 'Image quick start');
  const intro = fixedPanel(`${app.label} Workspace`, `
    <div class="neo-image-workspace-explainer" data-testid="image-workspace-explainer">
      <div><span class="neo-card-kicker">Workspace</span><strong>${escapeHtml(context.workspace_label)}</strong><p>${escapeHtml(context.workspace_description)}</p></div>
      <div><span class="neo-card-kicker">Workflow Mode</span><strong>${escapeHtml(context.workflow_label)}</strong><p>${escapeHtml(context.workflow_description || contract.description)}</p></div>
    </div>
    ${state.detailMode !== 'compact' ? `<p class="neo-muted">Workspace tabs organize tools. Workflow Mode controls the generation route/type. Switching workspace does not change the selected workflow mode.</p>` : `<p>${app.label} workspace · ${contract.display_name} workflow.</p>`}
    ${badgeRow([`Workspace: ${app.label}`, `Workflow Mode: ${contract.display_name}`, `Route: ${contract.mode}`, `Backend-neutral`])}
    ${state.detailMode === 'expert' ? `<pre>${JSON.stringify({ workflow_mode: contract.subtab_id, workspace_app: app, contract }, null, 2)}</pre>` : ''}
  `, 'image-workspace-summary');
  left.appendChild(intro);

  const sourceInRight = imageNeedsSourcePanel(subtab.subtab_id);
  const maskInRight = imageNeedsMaskPanel(subtab.subtab_id);
  const sections = contract.sections.filter((section) => !['backend', 'model', 'prompt', 'params', 'run', 'preview'].includes(section.section_id) && !(sourceInRight && section.section_id === 'source') && section.section_id !== 'mask');
  const appSections = sections.filter((section) => app.sections.includes(section.section_id));
  const fallbackSections = sections.filter((section) => ['extensions', 'source', 'reuse', 'filters'].includes(section.section_id));
  const leftSectionsBase = appSections.length ? appSections : (app.id === 'results' ? [] : fallbackSections.slice(0, 2));
  // Built-in extension panels must render before the generic External Extensions section.
  const leftSections = leftSectionsBase.filter((section) => section.section_id !== 'extensions');
  const externalExtensionSection = leftSectionsBase.find((section) => section.section_id === 'extensions');

  if (app.id === 'results') {
    left.appendChild(panel('Results', `${neoFeatureTitleCard('Image Results', 'Results Workspace', 'Review saved outputs, reuse selected images, inspect metadata, and manage safe output actions.', ['preview', 'reuse', 'metadata'], { testId: 'image-results-feature-title-card', extraClass: 'neo-image-feature-title-card' })}${imageResultsWorkspaceBody()}`, false, 'results-shell'));
    if (!state.imageOutputSettings && !state.imageOutputSettingsError) loadImageOutputSettings({ renderAfter: true });
    if (!state.imageReplayStorage && !state.imageReplayStorageError) loadImageReplayStorage({ renderAfter: true });
    loadImageResults();
  } else {
    leftSections.forEach((section) => {
      left.appendChild(panel(section.title, imageSectionBody(section, state.imageBase, surface, subtab), false, section.section_id));
    });

    // Finish workspace owns workflow/output finishing tools. Match built-ins by
    // workspace app first so the panel stays visible even if the current image
    // workflow mode is route-gated; the panel itself handles control visibility.
    const workspaceExtensions = activeWorkspaceExtensions(surface.surface_id, app.id, app.id === 'finish' ? null : subtab.subtab_id);
    let renderedBuiltInExtensionCount = 0;
    workspaceExtensions.builtIn.forEach((record) => {
      const gate = imageExtensionAllowedForActiveProfile(record);
      const extensionPanel = gate.allowed ? builtInExtensionPanel(record) : renderProviderGatedExtensionPanel(record, gate.reason);
      if (extensionPanel) {
        left.appendChild(extensionPanel);
        renderedBuiltInExtensionCount += 1;
      }
    });

    if (externalExtensionSection) {
      left.appendChild(panel(externalExtensionSection.title, imageSectionBody(externalExtensionSection, state.imageBase, surface, subtab), false, externalExtensionSection.section_id));
    }

    if (!leftSections.length && !renderedBuiltInExtensionCount && !externalExtensionSection) {
      left.appendChild(panel('No App-Specific Sections', '<p>This workspace app has no dedicated sections for this workflow mode.</p>', false, 'muted'));
    }
  }

  const promptSection = contract.sections.find((section) => section.section_id === 'prompt');
  const paramsSection = contract.sections.find((section) => section.section_id === 'params');
  const previewSection = contract.sections.find((section) => section.section_id === 'preview');
  const promptPreviewRow = document.createElement('section');
  promptPreviewRow.className = 'neo-prompt-preview-row';
  if (promptSection) promptPreviewRow.appendChild(fixedPanel(promptSection.title, imageSectionBody(promptSection, state.imageBase, surface, subtab), promptSection.section_id));
  if (previewSection) promptPreviewRow.appendChild(fixedPanel(previewSection.title, imageSectionBody(previewSection, state.imageBase, surface, subtab), 'preview'));
  if (promptPreviewRow.children.length) right.appendChild(promptPreviewRow);
  if (paramsSection) right.appendChild(panel(paramsSection.title, imageSectionBody(paramsSection, state.imageBase, surface, subtab), false, paramsSection.section_id));
  const sourceSection = contract.sections.find((section) => section.section_id === 'source');
  if (sourceSection && imageNeedsSourcePanel(subtab.subtab_id)) {
    right.appendChild(panel('Source Image', imageSectionBody(sourceSection, state.imageBase, surface, subtab), false, 'source-image-input'));
  }
  right.appendChild(panel('Image Memory Hooks', `
    ${state.detailMode !== 'compact' ? '<p>Base and extension actions are recorded as structured memory events so Assistant can support this workflow later.</p>' : ''}
    ${badgeRow(state.imageBase.memory_events || [])}
  `, false, 'memory'));

  el.surfacePanels.appendChild(left);
  el.surfacePanels.appendChild(right);
}


function promptCaptioningModeId(subtab) {
  const pc = state.promptCaptioning || {};
  if (pc.activeWorkspaceMode === 'captioning') return 'captioning';
  if (pc.activeWorkspaceMode === 'prompt_builder') return 'prompt_builder';
  const raw = subtab?.subtab_id || state.activeSubtabId || state.activeSubtabsBySurface?.prompt_captioning || 'prompt_builder';
  return ['captioning', 'caption_preset_details', 'caption_browser', 'batch_captioning'].includes(raw) ? 'captioning' : 'prompt_builder';
}

const PROMPT_CAPTIONING_MAIN_WORKSPACE_OPTIONS = [
  { id: 'prompt_builder', label: 'Prompt Studio' },
  { id: 'captioning', label: 'Caption Studio' },
];

// Prompt Studio helper/library panels deliberately stay embedded inside the Studio flow.
// Legacy helper panels are no longer exposed as separate subtabs.
const PROMPT_CAPTIONING_CHILD_TABS = {
  prompt_builder: [
    { id: 'prompt_preset_details', label: 'Prompt preset details' },
    { id: 'prompt_cleanup', label: 'Prompt cleanup' },
    { id: 'recent_work', label: 'Recent Work' },
    { id: 'saved_prompts', label: 'Saved Prompts' },
    { id: 'character_builder', label: 'Character Builder' },
    { id: 'keyword_browser', label: 'Keyword Browser' },
    { id: 'inspector', label: 'Inspector' },
  ],
  captioning: [
    { id: 'caption_preset_details', label: 'Caption preset details' },
    { id: 'caption_browser', label: 'Caption Browser' },
    { id: 'batch_captioning', label: 'Batch Captioning' },
    { id: 'inspector', label: 'Inspector' },
  ],
};

function promptCaptioningWorkspaceMode() {
  const pc = promptCaptioningState();
  if (pc.activeWorkspaceMode === 'captioning') return 'captioning';
  pc.activeWorkspaceMode = 'prompt_builder';
  pc.mode = 'prompt_builder';
  return 'prompt_builder';
}

function promptCaptioningChildTabsForMode(modeId = '') {
  const mode = modeId === 'captioning' ? 'captioning' : 'prompt_builder';
  return PROMPT_CAPTIONING_CHILD_TABS[mode] || PROMPT_CAPTIONING_CHILD_TABS.prompt_builder;
}

function promptCaptioningDefaultChildTab(modeId = '') {
  const tabs = promptCaptioningChildTabsForMode(modeId);
  return tabs[0]?.id || '';
}

function promptCaptioningCurrentLeftSubtab(modeId = '') {
  const pc = promptCaptioningState();
  const mode = modeId === 'captioning' ? 'captioning' : 'prompt_builder';
  const allowed = promptCaptioningChildTabsForMode(mode).map((item) => item.id);
  pc.activeChildTabsByMode = pc.activeChildTabsByMode || {};
  const laneValue = mode === 'captioning' ? pc.captioning?.activeLeftSubtab : pc.promptBuilder?.activeLeftSubtab;
  let active = '';
  // Mirror the Image tab pattern: the top rail owns state.activeWorkspaceAppId.
  // For Prompt & Captioning this ID is a left-shell tool, while state.activeSubtabId remains the main workspace route.
  if (allowed.includes(state.activeWorkspaceAppId)) active = state.activeWorkspaceAppId;
  else if (allowed.includes(pc.activeChildTabsByMode[mode])) active = pc.activeChildTabsByMode[mode];
  else if (allowed.includes(laneValue)) active = laneValue;
  else active = promptCaptioningDefaultChildTab(mode);
  pc.activeChildTabsByMode[mode] = active;
  if (mode === 'captioning') {
    pc.captioning = pc.captioning || {};
    pc.captioning.activeLeftSubtab = active;
  } else {
    pc.promptBuilder = pc.promptBuilder || {};
    pc.promptBuilder.activeLeftSubtab = active;
  }
  state.surfaceRuntime = state.surfaceRuntime || {};
  state.surfaceRuntime.prompt_captioning = { ...(state.surfaceRuntime.prompt_captioning || surfaceRuntimeDefaults('prompt_captioning')), schema_id: SURFACE_RUNTIME_SCHEMA_ID, workspace_mode: mode, child_tab: active, workspace_app: active, subtab: mode };
  syncLegacySurfaceState('prompt_captioning', state.surfaceRuntime.prompt_captioning);
  return active;
}

function promptCaptioningActiveChildTab(modeId = '') {
  return promptCaptioningCurrentLeftSubtab(modeId);
}

// Stable alias used by assist-tool panels. Keep this defined so panel renderers
// can safely ask which left-shell tab is active without throwing during render.
function promptCaptioningActiveLeftSubtab(modeId = '') {
  return promptCaptioningCurrentLeftSubtab(modeId || promptCaptioningWorkspaceMode());
}

function promptCaptioningSetWorkspaceMode(modeId = '') {
  const pc = promptCaptioningState();
  const mode = modeId === 'captioning' ? 'captioning' : 'prompt_builder';
  pc.activeWorkspaceMode = mode;
  pc.mode = mode;
  const active = promptCaptioningCurrentLeftSubtab(mode);
  state.surfaceRuntime = state.surfaceRuntime || {};
  state.surfaceRuntime.prompt_captioning = { ...(state.surfaceRuntime.prompt_captioning || surfaceRuntimeDefaults('prompt_captioning')), schema_id: SURFACE_RUNTIME_SCHEMA_ID, workspace_mode: mode, child_tab: active || promptCaptioningDefaultChildTab(mode), workspace_app: active || promptCaptioningDefaultChildTab(mode), subtab: mode };
  syncLegacySurfaceState('prompt_captioning', state.surfaceRuntime.prompt_captioning);
}

function promptCaptioningSetChildTab(childId = '', modeId = '') {
  const pc = promptCaptioningState();
  const mode = modeId === 'captioning' ? 'captioning' : promptCaptioningWorkspaceMode();
  const allowed = promptCaptioningChildTabsForMode(mode).map((item) => item.id);
  const next = allowed.includes(childId) ? childId : promptCaptioningDefaultChildTab(mode);
  pc.activeChildTabsByMode = pc.activeChildTabsByMode || {};
  pc.activeChildTabsByMode[mode] = next;
  if (mode === 'captioning') {
    pc.captioning = pc.captioning || {};
    pc.captioning.activeLeftSubtab = next;
  } else {
    pc.promptBuilder = pc.promptBuilder || {};
    pc.promptBuilder.activeLeftSubtab = next;
  }
  state.surfaceRuntime = state.surfaceRuntime || {};
  state.surfaceRuntime.prompt_captioning = { ...(state.surfaceRuntime.prompt_captioning || surfaceRuntimeDefaults('prompt_captioning')), schema_id: SURFACE_RUNTIME_SCHEMA_ID, workspace_mode: mode, child_tab: next, workspace_app: next, subtab: mode };
  syncLegacySurfaceState('prompt_captioning', state.surfaceRuntime.prompt_captioning);
}

function promptCaptioningDisplayModeSetup() {
  return window.NeoPromptCaptioningUIHelpers.displayModeSetup(state.detailMode);
}

function promptCaptioningHelperText(text) {
  return window.NeoPromptCaptioningUIHelpers.helperText(text, state.detailMode);
}

function promptCaptioningExpertDiagnostics(payload) {
  return window.NeoPromptCaptioningUIHelpers.expertDiagnostics(payload, state.detailMode);
}

function promptCaptioningDisplayModeSummary(modeId) {
  return window.NeoPromptCaptioningUIHelpers.displayModeSummary({ modeId, detailMode: state.detailMode });
}

function promptCaptioningModeLabel(modeId = '') {
  return window.NeoPromptCaptioningUIHelpers.modeLabel(modeId);
}

function promptCaptioningStudioLabel(modeId = '') {
  return window.NeoPromptCaptioningUIHelpers.studioLabel(modeId);
}

function promptCaptioningAssistToolLabel(toolId = '', modeId = '') {
  return window.NeoPromptCaptioningUIHelpers.assistToolLabel({
    toolId,
    modeId,
    childTabs: promptCaptioningChildTabsForMode(modeId),
  });
}

function promptCaptioningModeStudioAssistSummary(modeId = '', toolId = '') {
  const mode = modeId === 'captioning' ? 'captioning' : 'prompt_builder';
  return window.NeoPromptCaptioningUIHelpers.modeStudioAssistSummary({
    modeId: mode,
    toolId,
    detailMode: state.detailMode,
    childTabs: promptCaptioningChildTabsForMode(mode),
    currentLeftSubtab: promptCaptioningCurrentLeftSubtab(mode),
  });
}

function promptCaptioningSectionBody(items, helperText = '') {
  const helper = promptCaptioningHelperText(helperText);
  return `${helper}<div class="neo-badge-row">${items.map((item) => `<span class="neo-badge">${escapeHtml(item)}</span>`).join('')}</div>`;
}


function promptCaptioningProfileFlags(profile) {
  const flags = profile?.capability_flags || {};
  const runtimeFlags = profile?.runtime?.capabilities || {};
  const profileSupportsText = Boolean(flags.supports_text ?? runtimeFlags.supports_text ?? true);
  const profileSupportsVision = Boolean(flags.supports_vision ?? false);
  const profileSupportsCaptioning = Boolean(flags.supports_captioning ?? false);
  const runtimeSupportsVision = Boolean(runtimeFlags.runtime_supports_vision ?? runtimeFlags.supports_vision ?? false);
  const runtimeSupportsCaptioning = Boolean(runtimeFlags.runtime_supports_captioning ?? runtimeFlags.supports_captioning ?? false);
  const effectiveSupportsVision = profileSupportsVision || runtimeSupportsVision;
  const effectiveSupportsCaptioning = profileSupportsCaptioning || runtimeSupportsCaptioning || runtimeSupportsVision;
  return {
    supports_text: profileSupportsText,
    supports_vision: effectiveSupportsVision,
    supports_captioning: effectiveSupportsCaptioning,
    streaming_enabled: Boolean(runtimeFlags.streaming_enabled ?? flags.streaming_enabled ?? false),
    profile_supports_vision: profileSupportsVision,
    profile_supports_captioning: profileSupportsCaptioning,
    runtime_supports_vision: runtimeSupportsVision,
    runtime_supports_captioning: runtimeSupportsCaptioning,
    capability_source: profileSupportsCaptioning ? 'profile_caption_flag' : (profileSupportsVision ? 'profile_vision_flag' : ((runtimeSupportsVision || runtimeSupportsCaptioning) ? 'runtime_vision_detected' : 'profile_flag')),
  };
}

function promptCaptioningBackendProfileById(profileId) {
  const id = String(profileId || '').trim();
  if (!id) return null;
  return backendProfilesForSurface('prompt_captioning').find((profile) => profile.profile_id === id) || null;
}

function promptCaptioningSelectedBackendProfile(modeId, explicitProfileId = '') {
  const pc = promptCaptioningState();
  const localId = explicitProfileId || (modeId === 'captioning' ? pc.captioning.providerProfileId : pc.promptBuilder.providerProfileId);
  return promptCaptioningBackendProfileById(localId)
    || defaultBackendProfile('prompt_captioning')
    || defaultBackendProfile('text')
    || null;
}

function promptCaptioningCaptionGateReason(profile) {
  if (!profile) return 'missing_backend_profile';
  if (profile.enabled === false) return 'backend_profile_disabled';
  const status = backendProfileStatus(profile);
  if (['offline', 'missing_config', 'error'].includes(status)) return 'backend_profile_offline';
  const flags = promptCaptioningProfileFlags(profile);
  if (!flags.supports_vision) return 'vision_support_disabled';
  if (!flags.supports_captioning) return 'caption_support_disabled';
  return '';
}

function promptCaptioningRouteState(toolId, requiredCapability = 'text', selectedProfileId = '', modeId = '') {
  const profile = promptCaptioningSelectedBackendProfile(modeId || (requiredCapability === 'caption' ? 'captioning' : 'prompt_builder'), selectedProfileId);
  if (!profile) return { state: 'provider_gated', reason: 'missing_backend_profile: No backend profile configured.', gate_reason: 'missing_backend_profile', profile: null };
  if (profile.enabled === false) return { state: 'provider_gated', reason: `backend_profile_disabled: ${profile.display_name || profile.profile_id} is disabled.`, gate_reason: 'backend_profile_disabled', profile };
  const flags = promptCaptioningProfileFlags(profile);
  const status = backendProfileStatus(profile);
  if (!backendProfileConnectedForRuntime(profile)) return { state: 'provider_gated', reason: `backend_not_connected: ${profile.display_name || profile.profile_id} must be connected/tested before running Prompt & Captioning. Current status: ${status || 'not_checked'}.`, gate_reason: 'backend_not_connected', profile };
  if (requiredCapability === 'text' && !flags.supports_text) return { state: 'provider_gated', reason: `text_support_disabled: ${profile.display_name || profile.profile_id} does not support text.`, gate_reason: 'text_support_disabled', profile };
  if (requiredCapability === 'caption') {
    const gate = promptCaptioningCaptionGateReason(profile);
    if (gate) {
      const readable = {
        missing_backend_profile: 'No caption backend profile configured.',
        backend_profile_disabled: `${profile.display_name || profile.profile_id} is disabled.`,
        backend_profile_offline: `${profile.display_name || profile.profile_id} is ${status}.`,
        vision_support_disabled: `No backend vision model detected for ${profile.display_name || profile.profile_id}.`,
        caption_support_disabled: `Caption support disabled for ${profile.display_name || profile.profile_id}.`,
      }[gate] || `${profile.display_name || profile.profile_id} cannot run captioning.`;
      return { state: 'provider_gated', reason: `${gate}: ${readable}`, gate_reason: gate, profile };
    }
  }
  return { state: 'available', reason: `${profile.display_name || profile.profile_id} supports ${toolId}.`, gate_reason: '', profile };
}

function promptCaptioningSupportChip(label, route) {
  const state = route?.state || 'unsupported';
  const cls = state === 'available' ? 'success' : state === 'experimental_available' ? 'warning' : state === 'planned_gated' ? 'muted' : 'danger';
  return `<span class="neo-state-pill ${cls}" title="${escapeAttr(route?.reason || '')}">${escapeHtml(label)}: ${escapeHtml(state)}</span>`;
}

function promptCaptioningCapabilityPanel(modeId) {
  const promptRoute = promptCaptioningRouteState('prompt_generate', 'text', promptCaptioningProviderProfileId('prompt_builder'), 'prompt_builder');
  const captionRoute = promptCaptioningRouteState('image_captioning', 'caption', promptCaptioningProviderProfileId('captioning'), 'captioning');
  const profile = promptCaptioningSelectedBackendProfile(modeId);
  const flags = promptCaptioningProfileFlags(profile);
  const chips = modeId === 'captioning'
    ? [promptCaptioningSupportChip('Image captioning', captionRoute), promptCaptioningSupportChip('Batch captioning', captionRoute)]
    : [promptCaptioningSupportChip('Prompt tools', promptRoute), promptCaptioningSupportChip('Text transform', promptRoute)];
  const helper = promptCaptioningHelperText('Route-aware gating is active. Text tools can use text backends. Image captioning requires explicit Vision + Caption support and valid image assets.');
  const expert = promptCaptioningExpertDiagnostics({ backend_profile: profile?.profile_id || '', provider: profile?.provider_id || '', flags, prompt_route: promptRoute, caption_route: captionRoute });
  return `${helper}<div class="neo-badge-row">${chips.join('')}</div>${expert}`;
}

function promptCaptioningValidationStatus(modeId, toolId) {
  const payload = buildPromptCaptioningPayload(modeId, toolId || (modeId === 'captioning' ? 'image_captioning' : 'prompt_generate'));
  if (modeId === 'captioning' && payload.tool === 'batch_captioning') {
    const batchStatus = validateBatchCaptioningState();
    const errors = batchStatus.runnable ? [] : [`${batchStatus.reason}: ${batchStatus.reason_label}`];
    const chip = batchStatus.runnable ? 'Available' : (String(batchStatus.reason || '').includes('backend') || String(batchStatus.reason || '').includes('support') ? 'Provider gated' : 'Error');
    return { payload, route: { state: batchStatus.runnable ? 'available' : 'provider_gated', reason: batchStatus.reason_label, gate_reason: batchStatus.reason }, errors, runnable: batchStatus.runnable, status_chip: chip, state: batchStatus.runnable ? 'available' : 'provider_gated', gate_reason: batchStatus.reason, reason: errors[0] || 'Available' };
  }
  const required = modeId === 'captioning' ? 'caption' : 'text';
  const route = promptCaptioningRouteState(payload.tool, required, payload.metadata?.backend_profile_id || '', modeId);
  const errors = [];
  if (!['available', 'experimental_available'].includes(route.state)) errors.push(route.reason || 'Route is gated.');
  if (payload.metadata?.disabled === true || payload.metadata?.tool_enabled === false) errors.push('Tool is disabled.');
  if (modeId === 'captioning') {
    const refs = [payload.assets?.image, payload.assets?.source_image, ...(Array.isArray(payload.assets?.images) ? payload.assets.images : [])].filter(Boolean);
    if (!refs.length) errors.push('missing_image_asset: Captioning requires a valid image asset.');
  }
  if (['prompt_enhance', 'prompt_rewrite', 'prompt_cleanup', 'text_transform'].includes(payload.tool)) {
    const hasText = Boolean((payload.inputs?.source_text || payload.inputs?.idea || payload.inputs?.custom_instructions || '').trim());
    if (!hasText) errors.push(`${payload.tool} requires source text or custom instructions.`);
  }
  let chip = 'Available';
  if (errors.length) {
    const reason = errors.join(' ').toLowerCase();
    chip = reason.includes('unsupported') ? 'Unsupported' : reason.includes('offline') ? 'Offline' : reason.includes('backend') || reason.includes('provider') || reason.includes('disabled') || reason.includes('configured') ? 'Provider gated' : 'Error';
  }
  return { payload, route, errors, runnable: !errors.length, status_chip: chip, state: route.state, gate_reason: route.gate_reason || (errors[0] || '').split(':')[0], reason: errors[0] || route.reason || 'Available' };
}

function promptCaptioningValidationChip(label, status) {
  const chip = status?.status_chip || 'Unsupported';
  const cls = chip === 'Available' || chip === 'Saved' || chip === 'Sent' ? 'success' : chip === 'Provider gated' || chip === 'Offline' ? 'warning' : chip === 'Running' ? 'muted' : 'danger';
  return `<span class="neo-state-pill ${cls}" title="${escapeAttr(status?.reason || '')}">${escapeHtml(label)}: ${escapeHtml(chip)}</span>`;
}

function promptCaptioningActionDisabled(modeId, toolId) {
  const status = promptCaptioningValidationStatus(modeId, toolId);
  return status.runnable ? '' : `disabled title="${escapeAttr(status.reason || 'Route is not runnable.')}"`;
}

function promptCaptioningValidationPanel(modeId) {
  const primary = promptCaptioningValidationStatus(modeId, modeId === 'captioning' ? 'image_captioning' : 'prompt_generate');
  const secondary = modeId === 'captioning'
    ? promptCaptioningValidationStatus(modeId, 'batch_captioning')
    : promptCaptioningValidationStatus(modeId, 'prompt_cleanup');
  const saveChip = { status_chip: 'Saved', reason: 'Local save routes are available after valid output exists.' };
  const sentChip = { status_chip: 'Sent', reason: 'Cross-tab handoff routes validate target workspace, field, and append/replace mode.' };
  const helper = promptCaptioningHelperText('Run buttons are checked against the selected backend profile, provider capability, input type, assets, disabled state, and route state. Hidden stale fields are stripped before execution.');
  const expert = promptCaptioningExpertDiagnostics({ primary_validation: primary, secondary_validation: secondary, allowed_status_chips: ['Available', 'Provider gated', 'Unsupported', 'Offline', 'Running', 'Error', 'Saved', 'Sent'] });
  return `${helper}<div class="neo-badge-row neo-pc-validation-chips">
    ${promptCaptioningValidationChip(modeId === 'captioning' ? 'Image captioning' : 'Prompt generation', primary)}
    ${promptCaptioningValidationChip(modeId === 'captioning' ? 'Batch captioning' : 'Prompt cleanup', secondary)}
    ${promptCaptioningValidationChip('Save', saveChip)}
    ${promptCaptioningValidationChip('Send', sentChip)}
  </div>${primary.errors?.length ? `<div class="neo-inline-status danger">${escapeHtml(primary.errors.join(' '))}</div>` : ''}${expert}`;
}

function promptCaptioningPlaceholderNotice(modeId) {
  const label = modeId === 'captioning' ? 'Captioning' : 'Prompt Builder';
  return promptCaptioningHelperText(`${label} is mounted as the active surface. The old diagnostic cards are intentionally removed.`);
}

function promptCaptioningState() {
  state.promptCaptioning = normalizePromptCaptioningState(state.promptCaptioning);
  return state.promptCaptioning;
}


function promptCaptioningCollapsedSections() {
  const pc = promptCaptioningState();
  pc.ui = pc.ui || { collapsedSections: {} };
  pc.ui.collapsedSections = pc.ui.collapsedSections || {};
  return pc.ui.collapsedSections;
}

function promptCaptioningSectionCollapsed(sectionId) {
  return Boolean(promptCaptioningCollapsedSections()[sectionId]);
}

function promptCaptioningSectionStatus(sectionId, modeId = '') {
  if (sectionId.includes('validation')) return 'Available';
  if (sectionId.includes('save')) return 'Saved';
  if (sectionId.includes('handoff')) return 'Sent';
  if (sectionId.includes('capability')) {
    const route = promptCaptioningRouteState(modeId === 'captioning' ? 'image_captioning' : 'prompt_generate', modeId === 'captioning' ? 'caption' : 'text', promptCaptioningProviderProfileId(modeId), modeId);
    return route.state === 'available' || route.state === 'experimental_available' ? 'Available' : 'Provider gated';
  }
  return '';
}

function promptCaptioningCollapseButton(sectionId, collapsed) {
  const label = collapsed ? 'Expand section' : 'Collapse section';
  return `<button class="neo-section-toggle neo-btn neo-btn-icon" type="button" data-pc-collapse="${escapeAttr(sectionId)}" aria-expanded="${collapsed ? 'false' : 'true'}" title="${escapeAttr(label)}"><span class="neo-chevron">${collapsed ? '›' : '⌄'}</span></button>`;
}

function promptCaptioningFeatureHeaderForSection(title, sectionId, options = {}) {
  if (options.featureHeader === false) return '';
  const titleKey = String(title || '').toLowerCase();
  const sectionKey = String(sectionId || '').toLowerCase();
  const map = {
    prompt_studio: ['Prompt Studio', 'Build source ideas, custom instructions, prompt output, and negative prompt fragments in one safe workspace.', ['source text', 'prompt output', 'safe append']],
    save_prompt: ['Prompt Library', 'Save, update, and reuse Prompt Studio records without touching Image prompts or project records.', ['local record', 'safe save', 'library']],
    caption_studio: ['Caption Studio', 'Generate and refine image captions, then reuse the result as prompt-building context.', ['vision captioning', 'caption output', 'prompt reuse']],
    save_caption: ['Caption Library', 'Save reusable caption records while keeping source image assets untouched.', ['local record', 'asset safe', 'library']],
  };
  let item = map[sectionKey];
  if (!item) {
    if (titleKey.includes('prompt studio')) item = map.prompt_studio;
    else if (titleKey.includes('caption studio')) item = map.caption_studio;
    else if (titleKey.includes('save prompt')) item = map.save_prompt;
    else if (titleKey.includes('save')) item = map.save_caption;
  }
  if (!item) return '';
  return neoFeatureTitleCard('Feature Workspace', item[0], item[1], item[2], { extraClass: 'neo-pc-panel-feature-title' });
}

function promptCaptioningCollapsiblePanel(title, bodyHtml, sectionId, options = {}) {
  const article = document.createElement('article');
  const collapsed = promptCaptioningSectionCollapsed(sectionId);
  const status = options.status || '';
  const statusHtml = status ? `<span class="neo-panel-status ${statusClass(status)}">${escapeHtml(status)}</span>` : '';
  const hasFeatureTitle = String(bodyHtml || '').includes('data-neo-feature-title-card');
  const bodyWithFeatureHeader = hasFeatureTitle ? bodyHtml : `${promptCaptioningFeatureHeaderForSection(title, sectionId, options)}${bodyHtml}`;
  article.className = `neo-panel neo-fixed-panel neo-section-card neo-pc-section-card${collapsed ? ' collapsed' : ''}`;
  article.dataset.pcSectionId = sectionId;
  article.innerHTML = `
    <div class="neo-fixed-header neo-section-header">
      <span class="neo-panel-title neo-section-title"><span class="neo-panel-dot"></span><span>${escapeHtml(title)}</span>${statusHtml}</span>
      <span class="neo-section-status">${promptCaptioningCollapseButton(sectionId, collapsed)}</span>
    </div>
    <div class="neo-panel-body neo-section-body" style="display:${collapsed ? 'none' : ''}">${bodyWithFeatureHeader}</div>
  `;
  const btn = article.querySelector('[data-pc-collapse]');
  if (btn) {
    btn.dataset.pcBound = 'true';
    btn.addEventListener('click', () => {
    const body = article.querySelector('.neo-section-body');
    const icon = btn.querySelector('.neo-chevron');
    const nowCollapsed = body.style.display !== 'none';
    body.style.display = nowCollapsed ? 'none' : '';
    article.classList.toggle('collapsed', nowCollapsed);
    btn.setAttribute('aria-expanded', nowCollapsed ? 'false' : 'true');
    if (icon) icon.textContent = nowCollapsed ? '›' : '⌄';
    const collapsedSections = promptCaptioningCollapsedSections();
    if (nowCollapsed) collapsedSections[sectionId] = true;
    else delete collapsedSections[sectionId];
    saveUiState();
  });
  }
  return article;
}

function promptCaptioningActionGroup(title, buttonsHtml, extraClass = '') {
  return `<div class="neo-action-group ${escapeAttr(extraClass)}"><span class="neo-action-group-title">${escapeHtml(title)}</span><div class="neo-button-group">${buttonsHtml}</div></div>`;
}

function promptCaptioningButton(id, label, variant = 'secondary', attrs = '') {
  return `<button type="button" id="${escapeAttr(id)}" class="neo-btn ${escapeAttr(variant)}" ${attrs || ''}>${escapeHtml(label)}</button>`;
}


