function promptCaptioningQuickPresetButtons(kind = 'prompt') {
  const presets = kind === 'caption' ? PROMPT_CAPTIONING_CAPTION_FORMAT_PRESETS : PROMPT_CAPTIONING_QUICK_PROMPT_PRESETS;
  return `<div class="neo-quick-preset-row prompt-captioning-quick-presets" data-pc-preset-kind="${escapeAttr(kind)}">
    ${presets.map((preset) => `<button type="button" class="neo-btn ghost" data-pc-${kind}-preset="${escapeAttr(preset.id)}">${escapeHtml(preset.label)}</button>`).join('')}
  </div>`;
}

function applyPromptCaptioningQuickPromptPreset(presetId) {
  const preset = PROMPT_CAPTIONING_QUICK_PROMPT_PRESETS.find((item) => item.id === presetId);
  if (!preset) return;
  const pb = promptCaptioningState().promptBuilder;
  pb.sourceText = preset.sourceText || pb.sourceText || '';
  pb.customInstructions = preset.customInstructions || '';
  pb.promptStyle = preset.style || pb.promptStyle || 'cinematic';
  pb.generationMode = preset.generationMode || 'prompt_generate';
  pb.activeTool = pb.generationMode;
  pb.status = `Loaded quick preset: ${preset.label}.`;
  render();
}

function applyPromptCaptioningCaptionFormatPreset(presetId) {
  const preset = PROMPT_CAPTIONING_CAPTION_FORMAT_PRESETS.find((item) => item.id === presetId);
  if (!preset) return;
  const cap = promptCaptioningState().captioning;
  cap.captionInstruction = preset.instruction || cap.captionInstruction || '';
  cap.captionStyle = preset.captionStyle || cap.captionStyle || 'descriptive';
  cap.captionLength = preset.captionLength || cap.captionLength || 'medium';
  cap.outputStyle = preset.outputStyle || cap.outputStyle || 'auto';
  cap.params = cap.params || {};
  cap.params.detail_level = preset.detailLevel || cap.params.detail_level || 'detailed';
  cap.status = `Loaded caption format: ${preset.label}.`;
  refreshCaptionValidation();
  render();
}

function promptCaptioningEmptyState(title, body, action = '') {
  return `<div class="neo-empty prompt-captioning-empty"><strong>${escapeHtml(title)}</strong><p>${escapeHtml(body)}</p>${action ? `<span>${escapeHtml(action)}</span>` : ''}</div>`;
}

function promptCaptioningMetadataSummaryCard(record) {
  if (!record) return '';
  const route = record.route || {};
  const assets = record.assets || {};
  const outputs = record.outputs || {};
  const outputText = outputs.prompt || outputs.caption || outputs.output_text || outputs.text || '';
  const facts = [
    ['Tool', record.tool_id || ''],
    ['Mode', record.mode || ''],
    ['Backend', route.backend_profile_id || ''],
    ['Provider', route.provider_id || ''],
    ['Model', route.model || ''],
    ['Asset', assets.image || assets.source_image || ''],
  ].filter(([, value]) => String(value || '').trim());
  return `<div class="neo-mini-card prompt-captioning-metadata-card">
    <strong>${escapeHtml(record.tool_id || 'Latest result')}</strong>
    <p>${escapeHtml(record.workflow_summary || record.assistant_summary || 'Result metadata recorded.')}</p>
    <div class="neo-meta-grid">${facts.map(([label, value]) => `<span><small>${escapeHtml(label)}</small><b>${escapeHtml(String(value).split(/[\\/]/).pop() || value)}</b></span>`).join('')}</div>
    ${outputText ? `<p class="neo-muted">${escapeHtml(String(outputText).slice(0, 220))}</p>` : ''}
    <div class="neo-button-row">
      <button type="button" id="promptCaptioningLoadReplayPayload" data-metadata-id="${escapeAttr(record.metadata_id || '')}">Load Replay Payload</button>
    </div>
  </div>`;
}

function promptCaptioningProviderProfileId(modeId) {
  const pc = promptCaptioningState();
  const localId = modeId === 'captioning' ? pc.captioning.providerProfileId : pc.promptBuilder.providerProfileId;
  if (localId) return localId;
  if (modeId === 'captioning') {
    // display.expert; columns.left.appendChild(promptCaptioningCollapsiblePanel('Prompt Builder tools'
    const visionProfile = backendProfilesForSurface('prompt_captioning').find((profile) => {
      const flags = promptCaptioningProfileFlags(profile);
      return flags.supports_vision && flags.supports_captioning && profile.enabled !== false;
    });
    if (visionProfile) return visionProfile.profile_id;
  }
  return defaultBackendProfile('prompt_captioning')?.profile_id || defaultBackendProfile('text')?.profile_id || '';
}

function promptCaptioningCleanParams(params = {}, allowed = []) {
  const out = {};
  allowed.forEach((key) => { if (params[key] !== undefined && params[key] !== null && params[key] !== '') out[key] = params[key]; });
  return out;
}

function buildPromptCaptioningPayload(modeId, toolId) {
  const pc = promptCaptioningState();
  if (modeId === 'captioning') {
    const cap = pc.captioning;
    const resolvedTool = toolId || 'image_captioning';
    const captionAsset = captionAssetFromState(cap);
    const batchState = cap.batch || {};
    const assets = resolvedTool === 'batch_captioning'
      ? {}
      : { image: captionAsset.asset_ref || captionAsset.path || '', source_image: captionAsset.asset_ref || captionAsset.path || '', images: captionAsset.asset_ref || captionAsset.path ? [captionAsset] : [] };
    return {
      workspace: 'prompt_captioning',
      mode: 'captioning',
      tool: resolvedTool,
      inputs: {
        caption_instruction: cap.captionInstruction || '',
        caption_style: cap.captionStyle || 'descriptive',
        caption_length: cap.captionLength || 'medium',
        output_style: cap.outputStyle || 'auto',
        selected_preset: cap.selectedPresetId || '',
        folder_path: batchState.inputFolder || '',
        workflow_mode: batchState.workflowMode || 'dataset',
      },
      params: {
        ...promptCaptioningCleanParams(cap.params, ['temperature', 'top_p', 'top_k', 'max_tokens', 'caption_mode', 'component_type', 'detail_level', 'crop_json', 'recursive', 'skip_existing', 'start_index']),
        include_exts: batchState.includeExtensions || 'png,jpg,jpeg,webp,bmp,gif',
        recursive: Boolean(batchState.recursive),
        post_task_action: batchState.postAction || 'none',
        caption_settings: { caption_style: cap.captionStyle || 'descriptive', caption_length: cap.captionLength || 'medium', output_style: cap.outputStyle || 'auto', caption_mode: (cap.params || {}).caption_mode || 'full_image', component_type: (cap.params || {}).component_type || 'general', detail_level: (cap.params || {}).detail_level || 'detailed', instruction: cap.captionInstruction || '', max_tokens: (cap.params || {}).max_tokens ?? 256, temperature: (cap.params || {}).temperature ?? 0.7, top_p: (cap.params || {}).top_p ?? 0.9 },
        dataset: { output_folder: batchState.outputFolder || '', caption_images: batchState.datasetCaptionImages !== false, save_txt: batchState.datasetSaveTxt !== false, rename_images: batchState.datasetRenameImages !== false, transfer_mode: batchState.datasetTransferMode || 'copy', confirm_move: Boolean(batchState.datasetConfirmMove), external_output_confirmed: Boolean(batchState.datasetExternalOutputConfirmed), skip_processed: batchState.datasetSkipProcessed !== false, overwrite_existing: Boolean(batchState.datasetOverwriteExisting), log_format: batchState.datasetLogFormat || 'csv', prefix: batchState.datasetPrefix || 'character', pattern: batchState.datasetPattern || '{prefix}_{num}', number_start: Number(batchState.datasetNumberStart || 1), number_padding: Number(batchState.datasetNumberPadding || 4) },
        library: { category: batchState.libraryCategory || 'General', new_category: batchState.libraryCategoryNew || '', base_name: batchState.libraryBaseName || 'caption', number_start: Number(batchState.libraryNumberStart || 1), skip_duplicates: batchState.librarySkipDuplicates !== false },
      },
      assets,
      metadata: {
        backend_profile_id: promptCaptioningProviderProfileId('captioning'),
        source_ui: 'caption_studio',
        releaseStage: 'ready',
      },
    };
  }
  const pb = pc.promptBuilder;
  return {
    workspace: 'prompt_captioning',
    mode: 'prompt_builder',
    tool: toolId || 'prompt_generate',
    inputs: {
      source_text: pb.sourceText || '',
      idea: pb.sourceText || '',
      style: pb.promptStyle || '',
      custom_instructions: pb.customInstructions || '',
      selected_preset: pb.selectedPresetId || '',
      character_profile: pb.selectedCharacterId || '',
    },
    params: promptCaptioningCleanParams(pb.params, ['temperature', 'top_p', 'top_k', 'max_tokens', 'stop_sequences', 'stream', 'cleanup_enabled', 'enhance_mode', 'rewrite_mode', 'cleanup_mode', 'dedupe_tags', 'normalize_commas', 'trim_weights', 'remove_empty_tokens']),
    assets: {},
    metadata: {
      backend_profile_id: promptCaptioningProviderProfileId('prompt_builder'),
      source_ui: 'prompt_studio',
      releaseStage: 'ready',
    },
  };
}

function promptCaptioningPayloadPreview(modeId) {
  const toolId = modeId === 'captioning' ? 'image_captioning' : 'prompt_generate';
  const payload = buildPromptCaptioningPayload(modeId, toolId);
  const display = promptCaptioningDisplayModeSetup();
  const helper = promptCaptioningHelperText('Payload preview: state is namespaced, route-aware, and stripped of stale hidden fields before backend execution.');
  const summary = `
    <div class="neo-badge-row neo-pc-payload-summary" data-display-mode="${escapeAttr(display.mode)}">
      <span class="neo-badge">workspace: ${escapeHtml(payload.workspace)}</span>
      <span class="neo-badge">mode: ${escapeHtml(payload.mode)}</span>
      <span class="neo-badge">tool: ${escapeHtml(payload.tool)}</span>
      <span class="neo-badge">backend: ${escapeHtml(payload.metadata?.backend_profile_id || 'none')}</span>
    </div>`;
  const expert = promptCaptioningExpertDiagnostics(payload);
  return `${helper}${summary}${expert}`;
}

function promptCaptioningTextarea(id, value, placeholder) {
  return `<textarea id="${escapeAttr(id)}" class="neo-textarea" rows="4" placeholder="${escapeAttr(placeholder)}">${escapeHtml(value || '')}</textarea>`;
}


function promptCaptioningInput(id, value, placeholder = '', type = 'text') {
  return `<input id="${escapeAttr(id)}" type="${escapeAttr(type)}" value="${escapeAttr(value ?? '')}" placeholder="${escapeAttr(placeholder)}" />`;
}

function promptCaptioningSelect(id, value, options) {
  const extraAttrs = id === 'promptCaptioningBatchWorkflowMode' ? ' data-pc-batch-workflow-mode="true"' : '';
  return `<select id="${escapeAttr(id)}"${extraAttrs}>${options.map((option) => {
    const opt = typeof option === 'string' ? { value: option, label: option } : option;
    return `<option value="${escapeAttr(opt.value)}" ${String(value || '') === String(opt.value) ? 'selected' : ''}>${escapeHtml(opt.label)}</option>`;
  }).join('')}</select>`;
}

function normalizePromptCaptioningBatchWorkflowMode(value = '') {
  const text = String(value || '').trim().toLowerCase().replace(/\s+/g, '_');
  if (['library', 'save_to_library', 'save-to-library', 'save to library'].includes(text)) return 'library';
  return 'dataset';
}

function promptCaptioningBatchWorkflowSwitch(mode = 'dataset') {
  const currentMode = normalizePromptCaptioningBatchWorkflowMode(mode);
  const choice = (value, label) => {
    const normalized = normalizePromptCaptioningBatchWorkflowMode(value);
    const active = currentMode === normalized;
    return `<button type="button" class="neo-btn neo-segment-button${active ? ' neo-segment-active' : ''}" data-pc-batch-workflow-choice="${escapeAttr(normalized)}" onclick="window.switchPromptCaptioningBatchWorkflowMode && window.switchPromptCaptioningBatchWorkflowMode('${escapeAttr(normalized)}')" aria-pressed="${active ? 'true' : 'false'}">${escapeHtml(label)}</button>`;
  };
  return `<div class="neo-segmented-control neo-pc-workflow-switch" data-pc-batch-workflow-switch="true" data-pc-patch-marker="P20 workflow switch direct DOM binding">
    ${choice('dataset', 'Dataset Preparation')}
    ${choice('library', 'Save to Library')}
  </div>`;
}

function promptCaptioningBatchWorkflowModeFromDom() {
  const active = document.querySelector('[data-pc-batch-workflow-choice].neo-segment-active, [data-pc-batch-workflow-choice][aria-pressed="true"]');
  if (active) return normalizePromptCaptioningBatchWorkflowMode(active.getAttribute('data-pc-batch-workflow-choice') || '');
  const marker = document.querySelector('[data-pc-batch-workflow-status="true"]');
  const markerMode = marker?.getAttribute?.('data-pc-current-workflow-mode') || marker?.dataset?.pcCurrentWorkflowMode || '';
  if (markerMode) return normalizePromptCaptioningBatchWorkflowMode(markerMode);
  const markerText = String(marker?.textContent || '').toLowerCase();
  if (markerText.includes('save to library') || markerText.includes('library')) return 'library';
  return '';
}

function effectivePromptCaptioningBatchWorkflowMode(fallback = 'dataset') {
  const pc = promptCaptioningState();
  const stateMode = normalizePromptCaptioningBatchWorkflowMode(pc.captioning?.batch?.workflowMode || fallback);
  const domMode = promptCaptioningBatchWorkflowModeFromDom();
  if (domMode && domMode !== stateMode) {
    pc.captioning = pc.captioning || {};
    pc.captioning.batch = pc.captioning.batch || {};
    pc.captioning.batch.workflowMode = domMode;
    return domMode;
  }
  return stateMode;
}

function updatePromptCaptioningBatchWorkflowDom(nextMode = 'dataset') {
  const mode = normalizePromptCaptioningBatchWorkflowMode(nextMode);
  document.querySelectorAll('[data-pc-batch-workflow-choice]').forEach((button) => {
    const active = normalizePromptCaptioningBatchWorkflowMode(button.getAttribute('data-pc-batch-workflow-choice') || '') === mode;
    button.classList.toggle('neo-segment-active', active);
    button.setAttribute('aria-pressed', active ? 'true' : 'false');
  });
  document.querySelectorAll('[data-batch-mode]').forEach((panel) => {
    const panelMode = normalizePromptCaptioningBatchWorkflowMode(panel.getAttribute('data-batch-mode') || 'dataset');
    panel.style.display = panelMode === mode ? '' : 'none';
    panel.hidden = panelMode !== mode;
  });
  const marker = document.querySelector('[data-pc-batch-workflow-status="true"]');
  if (marker) {
    marker.textContent = mode === 'library' ? 'Mode: Save to Library' : 'Mode: Dataset Preparation';
    marker.setAttribute('data-pc-current-workflow-mode', mode);
  }
}

function switchPromptCaptioningBatchWorkflowMode(mode = 'dataset') {
  const pc = promptCaptioningState();
  const cap = pc.captioning || (pc.captioning = {});
  const batch = cap.batch || (cap.batch = {});
  const nextMode = normalizePromptCaptioningBatchWorkflowMode(mode);
  syncPromptCaptioningBatchVisibleFields?.();
  batch.workflowMode = nextMode;
  batch.lastAction = `Workflow mode changed to ${nextMode}`;
  batch.lastValidation = validateBatchCaptioningState();
  updatePromptCaptioningBatchWorkflowDom(nextMode);
  updatePromptCaptioningBatchRunGateDom();
  saveUiState();
}
window.switchPromptCaptioningBatchWorkflowMode = switchPromptCaptioningBatchWorkflowMode;

function bindPromptCaptioningBatchWorkflowSwitch(root = document) {
  root.querySelectorAll?.('[data-pc-batch-workflow-choice]').forEach((button) => {
    if (button.dataset.pcWorkflowChoiceBound === 'true') return;
    button.dataset.pcWorkflowChoiceBound = 'true';
    button.addEventListener('click', (event) => {
      event.__pcWorkflowSwitchHandled = true;
      event.preventDefault();
      switchPromptCaptioningBatchWorkflowMode(button.getAttribute('data-pc-batch-workflow-choice') || 'dataset');
    });
  });
}

function ensurePromptCaptioningWorkflowSwitchDelegatedBinding() {
  if (window.__neoPromptCaptioningWorkflowSwitchDelegated === true) return;
  window.__neoPromptCaptioningWorkflowSwitchDelegated = true;
  document.addEventListener('click', (event) => {
    if (event.target?.closest?.('select, option, input, textarea')) return;
    const button = event.target?.closest?.('[data-pc-batch-workflow-choice]');
    if (!button || event.__pcWorkflowSwitchHandled) return;
    event.__pcWorkflowSwitchHandled = true;
    event.preventDefault();
    switchPromptCaptioningBatchWorkflowMode(button.getAttribute('data-pc-batch-workflow-choice') || 'dataset');
  });
}


function promptCaptioningSharedCategories() {
  const pc = promptCaptioningState();
  const library = pc.library || {};
  const found = new Set(['General']);
  const add = (value) => {
    const text = String(value || '').trim();
    if (text) found.add(text);
  };
  ['promptRecords','promptPresets','captionRecords','captionPresets','captionComponents','captionBatchResults'].forEach((key) => {
    (library[key] || []).forEach((item) => add(item.category || item.library_category));
  });
  (library.categories || []).forEach((item) => add(typeof item === 'string' ? item : (item.label || item.name || item.id)));
  return Array.from(found).sort((a, b) => a.localeCompare(b));
}

function promptCaptioningCategorySelect(id, value) {
  const categories = promptCaptioningSharedCategories();
  return promptCaptioningSelect(id, value || 'General', categories.map((cat) => ({ value: cat, label: cat })));
}

function promptCaptioningResolvedCategory(selectId, newId, fallback = 'General') {
  const typed = document.getElementById(newId)?.value?.trim() || '';
  return typed || document.getElementById(selectId)?.value || fallback;
}

function promptCaptioningRememberCategory(category, usedBy = 'caption') {
  const text = String(category || '').trim();
  if (!text) return;
  const pc = promptCaptioningState();
  pc.library = pc.library || {};
  const list = Array.isArray(pc.library.categories) ? pc.library.categories : [];
  const exists = list.some((item) => String(typeof item === 'string' ? item : (item.label || item.name || item.id || '')).toLowerCase() === text.toLowerCase());
  if (!exists) list.push({ id: text.toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_|_$/g, '') || 'category', label: text, used_by: [usedBy], created_at: new Date().toISOString(), updated_at: new Date().toISOString() });
  pc.library.categories = list;
}

async function promptCaptioningRefreshCategories() {
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/categories');
    promptCaptioningState().library.categories = data.categories || [];
  } catch (error) {
    console.warn('Prompt/Captioning categories refresh failed', error);
  }
}

function promptCaptioningProviderBadgeText(profile, modeId = 'prompt_builder') {
  const flags = promptCaptioningProfileFlags(profile);
  const bits = [];
  if (flags.supports_text) bits.push('Text');
  if (flags.supports_vision && flags.supports_captioning) bits.push('Vision + Caption');
  else if (flags.supports_vision) bits.push('Vision only');
  else if (modeId === 'captioning') bits.push('Text-only');
  return bits.join(' / ') || 'No declared support';
}

function promptCaptioningProviderOptions(modeId) {
  const activeId = promptCaptioningProviderProfileId(modeId);
  const profiles = backendProfilesForSurface('prompt_captioning');
  if (!profiles.length) return '<option value="">No Text Backend Profile</option>';
  return profiles.map((profile) => {
    const label = `${profile.display_name || profile.profile_id} (${profile.provider_id || 'provider'} · ${promptCaptioningProviderBadgeText(profile, modeId)})`;
    return `<option value="${escapeAttr(profile.profile_id)}" ${profile.profile_id === activeId ? 'selected' : ''}>${escapeHtml(label)}</option>`;
  }).join('');
}


