function promptCaptioningTextFromCandidate(candidate, keys = []) {
  if (candidate === undefined || candidate === null) return '';
  if (typeof candidate === 'string') {
    const text = candidate.trim();
    if (!text) return '';
    if ((text.startsWith('{') && text.endsWith('}')) || (text.startsWith('[') && text.endsWith(']'))) {
      try {
        const parsed = JSON.parse(text);
        const nested = promptCaptioningTextFromCandidate(parsed, keys);
        if (nested) return nested;
      } catch (_error) {
        // Not JSON, treat as plain generated text.
      }
    }
    return text;
  }
  if (typeof candidate === 'object') {
    for (const key of keys || []) {
      if (Object.prototype.hasOwnProperty.call(candidate, key)) {
        const nested = promptCaptioningTextFromCandidate(candidate[key], keys);
        if (nested) return nested;
      }
    }
    for (const key of ['prompt', 'output_prompt', 'output_text', 'caption', 'output_caption', 'text', 'content', 'message', 'partial_text']) {
      if (Object.prototype.hasOwnProperty.call(candidate, key)) {
        const nested = promptCaptioningTextFromCandidate(candidate[key], keys);
        if (nested) return nested;
      }
    }
  }
  return '';
}

function promptCaptioningRecoveredText(data, keys) {
  const source = data || {};
  for (const key of keys || []) {
    if (!Object.prototype.hasOwnProperty.call(source, key)) continue;
    const value = promptCaptioningTextFromCandidate(source[key], keys);
    if (value) return value;
  }
  return promptCaptioningTextFromCandidate(source, keys);
}

const PROMPT_STUDIO_LEGACY_OUTPUT_KEYS = ['prompt', 'output_text', 'text', 'partial_text'];

const CAPTION_STUDIO_LEGACY_OUTPUT_KEYS = ['caption', 'output_caption', 'text', 'partial_text'];

function resolvePromptStudioOutput(response) {
  return promptCaptioningRecoveredText(response, ['prompt', 'output_prompt', 'output_text', 'text', 'result', 'partial_text']);
}

function resolveCaptionStudioOutput(response) {
  return promptCaptioningRecoveredText(response, ['caption', 'output_caption', 'output_text', 'text', 'result', 'partial_text']);
}

