async function copyCaptionOutput() {
  const pc = promptCaptioningState();
  const cap = pc.captioning;
  const dom = document.querySelector('[data-pc-caption-output="true"]') || document.getElementById('promptCaptioningCaptionOutput');
  const text = String((dom && dom.value) || cap.outputCaption || cap.lastCaptionText || '').trim();
  if (!text) {
    cap.status = 'Nothing to copy.';
    render();
    return;
  }
  try {
    await promptCaptioningCopyTextToClipboard(text);
    cap.outputCaption = text;
    cap.status = 'Copied caption.';
  } catch (error) {
    cap.status = `Copy failed: ${error.message || error}`;
  }
  render();
}

function promptCaptioningRecoveryStatus(data, fallbackDone = 'completed') {
  const warning = String((data || {}).warning || '').trim();
  if ((data || {}).recoverable && warning) return `Recovered with warning: ${warning}`;
  if ((data || {}).recoverable) return 'Recovered with warning: KoboldCpp connection ended early, but Neo recovered usable text.';
  if (warning) return `Warning: ${warning}`;
  return `Done: ${(data || {}).finish_reason || fallbackDone}`;
}

