function promptCaptioningSuggestPromptName(prompt = '', source = '') {
  const raw = String(source || prompt || '').replace(/["'`]/g, '').trim();
  const cleaned = raw
    .split(/\n|\./)[0]
    .replace(/\s+/g, ' ')
    .replace(/[^a-zA-Z0-9 ,&()\-_/]/g, '')
    .trim();
  if (!cleaned) return '';
  const words = cleaned.split(' ').filter(Boolean).slice(0, 7).join(' ');
  return words.charAt(0).toUpperCase() + words.slice(1);
}

async function copyPromptStudioOutput() {
  const pc = promptCaptioningState();
  const pb = promptCaptioningSyncPromptOutputsFromDom();
  const text = promptCaptioningLivePromptOutput({ promptOnly: true });
  if (!text) {
    pb.status = 'Nothing to copy from Prompt output.';
    pb.isRunning = false;
    render();
    return;
  }
  try {
    await promptCaptioningCopyTextToClipboard(text);
    pb.outputText = text;
    pb.status = 'Copied Prompt output.';
  } catch (error) {
    pb.status = `Copy failed: ${error.message || error}`;
    render();
  }
}

async function runPromptCaptioningPrompt(toolId) {
  const pc = promptCaptioningState();
  const pb = syncPromptCaptioningPromptFormFromDom();
  if (pb.isRunning) {
    const started = Date.parse(pb.runStartedAt || '') || 0;
    if (started && Date.now() - started < 120000) return;
    pb.isRunning = false;
  }
  pb.activeTool = toolId || pb.generationMode || 'prompt_generate';
  pb.generationMode = pb.activeTool;
  pb.status = 'Running Prompt Studio…';
  pb.isRunning = true;
  pb.runStartedAt = new Date().toISOString();
  render();
  const payload = buildPromptCaptioningPayload('prompt_builder', pb.activeTool);
  try {
    const response = await fetch('/api/prompt-captioning/prompt/run', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
    const data = await response.json().catch(() => ({}));
    const resolvedOutput = resolvePromptStudioOutput(data);
    if (!response.ok || (data.ok === false && !resolvedOutput)) throw new Error(promptCaptioningRunErrorMessage(data, 'Prompt Studio run failed'));
    if (pb.activeTool === 'negative_prompt') pb.negativeOutputText = resolvedOutput;
    else pb.outputText = resolvedOutput;
    promptCaptioningWritePromptOutputToDom(pb.activeTool, resolvedOutput);
    pb.lastPayload = data.payload || payload;
    pb.lastMetadata = data.metadata || null;
    pb.lastReplayPayload = data.replay_payload || null;
    pb.lastResponseDebug = data.response_debug || data.metadata?.outputs?.response_debug || null;
    pc.library.resultMetadata = data.metadata ? [data.metadata, ...(pc.library.resultMetadata || [])].slice(0, 50) : (pc.library.resultMetadata || []);
    recordMemoryEvent('prompt_captioning.prompt.generated', 'prompt_captioning', { tool_id: pb.activeTool, metadata_id: data.metadata?.metadata_id || '', replay_ready: Boolean(data.replay_payload) });
    pb.history = [data.history || { tool_id: pb.activeTool, output_text: pb.outputText, output_prompt: pb.outputText, created_at: new Date().toISOString() }, ...(pb.history || [])].slice(0, 20);
    pb.status = promptCaptioningRecoveryStatus(data);
  } catch (error) {
    pb.status = `Error: ${error.message}`;
  } finally {
    finalizePromptCaptioningPromptRun();
  }
  render();
  finalizePromptCaptioningPromptRun();
  promptCaptioningWritePromptOutputToDom(pb.activeTool, pb.activeTool === 'negative_prompt' ? pb.negativeOutputText : pb.outputText);
}

async function savePromptCaptioningPrompt() {
  const pc = promptCaptioningState();
  const pb = syncPromptCaptioningPromptFormFromDom();
  pb.isRunning = false;
  clearPromptCaptioningRunningUi();
  const prompt = promptCaptioningLivePromptOutput({ promptOnly: true });
  if (!prompt.trim()) {
    pb.status = 'Nothing to save yet.';
    render();
    return;
  }
  try {
    const response = await fetch('/api/prompt-captioning/prompt/save', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        name: (pb.saveName || '').trim() || promptCaptioningSuggestPromptName(prompt, pb.sourceText || '') || 'Untitled Prompt',
        category: promptCaptioningResolvedCategory('promptCaptioningSaveCategory', 'promptCaptioningSaveCategoryNew', pb.saveCategory || 'General'),
        tags: pb.saveTags || '',
        notes: pb.saveNotes || '',
        prompt,
        negative_prompt: promptCaptioningLiveFieldValue('promptCaptioningNegativeOutputText', pb.negativeOutputText || ''),
        source_text: pb.sourceText || '',
        style: pb.promptStyle || '',
        settings: pb.params || {},
        metadata: { source_surface: 'prompt_captioning', source_tool: pb.activeTool || pb.generationMode || 'prompt_generate' },
      }),
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok || data.ok === false) throw new Error((data.errors || []).join('\n') || data.detail || 'Save failed');
    pc.library.promptRecords = data.records || pc.library.promptRecords || [];
    const savedCategory = promptCaptioningResolvedCategory('promptCaptioningSaveCategory', 'promptCaptioningSaveCategoryNew', pb.saveCategory || 'General');
    promptCaptioningRememberCategory(savedCategory, 'prompt');
    pb.saveCategory = savedCategory;
    pb.saveCategoryNew = '';
    pb.selectedSavedPromptId = data.record?.prompt_id || '';
    pb.status = 'Saved prompt.';
  } catch (error) {
    pb.status = `Save error: ${error.message}`;
  }
  render();
}

async function promptCaptioningSendToWorkspace(options = {}) {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder;
  const cap = pc.captioning;
  const modeId = options.modeId || promptCaptioningModeId(activeSubtab());
  const isCaption = modeId === 'captioning';
  const text = options.text !== undefined ? options.text : (isCaption ? cap.outputCaption : (options.targetField === 'negative_prompt' ? pb.negativeOutputText : pb.outputText));
  const payload = {
    source_tool: options.sourceTool || (isCaption ? 'caption_studio' : 'prompt_studio'),
    target_workspace: options.targetWorkspace || 'image',
    target_field: options.targetField || 'positive_prompt',
    mode: options.handoffMode || 'append',
    text: text || '',
    assets: options.assets || (isCaption ? {
      source_image: cap.selectedImage || '',
      source_image_url: cap.selectedImageUrl || '',
      source_image_name: cap.selectedImageName || '',
    } : {}),
  };
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/send-to-workspace', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
    applyPromptCaptioningHandoff(data.handoff || data);
    pc.library.resultMetadata = data.metadata ? [data.metadata, ...(pc.library.resultMetadata || [])].slice(0, 50) : (pc.library.resultMetadata || []);
    recordMemoryEvent('prompt_captioning.handoff.sent', 'prompt_captioning', { metadata_id: data.metadata?.metadata_id || '', target_workspace: payload.target_workspace, target_field: payload.target_field, mode: payload.mode });
    const message = `Sent to ${payload.target_workspace}.${payload.target_field} (${payload.mode}).`;
    if (isCaption) cap.status = message;
    else pb.status = message;
  } catch (error) {
    if (isCaption) cap.status = `Handoff error: ${error.message}`;
    else pb.status = `Handoff error: ${error.message}`;
  }
  render();
}

function applyPromptCaptioningHandoff(handoff = {}) {
  const mutation = handoff.client_mutation || handoff;
  const workspace = mutation.target_workspace || handoff.target_workspace || 'image';
  const field = mutation.target_field || handoff.target_field || 'positive_prompt';
  const mode = mutation.mode || handoff.mode || 'append';
  const text = mutation.text || handoff.text || '';
  const assets = mutation.assets || handoff.assets || {};
  const replace = mode === 'replace';
  const pc = promptCaptioningState();
  if (workspace === 'image') {
    if (field === 'positive_prompt' || field === 'negative_prompt') {
      appendToPromptField(text, field, replace);
      state.activeSurfaceId = 'image';
      return;
    }
    if (['source_image', 'source_image_2', 'source_image_3'].includes(field)) {
      const path = assets.source_image || assets.image || assets.path || '';
      const url = assets.source_image_url || assets.image_url || assets.url || path;
      const name = assets.source_image_name || assets.image_name || assets.filename || basename(path || url || 'handoff_image');
      state.imageDraft[field] = path;
      state.imageDraft[`${field}_url`] = url;
      state.imageDraft[`${field}_name`] = name;
      state.activeSurfaceId = 'image';
      saveUiState();
      return;
    }
  }
  if (workspace === 'prompt_builder') {
    const pb = pc.promptBuilder;
    const current = field === 'output_text' ? pb.outputText : field === 'negative_output_text' ? pb.negativeOutputText : field === 'custom_instructions' ? pb.customInstructions : pb.sourceText;
    const next = replace ? text : [current, text].filter(Boolean).join(current ? '\n' : '');
    if (field === 'output_text') pb.outputText = next;
    else if (field === 'negative_output_text') pb.negativeOutputText = next;
    else if (field === 'custom_instructions') pb.customInstructions = next;
    else pb.sourceText = next;
    state.activeSurfaceId = 'prompt_captioning';
    state.activeSubtabsBySurface.prompt_captioning = 'prompt_builder';
    return;
  }
  if (workspace === 'captioning') {
    const cap = pc.captioning;
    if (field === 'selected_image') {
      cap.selectedImage = assets.source_image || assets.image || assets.path || text || '';
      cap.selectedImageUrl = assets.source_image_url || assets.image_url || assets.url || cap.selectedImageUrl || '';
      cap.selectedImageName = assets.source_image_name || assets.image_name || assets.filename || cap.selectedImageName || '';
    } else {
      const current = field === 'output_caption' ? cap.outputCaption : cap.captionInstruction;
      const next = replace ? text : [current, text].filter(Boolean).join(current ? '\n' : '');
      if (field === 'output_caption') cap.outputCaption = next;
      else cap.captionInstruction = next;
    }
    state.activeSurfaceId = 'prompt_captioning';
    state.activeSubtabsBySurface.prompt_captioning = 'captioning';
    return;
  }
}


