async function promptCaptioningFetchJson(url, options = {}) {
  const response = await fetch(url, options);
  const data = await response.json().catch(() => ({}));
  if (!response.ok || data.ok === false) throw new Error((data.errors || []).join('\n') || data.detail || data.message || `Request failed: ${url}`);
  return data;
}

async function refreshPromptCaptioningLeftData(kind = 'all') {
  const pc = promptCaptioningState();
  try {
    if (kind === 'all' || kind === 'saved') {
      const saved = await promptCaptioningFetchJson('/api/prompt-captioning/prompt-records');
      pc.library.promptRecords = saved.records || [];
    }
    if (kind === 'all' || kind === 'history') {
      const history = await promptCaptioningFetchJson('/api/prompt-captioning/prompt-history?limit=25');
      pc.library.promptHistory = history.records || [];
    }
    if (kind === 'all' || kind === 'presets') {
      const presets = await promptCaptioningFetchJson('/api/prompt-captioning/prompt-presets');
      pc.library.promptPresets = presets.records || [];
    }
    if (kind === 'all' || kind === 'characters') {
      const characters = await promptCaptioningFetchJson('/api/prompt-captioning/characters');
      pc.library.characterRecords = characters.records || [];
    }
    pc.promptBuilder.status = 'Prompt Builder left panel refreshed.';
  } catch (error) {
    pc.promptBuilder.status = `Left panel error: ${error.message}`;
  }
  render();
}


function promptCaptioningEnsureLibraryLoaded(kind = 'all') {
  const pc = promptCaptioningState();
  pc.library = pc.library || {};
  pc.library.loadedKinds = pc.library.loadedKinds || {};
  const key = kind || 'all';
  if (pc.library.loadedKinds[key] || pc.library.loadingKinds?.[key]) return;
  pc.library.loadingKinds = pc.library.loadingKinds || {};
  pc.library.loadingKinds[key] = true;
  window.setTimeout(async () => {
    try {
      await refreshPromptCaptioningLeftData(kind);
      const current = promptCaptioningState();
      current.library.loadedKinds = current.library.loadedKinds || {};
      current.library.loadedKinds[key] = true;
    } catch (error) {
      const current = promptCaptioningState();
      current.promptBuilder.status = `Library auto-load error: ${error.message || error}`;
    } finally {
      const current = promptCaptioningState();
      current.library.loadingKinds = current.library.loadingKinds || {};
      delete current.library.loadingKinds[key];
    }
  }, 0);
}

async function savePromptCaptioningPreset() {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder;
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/prompt-preset/save', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        preset_id: pb.selectedPresetId || '',
        name: pb.presetName || 'Untitled Preset',
        category: pb.presetCategory || 'General',
        style: pb.presetStyle || pb.promptStyle || '',
        subject: pb.presetSubject || '',
        mood: pb.presetMood || '',
        tags: pb.presetTags || '',
        notes: pb.presetNotes || '',
        default_positive: pb.outputText || pb.sourceText || '',
        default_negative: pb.negativeOutputText || '',
        settings: pb.params || {},
      }),
    });
    pc.library.promptPresets = data.records || pc.library.promptPresets || [];
    pb.selectedPresetId = data.record?.preset_id || '';
    pb.status = 'Saved prompt preset.';
  } catch (error) {
    pb.status = `Preset save error: ${error.message}`;
  }
  render();
}

async function savePromptCaptioningCharacter() {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder;
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/character/save', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        character_id: pb.selectedCharacterId || '',
        name: pb.characterName || 'Untitled Character',
        traits: pb.characterTraits || '',
        appearance: pb.characterAppearance || '',
        outfit: pb.characterOutfit || '',
        identity_fragments: pb.characterFragments || '',
        notes: pb.characterNotes || '',
      }),
    });
    pc.library.characterRecords = data.records || pc.library.characterRecords || [];
    pb.selectedCharacterId = data.record?.character_id || '';
    pb.status = 'Saved character block.';
  } catch (error) {
    pb.status = `Character save error: ${error.message}`;
  }
  render();
}

function loadPromptCaptioningRecord(id) {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder;
  const records = [ ...(pc.library.promptRecords || []), ...(pc.library.promptHistory || []) ];
  const item = records.find((record) => [record.prompt_id, record.history_id].includes(id));
  if (!item) return;
  pb.sourceText = item.source_text || pb.sourceText || '';
  pb.outputText = item.prompt || item.output_text || pb.outputText || '';
  pb.negativeOutputText = item.negative_prompt || pb.negativeOutputText || '';
  pb.promptStyle = item.style || pb.promptStyle || '';
  pb.selectedSavedPromptId = item.prompt_id || '';
  pb.saveName = item.name || pb.saveName || '';
  pb.saveCategory = item.category || pb.saveCategory || 'General';
  pb.saveTags = Array.isArray(item.tags) ? item.tags.join(', ') : (item.tags || pb.saveTags || '');
  pb.saveNotes = item.notes || pb.saveNotes || '';
  pb.status = 'Loaded prompt into Prompt Studio.';
  render();
}

function loadPromptCaptioningPreset(id) {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder;
  const item = (pc.library.promptPresets || []).find((record) => record.preset_id === id);
  if (!item) return;
  pb.selectedPresetId = item.preset_id || '';
  pb.presetName = item.name || '';
  pb.presetCategory = item.category || '';
  pb.presetStyle = item.style || '';
  pb.presetSubject = item.subject || '';
  pb.presetMood = item.mood || '';
  pb.presetTags = (item.tags || []).join(', ');
  pb.presetNotes = item.notes || '';
  pb.promptStyle = item.style || pb.promptStyle || '';
  pb.sourceText = item.default_positive || pb.sourceText || '';
  pb.negativeOutputText = item.default_negative || pb.negativeOutputText || '';
  pb.params = { ...(pb.params || {}), ...(item.settings || {}) };
  pb.status = 'Loaded prompt preset.';
  render();
}

function loadPromptCaptioningCharacter(id) {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder;
  const item = (pc.library.characterRecords || []).find((record) => record.character_id === id);
  if (!item) return;
  pb.selectedCharacterId = item.character_id || '';
  pb.characterName = item.name || '';
  pb.characterTraits = item.traits || '';
  pb.characterAppearance = item.appearance || '';
  pb.characterOutfit = item.outfit || '';
  pb.characterFragments = item.identity_fragments || '';
  const block = [item.name, item.traits, item.appearance, item.outfit, item.identity_fragments].filter(Boolean).join(', ');
  pb.sourceText = [pb.sourceText, block].filter(Boolean).join(pb.sourceText ? ', ' : '');
  pb.status = 'Sent character block to Prompt Studio.';
  render();
}


