function promptCaptioningCaptionBrowserItems(library = {}) {
  const assistItems = Array.isArray(library.assistCaptionItems) ? library.assistCaptionItems : [];
  const fallbackItems = [
    ...((library.captionRecords || []).map((item) => ({ ...item, caption_item_id: item.caption_id || item.id || '', title: item.name || item.title || 'Saved caption', caption: item.caption || item.output_caption || item.output_text || '' }))),
    ...((library.captionHistory || []).map((item) => ({ ...item, caption_item_id: item.history_id || item.id || '', title: item.name || item.title || 'Recent caption', caption: item.caption || item.output_caption || item.output_text || '' }))),
    ...((library.captionBatchResults || []).flatMap((batch) => (Array.isArray(batch.results) ? batch.results : []).map((item, index) => ({ ...item, caption_item_id: `${batch.batch_id || 'batch'}_${index}`, source: 'batch_result', title: item.name || item.title || basename(item.image || item.file || 'Batch caption'), category: item.category || batch.category || batch.workflow_mode || 'Batch', caption: item.caption || item.output_caption || item.output_text || '', created_at: item.created_at || batch.created_at || '' })))),
  ].filter((item) => String(item.caption || '').trim());
  return (assistItems.length ? assistItems : fallbackItems).map((item, index) => {
    const id = String(item.caption_item_id || item.caption_id || item.history_id || item.id || `caption_browser_${index}`);
    const title = String(item.title || item.name || basename(item.source_image || item.image || item.file || '') || 'Caption');
    const imageUrl = String(item.image_url || item.library_image_url || item.stored_image_url || item.source_image_url || item.preview_url || item.url || '');
    const sourceImage = String(item.source_image || item.stored_image || item.image || item.file || item.asset_ref || '');
    return { ...item, caption_item_id: id, title, name: item.name || title, caption: String(item.caption || item.output_caption || item.output_text || '').trim(), category: String(item.category || 'Caption'), image_url: imageUrl, source_image: sourceImage, source_image_url: String(item.source_image_url || imageUrl), source_image_name: String(item.source_image_name || item.filename || basename(sourceImage || imageUrl || title)), source: String(item.source || 'caption'), created_at: String(item.created_at || item.updated_at || '') };
  }).filter((item) => item.caption);
}

function promptCaptioningCaptionBrowserSelectedItem(library = {}) {
  const items = promptCaptioningCaptionBrowserItems(library);
  if (!items.length) return null;
  const selectedId = String(library.assistCaptionSelectedId || '');
  return items.find((item) => item.caption_item_id === selectedId) || items[0];
}

function promptCaptioningCaptionBrowserSourceFromItem(item = {}) {
  const url = String(item.image_url || item.source_image_url || item.library_image_url || item.stored_image_url || '').trim();
  const path = String(item.source_image || item.stored_image || item.path || '').trim();
  const filename = String(item.source_image_name || item.filename || item.title || basename(path || url || 'caption_image')).trim();
  return {
    source_type: 'caption_browser',
    source_scope: item.source || 'caption_library',
    result_id: item.caption_item_id || '',
    file_id: item.caption_item_id || '',
    output_id: item.caption_item_id || '',
    filename,
    path,
    saved_path: path,
    url,
    view_url: url,
    preview_url: url,
  };
}

