function promptCaptioningCapabilityChips(profile, modeId = 'captioning') {
  const flags = promptCaptioningProfileFlags(profile);
  if (!profile) return '<div class="neo-badge-row neo-pc-capability-chips"><span class="neo-state-pill warning">No backend profile selected</span></div>';
  const status = backendProfileStatus(profile);
  const runtimeHint = (flags.runtime_supports_vision || flags.runtime_supports_captioning)
    ? '<span class="neo-state-pill muted">Runtime vision detected</span>'
    : '';
  return `<div class="neo-badge-row neo-chip-row neo-pc-capability-chips" data-testid="caption-effective-capability-chips">
    <span class="neo-state-pill ${flags.supports_text ? 'success' : 'danger'}">Text ${flags.supports_text ? '✅' : '❌'}</span>
    <span class="neo-state-pill ${flags.supports_vision ? 'success' : 'warning'}">Vision ${flags.supports_vision ? '✅' : '❌'}</span>
    <span class="neo-state-pill ${flags.supports_captioning ? 'success' : 'warning'}">Caption ${flags.supports_captioning ? '✅' : '❌'}</span>
    ${runtimeHint}
    <span class="neo-state-pill muted">Source: ${escapeHtml(flags.capability_source || 'profile_flag')}</span>
    <span class="neo-state-pill ${statusClass(status)}">${escapeHtml(status)}</span>
  </div>`;
}

