async function uploadCaptionSourceImage(file) {
  const pc = promptCaptioningState();
  const cap = pc.captioning;
  cap.uploadError = '';
  if (!file) return;
  if (!String(file.type || '').startsWith('image/')) {
    cap.uploading = false;
    cap.uploadError = 'Only image files can be uploaded.';
    cap.uploadStatus = 'Upload failed';
    cap.status = `Caption image upload error: ${cap.uploadError}`;
    render();
    return;
  }
  cap.uploading = true;
  cap.uploadStatus = 'Uploading caption image...';
  cap.status = 'Uploading caption image...';
  render();
  const form = new FormData();
  form.append('file', file);
  try {
    const response = await fetch('/api/prompt-captioning/caption/upload-image', { method: 'POST', body: form });
    const data = await response.json().catch(() => ({}));
    if (!response.ok || data.ok === false) throw new Error((data.errors || []).join('\n') || data.detail || data.message || 'Caption image upload failed');
    const asset = normalizeCaptionUploadResponse(data, file);
    setCaptionImageStateFromUpload(asset);
    refreshCaptionValidation();
  } catch (error) {
    cap.uploadError = error.message || 'Caption image upload failed';
    cap.uploadStatus = 'Upload failed';
    cap.status = `Caption image upload error: ${cap.uploadError}`;
  } finally {
    cap.uploading = false;
    updateCaptionImagePreviewDom();
    render();
  }
}

