async function runPromptCaptioningCaption(toolId = 'image_captioning') {
  const pc = promptCaptioningState();
  const cap = pc.captioning;
  if (cap.isRunning) {
    const started = Date.parse(cap.runStartedAt || '') || 0;
    if (started && Date.now() - started < 120000) return;
    cap.isRunning = false;
  }
  cap.activeTool = toolId || 'image_captioning';
  cap.status = 'Running Caption Studio…';
  cap.isRunning = true;
  cap.runStartedAt = new Date().toISOString();
  render();
  const payload = buildPromptCaptioningPayload('captioning', cap.activeTool);
  try {
    const response = await fetch('/api/prompt-captioning/caption/run', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
    const data = await response.json().catch(() => ({}));
    const recoveredText = resolveCaptionStudioOutput(data);
    if (!response.ok || (data.ok === false && !recoveredText)) throw new Error(promptCaptioningRunErrorMessage(data, 'Caption Studio run failed'));
    cap.outputCaption = recoveredText;
    promptCaptioningWriteCaptionOutputToDom(recoveredText);
    cap.lastPayload = data.payload || payload;
    cap.lastMetadata = data.metadata || null;
    cap.lastReplayPayload = data.replay_payload || null;
    pc.library.resultMetadata = data.metadata ? [data.metadata, ...(pc.library.resultMetadata || [])].slice(0, 50) : (pc.library.resultMetadata || []);
    recordMemoryEvent('prompt_captioning.caption.generated', 'prompt_captioning', { tool_id, metadata_id: data.metadata?.metadata_id || '', replay_ready: Boolean(data.replay_payload) });
    cap.history = [data.history || { tool_id: cap.activeTool, caption: cap.outputCaption, created_at: new Date().toISOString() }, ...(cap.history || [])].slice(0, 20);
    cap.status = promptCaptioningRecoveryStatus(data);
  } catch (error) {
    cap.status = `Error: ${error.message}`;
  } finally {
    finalizePromptCaptioningCaptionRun();
  }
  render();
  finalizePromptCaptioningCaptionRun();
  promptCaptioningWriteCaptionOutputToDom(cap.outputCaption || '');
}

async function savePromptCaptioningCaption() {
  const pc = promptCaptioningState();
  const cap = pc.captioning;
  const captionDom = document.getElementById('promptCaptioningCaptionOutput');
  if (captionDom && captionDom.value && captionDom.value !== cap.outputCaption) cap.outputCaption = captionDom.value;
  const caption = cap.outputCaption || '';
  if (!caption.trim()) {
    cap.status = 'Nothing to save yet.';
    render();
    return;
  }
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/caption/save', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        name: cap.saveName || 'Untitled Caption',
        category: promptCaptioningResolvedCategory('promptCaptioningSaveCaptionCategory', 'promptCaptioningSaveCaptionCategoryNew', cap.saveCategory || 'General'),
        tags: cap.saveTags || '',
        notes: cap.saveNotes || '',
        caption,
        source_image: cap.selectedImage || '',
        source_image_url: cap.selectedImageUrl || '',
        caption_style: cap.captionStyle || '',
        caption_length: cap.captionLength || '',
        output_style: cap.outputStyle || '',
        component_type: (cap.params || {}).component_type || '',
        caption_mode: (cap.params || {}).caption_mode || '',
        detail_level: (cap.params || {}).detail_level || '',
        settings: cap.params || {},
        metadata: { source_surface: 'prompt_captioning', source_tool: cap.activeTool || 'image_captioning' },
      }),
    });
    pc.library.captionRecords = data.records || pc.library.captionRecords || [];
    const savedCategory = promptCaptioningResolvedCategory('promptCaptioningSaveCaptionCategory', 'promptCaptioningSaveCaptionCategoryNew', cap.saveCategory || 'General');
    promptCaptioningRememberCategory(savedCategory, 'caption');
    cap.saveCategory = savedCategory;
    cap.saveCategoryNew = '';
    cap.selectedCaptionId = data.record?.caption_id || '';
    cap.status = 'Saved to library.';
  } catch (error) {
    cap.status = `Caption save error: ${error.message}`;
  }
  render();
}

function promptCaptioningMetadataReplayPanel() {
  const pc = promptCaptioningState();
  const library = pc.library || {};
  const records = Array.isArray(library.resultMetadata) ? library.resultMetadata : [];
  const latest = records[0] || null;
  const display = promptCaptioningDisplayModeSetup();
  const helper = promptCaptioningHelperText('Structured result metadata is recorded for Prompt Studio, Caption Studio, batch runs, and handoffs. Replay payloads are prepared only; Assistant memory behavior is not enabled here.');
  const latestSummary = latest ? promptCaptioningMetadataSummaryCard(latest) : promptCaptioningEmptyState('No Prompt/Captioning metadata recorded yet.', 'Run a prompt, caption an image, save an item, or send a result to another workspace to create replay-ready metadata.', 'Expert mode shows the raw replay payload when available.');
  const replayPreview = library.lastReplayPayload ? `<pre>${escapeHtml(JSON.stringify(library.lastReplayPayload, null, 2))}</pre>` : '';
  return `
    ${helper}
    <div class="neo-button-row">
      <button type="button" id="promptCaptioningRefreshMetadata">Refresh Metadata</button>
    </div>
    ${latestSummary}
    ${display.expert ? `${promptCaptioningMiniList(records.slice(0, 5), 'No metadata records yet.')}${replayPreview}` : ''}
  `;
}

async function refreshPromptCaptioningResultMetadata() {
  const pc = promptCaptioningState();
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/result-metadata?limit=50');
    pc.library.resultMetadata = data.records || [];
  } catch (error) {
    console.warn('Prompt/Captioning metadata refresh failed', error);
  }
}

async function loadPromptCaptioningReplayPayload(metadataId = '') {
  if (!metadataId) return;
  const pc = promptCaptioningState();
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/replay-payload', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ metadata_id: metadataId }),
    });
    pc.library.lastReplayPayload = data.replay_payload || null;
  } catch (error) {
    pc.library.lastReplayPayload = { ok: false, error: error.message };
  }
  render();
}

