function promptCaptioningAssistControlValue(id, fallback = '') {
  const field = document.getElementById(id);
  return field ? String(field.value || '') : String(fallback || '');
}

function promptCaptioningAssistTargetField(target = 'prompt_output') {
  const map = {
    source_text: { id: 'promptCaptioningSourceText', stateKey: 'sourceText', label: 'Source text / idea' },
    custom_instructions: { id: 'promptCaptioningCustomInstructions', stateKey: 'customInstructions', label: 'Custom instructions' },
    prompt_output: { id: 'promptCaptioningOutputText', stateKey: 'outputText', label: 'Prompt output' },
    negative_prompt: { id: 'promptCaptioningNegativeOutputText', stateKey: 'negativeOutputText', label: 'Negative prompt output' },
  };
  return map[target] || map.prompt_output;
}

function promptCaptioningJoinText(existing = '', incoming = '', mode = 'append') {
  const left = String(existing || '').trim();
  const right = String(incoming || '').trim();
  if (!right) return left;
  if (mode === 'replace_full') return right;
  if (!left) return right;
  if (mode === 'prepend') return `${right}${right.endsWith(',') ? ' ' : ', '}${left}`;
  return `${left}${left.endsWith(',') ? ' ' : ', '}${right}`;
}

async function promptCaptioningApplyAssistInsert(text = '', options = {}) {
  const value = String(text || '').trim();
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder || (pc.promptBuilder = {});
  const shouldRender = options.render !== false;
  const updateLocalStatus = () => {
    const status = document.getElementById('pcKeywordV2Status');
    if (status && pb.status) status.textContent = pb.status;
  };
  if (!value) {
    pb.status = 'Nothing to insert from assist tool.';
    if (shouldRender) render(); else updateLocalStatus();
    return false;
  }
  const mode = String(options.mode || 'append');
  const target = String(options.target || 'prompt_output');
  if (mode === 'copy_only') {
    await promptCaptioningCopyTextToClipboard(value);
    pb.status = 'Copied assist text. Prompt Studio was not changed.';
    saveUiState();
    if (shouldRender) render(); else updateLocalStatus();
    return true;
  }
  syncPromptCaptioningPromptFormFromDom();
  const fieldInfo = promptCaptioningAssistTargetField(target);
  const field = document.getElementById(fieldInfo.id);
  const current = field ? String(field.value || '') : String(pb[fieldInfo.stateKey] || '');
  let next = '';
  if (mode === 'replace_selected' && field && typeof field.selectionStart === 'number' && field.selectionStart !== field.selectionEnd) {
    const start = field.selectionStart;
    const end = field.selectionEnd;
    next = `${current.slice(0, start)}${value}${current.slice(end)}`;
  } else {
    next = promptCaptioningJoinText(current, value, mode);
  }
  pb[fieldInfo.stateKey] = next;
  if (field) field.value = next;
  pb.status = `Inserted assist text into ${fieldInfo.label} (${mode.replaceAll('_', ' ')}).`;
  saveUiState();
  if (shouldRender) {
    render();
  } else {
    updateLocalStatus();
  }
  return true;
}

function promptCaptioningAssistTagTextFromDom() {
  return promptCaptioningAssistControlValue('promptAssistTagOutput') || promptCaptioningAssistControlValue('promptAssistTagSource');
}

async function generatePromptAssistTags() {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder || (pc.promptBuilder = {});
  const source = promptCaptioningAssistControlValue('promptAssistTagSource');
  const mode = promptCaptioningAssistControlValue('promptAssistTagMode', 'normalize');
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/tag-assist/generate', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ source_text: source, style: mode, insert_mode: 'append' }),
    });
    const fragment = data.prompt_fragment || (Array.isArray(data.tags) ? data.tags.join(', ') : '');
    const output = document.getElementById('promptAssistTagOutput');
    if (output) output.value = fragment;
    promptCaptioningAssistState().lastTagGroup = data.record || { prompt_fragment: fragment, tags: data.tags || [] };
    pb.status = 'Tag Assist generated a staged tag group.';
  } catch (error) {
    pb.status = `Tag Assist error: ${error.message}`;
  }
  render();
}

async function savePromptAssistTags() {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder || (pc.promptBuilder = {});
  const fragment = promptCaptioningAssistTagTextFromDom();
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/tag-assist/save', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name: promptCaptioningAssistControlValue('promptAssistTagName', 'Tag Group'), category: promptCaptioningAssistControlValue('promptAssistTagCategory', 'General'), tags: fragment, prompt_fragment: fragment, source_text: promptCaptioningAssistControlValue('promptAssistTagSource') }),
    });
    promptCaptioningState().library.tagGroups = data.records || [];
    pb.status = 'Saved Tag Assist group.';
  } catch (error) {
    pb.status = `Tag save error: ${error.message}`;
  }
  render();
}

function insertPromptAssistTags() {
  const target = promptCaptioningAssistControlValue('promptAssistTagTarget', 'prompt_output');
  const mode = promptCaptioningAssistControlValue('promptAssistTagMode', 'append');
  return promptCaptioningApplyAssistInsert(promptCaptioningAssistTagTextFromDom(), { target, mode });
}

function promptCaptioningCharacterPayloadFromDom() {
  return {
    name: promptCaptioningAssistControlValue('promptAssistCharacterName'),
    presentation: promptCaptioningAssistControlValue('promptAssistCharacterPresentation'),
    appearance: promptCaptioningAssistControlValue('promptAssistCharacterAppearance'),
    outfit: promptCaptioningAssistControlValue('promptAssistCharacterOutfit'),
    pose: promptCaptioningAssistControlValue('promptAssistCharacterPoseMood'),
    mood: promptCaptioningAssistControlValue('promptAssistCharacterPoseMood'),
    style: promptCaptioningAssistControlValue('promptAssistCharacterStyleNotes'),
    negative_safeguards: promptCaptioningAssistControlValue('promptAssistCharacterNegative'),
  };
}

async function buildPromptAssistCharacter() {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder || (pc.promptBuilder = {});
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/character/build-prompt', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ ...promptCaptioningCharacterPayloadFromDom(), mode: promptCaptioningAssistControlValue('promptAssistCharacterOutputMode', 'detailed') }),
    });
    const promptOut = document.getElementById('promptAssistCharacterPromptFragment');
    const negOut = document.getElementById('promptAssistCharacterNegativeFragment');
    if (promptOut) promptOut.value = data.prompt_fragment || '';
    if (negOut) negOut.value = data.negative_fragment || '';
    pb.status = 'Character Builder prepared prompt fragments.';
  } catch (error) {
    pb.status = `Character build error: ${error.message}`;
  }
  render();
}

async function savePromptAssistCharacter() {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder || (pc.promptBuilder = {});
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/character/save', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ ...promptCaptioningCharacterPayloadFromDom(), prompt_fragment: promptCaptioningAssistControlValue('promptAssistCharacterPromptFragment'), negative_fragment: promptCaptioningAssistControlValue('promptAssistCharacterNegativeFragment') }),
    });
    pc.library.characterRecords = data.records || pc.library.characterRecords || [];
    pb.status = 'Saved character record.';
  } catch (error) {
    pb.status = `Character save error: ${error.message}`;
  }
  render();
}

function insertPromptAssistCharacter(kind = 'prompt') {
  const text = kind === 'negative' ? promptCaptioningAssistControlValue('promptAssistCharacterNegativeFragment') || promptCaptioningAssistControlValue('promptAssistCharacterNegative') : promptCaptioningAssistControlValue('promptAssistCharacterPromptFragment');
  const target = kind === 'negative' ? 'negative_prompt' : promptCaptioningAssistControlValue('promptAssistCharacterTarget', 'prompt_output');
  const mode = promptCaptioningAssistControlValue('promptAssistCharacterMode', 'append');
  return promptCaptioningApplyAssistInsert(text, { target, mode });
}


function promptCaptioningCharacterKeywordBrowserV2State() {
  const pc = promptCaptioningState();
  pc.characterKeywordBrowserV2 = pc.characterKeywordBrowserV2 || {
    records: [],
    genders: ['all'],
    categories: ['all'],
    types: ['all'],
    eras: ['all'],
    gender: 'all',
    category: 'all',
    type: 'all',
    era: 'all',
    query: '',
    libraryPath: localStorage.getItem('neoCharacterKeywordBrowserV2Path') || '',
    diagnostics: {},
    status: 'Not loaded yet.',
    loading: false,
    selectedId: '',
    insertedIds: {},
    chipTarget: 'character_prompt_fragment',
    chipMode: 'append',
  };
  return pc.characterKeywordBrowserV2;
}

function promptCaptioningCharacterKeywordBrowserV2DomValue(id, fallback = '') {
  const el = document.getElementById(id);
  return el ? el.value : fallback;
}

function promptCaptioningCharacterKeywordBrowserV2TargetField(target = 'character_prompt_fragment') {
  const clean = String(target || 'character_prompt_fragment');
  if (clean === 'character_prompt_fragment') return { id: 'promptAssistCharacterPromptFragment', label: 'Character prompt fragment' };
  if (clean === 'character_negative_fragment') return { id: 'promptAssistCharacterNegativeFragment', label: 'Negative fragment' };
  return promptCaptioningAssistTargetField(clean);
}

function promptCaptioningCharacterKeywordBrowserV2InsertIntoTarget(text = '', target = 'character_prompt_fragment', mode = 'append') {
  const value = String(text || '').trim();
  const state = promptCaptioningCharacterKeywordBrowserV2State();
  if (!value) {
    state.status = 'No character keyword text to insert.';
    promptCaptioningCharacterKeywordBrowserV2SetStatus(state.status);
    return false;
  }
  const fieldInfo = promptCaptioningCharacterKeywordBrowserV2TargetField(target);
  const field = document.getElementById(fieldInfo.id);
  if (!field) {
    if (target === 'character_prompt_fragment' || target === 'character_negative_fragment') {
      state.status = `${fieldInfo.label} is not mounted yet.`;
      promptCaptioningCharacterKeywordBrowserV2SetStatus(state.status);
      return false;
    }
    return promptCaptioningApplyAssistInsert(value, { target, mode, render: false });
  }
  const current = String(field.value || '');
  let next = '';
  if (mode === 'replace_selected' && typeof field.selectionStart === 'number' && field.selectionStart !== field.selectionEnd) {
    next = `${current.slice(0, field.selectionStart)}${value}${current.slice(field.selectionEnd)}`;
  } else {
    next = promptCaptioningJoinText(current, value, mode);
  }
  field.value = next;
  field.dispatchEvent(new Event('input', { bubbles: true }));
  state.status = `Inserted character keyword into ${fieldInfo.label}.`;
  promptCaptioningCharacterKeywordBrowserV2SetStatus(state.status);
  saveUiState();
  return true;
}

function promptCaptioningCharacterKeywordBrowserV2SetStatus(message = '') {
  const state = promptCaptioningCharacterKeywordBrowserV2State();
  state.status = String(message || state.status || '');
  const status = document.getElementById('pcCharacterKeywordV2Status');
  if (status) status.textContent = state.status;
}

function promptCaptioningCharacterKeywordBrowserV2SelectedRecord() {
  const state = promptCaptioningCharacterKeywordBrowserV2State();
  const selected = promptCaptioningCharacterKeywordBrowserV2DomValue('pcCharacterKeywordV2TitleSelect', state.selectedId || '');
  return (state.records || []).find((item) => String(item.keyword_id || item.id || '') === String(selected || state.selectedId || '')) || (state.records || [])[0] || null;
}

function promptCaptioningCharacterKeywordBrowserV2DescChipParts(record) {
  const label = String(record?.label || record?.name || '').trim();
  const alias = String((record?.aliases || [])[0] || record?.title || record?.keyword_title || '').trim();
  const desc = String(record?.desc || record?.description || '').trim();
  const chips = [];
  const push = (kind, text, title = '') => {
    const clean = String(text || '').replace(/\s+/g, ' ').trim();
    if (!clean) return;
    const key = clean.toLowerCase();
    if (chips.some((chip) => chip.key === key)) return;
    chips.push({ kind, text: clean, title: title || clean, key });
  };
  push('keyword', label, 'Keyword title');
  if (alias && alias !== label) push('alias', alias, 'Alias');
  if (desc) push('description', desc, 'Full description');
  if (desc) {
    const segments = desc.includes(',') || desc.includes(';')
      ? desc.split(/[;,]+/g)
      : desc.split(/\s+(?=(?:wearing|holding|ornate|fantasy|modern|ancient|soft|dark|elegant|detailed|cinematic|royal|leather|silk|gold|silver|glowing|mystic|casual|formal|battle|mage|warrior)\b)/gi);
    segments.forEach((part) => {
      const clean = String(part || '').trim();
      if (clean.split(/\s+/).filter(Boolean).length >= 2) push('desc-chip', clean, 'Description phrase');
    });
  }
  return chips.slice(0, 80);
}

function promptCaptioningCharacterKeywordBrowserV2RenderDiagnostics(state) {
  const d = state.diagnostics || {};
  const files = Array.isArray(d.markdown_files) ? d.markdown_files : [];
  return `<details class="neo-pc-keyword-v2-diagnostics"><summary class="neo-pc-keyword-v2-diagnostics-summary"><span>${Number(d.markdown_file_count || 0)} character Markdown file(s)</span><span>${Number(d.loaded_keyword_count || 0)} loaded</span><span>${Number(d.visible_keyword_count || 0)} visible</span><strong>Details</strong></summary><div class="neo-pc-keyword-v2-diagnostics-body"><strong>Status</strong><p>${escapeHtml(state.status || '')}</p><strong>Loaded files</strong><ul class="neo-pc-keyword-v2-path-list">${files.slice(0, 24).map((path) => `<li><code>${escapeHtml(path)}</code></li>`).join('') || '<li>None.</li>'}</ul><p class="neo-muted">Filename rule: <code>Gender__Category__Type__Era.md</code>. Search filters keyword titles/aliases only.</p></div></details>`;
}

function promptCaptioningCharacterKeywordBrowserV2RenderResults() {
  const state = promptCaptioningCharacterKeywordBrowserV2State();
  const root = document.getElementById('pcCharacterKeywordV2Results');
  if (!root) return;
  const records = state.records || [];
  const selected = promptCaptioningCharacterKeywordBrowserV2SelectedRecord();
  const selectedId = String(selected?.keyword_id || selected?.id || '');
  const inserted = state.insertedIds || {};
  const chips = promptCaptioningCharacterKeywordBrowserV2DescChipParts(selected);
  const titleOptions = records.map((item) => {
    const id = String(item.keyword_id || item.id || '');
    const title = String(item.title || item.keyword_title || item.label || 'Character keyword');
    return `<option value="${escapeAttr(id)}" ${id === selectedId ? 'selected' : ''}>${escapeHtml(title)}</option>`;
  }).join('');
  const titleCards = records.slice(0, 120).map((item) => {
    const id = String(item.keyword_id || item.id || '');
    const active = id === selectedId ? ' is-active' : '';
    return `<button type="button" class="neo-pc-keyword-v2-title${active}" onclick="promptCaptioningCharacterKeywordBrowserV2Select('${escapeAttr(id)}')"><span>${escapeHtml(item.title || item.label || 'Keyword')}</span><small>${escapeHtml([item.gender, item.category, item.type, item.era].filter(Boolean).join(' › '))}</small></button>`;
  }).join('');
  root.innerHTML = `
    <div class="neo-pc-keyword-v2-all">
      <div class="neo-pc-keyword-v2-all-head"><strong>${records.length} character keyword title(s) visible</strong><span>${Number(state.total || records.length)} total</span></div>
      <div class="neo-form-grid neo-pc-keyword-v2-chip-controls">
        <label>Keyword title${promptCaptioningSelect('pcCharacterKeywordV2TitleSelect', selectedId, titleOptions ? records.map((item) => ({ value: String(item.keyword_id || item.id || ''), label: String(item.title || item.label || 'Keyword') })) : [{ value: '', label: 'No character keywords loaded' }])}</label>
        <label>Chip click target${promptCaptioningSelect('pcCharacterKeywordV2ChipTarget', state.chipTarget || 'character_prompt_fragment', [
          { value: 'character_prompt_fragment', label: 'Character prompt fragment' },
          { value: 'character_negative_fragment', label: 'Negative fragment' },
          { value: 'source_text', label: 'Source text / idea' },
          { value: 'custom_instructions', label: 'Custom instructions' },
          { value: 'prompt_output', label: 'Prompt output' },
          { value: 'negative_prompt', label: 'Negative prompt output' },
        ])}</label>
        <label>Insert mode${promptCaptioningSelect('pcCharacterKeywordV2ChipMode', state.chipMode || 'append', [
          { value: 'append', label: 'Append' },
          { value: 'prepend', label: 'Prepend' },
          { value: 'replace_selected', label: 'Replace selected text' },
          { value: 'replace_full', label: 'Replace full field' },
        ])}</label>
      </div>
      <div class="neo-button-row">
        <button type="button" class="neo-btn primary" onclick="promptCaptioningCharacterKeywordBrowserV2InsertSelected('character_prompt_fragment')">Append selected description to Character prompt fragment</button>
        <button type="button" class="neo-btn secondary" onclick="promptCaptioningCharacterKeywordBrowserV2InsertSelected('character_negative_fragment')">Append selected description to Negative fragment</button>
        <button type="button" class="neo-btn secondary" onclick="promptCaptioningCharacterKeywordBrowserV2ResetInsertedChips()">Reset green chips</button>
      </div>
      <div class="neo-pc-keyword-v2-title-grid">${titleCards || '<p class="neo-muted">No character keyword titles visible yet.</p>'}</div>
      <strong>Description chips</strong>
      <div class="neo-pc-keyword-v2-chip-grid">${chips.map((chip, index) => {
        const id = `${selectedId}::${index}`;
        const isInserted = inserted[id] ? ' is-inserted' : '';
        return `<button type="button" class="neo-pc-keyword-v2-chip${isInserted}" onclick="promptCaptioningCharacterKeywordBrowserV2InsertDescChip('${escapeAttr(selectedId)}', ${index})"><span>${escapeHtml(chip.text)}</span><small>${escapeHtml(chip.title)}</small><em>${inserted[id] ? 'Inserted' : 'Click to insert'}</em></button>`;
      }).join('') || '<p class="neo-muted">Pick a character keyword title to show description chips.</p>'}</div>
    </div>
    ${promptCaptioningCharacterKeywordBrowserV2RenderDiagnostics(state)}
  `;
  const titleSelect = document.getElementById('pcCharacterKeywordV2TitleSelect');
  if (titleSelect) titleSelect.onchange = () => promptCaptioningCharacterKeywordBrowserV2Select(titleSelect.value);
}

function promptCaptioningCharacterKeywordBrowserV2RememberControls() {
  const state = promptCaptioningCharacterKeywordBrowserV2State();
  state.libraryPath = promptCaptioningCharacterKeywordBrowserV2DomValue('pcCharacterKeywordV2LibraryPath', state.libraryPath || '');
  state.gender = promptCaptioningCharacterKeywordBrowserV2DomValue('pcCharacterKeywordV2Gender', state.gender || 'all') || 'all';
  state.category = promptCaptioningCharacterKeywordBrowserV2DomValue('pcCharacterKeywordV2Category', state.category || 'all') || 'all';
  state.type = promptCaptioningCharacterKeywordBrowserV2DomValue('pcCharacterKeywordV2Type', state.type || 'all') || 'all';
  state.era = promptCaptioningCharacterKeywordBrowserV2DomValue('pcCharacterKeywordV2Era', state.era || 'all') || 'all';
  state.query = promptCaptioningCharacterKeywordBrowserV2DomValue('pcCharacterKeywordV2Search', state.query || '');
  state.chipTarget = promptCaptioningCharacterKeywordBrowserV2DomValue('pcCharacterKeywordV2ChipTarget', state.chipTarget || 'character_prompt_fragment');
  state.chipMode = promptCaptioningCharacterKeywordBrowserV2DomValue('pcCharacterKeywordV2ChipMode', state.chipMode || 'append');
  return state;
}

async function promptCaptioningCharacterKeywordBrowserV2Load(clearFilters = false) {
  const state = promptCaptioningCharacterKeywordBrowserV2RememberControls();
  if (clearFilters) {
    state.gender = 'all'; state.category = 'all'; state.type = 'all'; state.era = 'all'; state.query = ''; state.selectedId = '';
  }
  state.loading = true;
  promptCaptioningCharacterKeywordBrowserV2SetStatus('Loading character Markdown keyword files...');
  if (state.libraryPath) localStorage.setItem('neoCharacterKeywordBrowserV2Path', state.libraryPath);
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/character-keyword-browser-v2/list', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ library_path: state.libraryPath, gender: state.gender, category: state.category, type: state.type, era: state.era, query: state.query }),
    });
    state.records = data.records || [];
    state.genders = data.genders || ['all'];
    state.categories = data.categories || ['all'];
    state.types = data.types || ['all'];
    state.eras = data.eras || ['all'];
    state.gender = data.selected_gender || state.gender || 'all';
    state.category = data.selected_category || state.category || 'all';
    state.type = data.selected_type || state.type || 'all';
    state.era = data.selected_era || state.era || 'all';
    state.diagnostics = data.diagnostics || {};
    state.total = data.total || state.records.length;
    state.selectedId = String(state.records[0]?.keyword_id || state.records[0]?.id || '');
    state.status = `${state.records.length} character keyword(s) visible · ${state.diagnostics.markdown_file_count || 0} Markdown file(s) scanned.`;
  } catch (error) {
    state.records = [];
    state.diagnostics = { markdown_file_count: 0, loaded_keyword_count: 0, visible_keyword_count: 0, markdown_files: [], empty_reason: 'request_failed' };
    state.status = `Character Keyword Browser request failed: ${error.message || error}`;
  } finally {
    state.loading = false;
  }
  ['Gender', 'Category', 'Type', 'Era'].forEach((name) => {
    const key = name.toLowerCase();
    const id = `pcCharacterKeywordV2${name}`;
    const el = document.getElementById(id);
    const listKey = key === 'type' ? 'types' : `${key}s`;
    if (el) el.innerHTML = (state[listKey] || ['all']).map((item) => `<option value="${escapeAttr(item)}" ${item === state[key] ? 'selected' : ''}>${escapeHtml(item)}</option>`).join('');
  });
  promptCaptioningCharacterKeywordBrowserV2SetStatus(state.status);
  promptCaptioningCharacterKeywordBrowserV2RenderResults();
}

function promptCaptioningCharacterKeywordBrowserV2ClearPath() {
  const state = promptCaptioningCharacterKeywordBrowserV2State();
  state.libraryPath = '';
  localStorage.removeItem('neoCharacterKeywordBrowserV2Path');
  const input = document.getElementById('pcCharacterKeywordV2LibraryPath');
  if (input) input.value = '';
  return promptCaptioningCharacterKeywordBrowserV2Load(true);
}

function promptCaptioningCharacterKeywordBrowserV2Select(id = '') {
  const state = promptCaptioningCharacterKeywordBrowserV2State();
  state.selectedId = String(id || '');
  promptCaptioningCharacterKeywordBrowserV2RenderResults();
}

function promptCaptioningCharacterKeywordBrowserV2InsertSelected(target = 'character_prompt_fragment') {
  const state = promptCaptioningCharacterKeywordBrowserV2RememberControls();
  const selected = promptCaptioningCharacterKeywordBrowserV2SelectedRecord();
  const text = String(selected?.desc || selected?.description || selected?.prompt_fragment || selected?.label || '').trim();
  const ok = promptCaptioningCharacterKeywordBrowserV2InsertIntoTarget(text, target, state.chipMode || 'append');
  if (ok && selected) {
    const key = `${String(selected.keyword_id || selected.id || '')}::selected::${target}`;
    state.insertedIds[key] = { inserted_at: new Date().toISOString(), target, text };
  }
  promptCaptioningCharacterKeywordBrowserV2RenderResults();
  return ok;
}

function promptCaptioningCharacterKeywordBrowserV2InsertDescChip(id = '', index = 0) {
  const state = promptCaptioningCharacterKeywordBrowserV2RememberControls();
  const record = (state.records || []).find((item) => String(item.keyword_id || item.id || '') === String(id || state.selectedId || '')) || promptCaptioningCharacterKeywordBrowserV2SelectedRecord();
  const chip = promptCaptioningCharacterKeywordBrowserV2DescChipParts(record)[Number(index) || 0];
  if (!chip) return false;
  const target = state.chipTarget || 'character_prompt_fragment';
  const ok = promptCaptioningCharacterKeywordBrowserV2InsertIntoTarget(chip.text, target, state.chipMode || 'append');
  if (ok) {
    const chipKey = `${String(record.keyword_id || record.id || '')}::${Number(index) || 0}`;
    state.insertedIds[chipKey] = { inserted_at: new Date().toISOString(), target, text: chip.text };
  }
  promptCaptioningCharacterKeywordBrowserV2RenderResults();
  return ok;
}

function promptCaptioningCharacterKeywordBrowserV2ResetInsertedChips() {
  const state = promptCaptioningCharacterKeywordBrowserV2State();
  state.insertedIds = {};
  promptCaptioningCharacterKeywordBrowserV2SetStatus('Character keyword inserted-state reset.');
  promptCaptioningCharacterKeywordBrowserV2RenderResults();
}

function promptCaptioningCharacterKeywordBrowserV2Panel() {
  const state = promptCaptioningCharacterKeywordBrowserV2State();
  return `<section id="pcCharacterKeywordBrowserV2Root" class="neo-mini-card neo-pc-assist-card neo-field-span-all neo-pc-keyword-v2" data-character-keyword-browser="v2">
    <strong>Character Markdown Library</strong>
    <p class="neo-muted">Use files named <code>Gender__Category__Type__Era.md</code>, then click character keyword chips to append them into the Character prompt fragment.</p>
    <div class="neo-form-grid neo-pc-keyword-browser-grid">
      <label class="neo-field-span-all">Library folder path${promptCaptioningInput('pcCharacterKeywordV2LibraryPath', state.libraryPath || '', 'neo_data\\prompt_captioning\\characters\\libraries')}</label>
      <label>Gender${promptCaptioningSelect('pcCharacterKeywordV2Gender', state.gender || 'all', state.genders || ['all'])}</label>
      <label>Category${promptCaptioningSelect('pcCharacterKeywordV2Category', state.category || 'all', state.categories || ['all'])}</label>
      <label>Type${promptCaptioningSelect('pcCharacterKeywordV2Type', state.type || 'all', state.types || ['all'])}</label>
      <label>Era${promptCaptioningSelect('pcCharacterKeywordV2Era', state.era || 'all', state.eras || ['all'])}</label>
      <label class="neo-field-span-all">Search keyword titles${promptCaptioningInput('pcCharacterKeywordV2Search', state.query || '', 'amulet / hoodie / mage / fantasy...')}</label>
    </div>
    <div class="neo-button-row">
      <button type="button" class="neo-btn primary" onclick="promptCaptioningCharacterKeywordBrowserV2Load(false)">Load Character Markdown</button>
      <button type="button" class="neo-btn secondary" onclick="promptCaptioningCharacterKeywordBrowserV2Load(false)">Apply filters</button>
      <button type="button" class="neo-btn secondary" onclick="promptCaptioningCharacterKeywordBrowserV2Load(true)">Clear filters</button>
      <button type="button" class="neo-btn secondary" onclick="promptCaptioningCharacterKeywordBrowserV2ClearPath()">Clear folder path</button>
    </div>
    <p id="pcCharacterKeywordV2Status" class="neo-muted">${escapeHtml(state.status || 'Not loaded yet.')}</p>
    <div id="pcCharacterKeywordV2Results"></div>
  </section>`;
}



function promptCaptioningKeywordRecordById(keywordId = '') {
  const records = promptCaptioningState().library?.keywordRecords || [];
  return records.find((item) => String(item.keyword_id || item.id || '') === String(keywordId || '')) || null;
}

function promptCaptioningKeywordDisplayLabel(record) {
  if (!record) return 'Keyword';
  const alias = Array.isArray(record.aliases) && record.aliases.length ? String(record.aliases[0] || '').trim() : '';
  const name = String(record.label || record.name || '').trim();
  if (alias && name && alias.toLowerCase() !== name.toLowerCase()) return `${alias} · ${name}`;
  return alias || name || 'Keyword';
}

function promptCaptioningMaybeAutoloadKeywords() {
  const pc = promptCaptioningState();
  const library = pc.library || (pc.library = {});
  if (library.keywordLoading) return;
  const diagnostics = library.keywordDiagnostics || {};
  const hasBackendResponse = Array.isArray(diagnostics.library_roots) || Array.isArray(library.keywordLibraryRoots);
  const now = Date.now();
  const lastAttempt = Number(library.keywordAutoloadAttemptAt || 0);
  if (library.keywordAutoloaded && hasBackendResponse) return;
  if (library.keywordAutoloaded && now - lastAttempt < 1500) return;
  if (document.activeElement?.id === 'promptAssistKeywordManualPath') {
    return;
  }
  // First open should show the library without interrupting manual path typing.
  library.keywordAutoloaded = true;
  library.keywordAutoloadAttemptAt = now;
  library.keywordLoading = true;
  if (!library.keywordQuery) library.keywordQuery = '';
  if (!library.keywordSelectedCategory) library.keywordSelectedCategory = 'all';
  if (!library.keywordSelectedSubcategory) library.keywordSelectedSubcategory = 'all';
  setTimeout(() => {
    Promise.resolve(refreshPromptAssistKeywords({ forceAll: true, autoload: true, direct: true })).finally(() => {
      const state = promptCaptioningState();
      state.library = state.library || {};
      state.library.keywordLoading = false;
    });
  }, 0);
}

function promptCaptioningKeywordInsertTextFromRecord(record, includeDesc = true) {
  if (!record) return '';
  const label = String(record.prompt_fragment || record.label || record.name || '').trim();
  const desc = String(record.desc || record.description || '').trim();
  return includeDesc && desc ? `${label}, ${desc}` : label;
}

function promptCaptioningUpdateKeywordPreview() {
  const library = promptCaptioningState().library || {};
  const select = document.getElementById('promptAssistKeywordSelected');
  const includeDesc = document.getElementById('promptAssistKeywordIncludeDesc')?.checked !== false;
  const keywordId = select?.value || library.keywordSelectedId || '';
  library.keywordSelectedId = keywordId;
  const record = promptCaptioningKeywordRecordById(keywordId);
  const preview = promptCaptioningKeywordInsertTextFromRecord(record, includeDesc);
  const box = document.getElementById('promptAssistKeywordPreview');
  if (box) box.value = preview;
  const source = document.getElementById('promptAssistKeywordSource');
  if (source && record) source.textContent = `${record.category || 'General'} › ${record.subcategory || 'general'} · ${record.source_name || 'custom keyword'}`;
  return preview;
}


function promptCaptioningKeywordManualPathValue() {
  const live = document.getElementById('promptAssistKeywordManualPath');
  const library = promptCaptioningState().library || (promptCaptioningState().library = {});
  if (live) return live.value || '';
  return library.keywordManualPath || localStorage.getItem('neoKeywordLibraryPath') || '';
}

function promptCaptioningSetKeywordManualPath(value = '') {
  const library = promptCaptioningState().library || (promptCaptioningState().library = {});
  library.keywordManualPath = String(value || '').trim();
  if (library.keywordManualPath) {
    localStorage.setItem('neoKeywordLibraryPath', library.keywordManualPath);
  } else {
    localStorage.removeItem('neoKeywordLibraryPath');
  }
  return library.keywordManualPath;
}

function promptCaptioningStageKeywordFiltersFromDom() {
  const library = promptCaptioningState().library || (promptCaptioningState().library = {});
  library.keywordQuery = promptCaptioningAssistControlValue('promptAssistKeywordSearch', library.keywordQuery || '');
  library.keywordSelectedCategory = promptCaptioningAssistControlValue('promptAssistKeywordCategory', library.keywordSelectedCategory || 'all') || 'all';
  library.keywordSelectedSubcategory = promptCaptioningAssistControlValue('promptAssistKeywordSubcategory', library.keywordSelectedSubcategory || 'all') || 'all';
  const pb = promptCaptioningState().promptBuilder || (promptCaptioningState().promptBuilder = {});
  pb.status = 'Keyword filters staged. Click Apply filters or Refresh keywords to reload the library view.';
}

async function refreshPromptAssistKeywords(options = {}) {
  const pc = promptCaptioningState();
  const library = pc.library || (pc.library = {});
  const pb = pc.promptBuilder || (pc.promptBuilder = {});
  const forceAll = !!options.forceAll;
  library.keywordLoading = true;
  library.keywordLastRequestAt = new Date().toISOString();
  library.keywordManualPath = promptCaptioningSetKeywordManualPath(promptCaptioningKeywordManualPathValue());
  const query = forceAll ? '' : promptCaptioningAssistControlValue('promptAssistKeywordSearch', library.keywordQuery || '');
  const category = forceAll ? 'all' : promptCaptioningAssistControlValue('promptAssistKeywordCategory', library.keywordSelectedCategory || 'all');
  const subcategory = forceAll ? 'all' : promptCaptioningAssistControlValue('promptAssistKeywordSubcategory', library.keywordSelectedSubcategory || 'all');
  library.keywordQuery = query;
  library.keywordSelectedCategory = category || 'all';
  library.keywordSelectedSubcategory = subcategory || 'all';
  try {
    pb.status = 'Loading Keyword Browser libraries…';
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/keyword/list', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        query,
        category: category === 'all' ? '' : category,
        subcategory: subcategory === 'all' ? '' : subcategory,
        include_builtin: true,
        library_path: library.keywordManualPath || '',
      }),
    });
    library.keywordRecords = data.records || [];
    library.keywordCategories = data.categories || ['all'];
    library.keywordSubcategories = data.subcategories || ['all'];
    library.keywordSelectedCategory = data.selected_category || category || 'all';
    library.keywordSelectedSubcategory = data.selected_subcategory || subcategory || 'all';
    library.keywordLibraryPath = data.library_path || '';
    library.keywordLibraryFileCount = data.library_file_count || 0;
    library.keywordLibraryRoots = data.library_roots || [];
    library.keywordLibraryExistingRoots = data.library_existing_roots || [];
    library.keywordLibraryFiles = data.library_files || [];
    library.keywordDiagnostics = data.keyword_diagnostics || {};
    library.keywordActiveLibraryRoot = data.active_library_root || library.keywordDiagnostics.active_root || '';
    library.keywordManualPathStatus = data.manual_library_path_status || library.keywordDiagnostics.manual_path_status || 'not_set';
    library.keywordProjectRootCandidates = data.project_root_candidates || [];
    library.keywordManualPath = data.manual_library_path || library.keywordManualPath || '';
    library.keywordEmptyReason = data.empty_reason || library.keywordDiagnostics.empty_reason || '';
    library.keywordTotal = data.total || data.count || 0;
    if (!library.keywordRecords.some((item) => String(item.keyword_id || item.id || '') === String(library.keywordSelectedId || ''))) {
      library.keywordSelectedId = String(library.keywordRecords[0]?.keyword_id || library.keywordRecords[0]?.id || '');
    }
    pb.status = data.count ? `Keyword Browser loaded ${data.count || 0} keyword(s) from Markdown libraries.` : `Keyword Browser found ${data.total || 0} keyword(s), but current search/filter shows 0.`;
  } catch (error) {
    pb.status = `Keyword refresh error: ${error.message}`;
    library.keywordDiagnostics = {
      schema: 'neo.prompt_captioning.keyword_browser_diagnostics.v1',
      loaded_file_count: 0,
      loaded_keyword_count: 0,
      visible_keyword_count: 0,
      library_roots: [],
      existing_roots: [],
      sample_files: [],
      manual_library_path: library.keywordManualPath || '',
      manual_path_status: library.keywordManualPath ? 'request_failed' : 'not_set',
      empty_reason: 'request_failed',
      empty_reason_label: `Keyword Browser request failed: ${error.message || error}`,
    };
  } finally {
    library.keywordLoading = false;
    library.keywordLastResponseAt = new Date().toISOString();
  }
  if (!promptCaptioningRenderLeftShellOnly('keyword_browser')) render();
}

function clearPromptAssistKeywordFilters() {
  const library = promptCaptioningState().library || (promptCaptioningState().library = {});
  library.keywordQuery = '';
  library.keywordSelectedCategory = 'all';
  library.keywordSelectedSubcategory = 'all';
  const search = document.getElementById('promptAssistKeywordSearch');
  const category = document.getElementById('promptAssistKeywordCategory');
  const subcategory = document.getElementById('promptAssistKeywordSubcategory');
  if (search) search.value = '';
  if (category) category.value = 'all';
  if (subcategory) subcategory.value = 'all';
  return refreshPromptAssistKeywords({ forceAll: true });
}

async function savePromptAssistKeyword() {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder || (pc.promptBuilder = {});
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/keyword/save', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        label: promptCaptioningAssistControlValue('promptAssistKeywordNew'),
        category: promptCaptioningAssistControlValue('promptAssistKeywordNewCategory', promptCaptioningAssistControlValue('promptAssistKeywordCategory', 'Custom')),
        subcategory: promptCaptioningAssistControlValue('promptAssistKeywordNewSubcategory', promptCaptioningAssistControlValue('promptAssistKeywordSubcategory', 'general')),
        aliases: promptCaptioningAssistControlValue('promptAssistKeywordNewAliases', ''),
        desc: promptCaptioningAssistControlValue('promptAssistKeywordNewDescription', ''),
      }),
    });
    pc.library.keywordRecords = data.records || pc.library.keywordRecords || [];
    pc.library.keywordCategories = data.categories || pc.library.keywordCategories || [];
    pc.library.keywordSubcategories = data.subcategories || pc.library.keywordSubcategories || [];
    pc.library.keywordSelectedId = data.record?.keyword_id || data.record?.id || pc.library.keywordSelectedId || '';
    pb.status = 'Saved keyword to Markdown library.';
  } catch (error) {
    pb.status = `Keyword save error: ${error.message}`;
  }
  render();
}

function insertPromptAssistKeyword(text = '') {
  const includeDesc = document.getElementById('promptAssistKeywordIncludeDesc')?.checked !== false;
  const selectedText = promptCaptioningUpdateKeywordPreview();
  const finalText = text || selectedText || promptCaptioningAssistControlValue('promptAssistKeywordPreview');
  const target = promptCaptioningAssistControlValue('promptAssistKeywordTarget', 'prompt_output');
  const mode = promptCaptioningAssistControlValue('promptAssistKeywordMode', 'append');
  return promptCaptioningApplyAssistInsert(finalText, { target, mode });
}

async function refreshPromptAssistCaptionBrowser() {
  const pc = promptCaptioningState();
  const cap = pc.captioning || {};
  const pb = pc.promptBuilder || (pc.promptBuilder = {});
  const query = promptCaptioningAssistControlValue('promptCaptioningCaptionBrowserSearch');
  const category = promptCaptioningAssistControlValue('promptCaptioningCaptionBrowserCategory');
  const sortBy = promptCaptioningAssistControlValue('promptCaptioningCaptionBrowserSort', 'newest');
  pc.library.assistCaptionQuery = query;
  pc.library.assistCaptionCategory = category;
  pc.library.assistCaptionSort = sortBy;
  try {
    const url = `/api/prompt-captioning/caption-browser/list?query=${encodeURIComponent(query)}&category=${encodeURIComponent(category)}&sort_by=${encodeURIComponent(sortBy)}`;
    const data = await promptCaptioningFetchJson(url);
    pc.library.assistCaptionItems = data.records || [];
    pc.library.assistCaptionCategories = data.categories || pc.library.assistCaptionCategories || [];
    pb.status = `Caption Browser loaded ${data.count || 0} caption(s).`;
    cap.status = pb.status;
  } catch (error) {
    pb.status = `Caption Browser refresh error: ${error.message}`;
  }
  render();
}

async function savePromptAssistCaptionFromStudio() {
  const pc = promptCaptioningState();
  const cap = pc.captioning || {};
  const pb = pc.promptBuilder || (pc.promptBuilder = {});
  const caption = promptCaptioningLiveFieldValue('promptCaptioningCaptionOutput', cap.outputCaption || '');
  const asset = captionAssetFromState(cap);
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/caption-browser/save', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        title: promptCaptioningAssistControlValue('promptAssistCaptionTitle', 'Saved caption'),
        caption,
        category: promptCaptioningAssistControlValue('promptCaptioningCaptionBrowserCategory', cap.category || 'Caption'),
        source_image: asset.asset_ref || cap.selectedImageName || cap.selectedImage || '',
        source_image_url: asset.preview_url || asset.url || '',
      }),
    });
    pc.library.assistCaptionItems = data.records || pc.library.assistCaptionItems || [];
    pc.library.assistCaptionCategory = promptCaptioningAssistControlValue('promptCaptioningCaptionBrowserCategory', pc.library.assistCaptionCategory || '');
    pb.status = 'Saved current Caption Studio output to Caption Browser.';
  } catch (error) {
    pb.status = `Caption Browser save error: ${error.message}`;
  }
  render();
}

async function sendPromptAssistCaptionToPrompt(captionItemId = '', captionText = '') {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder || (pc.promptBuilder = {});
  try {
    const data = await promptCaptioningFetchJson('/api/prompt-captioning/caption-browser/send-to-prompt', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ caption_item_id: captionItemId, caption: captionText, insert_mode: promptCaptioningAssistControlValue('promptAssistCaptionMode', 'append') }),
    });
    const inputs = data.prompt_payload?.inputs || {};
    const text = inputs.source_text || data.caption || captionText || '';
    const target = promptCaptioningAssistControlValue('promptAssistCaptionTarget', 'source_text');
    const mode = data.prompt_payload?.params?.insert_mode || promptCaptioningAssistControlValue('promptAssistCaptionMode', 'append');
    await promptCaptioningApplyAssistInsert(text, { target, mode });
    if (inputs.custom_instructions && target !== 'custom_instructions') {
      const current = promptCaptioningLiveFieldValue('promptCaptioningCustomInstructions', pb.customInstructions || '');
      const next = promptCaptioningJoinText(current, inputs.custom_instructions, 'append');
      pb.customInstructions = next;
      const custom = document.getElementById('promptCaptioningCustomInstructions');
      if (custom) custom.value = next;
    }
    pb.status = 'Sent caption to Prompt Studio.';
  } catch (error) {
    pb.status = `Caption send error: ${error.message}`;
  }
  render();
}

function promptCaptioningCaptionBrowserRememberFromDom() {
  const pc = promptCaptioningState();
  const library = pc.library || (pc.library = {});
  library.assistCaptionQuery = promptCaptioningAssistControlValue('promptCaptioningCaptionBrowserSearch', library.assistCaptionQuery || '');
  library.assistCaptionCategory = promptCaptioningAssistControlValue('promptCaptioningCaptionBrowserCategory', library.assistCaptionCategory || '');
  library.assistCaptionSort = promptCaptioningAssistControlValue('promptCaptioningCaptionBrowserSort', library.assistCaptionSort || 'newest');
  library.assistCaptionImageTarget = promptCaptioningAssistControlValue('promptCaptioningCaptionBrowserImageTarget', library.assistCaptionImageTarget || 'img2img');
  const nameId = promptCaptioningAssistControlValue('promptCaptioningCaptionBrowserName', '');
  const imageId = promptCaptioningAssistControlValue('promptCaptioningCaptionBrowserImage', '');
  if (nameId || imageId) library.assistCaptionSelectedId = nameId || imageId;
  return library;
}

function promptCaptioningCaptionBrowserSetSelected(id = '') {
  const pc = promptCaptioningState();
  const library = pc.library || (pc.library = {});
  library.assistCaptionSelectedId = String(id || '');
  const selected = promptCaptioningCaptionBrowserSelectedItem(library);
  if (selected) library.assistCaptionSelectedId = selected.caption_item_id;
  saveUiState();
  render();
}

function promptCaptioningCaptionBrowserCurrentCaption() {
  const library = promptCaptioningCaptionBrowserRememberFromDom();
  const selected = promptCaptioningCaptionBrowserSelectedItem(library);
  const live = promptCaptioningAssistControlValue('promptCaptioningCaptionBrowserPreviewCaption', '');
  return { library, selected, caption: String(live || selected?.caption || '').trim() };
}

function sendPromptAssistCaptionToImagePositive() {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder || (pc.promptBuilder = {});
  const { caption } = promptCaptioningCaptionBrowserCurrentCaption();
  if (!caption) {
    pb.status = 'Caption Browser has no caption selected.';
    render();
    return;
  }
  appendToPromptField(caption, 'positive_prompt', false);
  state.activeSurfaceId = 'image';
  ensureSurfaceRuntime('image');
  pb.status = 'Sent caption to Image tab main positive prompt.';
  saveUiState();
  render();
}

async function copyPromptAssistCaptionBrowserCaption() {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder || (pc.promptBuilder = {});
  const { caption } = promptCaptioningCaptionBrowserCurrentCaption();
  if (!caption) {
    pb.status = 'Caption Browser has no caption to copy.';
    render();
    return;
  }
  await promptCaptioningCopyTextToClipboard(caption);
  pb.status = 'Copied selected caption.';
  render();
}

function sendPromptAssistCaptionBrowserImageToSource() {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder || (pc.promptBuilder = {});
  const { library, selected } = promptCaptioningCaptionBrowserCurrentCaption();
  if (!selected) {
    pb.status = 'Caption Browser has no image selected.';
    render();
    return;
  }
  const source = promptCaptioningCaptionBrowserSourceFromItem(selected);
  const mode = promptCaptioningAssistControlValue('promptCaptioningCaptionBrowserImageTarget', library.assistCaptionImageTarget || 'img2img');
  library.assistCaptionImageTarget = mode;
  if (!previewActionHasSource(source)) {
    pb.status = 'Selected caption record has no image source.';
    render();
    return;
  }
  sendOutputToSourceMode(mode, source);
  pb.status = `Sent caption image to Image tab ${mode} source.`;
  saveUiState();
}

function sendPromptAssistCaptionBrowserImageToControlNet() {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder || (pc.promptBuilder = {});
  const { selected } = promptCaptioningCaptionBrowserCurrentCaption();
  if (!selected) {
    pb.status = 'Caption Browser has no image selected.';
    render();
    return;
  }
  const source = promptCaptioningCaptionBrowserSourceFromItem(selected);
  if (!previewActionHasSource(source)) {
    pb.status = 'Selected caption record has no image source for ControlNet.';
    render();
    return;
  }
  try {
    previewActionStageControlNetSource(source, { renderPanel: false });
    state.activeSurfaceId = 'image';
    state.activeSurfaceId = 'image';
    setSurfaceWorkspaceAppId('image', 'reference');
    pb.status = 'Sent caption image to ControlNet.';
    saveUiState();
    render();
  } catch (error) {
    pb.status = `ControlNet handoff error: ${error.message}`;
    render();
  }
}

async function sendPromptAssistCaptionBrowserToPromptStudio() {
  const { library, selected, caption } = promptCaptioningCaptionBrowserCurrentCaption();
  if (!caption) return sendPromptAssistCaptionToPrompt('', '');
  library.assistCaptionSelectedId = selected?.caption_item_id || library.assistCaptionSelectedId || '';
  await sendPromptAssistCaptionToPrompt(library.assistCaptionSelectedId, caption);
}

function ensurePromptCaptioningKeywordBrowserDelegatedBinding() {
  if (window.__neoPromptCaptioningKeywordBrowserDelegated === true) return;
  window.__neoPromptCaptioningKeywordBrowserDelegated = true;
  document.addEventListener('click', (event) => {
    const target = event.target?.closest?.('#promptAssistKeywordRefresh, #promptAssistKeywordApplyFilters, #promptAssistKeywordClearFilters, #promptAssistKeywordUsePath, #promptAssistKeywordClearPath, #promptAssistKeywordInsertSelected');
    if (!target) return;
    event.preventDefault();
    event.stopPropagation();
    if (target.id === 'promptAssistKeywordRefresh') return refreshPromptAssistKeywords({ direct: true });
    if (target.id === 'promptAssistKeywordApplyFilters') return refreshPromptAssistKeywords({ direct: true });
    if (target.id === 'promptAssistKeywordClearFilters') return clearPromptAssistKeywordFilters();
    if (target.id === 'promptAssistKeywordUsePath') {
      promptCaptioningSetKeywordManualPath(document.getElementById('promptAssistKeywordManualPath')?.value || '');
      return refreshPromptAssistKeywords({ forceAll: true, direct: true });
    }
    if (target.id === 'promptAssistKeywordClearPath') {
      const input = document.getElementById('promptAssistKeywordManualPath');
      if (input) input.value = '';
      promptCaptioningSetKeywordManualPath('');
      return refreshPromptAssistKeywords({ forceAll: true, direct: true });
    }
    if (target.id === 'promptAssistKeywordInsertSelected') return insertPromptAssistKeyword('');
  }, true);
}

function bindPromptAssistToolControls(root = document) {
  const once = (id, handler) => {
    const el = document.getElementById(id);
    if (!el || el.dataset.pcAssistBound === 'true') return;
    el.dataset.pcAssistBound = 'true';
    el.addEventListener('click', (event) => { event.preventDefault(); event.stopPropagation(); handler(event); });
  };
  once('promptAssistTagGenerate', generatePromptAssistTags);
  once('promptAssistTagSave', savePromptAssistTags);
  once('promptAssistTagInsert', insertPromptAssistTags);
  once('promptAssistCharacterBuild', buildPromptAssistCharacter);
  once('promptAssistCharacterSave', savePromptAssistCharacter);
  once('promptAssistCharacterInsertPrompt', () => insertPromptAssistCharacter('prompt'));
  once('promptAssistCharacterInsertNegative', () => insertPromptAssistCharacter('negative'));
  once('promptAssistKeywordRefresh', () => refreshPromptAssistKeywords());
  once('promptAssistKeywordApplyFilters', () => refreshPromptAssistKeywords());
  once('promptAssistKeywordClearFilters', clearPromptAssistKeywordFilters);
  once('promptAssistKeywordSave', savePromptAssistKeyword);
  once('promptAssistKeywordInsertSelected', () => insertPromptAssistKeyword(''));
  ['promptAssistKeywordCategory', 'promptAssistKeywordSubcategory'].forEach((id) => {
    const el = document.getElementById(id);
    if (el && el.dataset.pcAssistBound !== 'true') {
      el.dataset.pcAssistBound = 'true';
      el.addEventListener('change', (event) => { event.preventDefault(); promptCaptioningStageKeywordFiltersFromDom(); });
    }
  });
  ['promptAssistKeywordSelected', 'promptAssistKeywordIncludeDesc'].forEach((id) => {
    const el = document.getElementById(id);
    if (el && el.dataset.pcAssistBound !== 'true') {
      el.dataset.pcAssistBound = 'true';
      el.addEventListener('change', () => promptCaptioningUpdateKeywordPreview());
    }
  });
  const keywordPath = document.getElementById('promptAssistKeywordManualPath');
  if (keywordPath && keywordPath.dataset.pcAssistBound !== 'true') {
    keywordPath.dataset.pcAssistBound = 'true';
    const rememberPath = () => promptCaptioningSetKeywordManualPath(keywordPath.value || '');
    keywordPath.addEventListener('input', rememberPath);
    keywordPath.addEventListener('change', rememberPath);
    keywordPath.addEventListener('keydown', (event) => { if (event.key === 'Enter') { event.preventDefault(); rememberPath(); refreshPromptAssistKeywords({ forceAll: true }); } });
  }
  once('promptAssistKeywordUsePath', () => {
    const input = document.getElementById('promptAssistKeywordManualPath');
    promptCaptioningSetKeywordManualPath(input?.value || '');
    refreshPromptAssistKeywords({ forceAll: true });
  });
  once('promptAssistKeywordClearPath', () => {
    const input = document.getElementById('promptAssistKeywordManualPath');
    if (input) input.value = '';
    promptCaptioningSetKeywordManualPath('');
    refreshPromptAssistKeywords({ forceAll: true });
  });
  const keywordSearch = document.getElementById('promptAssistKeywordSearch');
  if (keywordSearch && keywordSearch.dataset.pcAssistBound !== 'true') {
    keywordSearch.dataset.pcAssistBound = 'true';
    keywordSearch.addEventListener('keydown', (event) => { if (event.key === 'Enter') { event.preventDefault(); refreshPromptAssistKeywords(); } });
  }
  setTimeout(promptCaptioningUpdateKeywordPreview, 0);
  ['promptCaptioningCaptionBrowserSearch', 'promptCaptioningCaptionBrowserCategory', 'promptCaptioningCaptionBrowserSort', 'promptCaptioningCaptionBrowserName', 'promptCaptioningCaptionBrowserImage', 'promptCaptioningCaptionBrowserImageTarget', 'promptCaptioningCaptionBrowserPreviewCaption'].forEach((id) => {
    const el = document.getElementById(id);
    if (!el || el.dataset.pcCaptionBrowserBound === 'true') return;
    el.dataset.pcCaptionBrowserBound = 'true';
    const remember = () => promptCaptioningCaptionBrowserRememberFromDom();
    el.addEventListener('input', remember);
    el.addEventListener('change', (event) => {
      remember();
      if (id === 'promptCaptioningCaptionBrowserSort' || id === 'promptCaptioningCaptionBrowserSearch') return refreshPromptAssistCaptionBrowser();
      if (id === 'promptCaptioningCaptionBrowserCategory') {
        const lib = promptCaptioningState().library || (promptCaptioningState().library = {});
        const items = promptCaptioningCaptionBrowserItems(lib).filter((item) => !lib.assistCaptionCategory || item.category === lib.assistCaptionCategory);
        lib.assistCaptionSelectedId = items[0]?.caption_item_id || '';
        render();
        return;
      }
      if (id === 'promptCaptioningCaptionBrowserName' || id === 'promptCaptioningCaptionBrowserImage') return promptCaptioningCaptionBrowserSetSelected(event.target.value || '');
    });
    el.addEventListener('keydown', (event) => { if (event.key === 'Enter') { event.preventDefault(); remember(); refreshPromptAssistCaptionBrowser(); } });
  });
  once('promptAssistCaptionRefresh', refreshPromptAssistCaptionBrowser);
  once('promptAssistCaptionSaveCurrent', savePromptAssistCaptionFromStudio);
  once('promptAssistCaptionSendImagePositive', sendPromptAssistCaptionToImagePositive);
  once('promptAssistCaptionSendPromptStudio', sendPromptAssistCaptionBrowserToPromptStudio);
  once('promptAssistCaptionCopyCaption', copyPromptAssistCaptionBrowserCaption);
  once('promptAssistCaptionSendImageSource', sendPromptAssistCaptionBrowserImageToSource);
  once('promptAssistCaptionSendControlNet', sendPromptAssistCaptionBrowserImageToControlNet);
  root.querySelectorAll?.('[data-pc-keyword-insert]').forEach((button) => {
    if (button.dataset.pcAssistBound === 'true') return;
    button.dataset.pcAssistBound = 'true';
    button.addEventListener('click', (event) => { event.preventDefault(); insertPromptAssistKeyword(button.getAttribute('data-pc-keyword-insert') || ''); });
  });
  root.querySelectorAll?.('[data-pc-caption-send]').forEach((button) => {
    if (button.dataset.pcAssistBound === 'true') return;
    button.dataset.pcAssistBound = 'true';
    button.addEventListener('click', (event) => {
      event.preventDefault();
      sendPromptAssistCaptionToPrompt(button.getAttribute('data-pc-caption-send') || '', button.getAttribute('data-pc-caption-text') || '');
    });
  });
}

