function promptCaptioningAssistToolRoutePanel(subtabId) {
  const pc = promptCaptioningState();
  const pb = pc.promptBuilder;
  const cap = pc.captioning;
  const library = pc.library || {};
  if (subtabId === 'prompt_preset_details') return promptCaptioningPromptPresetDetailsPanel(pb, library);
  if (subtabId === 'prompt_cleanup') return promptCaptioningPromptCleanupPanel(pb);
  if (subtabId === 'recent_work') return promptCaptioningRecentWorkPanel(library);
  if (subtabId === 'saved_prompts') return promptCaptioningSavedPromptsWorkspacePanel();
  if (subtabId === 'character_library') return promptCaptioningCharacterLibraryPanel(pb, library);
  if (subtabId === 'tag_assist') return promptCaptioningTagAssistPanel();
  if (subtabId === 'character_builder') return promptCaptioningCharacterBuilderPanel();
  if (subtabId === 'keyword_browser') return promptCaptioningKeywordBrowserPanel();
  if (subtabId === 'caption_preset_details') return promptCaptioningCaptionPresetDetailsPanel(cap, library);
  if (subtabId === 'caption_browser') return promptCaptioningCaptionBrowserWorkspacePanel();
  if (subtabId === 'batch_captioning') return promptCaptioningBatchWorkspacePanel();
  if (subtabId === 'inspector') return promptCaptioningInspectorWorkspacePanel(promptCaptioningWorkspaceMode());
  return '';
}


function promptCaptioningResolvedLeftSubtab(modeId = '') {
  return promptCaptioningCurrentLeftSubtab(modeId);
}

function renderPromptCaptioningPanels(surface, subtab) {
  const columns = beginTwoColumnWorkspace();
  const modeId = promptCaptioningWorkspaceMode();
  // Legacy lock marker: promptCaptioningActiveChildTab(modeId) remains the fallback inside promptCaptioningResolvedLeftSubtab.
  const childTabId = promptCaptioningResolvedLeftSubtab(modeId);
  const display = promptCaptioningDisplayModeSetup();
  columns.left.classList.add('prompt-captioning-column', `prompt-captioning-mode-${display.mode}`, 'prompt-captioning-left-shell');
  columns.left.dataset.pcActiveLeftSubtab = childTabId;
  columns.left.dataset.pcWorkspaceMode = modeId;
  columns.right.classList.add('prompt-captioning-column', `prompt-captioning-mode-${display.mode}`, 'prompt-captioning-main-shell');
  appendNeoFirstRunPanel(columns.left, 'prompt_captioning', 'Prompt & Captioning quick start');
  columns.right.dataset.displayMode = display.mode;
  if (!surface) {
    columns.left.innerHTML = '<div class="neo-empty">Prompt & Captioning surface is not registered.</div>';
    return;
  }

  promptCaptioningEnsureLibraryLoaded('all');

  const childPanel = promptCaptioningAssistToolRoutePanel(childTabId);
  const childLabel = promptCaptioningChildTabsForMode(modeId).find((item) => item.id === childTabId)?.label || (modeId === 'captioning' ? 'Caption Tool' : 'Prompt Tool');
  columns.left.insertAdjacentHTML('beforeend', `<div class="neo-pc-navigation-map" data-testid="prompt-captioning-navigation-map">${promptCaptioningModeStudioAssistSummary(modeId, childTabId)}</div>`);
  if (childPanel) {
    columns.left.appendChild(promptCaptioningCollapsiblePanel(childLabel, childPanel, `prompt_assist_${childTabId}`, { status: childTabId === 'inspector' ? 'Expert' : 'Available' }));
  }

  if (modeId === 'captioning') {
    columns.right.appendChild(promptCaptioningCollapsiblePanel('Caption Studio', promptCaptioningCaptionStudioPanel(), 'caption_studio', { status: promptCaptioningSectionStatus('caption_studio', modeId) }));
    columns.right.appendChild(promptCaptioningCollapsiblePanel('Save to Library', promptCaptioningSaveCaptionPanel(), 'save_caption', { status: 'Saved' }));
    return;
  }

  columns.right.appendChild(promptCaptioningCollapsiblePanel('Prompt Studio', promptCaptioningPromptStudioPanel(), 'prompt_studio', { status: promptCaptioningSectionStatus('prompt_studio', modeId) }));
  columns.right.appendChild(promptCaptioningCollapsiblePanel('Save Prompt', promptCaptioningSavePromptPanel(), 'save_prompt', { status: 'Saved' }));
  // Prompt Studio diagnostics moved out of the normal workflow view per UI cleanup request.
  // Compatibility markers for regression/source contract tests: prompt_payload_preview prompt_provider_capability prompt_validation_gating prompt_metadata_replay Payload Setup Preview Provider Capability Map Validation + Gating Metadata + Replay Readiness.

}


