function roleplayForgeCountForKind(forge, kindId) {
  return (forge?.kinds || []).find((kind) => kind.kind_id === kindId)?.record_count || 0;
}

function roleplayForgeKindDisplay(kindId) {
  const forge = state.roleplayForge || {};
  return (forge.kinds || []).find((kind) => kind.kind_id === kindId)?.display_name || String(kindId || 'Record').replace(/_/g, ' ').replace(/\b\w/g, (m) => m.toUpperCase());
}

function roleplayForgeTemplate(kindId) {
  const forge = state.roleplayForge || {};
  const clean = kindId || forge.active_kind || 'universe';
  return forge.templates_by_kind?.[clean] || forge.active_template || null;
}

function roleplayForgeClone(value) {
  try { return JSON.parse(JSON.stringify(value ?? null)); } catch (_) { return value; }
}

function roleplayForgeTemplatePayload(kindId) {
  const template = roleplayForgeTemplate(kindId);
  const payload = roleplayForgeClone(template?.json_template_payload || {});
  payload.kind = kindId || payload.kind || 'universe';
  return payload;
}

function roleplayForgeCurrentKind() {
  return state.roleplayForgeWorkingPayload?.kind || state.roleplayForge?.active_kind || 'universe';
}

function roleplayForgeWorkingPayload(kindId = '') {
  const kind = kindId || roleplayForgeCurrentKind();
  if (!state.roleplayForgeWorkingPayload || state.roleplayForgeWorkingPayload.kind !== kind) {
    state.roleplayForgeWorkingPayload = roleplayForgeApplyActiveScopeToPayload(roleplayForgeTemplatePayload(kind));
  }
  return state.roleplayForgeWorkingPayload;
}

function roleplayForgeEnsureScopeObject(payload = {}) {
  payload.links = payload.links || {};
  payload.links.scope = payload.links.scope || {};
  return payload.links.scope;
}

function roleplayForgeSetScopeValue(scope, baseKey, value) {
  if (!scope || !value) return;
  scope[`${baseKey}_id`] = value;
}

function roleplayForgeApplyActiveScopeToPayload(payload = {}) {
  if (!payload || typeof payload !== 'object') return payload;
  const active = roleplayForgeActiveScopeRecord();
  if (!active) return payload;
  const activeId = roleplayForgeRecordId(active);
  const activeKind = String(active.kind || '').toLowerCase();
  const payloadKind = String(payload.kind || roleplayForgeCurrentKind() || '').toLowerCase();
  if (!activeId || activeId === String(payload.id || '')) return payload;
  const scope = roleplayForgeEnsureScopeObject(payload);
  const setCharacterStyle = (key) => {
    scope[`origin_${key}_id`] = scope[`origin_${key}_id`] || activeId;
    scope[`current_${key}_id`] = scope[`current_${key}_id`] || activeId;
  };
  const setDirect = (key) => roleplayForgeSetScopeValue(scope, key, activeId);
  if (activeKind === 'universe') {
    setDirect('universe');
  } else if (activeKind === 'world') {
    if (['character', 'relationship'].includes(payloadKind)) setCharacterStyle('world');
    else setDirect('world');
  } else if (activeKind === 'region') {
    if (['character', 'relationship'].includes(payloadKind)) setCharacterStyle('region');
    else setDirect('region');
  } else if (activeKind === 'city') {
    if (['character', 'relationship'].includes(payloadKind)) setCharacterStyle('city');
    else setDirect('city');
  } else if (activeKind === 'location') {
    if (['character', 'relationship'].includes(payloadKind)) setCharacterStyle('location');
    else setDirect('location');
  } else if (activeKind === 'character') {
    scope.character_id = scope.character_id || activeId;
    if (payloadKind === 'relationship') {
      payload.fields = payload.fields || {};
      payload.fields.participants = payload.fields.participants || {};
      payload.fields.participants.character_a_id = payload.fields.participants.character_a_id || activeId;
    }
  } else {
    scope.canon_scope_id = scope.canon_scope_id || activeId;
  }
  payload.meta = payload.meta || {};
  payload.meta.active_forge_scope_id = activeId;
  payload.meta.active_forge_scope_kind = activeKind;
  return payload;
}

function roleplayForgeSetByPath(target, path, value) {
  const parts = String(path || '').split('.').filter(Boolean);
  if (!parts.length) return;
  let cursor = target;
  parts.forEach((part, index) => {
    if (index === parts.length - 1) {
      cursor[part] = value;
      return;
    }
    if (!cursor[part] || typeof cursor[part] !== 'object' || Array.isArray(cursor[part])) cursor[part] = {};
    cursor = cursor[part];
  });
}

function roleplayForgeGetByPath(target, path) {
  return String(path || '').split('.').filter(Boolean).reduce((cursor, part) => {
    if (!cursor || typeof cursor !== 'object') return undefined;
    return cursor[part];
  }, target);
}

function roleplayForgeParseInputValue(raw, existing, input = null) {
  const value = String(raw ?? '');
  if (input?.getAttribute?.('data-forge-json-value') === 'true') {
    try {
      const parsed = JSON.parse(value || 'null');
      return parsed == null ? (Array.isArray(existing) ? [] : '') : parsed;
    } catch (_) {
      return Array.isArray(existing) ? [] : value;
    }
  }
  if (Array.isArray(existing)) return value.split(',').map((item) => item.trim()).filter(Boolean);
  if (typeof existing === 'number') {
    const number = Number(value);
    return Number.isFinite(number) ? number : existing;
  }
  if (typeof existing === 'boolean') return value === 'true' || value === 'on' || value === 'yes';
  return value;
}

function roleplayForgeCaptureFormPayload() {
  const root = document.getElementById('roleplay-forge-dynamic-form');
  if (!root) return state.roleplayForgeWorkingPayload || roleplayForgeWorkingPayload();
  const payload = roleplayForgeClone(state.roleplayForgeWorkingPayload || roleplayForgeWorkingPayload());
  root.querySelectorAll('[data-forge-path]').forEach((input) => {
    const path = input.getAttribute('data-forge-path');
    const existing = roleplayForgeGetByPath(payload, path);
    roleplayForgeSetByPath(payload, path, roleplayForgeParseInputValue(input.value, existing, input));
  });
  state.roleplayForgeWorkingPayload = payload;
  return payload;
}

function roleplayForgeSyncJsonEditor() {
  const payload = roleplayForgeCaptureFormPayload();
  const editor = document.getElementById('roleplay-forge-json-draft');
  if (editor) editor.value = JSON.stringify(payload, null, 2);
}


function roleplayForgeNormalizeCategoryValue(value = '') {
  return String(value ?? '')
    .trim()
    .toLowerCase()
    .replace(/&/g, 'and')
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
}

