function roleplaySceneSetupHtml(scene) {
  const setup = scene?.setup || {};
  const bridge = scene?.text_backend || state.roleplayTextBackend || {};
  const runtime = scene?.runtime_bundle_selector || {};
  const options = runtime.options || setup.runtime_bundle_options || [];
  const selected = setup.runtime_bundle_id || runtime.selected_bundle_id || '';
  const optionHtml = ['<option value="">Select Scene packet</option>', ...options.map((bundle) => `<option value="${escapeHtml(bundle.bundle_id)}" ${bundle.bundle_id === selected ? 'selected' : ''}>${escapeHtml(bundle.title || bundle.bundle_id)} · ${escapeHtml(bundle.status || 'active')}</option>`)].join('');
  return `
    <div class="roleplay-v1-scene-head">
      <div>
        <div class="roleplay-kicker">Scene setup</div>
        <p>Live use lane. Scene loads a Studio-built Scene packet, tracks scene state, and hands checkpoints off to Stories.</p>
      </div>
      <span class="neo-chip">Live use</span>
    </div>
    <label>Scene premise</label>
    <textarea id="roleplay-scene-premise" rows="5" placeholder="Late-night reunion in the harbor after the ban on magic.">${escapeHtml(setup.premise || '')}</textarea>
    <div class="roleplay-v1-scene-grid two">
      <div><label>Tone</label><select id="roleplay-scene-tone">${roleplaySceneToneOptions(setup.tone)}</select></div>
      <div><label>Reply style</label><select id="roleplay-scene-style">${roleplaySceneStyleOptions(setup.reply_style)}</select></div>
    </div>
    <label>Scene notes</label>
    <textarea id="roleplay-scene-notes" rows="4" placeholder="Stage direction, continuity notes, or what the Scene packet should emphasize.">${escapeHtml(setup.scene_notes || '')}</textarea>
    <div class="roleplay-v1-scene-grid two">
      <div><label>Narrator posture</label><select id="roleplay-scene-posture">${roleplayScenePostureOptions(setup.narrator_posture)}</select></div>
      <div><label>Continuity mode</label><select id="roleplay-scene-continuity-mode">${roleplaySceneContinuityOptions(setup.continuity_mode)}</select></div>
    </div>
    <label>Scene packet</label>
    <select id="roleplay-scene-runtime" ${(runtime.binding_enabled || runtime.binding_available) ? '' : 'disabled'} onchange="saveRoleplaySceneSetupFromUi()">${optionHtml}</select>
    <div class="neo-actions roleplay-v1-scene-actions">
      <button type="button" class="neo-btn secondary roleplay-btn" onclick="refreshRoleplaySceneStateFromUi()">Refresh packets</button>
      <button type="button" class="neo-btn primary admin-engine-btn" onclick="saveRoleplaySceneSetupFromUi()">Load into Scene</button>
    </div>
    <div class="roleplay-v1-scene-status">${escapeHtml(runtime.active_summary || 'No Scene packet is active yet.')}</div>
    <div class="roleplay-v1-scene-summary">${escapeHtml(runtime.state_summary || `Posture · ${setup.narrator_posture || 'partner_focus'}  Continuity · ${setup.continuity_mode || 'runtime_anchored'}  Cast ids · 0`)}</div>
    <div class="roleplay-v1-scene-summary muted">${escapeHtml(runtime.continuity_summary || 'Focus stack · none')}</div>
    ${state.detailMode === 'expert' ? `<div class="roleplay-v1-scene-debug"><strong>Text backend</strong>${roleplayTextBackendSummaryHtml(bridge)}</div>` : badgeRow([`Profile · ${setup.active_profile_id || bridge.active_profile_id || 'none'}`, `Backend ${setup.text_backend_ready ? 'ready' : 'not ready'}`, (runtime.binding_enabled || runtime.binding_available) ? 'runtime bundle selectable' : 'runtime bundle not selected'])}
  `;
}

function roleplaySceneTranscriptHtml(transcript) {
  const hiddenSetupStatuses = new Set(['scene_session_setup_prompt', 'scene_session_setup_required']);
  const turns = (transcript?.turns || []).filter((turn) => !hiddenSetupStatuses.has(String(turn?.status || '')));
  if (!turns.length) return '<div class="roleplay-v1-scene-empty">Scene transcript will render here once you start sending turns.</div>';
  return `<div class="roleplay-v1-scene-transcript-list story-transcript">${turns.slice(-36).map((turn) => {
    const role = turn.role || 'turn';
    const displayRole = turn.display_role || (role === 'assistant' ? 'Neo' : role === 'system' ? 'Scene' : 'User');
    return `<div class="roleplay-v1-scene-turn ${escapeHtml(role)} story-turn"><strong>${escapeHtml(displayRole)}</strong><p>${escapeHtml(turn.text || '')}</p><span>${escapeHtml(turn.status || 'placeholder')} · ${escapeHtml(turn.created_at || '')}</span></div>`;
  }).join('')}</div>`;
}

function roleplaySceneChoiceAssistHtml(scene, sessionReady) {
  const setup = scene?.setup || {};
  const transcript = scene?.chat?.transcript || {};
  const style = document.getElementById('roleplay-scene-turn-input-style')?.value || transcript.turn_input_style || setup.turn_input_style || 'free_typing';
  const actions = Array.isArray(transcript.suggested_actions) ? transcript.suggested_actions : [];
  if (!sessionReady || !['choice_assist', 'hybrid'].includes(String(style || '').toLowerCase())) return '';
  const modeLabel = style === 'choice_assist' ? 'Choice Assist' : 'Hybrid';
  const note = style === 'choice_assist'
    ? 'Pick one suggested next action to send as your character. Manual input stays available for edits, but suggestions are the main lane.'
    : 'Hybrid keeps suggested next actions and manual typing visible together.';
  if (!actions.length) {
    return `<section class="roleplay-v1-scene-status roleplay-choice-assist"><div class="roleplay-v1-scene-row-between"><div><strong>${escapeHtml(modeLabel)}</strong><p>${escapeHtml(note)}</p></div><span class="neo-chip">waiting</span></div><div class="roleplay-v1-studio-empty">Send one scene turn first. Neo will offer grounded next-action options after the response.</div></section>`;
  }
  const buttons = actions.slice(0, 5).map((action, idx) => {
    const prompt = String(action.prompt || action.text || '').trim();
    const label = String(action.label || `Choice ${idx + 1}`).trim();
    const encoded = escapeAttr(JSON.stringify(prompt));
    const playLabel = style === 'choice_assist' ? 'Play choice' : 'Use in input';
    return `<article class="roleplay-choice-card"><strong>${escapeHtml(label)}</strong><p>${escapeHtml(prompt)}</p><div class="neo-actions"><button type="button" class="neo-btn small primary" onclick="roleplayUseChoiceAssistAction(${encoded}, ${style === 'choice_assist' ? 'true' : 'false'})">${playLabel}</button>${style !== 'choice_assist' ? `<button type="button" class="neo-btn small secondary" onclick="roleplayUseChoiceAssistAction(${encoded}, false)">Edit</button>` : ''}</div></article>`;
  }).join('');
  return `<section class="roleplay-v1-scene-status roleplay-choice-assist"><div class="roleplay-v1-scene-row-between"><div><strong>${escapeHtml(modeLabel)}</strong><p>${escapeHtml(note)}</p></div><span class="neo-chip">${actions.length} choices</span></div><div class="roleplay-choice-grid">${buttons}</div></section>`;
}


