function roleplayPackageListHtml(items = [], type = 'export') {
  const rows = Array.isArray(items) ? items : [];
  if (!rows.length) return `<div class="roleplay-v1-studio-empty">No package ${escapeHtml(type)} records yet.</div>`;
  return `<div class="roleplay-story-list">${rows.map((item) => {
    const name = item.archive || item.import_id || item.package_id || 'package';
    const status = item.status || (type === 'export' ? 'exported' : 'imported');
    const meta = type === 'export'
      ? `${Math.round(Number(item.size_bytes || 0) / 1024)} KB · ${item.created_at || ''}`
      : `${item.mode || 'merge_safe'} · written ${item.written ?? 0} · skipped ${item.skipped ?? 0}`;
    const action = type === 'export' && item.download_url ? `<a class="neo-btn admin-engine-btn" href="${escapeAttr(item.download_url)}">Download</a>` : '';
    return `<div class="roleplay-story-card"><div class="roleplay-v1-row-between"><div><strong>${escapeHtml(name)}</strong><p>${escapeHtml(meta)}</p></div><span class="neo-badge">${escapeHtml(status)}</span></div>${action}</div>`;
  }).join('')}</div>`;
}

