async function addRoleplayPackageToRegistryFromUi() {
  const payload = {
    archive_path: document.getElementById('roleplay-registry-add-path')?.value || '',
    package_type: document.getElementById('roleplay-registry-add-type')?.value || 'roleplay_package',
    title: document.getElementById('roleplay-registry-add-title')?.value || '',
    author: document.getElementById('roleplay-registry-add-author')?.value || '',
    description: document.getElementById('roleplay-registry-add-description')?.value || '',
    version: document.getElementById('roleplay-registry-add-version')?.value || '',
    tags: (document.getElementById('roleplay-registry-add-tags')?.value || '').split(',').map(x => x.trim()).filter(Boolean),
  };
  try {
    const response = await fetch('/api/roleplay/package-registry/add', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
    const result = await response.json().catch(() => ({}));
    if (!response.ok || result.ok === false) throw new Error(result.detail || result.error || 'Registry add failed');
    state.roleplayPackageRegistryLastAction = result;
    state.roleplayPackageRegistry = result.state || await loadJson('/api/roleplay/package-registry/state', null);
    render();
  } catch (error) { alert(error.message || 'Registry add failed'); }
}

