async function installRoleplayRegistryPackage(packageId) {
  if (!packageId) return;
  const mode = document.getElementById('roleplay-registry-install-mode')?.value || 'merge_safe';
  const payload = { package_id: packageId, mode, enable: true, include_sqlite: Boolean(document.getElementById('roleplay-registry-install-sqlite')?.checked), include_vector_store: Boolean(document.getElementById('roleplay-registry-install-vector')?.checked) };
  try {
    const response = await fetch('/api/roleplay/package-registry/install', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
    const result = await response.json().catch(() => ({}));
    if (!response.ok || result.ok === false) throw new Error(result.detail || result.error || 'Registry install failed');
    state.roleplayPackageRegistryLastAction = result;
    state.roleplayPackageRegistry = result.state || await loadJson('/api/roleplay/package-registry/state', null);
    state.roleplayPackage = await loadJson('/api/roleplay/package/state', state.roleplayPackage || null);
    state.roleplayForge = await loadJson('/api/roleplay/forge/state', state.roleplayForge || null);
    state.roleplayStories = await loadJson('/api/roleplay/stories/state', state.roleplayStories || null);
    render();
  } catch (error) { alert(error.message || 'Registry install failed'); }
}

async function toggleRoleplayRegistryPackage(packageId, enabled) {
  if (!packageId) return;
  try {
    const response = await fetch('/api/roleplay/package-registry/toggle', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ package_id: packageId, enabled }) });
    const result = await response.json().catch(() => ({}));
    if (!response.ok || result.ok === false) throw new Error(result.detail || result.error || 'Registry toggle failed');
    state.roleplayPackageRegistryLastAction = result;
    state.roleplayPackageRegistry = result.state || await loadJson('/api/roleplay/package-registry/state', null);
    render();
  } catch (error) { alert(error.message || 'Registry toggle failed'); }
}

