async function compileRoleplayRuntimeFoundationFromUi() {
  const projectId = document.getElementById('roleplay-runtime-project-id')?.value || document.getElementById('roleplay-studio-source-project')?.value || '';
  const payload = {
    title: document.getElementById('roleplay-runtime-title')?.value || 'Roleplay Runtime Bundle',
    project_id: projectId,
    include_kinds: document.getElementById('roleplay-runtime-include-kinds')?.value || '',
    max_entities: Number(document.getElementById('roleplay-runtime-max-entities')?.value || 80),
    max_sources: Number(document.getElementById('roleplay-runtime-max-sources')?.value || 24),
    max_memory_fragments: Number(document.getElementById('roleplay-runtime-max-memory')?.value || 120),
  };
  try {
    const response = await fetch('/api/roleplay/runtime/compile-foundation', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
    if (!response.ok) throw new Error('Runtime compile failed');
    const result = await response.json();
    state.roleplayRuntime = result.runtime || await loadJson('/api/roleplay/runtime/bundles', null);
    state.roleplayStudio = await loadJson('/api/roleplay/studio/state', state.roleplayStudio || null);
    state.roleplayScene = await loadJson('/api/roleplay/scene/state', state.roleplayScene || null);
    state.roleplayStudioActiveView = 'runtime';
    render();
  } catch (error) { alert(error.message || 'Runtime compile failed'); }
}

