async function buildRoleplayScopeMemoryRuntimeFromUi(runtimeOnly = false) {
  if (await neoTryRoleplayAction('buildRoleplayScopeMemoryRuntimeFromUi', { runtimeOnly })) return;
  let payload = null;
  try {
    setRoleplayScopeBuildSelectionFromUi();
    payload = roleplayScopeBuildPayloadFromUi();
    if (!payload.scope_id) throw new Error('Choose a scope record first.');
    if (runtimeOnly) {
      payload.compile_memory = false;
      payload.rebuild_search = false;
      payload.index_after = false;
      payload.mirror_after = false;
      payload.build_runtime = true;
    }
    payload.preview = state.roleplayScopeBuildPreview || null;
    state.roleplayScopeBuildProgress = {
      status: 'running',
      label: runtimeOnly ? 'Rebuilding runtime bundle…' : 'Building memory + runtime…',
      detail: runtimeOnly ? 'Using the selected scope and existing compiled memory.' : 'Compiling changed records, rebuilding search docs, indexing vectors, then writing the runtime bundle.',
      step: runtimeOnly ? 'runtime_bundle' : 'compile_memory',
      started_at: new Date().toISOString(),
    };
    render();
    const response = await fetch('/api/roleplay/scope-build/build', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
    const result = await response.json().catch(() => ({}));
    if (!response.ok || result.status === 'error') throw new Error(result.error || result.detail || 'Scope build failed');
    state.roleplayScopeBuildLastRun = result;
    state.roleplayScopeBuildPreview = result.preview || state.roleplayScopeBuildPreview;
    state.roleplayScopeBuild = result.state || await loadJson('/api/roleplay/scope-build/state', state.roleplayScopeBuild || null);
    state.roleplayScopedCompile = await loadJson('/api/roleplay/scoped-compile/state', state.roleplayScopedCompile || null);
    state.roleplayRuntime = await loadJson('/api/roleplay/runtime/bundles', state.roleplayRuntime || null);
    state.roleplayRuntimePresets = await loadJson('/api/roleplay/runtime-presets/state', state.roleplayRuntimePresets || null);
    state.roleplayMemory = await loadJson('/api/roleplay/memory/state', state.roleplayMemory || null);
    state.roleplayRuntimeRetrieval = await loadJson('/api/roleplay/runtime-retrieval/state', state.roleplayRuntimeRetrieval || null);
    const summary = result.summary || {};
    state.roleplayScopeBuildProgress = {
      status: 'built',
      label: 'Memory + Runtime build complete',
      detail: `Linked ${summary.linked_record_count ?? 0}, compiled ${summary.compiled_count ?? 0}, fragments ${summary.fragment_count ?? 0}, runtime ${summary.runtime_bundle_id || 'skipped'}.`,
      step: 'done',
      finished_at: new Date().toISOString(),
    };
    render();
  } catch (error) {
    state.roleplayScopeBuildProgress = {
      status: 'failed',
      label: 'Scope build failed',
      detail: error.message || 'Scope build failed',
      step: 'failed',
      finished_at: new Date().toISOString(),
    };
    render();
    alert(error.message || 'Scope build failed');
  }
}


function roleplayActionProgressHtml(progress, options = {}) {
  if (!progress) return '';
  const status = progress.status || 'idle';
  const isRunning = status === 'running';
  const isFailed = status === 'failed' || status === 'error';
  const isDone = ['built', 'complete', 'completed', 'done', 'ready'].includes(status);
  const label = progress.label || (isRunning ? 'Working…' : isFailed ? 'Failed' : isDone ? 'Done' : 'Ready');
  const detail = progress.detail || '';
  const step = progress.step ? `Step: ${progress.step}` : '';
  const badgeClass = isFailed ? 'danger' : isDone ? 'success' : 'warn';
  const title = options.title || 'Progress';
  return `<div class="roleplay-action-progress ${isRunning ? 'is-running' : ''} ${isFailed ? 'is-failed' : ''} ${isDone ? 'is-done' : ''}" role="status" aria-live="polite">
    <div class="roleplay-action-progress-head"><div><strong>${escapeHtml(title)}</strong><span>${escapeHtml(label)}</span></div><span class="neo-badge ${badgeClass}">${escapeHtml(status)}</span></div>
    ${isRunning ? '<div class="roleplay-action-progress-bar"><span></span></div>' : ''}
    ${detail ? `<p>${escapeHtml(detail)}</p>` : ''}
    ${step ? `<small>${escapeHtml(step)}</small>` : ''}
  </div>`;
}

function roleplayBusyButtonLabel(label, busyLabel, isBusy) {
  return isBusy ? `<span class="roleplay-btn-spinner" aria-hidden="true"></span>${escapeHtml(busyLabel)}` : escapeHtml(label);
}

async function roleplayFetchJsonWithTimeout(url, options = {}, timeoutMs = 60000) {
  const controller = new AbortController();
  const timer = window.setTimeout(() => controller.abort(), Math.max(5000, Number(timeoutMs || 60000)));
  try {
    const response = await fetch(url, { ...options, signal: controller.signal });
    const result = await response.json().catch(() => ({}));
    return { response, result };
  } catch (error) {
    if (error?.name === 'AbortError') {
      throw new Error(`Request timed out after ${Math.round(Math.max(5000, Number(timeoutMs || 60000)) / 1000)}s. Try Fast packet mode, or disable retrieval/rerank for this test.`);
    }
    throw error;
  } finally {
    window.clearTimeout(timer);
  }
}

function roleplayScopeBuildHtml(studio) {
  const moduleHtml = neoInvokeSurfaceModule('roleplay', 'roleplayScopeBuildDeepHtml', { studio });
  if (moduleHtml !== undefined) return moduleHtml;
  const scopeBuild = state.roleplayScopeBuild || {};
  const scopeLevel = roleplayScopeBuildScopeLevel();
  const scopeLevels = [
    ['project', 'Project'],
    ['universe', 'Universe'],
    ['world', 'World'],
    ['region', 'Region / Kingdom'],
    ['city', 'City / Settlement'],
    ['location', 'Location'],
    ['scenario', 'Scenario'],
  ];
  const levelOptions = scopeLevels.map(([value, label]) => {
    const count = Number((scopeBuild.scope_counts || {})[value] || 0);
    const suffix = count ? ` (${count})` : '';
    return `<option value="${escapeAttr(value)}" ${value === scopeLevel ? 'selected' : ''}>${escapeHtml(label + suffix)}</option>`;
  }).join('');
  const scopes = roleplayScopeBuildScopesForLevel(scopeLevel);
  const selectedValue = roleplayScopeBuildSelectedValue();
  const scopeOptions = scopes.length ? scopes.map((item) => {
    const value = `${item.scope_type}::${item.scope_id}`;
    const status = item.compile_status ? ` · ${item.compile_status}` : '';
    return `<option value="${escapeAttr(value)}" ${value === selectedValue ? 'selected' : ''}>${escapeHtml(item.title || item.label || item.scope_id)}${escapeHtml(status)}</option>`;
  }).join('') : `<option value="">No ${escapeHtml(scopeLevels.find(([value]) => value === scopeLevel)?.[1] || scopeLevel)} records found</option>`;
  const preview = state.roleplayScopeBuildPreview || {};
  const linked = preview.linked_records || {};
  const groups = linked.groups || [];
  const plan = preview.compile_plan || {};
  const last = state.roleplayScopeBuildLastRun || (scopeBuild.latest_runs || [])[0] || {};
  const scopeProgress = state.roleplayScopeBuildProgress || null;
  const scopeBuildBusy = scopeProgress?.status === 'running';
  const buildOpts = state.roleplayScopeBuildOptions || {};
  const checkedAttr = (key, fallback = false) => (buildOpts[key] ?? fallback) ? 'checked' : '';
  const selectedNotice = selectedValue ? 'Select Preview Build Plan to inspect the linked graph before compiling.' : 'Import or create records, then pick a scope level and scope record.';
  const groupRows = groups.length ? groups.map((group) => {
    const records = (group.records || []).map((record) => {
      const badge = record.compile_status || 'new';
      return `<div class="roleplay-v1-record-row"><div><strong>${escapeHtml(record.title || record.record_id)}</strong><span>${escapeHtml(record.kind_label || record.kind || '')} · ${escapeHtml(record.record_id || '')} · ${escapeHtml(record.link_reason || '')}</span>${record.summary ? `<p>${escapeHtml(record.summary)}</p>` : ''}</div><span class="neo-badge">${escapeHtml(badge)}</span></div>`;
    }).join('');
    return `<details class="roleplay-v1-studio-card inner" open><summary><strong>${escapeHtml(group.kind_label || group.kind)}</strong> <span class="neo-badge">${group.count || 0}</span></summary><div class="neo-stack compact">${records || '<div class="roleplay-v1-studio-empty">No records.</div>'}</div></details>`;
  }).join('') : `<div class="roleplay-v1-studio-empty">${escapeHtml(selectedNotice)}</div>`;
  const kindChips = groups.length ? roleplayStudioBadgeItems(Object.entries(linked.kind_counts || {}).map(([kind, count]) => `${kind} ${count}`)) : '';
  return `
    <div class="roleplay-v1-studio-card wide">
      <div class="roleplay-v1-scene-row-between"><div><strong>Build Scope Memory + Runtime</strong><p>Select a scope level, choose an imported Forge scope record, review linked records, then build from one safe plan.</p></div><span class="neo-badge success">Scope Picker</span></div>
      <div class="roleplay-v1-studio-grid three compact">
        <div><label>Scope level</label><select id="roleplay-scope-build-level" onchange="setRoleplayScopeBuildLevelFromUi()">${levelOptions}</select></div>
        <div class="wide"><label>Scope record</label><select id="roleplay-scope-build-select" onchange="setRoleplayScopeBuildSelectionFromUi()">${scopeOptions}</select></div>
        <div><label>Bundle title</label><input id="roleplay-scope-build-title" placeholder="Auto: Runtime — selected scope" value="${escapeAttr(buildOpts.bundle_title || '')}"></div>
      </div>
      <div class="roleplay-v1-studio-grid four compact">
        <div><label>Compile mode</label><select id="roleplay-scope-build-mode"><option value="changed_only" ${(buildOpts.mode || 'changed_only') === 'changed_only' ? 'selected' : ''}>Changed / stale only</option><option value="selected_records" ${buildOpts.mode === 'selected_records' ? 'selected' : ''}>All linked records except compiled</option><option value="all" ${buildOpts.mode === 'all' ? 'selected' : ''}>Force rebuild all linked records</option></select></div>
        <div><label>Graph depth</label><input id="roleplay-scope-build-depth" type="number" min="0" max="5" value="${escapeAttr(buildOpts.graph_depth ?? 2)}"></div>
        <div><label>Kind filter</label><input id="roleplay-scope-build-kind" placeholder="optional kind" value="${escapeAttr(buildOpts.kind || '')}"></div>
        <div><label>Include compiled</label><input id="roleplay-scope-build-include-compiled" type="checkbox" ${checkedAttr('include_compiled', false)}></div>
      </div>
      <div class="roleplay-v1-studio-grid four compact">
        <label class="roleplay-checkbox"><input id="roleplay-scope-build-family" type="checkbox" ${checkedAttr('include_scope_family', true)}> Scope family</label>
        <label class="roleplay-checkbox"><input id="roleplay-scope-build-reverse" type="checkbox" ${checkedAttr('include_reverse_links', true)}> Reverse links</label>
        <label class="roleplay-checkbox"><input id="roleplay-scope-build-compile" type="checkbox" ${checkedAttr('compile_memory', true)}> Compile memory</label>
        <label class="roleplay-checkbox"><input id="roleplay-scope-build-runtime" type="checkbox" ${checkedAttr('build_runtime', true)}> Build runtime</label>
      </div>
      <div class="roleplay-v1-studio-grid four compact">
        <label class="roleplay-checkbox"><input id="roleplay-scope-build-rebuild" type="checkbox" ${checkedAttr('rebuild_search', true)}> Rebuild search</label>
        <label class="roleplay-checkbox"><input id="roleplay-scope-build-index" type="checkbox" ${checkedAttr('index_after', true)}> Index vectors</label>
        <label class="roleplay-checkbox"><input id="roleplay-scope-build-mirror" type="checkbox" ${checkedAttr('mirror_after', false)}> Mirror Chroma</label>
        <span class="roleplay-panel-note">Scope records are read from live Forge records, including newly imported bundles.</span>
      </div>
      <div class="roleplay-v1-studio-row wrap"><button type="button" class="neo-btn primary admin-engine-btn" onclick="previewRoleplayScopeBuildFromUi()" ${scopeBuildBusy ? 'disabled' : ''}>Preview Build Plan</button><button type="button" class="neo-btn primary admin-engine-btn ${scopeBuildBusy ? 'is-busy' : ''}" onclick="buildRoleplayScopeMemoryRuntimeFromUi(false)" ${scopeBuildBusy ? 'disabled' : ''}>${roleplayBusyButtonLabel('Build Memory + Runtime', 'Building…', scopeBuildBusy)}</button><button type="button" class="neo-btn admin-engine-btn" onclick="buildRoleplayScopeMemoryRuntimeFromUi(true)" ${scopeBuildBusy ? 'disabled' : ''}>Rebuild Runtime Only</button><button type="button" class="neo-btn admin-engine-btn" onclick="reloadRoleplayScopeBuildState()" ${scopeBuildBusy ? 'disabled' : ''}>Refresh scopes</button></div>
      ${roleplayActionProgressHtml(scopeProgress, { title: 'Compile progress' })}
      ${roleplayStudioBadgeItems(scopeLevels.map(([value, label]) => `${label} ${(scopeBuild.scope_counts || {})[value] || 0}`))}
      ${preview.schema_id ? roleplayStudioBadgeItems([`linked ${linked.linked_record_count || 0}`, `compile ${plan.compile_count ?? 0}`, `skip ${plan.skipped_count ?? 0}`, `runtime records ${(preview.runtime_plan || {}).record_count ?? 0}`, `status ${preview.status || 'ready'}`]) : ''}
      ${last.build_run_id ? `<p class="roleplay-panel-note">Last scope build: ${escapeHtml(last.status || '')} · ${escapeHtml(last.build_run_id || '')} · bundle ${escapeHtml(last.runtime_bundle_id || 'none')}</p>` : ''}
    </div>
    <div class="roleplay-v1-studio-card wide">
      <div class="roleplay-v1-scene-row-between"><div><strong>Linked record browser</strong><p>After selecting a scope record, preview shows direct scope records, related links, reverse links, and neighbor records before memory is compiled.</p></div><span class="neo-badge">${linked.linked_record_count || 0}</span></div>
      ${kindChips}
      <div class="neo-stack">${groupRows}</div>
    </div>`;
}

