async function prepareRoleplayPresetScenePacketFromUi() {
  if (await neoTryRoleplayAction('prepareRoleplayPresetScenePacketFromUi')) return;
  const presetId = roleplayRuntimePresetSelectedValue();
  const payload = {
    preset_id: presetId,
    scenario_id: document.getElementById('roleplay-runtime-preset-scenario')?.value || '',
    player_character_ids: document.getElementById('roleplay-runtime-preset-player')?.value || '',
    query: document.getElementById('roleplay-runtime-preset-query')?.value || '',
    title: document.getElementById('roleplay-runtime-preset-packet-title')?.value || '',
    mode: document.getElementById('roleplay-runtime-preset-mode')?.value || 'hybrid',
    limit: Number(document.getElementById('roleplay-runtime-preset-limit')?.value || 8),
    candidate_limit: Number(document.getElementById('roleplay-runtime-preset-candidate-limit')?.value || 24),
    rerank_candidate_limit: Number(document.getElementById('roleplay-runtime-preset-rerank-candidate-limit')?.value || 8),
    rerank: document.getElementById('roleplay-runtime-preset-rerank')?.checked !== false,
    run_retrieval: Boolean(document.getElementById('roleplay-runtime-preset-run-retrieval')?.checked),
  };
  try {
    state.roleplayRuntimePacketProgress = { status: 'running', label: 'Previewing scene packet…', detail: 'Resolving preset, scenario, cast, linked records, and retrieval query.', step: 'prepare_packet', started_at: new Date().toISOString() };
    render();
    const { response, result } = await roleplayFetchJsonWithTimeout('/api/roleplay/runtime-presets/prepare-scene-packet', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) }, 30000);
    if (!response.ok || result.status === 'error') throw new Error(result.error || result.detail || 'Prepare packet failed');
    state.roleplayRuntimePreparedPacket = result;
    const packet = result.packet_payload || {};
    state.roleplayRuntimePacketProgress = { status: 'ready', label: 'Scene packet preview ready', detail: `Prepared ${packet.title || 'auto packet'} with scope ${packet.scope_id || 'global'}.`, step: 'preview_ready', finished_at: new Date().toISOString() };
    render();
  } catch (error) {
    state.roleplayRuntimePacketProgress = { status: 'failed', label: 'Scene packet preview failed', detail: error.message || 'Prepare packet failed', step: 'failed', finished_at: new Date().toISOString() };
    render();
    alert(error.message || 'Prepare packet failed');
  }
}

async function pollRoleplayPresetScenePacketJob(jobId) {
  const started = Date.now();
  while (true) {
    const { response, result } = await roleplayFetchJsonWithTimeout(`/api/roleplay/runtime-presets/build-scene-packet-job/${encodeURIComponent(jobId)}`, { method: 'GET' }, 30000);
    if (!response.ok) throw new Error(result.error || result.detail || 'Scene packet job status failed');
    const job = result.job || result;
    const elapsed = Math.round((Date.now() - started) / 1000);
    state.roleplayRuntimePacketProgress = {
      status: job.status || 'running',
      label: job.status === 'built' ? 'Scene packet built' : job.status === 'failed' ? 'Scene packet build failed' : 'Building scene packet…',
      detail: `${job.message || 'Retrieval/rerank is still running.'} · ${elapsed}s elapsed`,
      step: job.stage || 'background_job',
      job_id: jobId,
      started_at: job.started_at,
      updated_at: job.updated_at,
      elapsed_ms: job.elapsed_ms,
    };
    render();
    if (job.status === 'built') return job.result || {};
    if (job.status === 'failed' || job.status === 'missing') throw new Error(job.error || job.message || 'Scene packet background job failed');
    await new Promise((resolve) => setTimeout(resolve, 2000));
  }
}

async function buildRoleplayPresetScenePacketFromUi() {
  if (await neoTryRoleplayAction('buildRoleplayPresetScenePacketFromUi')) return;
  const presetId = roleplayRuntimePresetSelectedValue();
  const payload = {
    preset_id: presetId,
    scenario_id: document.getElementById('roleplay-runtime-preset-scenario')?.value || '',
    player_character_ids: document.getElementById('roleplay-runtime-preset-player')?.value || '',
    query: document.getElementById('roleplay-runtime-preset-query')?.value || '',
    title: document.getElementById('roleplay-runtime-preset-packet-title')?.value || '',
    mode: document.getElementById('roleplay-runtime-preset-mode')?.value || 'hybrid',
    limit: Number(document.getElementById('roleplay-runtime-preset-limit')?.value || 8),
    candidate_limit: Number(document.getElementById('roleplay-runtime-preset-candidate-limit')?.value || 24),
    rerank_candidate_limit: Number(document.getElementById('roleplay-runtime-preset-rerank-candidate-limit')?.value || 8),
    rerank: document.getElementById('roleplay-runtime-preset-rerank')?.checked !== false,
    run_retrieval: Boolean(document.getElementById('roleplay-runtime-preset-run-retrieval')?.checked),
  };
  try {
    state.roleplayRuntimePacketProgress = { status: 'running', label: 'Building scene packet…', detail: 'Saving packet payload and binding the runtime preset for Scene Chat. Fast mode skips heavy retrieval unless enabled.', step: 'build_packet', started_at: new Date().toISOString() };
    render();
    let result;
    if (payload.run_retrieval) {
      const started = await roleplayFetchJsonWithTimeout('/api/roleplay/runtime-presets/build-scene-packet-job', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) }, 30000);
      if (!started.response.ok || started.result.status === 'error') throw new Error(started.result.error || started.result.detail || 'Build packet job failed');
      const jobId = started.result.job?.job_id || started.result.job_id;
      if (!jobId) throw new Error('Build packet job did not return a job id');
      state.roleplayRuntimePacketProgress = { status: 'running', label: 'Building scene packet…', detail: `Background retrieval/rerank job started: ${jobId}`, step: 'background_job', job_id: jobId, started_at: new Date().toISOString() };
      render();
      result = await pollRoleplayPresetScenePacketJob(jobId);
    } else {
      const direct = await roleplayFetchJsonWithTimeout('/api/roleplay/runtime-presets/build-scene-packet', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) }, 30000);
      if (!direct.response.ok || direct.result.status === 'error') throw new Error(direct.result.error || direct.result.detail || 'Build packet failed');
      result = direct.result;
    }
    if (!result || result.status === 'error') throw new Error(result?.error || result?.detail || 'Build packet failed');
    state.roleplayScenePacket = result.scene_packet || null;
    state.roleplayScenePacketBuilder = result.scene_packet_builder || await loadJson('/api/roleplay/scene-packet/state', state.roleplayScenePacketBuilder || null);
    state.roleplayRuntimePresets = result.runtime_presets || await loadJson('/api/roleplay/runtime-presets/state', state.roleplayRuntimePresets || null);
    state.roleplayRuntimePreparedPacket = result.prepared || null;
    const packet = state.roleplayScenePacket || {};
    state.roleplayRuntimePacketProgress = { status: 'built', label: 'Scene packet built', detail: `Packet ${packet.packet_id || packet.id || 'saved'} is ready. Next: Open Scene Chat.`, step: 'done', finished_at: new Date().toISOString() };
    render();
  } catch (error) {
    state.roleplayRuntimePacketProgress = { status: 'failed', label: 'Scene packet build failed', detail: error.message || 'Build packet failed', step: 'failed', finished_at: new Date().toISOString() };
    render();
    alert(error.message || 'Build packet failed');
  }
}

