function roleplayPreparedPacketPreviewHtml(prepared) {
  if (!prepared?.packet_payload) return '<div class="roleplay-v1-studio-empty">Prepare or build a Scene Packet to preview the auto-filled packet payload.</div>';
  const payload = prepared.packet_payload || {};
  const rows = ['universe_ids','world_ids','region_ids','city_ids','location_ids','scenario_ids','character_ids','relationship_ids','organization_ids','artifact_ids','ritual_ids','cycle_ids','creature_ids','legend_ids'].map((key) => `${key.replace(/_/g, ' ')}: ${(payload[key] || '').split(',').filter(Boolean).length}`);
  return `<div class="roleplay-v1-studio-card inner"><strong>Auto-filled Scene Packet payload</strong>${listItems([`Title: ${payload.title || 'auto'}`, `Scene: ${payload.scene_id || 'default'}`, `Scope: ${payload.scope_id || 'global'}`, `Query: ${(payload.query || '').slice(0, 120)}`])}${listItems(rows)}<details><summary>Prepared payload JSON</summary><pre class="roleplay-v1-code">${escapeHtml(JSON.stringify(payload, null, 2))}</pre></details></div>`;
}

function roleplayStudioRuntimeHtml(studio) {
  const moduleHtml = neoInvokeSurfaceModule('roleplay', 'roleplayStudioRuntimeDeepHtml', { studio });
  if (moduleHtml !== undefined) return moduleHtml;
  const runtime = state.roleplayRuntime || studio?.runtime || {};
  const presetsState = state.roleplayRuntimePresets || {};
  const selectedId = roleplayRuntimePresetSelectedValue();
  const preset = roleplaySelectedRuntimePreset();
  const scenarioOptions = roleplayPresetSelectOptions(preset?.scenario_options || [], '');
  const playerOptions = roleplayPresetSelectOptions(preset?.character_options || [], '');
  const readiness = preset ? [
    `Memory scope: ${preset.scope_type || 'scope'} · ${preset.scope_id || 'unknown'}`,
    `Runtime bundle: ${preset.runtime_bundle_id || 'not built'}`,
    `Linked records: ${preset.linked_record_count || 0}`,
    `Compiled records: ${preset.compiled_count || 0}`,
    `Fragments: ${preset.fragment_count || 0}`,
    `Status: ${preset.status || 'ready'}`,
  ] : ['No compiled scope selected yet'];
  const prepared = state.roleplayRuntimePreparedPacket;
  const packetProgress = state.roleplayRuntimePacketProgress || null;
  const packetBusy = packetProgress?.status === 'running';
  return `
    <div class="roleplay-v1-studio-grid two">
      <div class="roleplay-v1-studio-card wide">
        <div class="roleplay-v1-scene-row-between"><div><strong>Runtime Preset</strong><p>Select a compiled scope from Compile. Neo will reuse its linked records and runtime bundle instead of asking for manual IDs again.</p></div><span class="neo-badge success">Runtime</span></div>
        <div class="roleplay-v1-studio-grid two compact">
          <div><label>Compiled scope / runtime preset</label><select id="roleplay-runtime-preset-select" onchange="setRoleplayRuntimePresetFromUi()">${roleplayRuntimePresetOptionsHtml(selectedId)}</select></div>
          <div><label>Status</label><input readonly value="${escapeAttr(preset ? (preset.status || 'ready') : 'No preset')}"></div>
        </div>
        <div class="roleplay-v1-studio-row wrap"><button type="button" class="neo-btn admin-engine-btn" onclick="reloadRoleplayRuntimePresets()">Refresh presets</button><button type="button" class="neo-btn admin-engine-btn" onclick="setActiveSubtab('roleplay','studio')">Open Compile Build</button><button type="button" class="neo-btn admin-engine-btn" onclick="refreshRoleplayRuntimeFoundation()">Refresh runtime history</button></div>
        <div class="roleplay-memory-grid"><div class="roleplay-memory-card"><strong>Readiness</strong>${listItems(readiness)}</div><div class="roleplay-memory-card"><strong>Runtime store</strong>${listItems([`Bundles: ${(runtime.bundles || []).length}`, `Latest bundle: ${runtime.latest_bundle_id || 'none'}`, `Preset count: ${presetsState.preset_count || 0}`])}</div></div>
      </div>

      <div class="roleplay-v1-studio-card wide">
        <div class="roleplay-v1-scene-row-between"><div><strong>Scene Packet from Preset</strong><p>Pick a scenario and player character from the compiled scope. Neo auto-fills world, cast, relationships, artifacts, rituals, legends, and retrieval scope.</p></div><span class="neo-badge">simple mode</span></div>
        <div class="roleplay-v1-studio-grid three compact">
          <div><label>Scenario</label><select id="roleplay-runtime-preset-scenario">${scenarioOptions}</select></div>
          <div><label>Player character</label><select id="roleplay-runtime-preset-player">${playerOptions}</select></div>
          <div><label>Mode</label><select id="roleplay-runtime-preset-mode"><option value="hybrid">hybrid</option><option value="semantic">semantic</option><option value="keyword">keyword</option><option value="auto">auto</option></select></div>
        </div>
        <label>Packet title</label><input id="roleplay-runtime-preset-packet-title" placeholder="Auto: Scenario — Runtime Packet">
        <label>Retrieval query override</label><input id="roleplay-runtime-preset-query" placeholder="Optional. Leave blank to auto-build from scenario, cast, relationship, artifacts.">
        <div class="roleplay-v1-studio-grid four compact"><div><label>Final results</label><input id="roleplay-runtime-preset-limit" type="number" value="8" min="1" max="24"></div><div><label>Candidate limit</label><input id="roleplay-runtime-preset-candidate-limit" type="number" value="24" min="1" max="48"></div><div><label>Rerank top</label><input id="roleplay-runtime-preset-rerank-candidate-limit" type="number" value="8" min="1" max="16"></div><div><label>Rerank</label><input id="roleplay-runtime-preset-rerank" type="checkbox"></div></div>
        <label class="roleplay-checkbox"><input id="roleplay-runtime-preset-run-retrieval" type="checkbox"> Run retrieval during packet build <span class="roleplay-panel-note">Optional. When enabled, Neo retrieves 24 candidates, reranks only the top 8, then saves diagnostics. This keeps real reranking without freezing packet builds.</span></label>
        <div class="roleplay-v1-studio-row wrap"><button type="button" class="neo-btn admin-engine-btn" onclick="prepareRoleplayPresetScenePacketFromUi()" ${packetBusy ? 'disabled' : ''}>${roleplayBusyButtonLabel('Preview Auto Packet', 'Previewing…', packetBusy && packetProgress?.step === 'prepare_packet')}</button><button type="button" class="neo-btn primary admin-engine-btn ${packetBusy ? 'is-busy' : ''}" onclick="buildRoleplayPresetScenePacketFromUi()" ${packetBusy ? 'disabled' : ''}>${roleplayBusyButtonLabel('Build Scene Packet', 'Building…', packetBusy && packetProgress?.step === 'build_packet')}</button><button type="button" class="neo-btn admin-engine-btn" onclick="openRoleplaySceneChatFromRuntime()" ${packetBusy ? 'disabled' : ''}>Open Scene Chat</button></div>
        ${roleplayActionProgressHtml(packetProgress, { title: 'Scene packet progress' })}
        ${roleplayPreparedPacketPreviewHtml(prepared)}
        ${roleplayScenePacketPreviewHtml(state.roleplayScenePacket || (state.roleplayScenePacketBuilder || {}).latest_packet)}
      </div>

      <div class="roleplay-v1-studio-card wide">
        <div class="roleplay-v1-scene-row-between"><div><strong>Linked Records</strong><p>These records came from the selected compiled scope. This is what the Runtime preset can use.</p></div><span class="neo-badge">${preset?.linked_record_count || 0} records</span></div>
        ${roleplayPresetRecordSummaryHtml(preset)}
      </div>

      <details class="roleplay-v1-studio-card wide">
        <summary><strong>Advanced retrieval + manual packet controls</strong></summary>
        <div class="roleplay-v1-studio-card inner">
          <div class="roleplay-v1-scene-row-between"><div><strong>Retrieval debug</strong><p>Use this only when you need to debug memory ranking. Simple mode above is the normal path.</p></div><span class="neo-badge">advanced</span></div>
          <div class="roleplay-v1-studio-grid three compact">
            <div><label>Query</label><input id="roleplay-runtime-memory-query" placeholder="Search entities, memories, continuity..."></div>
            <div><label>Scope / sandbox</label><input id="roleplay-runtime-memory-scope" placeholder="optional sandbox/session/bundle id"></div>
            <div><label>Mode</label><select id="roleplay-runtime-memory-mode"><option value="hybrid">hybrid</option><option value="semantic">semantic</option><option value="keyword">keyword</option><option value="auto">auto</option></select></div>
          </div>
          <div class="roleplay-v1-studio-grid three compact"><div><label>Final limit</label><input id="roleplay-runtime-memory-limit" type="number" value="12"></div><div><label>Candidate limit</label><input id="roleplay-runtime-memory-candidate-limit" type="number" value="36"></div><div><label>Index limit</label><input id="roleplay-runtime-memory-index-limit" type="number" value="500"></div></div>
          <label>Memory types</label><input id="roleplay-runtime-memory-types" value="entities,memory_fragments,shared_memories,continuity,turn_summaries,story_checkpoints">
          <div class="roleplay-v1-studio-grid three compact"><div><label>Rerank</label><input id="roleplay-runtime-memory-rerank" type="checkbox" checked></div><div><label>Force reindex</label><input id="roleplay-runtime-memory-index-force" type="checkbox"></div><div><label>Rebuild search docs</label><input id="roleplay-runtime-memory-rebuild-search" type="checkbox"></div></div>
          <div class="roleplay-v1-studio-row wrap"><button type="button" class="neo-btn admin-engine-btn" onclick="indexRoleplaySemanticMemoryFromUi('studio')">Index memory vectors</button><button type="button" class="neo-btn primary admin-engine-btn" onclick="runRoleplayRuntimeRetrievalLaneFromUi('studio')">Run runtime retrieval</button><button type="button" class="neo-btn admin-engine-btn" onclick="searchRoleplaySemanticRetrievalFromUi('studio')">Semantic only</button><button type="button" class="neo-btn admin-engine-btn" onclick="searchRoleplayRetrievalFoundationFromUi('studio')">Keyword only</button></div>
          ${roleplayRetrievalResultsHtml(state.roleplayRuntimeRetrievalSearch || state.roleplayRetrievalSearch)}
        </div>
        <div class="roleplay-v1-studio-card inner"><strong>Raw preset JSON</strong><pre class="roleplay-v1-code">${escapeHtml(JSON.stringify(preset || {}, null, 2))}</pre></div>
      </details>
    </div>`;
}


function roleplayMemoryFoundationHtml(memory = state.roleplayMemory || {}, retrieval = state.roleplayRetrieval || {}) {
  const sqlite = memory.sqlite || {};
  const counts = sqlite.table_counts || {};
  const bridge = memory.admin_engine_bridge || {};
  const rows = retrieval.available_memory_rows || {};
  return `
    <div class="roleplay-memory-grid">
      <div class="roleplay-memory-card"><strong>SQLite backbone</strong>${listItems([`Status: ${sqlite.status || 'pending'}`, `Path: ${sqlite.path || 'neo_data/roleplay/roleplay.sqlite'}`, `Entities: ${counts.rp_entities || 0}`, `Fragments: ${counts.rp_memory_fragments || 0}`, `Traces: ${counts.rp_retrieval_traces || 0}`, `Vector index: ${counts.rp_vector_index || 0}`])}</div>
      <div class="roleplay-memory-card"><strong>Memory Engine bridge</strong>${listItems([`Embedding: ${bridge.embedding_model_path ? 'configured' : 'not set'}`, `Reranker: ${bridge.reranker_model_path ? 'configured' : 'not set'}`, `Vector path: ${bridge.vector_path || 'not set'}`, `Vector store: ${bridge.vector_store_ready ? 'ready' : 'not configured'}`])}</div>
      <div class="roleplay-memory-card"><strong>Retrieval setup</strong>${listItems([`Entities: ${rows.entities || 0}`, `Memory fragments: ${rows.memory_fragments || 0}`, `Shared memories: ${rows.shared_memories || 0}`, `Retrieval traces: ${rows.retrieval_traces || 0}`, `Vector rows: ${retrieval.semantic_search?.indexed_rows || 0}`, `Semantic ready: ${retrieval.semantic_search?.ready ? 'yes' : 'no'}`])}</div>
    </div>
    <div class="roleplay-v1-studio-row"><button type="button" class="neo-btn primary admin-engine-btn" onclick="compileRoleplayAllBuilderMemoryFromUi()">Compile all Builder memory</button><button type="button" class="neo-btn admin-engine-btn" onclick="syncRoleplayMemoryFoundation()">Legacy sync / recompile</button><button type="button" class="neo-btn admin-engine-btn" onclick="reloadRoleplayMemoryFoundation()">Refresh memory</button></div>
  `;
}

async function reloadRoleplayMemoryFoundation() {
  state.roleplayMemory = await loadJson('/api/roleplay/memory/state', state.roleplayMemory || null);
  state.roleplayRetrieval = await loadJson('/api/roleplay/retrieval/state', state.roleplayRetrieval || null);
  render();
}

async function compileRoleplayAllBuilderMemoryFromUi() {
  try {
    const response = await fetch('/api/roleplay/scoped-compile/execute-plan', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ mode: 'changed_only', scope_type: 'global', include_compiled: false, rebuild_search: true, index_after: true }),
    });
    if (!response.ok) throw new Error('Scoped Builder memory compile failed');
    const result = await response.json();
    state.roleplayScopedCompileLastRun = result;
    state.roleplayScopedCompile = result.state || await loadJson('/api/roleplay/scoped-compile/state', state.roleplayScopedCompile || null);
    state.roleplayMemory = await loadJson('/api/roleplay/memory/state', state.roleplayMemory || null);
    state.roleplayRetrieval = await loadJson('/api/roleplay/retrieval/state', state.roleplayRetrieval || null);
    alert(`Scoped compile ${result.status || 'done'}: ${result.compiled_count ?? 0} record(s), ${result.fragment_count ?? 0} fragment(s).`);
    render();
  } catch (error) { alert(error.message || 'Scoped Builder memory compile failed'); }
}

async function syncRoleplayMemoryFoundation() {
  try {
    const response = await fetch('/api/roleplay/memory/sync-foundation', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ kind: '' }) });
    if (!response.ok) throw new Error('Roleplay memory sync failed');
    const result = await response.json();
    state.roleplayMemory = result.memory || await loadJson('/api/roleplay/memory/state', null);
    state.roleplayRetrieval = await loadJson('/api/roleplay/retrieval/state', null);
  state.roleplayContradictions = await loadJson('/api/roleplay/contradictions/state', null);
  state.roleplayProvenance = await loadJson('/api/roleplay/provenance/state', null);
  state.roleplayProvenanceGraph = await loadJson('/api/roleplay/provenance/graph?limit=160', null);
  state.roleplayProvenanceDebug = await loadJson('/api/roleplay/provenance-debug/state', state.roleplayProvenanceDebug || null);
  state.roleplayCollaboration = await loadJson('/api/roleplay/collaboration/state', null);
  state.roleplayCloudSync = await loadJson('/api/roleplay/cloud-sync/state', null);
  state.roleplayRuntime = await loadJson('/api/roleplay/runtime/bundles', null);
  state.assistantBootstrap = await loadJson('/api/assistant/bootstrap', null);
  if (state.assistantBootstrap?.ok) {
    state.assistant.profile = state.assistantBootstrap.profile || null;
    state.assistant.projects = state.assistantBootstrap.projects || [];
    state.assistant.sessions = state.assistantBootstrap.sessions || [];
    state.assistant.activeSession = state.assistantBootstrap.active_session || null;
    state.assistant.memoryCaptures = state.assistantBootstrap.memory_captures || [];
    state.assistant.storage = state.assistantBootstrap.storage || {};
    state.assistant.capabilities = state.assistantBootstrap.capabilities || {};
    state.assistant.deferred = state.assistantBootstrap.deferred_to_wave3 || state.assistantBootstrap.deferred_to_wave2 || [];
    state.assistant.thinkingLayer = state.assistantBootstrap.thinking_layer || {};
    state.assistant.selectedProjectId = state.assistant.activeSession?.project_id || state.assistant.profile?.default_project_id || 'general';
  }
    render();
  } catch (error) { console.warn(error); }
}


function roleplayCollaborationHtml(collab = state.roleplayCollaboration || {}) {
  const counts = collab.counts || {};
  const sessions = collab.sessions || [];
  const locks = collab.locks || [];
  const activity = collab.activity || [];
  const conflicts = collab.conflicts || [];
  const sessionCards = sessions.length ? sessions.slice(-6).reverse().map((item) => `<div class="roleplay-collab-row"><strong>${escapeHtml(item.display_name || item.user_id || 'User')}</strong><span>${escapeHtml(item.surface_id || 'roleplay')} · ${escapeHtml(item.tab_id || 'unknown')}</span><small>${escapeHtml(item.last_seen_at || '')}</small></div>`).join('') : '<div class="roleplay-v1-studio-empty">No active collaborator sessions yet.</div>';
  const lockCards = locks.length ? locks.map((item) => `<div class="roleplay-collab-row lock"><strong>${escapeHtml(item.target_type || 'record')}:${escapeHtml(item.target_id || '')}</strong><span>${escapeHtml(item.display_name || item.user_id || 'local_user')}</span><button type="button" class="neo-btn mini roleplay-btn" onclick="roleplayReleaseCollaborationLock('${escapeAttr(item.lock_id || '')}')">Release</button></div>`).join('') : '<div class="roleplay-v1-studio-empty">No active edit locks.</div>';
  const conflictCards = conflicts.length ? conflicts.slice(0, 5).map((item) => `<div class="roleplay-collab-row conflict"><strong>${escapeHtml(item.conflict_type || 'conflict')}</strong><span>${escapeHtml(item.summary || item.target_id || '')}</span><button type="button" class="neo-btn mini roleplay-btn" onclick="roleplayResolveCollaborationConflict('${escapeAttr(item.conflict_id || '')}', 'resolved')">Resolve</button></div>`).join('') : '<div class="roleplay-v1-studio-empty">No open collaboration conflicts.</div>';
  const activityCards = activity.length ? activity.slice(0, 8).map((item) => `<div class="roleplay-collab-row activity"><strong>${escapeHtml(item.event_type || 'activity')}</strong><span>${escapeHtml(item.display_name || item.user_id || '')}</span><small>${escapeHtml(item.created_at || '')}</small></div>`).join('') : '<div class="roleplay-v1-studio-empty">No collaboration activity yet.</div>';
  return `<div class="roleplay-collab-shell">
    <div class="roleplay-v1-studio-grid four compact">
      <div class="roleplay-memory-card"><strong>Sessions</strong><br>${counts.active_sessions ?? 0} active / ${counts.sessions ?? 0} total</div>
      <div class="roleplay-memory-card"><strong>Locks</strong><br>${counts.locks ?? 0} active</div>
      <div class="roleplay-memory-card"><strong>Conflicts</strong><br>${counts.open_conflicts ?? 0} open</div>
      <div class="roleplay-memory-card"><strong>Mode</strong><br>${escapeHtml(collab.mode || 'local setup')}</div>
    </div>
    <div class="roleplay-v1-studio-row wrap">
      <input id="roleplay-collab-user-id" placeholder="user id" value="local_user">
      <input id="roleplay-collab-display-name" placeholder="display name" value="Local User">
      <input id="roleplay-collab-target-type" placeholder="target type" value="record">
      <input id="roleplay-collab-target-id" placeholder="target id to lock">
      <button type="button" class="neo-btn admin-engine-btn" onclick="roleplayCollaborationHeartbeat()">Heartbeat</button>
      <button type="button" class="neo-btn primary admin-engine-btn" onclick="roleplayAcquireCollaborationLock()">Acquire lock</button>
      <button type="button" class="neo-btn admin-engine-btn" onclick="reloadRoleplayCollaboration()">Refresh</button>
    </div>
    <div class="roleplay-collab-grid">
      <section><h4>Active sessions</h4>${sessionCards}</section>
      <section><h4>Edit locks</h4>${lockCards}</section>
      <section><h4>Conflict warnings</h4>${conflictCards}</section>
      <section><h4>Activity log</h4>${activityCards}</section>
    </div>
    <div class="roleplay-v1-studio-empty">Local collaboration scope: identity, heartbeat, record locks, conflict warnings, and activity log. Real-time sync is planned for later.</div>
  </div>`;
}

function roleplayCollaborationUserPayload() {
  return {
    user_id: document.getElementById('roleplay-collab-user-id')?.value || 'local_user',
    display_name: document.getElementById('roleplay-collab-display-name')?.value || 'Local User',
    color: 'neo',
  };
}

async function reloadRoleplayCollaboration() {
  state.roleplayCollaboration = await loadJson('/api/roleplay/collaboration/state', state.roleplayCollaboration || null);
  render();
}

async function roleplayCollaborationHeartbeat() {
  const payload = { ...roleplayCollaborationUserPayload(), surface_id: 'roleplay', tab_id: state.activeSubtabId || 'studio', session_id: 'local_session' };
  const response = await fetch('/api/roleplay/collaboration/session/heartbeat', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
  if (response.ok) {
    const result = await response.json();
    state.roleplayCollaboration = result.collaboration || await loadJson('/api/roleplay/collaboration/state', null);
    render();
  }
}

async function roleplayAcquireCollaborationLock() {
  const payload = { ...roleplayCollaborationUserPayload(), target_type: document.getElementById('roleplay-collab-target-type')?.value || 'record', target_id: document.getElementById('roleplay-collab-target-id')?.value || '' };
  if (!payload.target_id) { alert('Add a target id to lock.'); return; }
  const response = await fetch('/api/roleplay/collaboration/lock/acquire', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
  const result = await response.json();
  state.roleplayCollaboration = result.collaboration || await loadJson('/api/roleplay/collaboration/state', null);
  render();
}

async function roleplayReleaseCollaborationLock(lockId) {
  const payload = { ...roleplayCollaborationUserPayload(), lock_id: lockId };
  const response = await fetch('/api/roleplay/collaboration/lock/release', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
  if (response.ok) {
    const result = await response.json();
    state.roleplayCollaboration = result.collaboration || await loadJson('/api/roleplay/collaboration/state', null);
    render();
  }
}

async function roleplayResolveCollaborationConflict(conflictId, status = 'resolved') {
  const payload = { ...roleplayCollaborationUserPayload(), conflict_id: conflictId, status, resolution_note: 'Resolved from Roleplay Studio Inspector.' };
  const response = await fetch('/api/roleplay/collaboration/conflict/resolve', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
  if (response.ok) {
    const result = await response.json();
    state.roleplayCollaboration = result.collaboration || await loadJson('/api/roleplay/collaboration/state', null);
    render();
  }
}


function roleplayCloudSyncLogHtml(items = []) {
  const rows = Array.isArray(items) ? items : [];
  if (!rows.length) return '<div class="roleplay-v1-studio-empty">No cloud sync activity yet.</div>';
  return `<div class="roleplay-story-list">${rows.slice(0, 8).map((item) => `<div class="roleplay-story-card"><div class="roleplay-v1-row-between"><div><strong>${escapeHtml(item.event_type || 'sync')}</strong><p>${escapeHtml(item.created_at || '')}</p></div><span class="neo-badge">${escapeHtml(item.status || item.action || 'log')}</span></div><small>${escapeHtml(item.remote_path || item.archive || item.summary ? JSON.stringify(item.summary || item.archive || item.remote_path) : '')}</small></div>`).join('')}</div>`;
}

function roleplayCloudSyncSnapshotsHtml(items = [], label = 'snapshot') {
  const rows = Array.isArray(items) ? items : [];
  if (!rows.length) return `<div class="roleplay-v1-studio-empty">No ${escapeHtml(label)} records yet.</div>`;
  return `<div class="roleplay-story-list">${rows.slice(0, 6).map((item) => `<div class="roleplay-story-card"><div class="roleplay-v1-row-between"><div><strong>${escapeHtml(item.archive || 'snapshot.zip')}</strong><p>${Math.round(Number(item.size_bytes || 0) / 1024)} KB · ${escapeHtml(item.created_at || '')}</p></div><span class="neo-badge">${escapeHtml(label)}</span></div><small>${escapeHtml(item.path || '')}</small></div>`).join('')}</div>`;
}

