async function createRoleplayStudioProjectFromUi() {
  const payload = {
    title: document.getElementById('roleplay-studio-project-title')?.value || 'Untitled Roleplay Project',
    description: document.getElementById('roleplay-studio-project-description')?.value || '',
    author: document.getElementById('roleplay-studio-project-author')?.value || '',
  };
  try {
    const response = await fetch('/api/roleplay/studio/project/create', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
    if (!response.ok) throw new Error('Studio project create failed');
    const result = await response.json();
    state.roleplayStudio = result.studio || await loadJson('/api/roleplay/studio/state', null);
    state.roleplayStudioActiveView = 'project';
    render();
  } catch (error) { console.warn(error); }
}


async function reloadRoleplaySourceBreakdowns() {
  try {
    const response = await fetch('/api/roleplay/source-breakdown/list', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ limit: 80 }) });
    if (response.ok) state.roleplaySourceBreakdowns = await response.json();
  } catch (error) { console.warn(error); }
}

async function generateRoleplaySourceBreakdownFromUi(sourceId) {
  try {
    if (!sourceId) { alert('Select or save a source document first.'); return; }
    const response = await fetch('/api/roleplay/source-breakdown/generate', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ source_id: sourceId }),
    });
    if (!response.ok) throw new Error('Source breakdown generation failed');
    const result = await response.json();
    state.roleplayLastSourceBreakdown = result;
    await reloadRoleplaySourceBreakdowns();
    state.roleplayStudio = await loadJson('/api/roleplay/studio/state', state.roleplayStudio || null);
    alert(`Generated ${result.candidate_count ?? 0} canon candidate(s) from ${result.chunk_count ?? 0} chunk(s).`);
    render();
  } catch (error) { alert(error.message || 'Source breakdown generation failed'); }
}

async function generateRoleplayAllSourceBreakdownsFromUi() {
  try {
    const projectId = document.getElementById('roleplay-studio-source-project')?.value || document.getElementById('roleplay-studio-project-select')?.value || '';
    const response = await fetch('/api/roleplay/source-breakdown/generate-all', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ project_id: projectId }),
    });
    if (!response.ok) throw new Error('Source breakdown batch failed');
    const result = await response.json();
    state.roleplayLastSourceBreakdown = result;
    await reloadRoleplaySourceBreakdowns();
    alert(`Generated breakdowns for ${result.generated_count ?? 0} source document(s), ${result.candidate_count ?? 0} candidate(s).`);
    render();
  } catch (error) { alert(error.message || 'Source breakdown batch failed'); }
}

async function approveRoleplaySourceCanonFromUi(breakdownId = '', sourceId = '') {
  try {
    const payload = { breakdown_id: breakdownId || '', source_id: sourceId || '', approve_all: true };
    const response = await fetch('/api/roleplay/source-breakdown/approve-canon', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
    if (!response.ok) throw new Error('Canon approval failed. Generate a breakdown first.');
    const result = await response.json();
    state.roleplayLastCanonApproval = result;
    state.roleplayMemory = await loadJson('/api/roleplay/memory/state', state.roleplayMemory || null);
    state.roleplayRetrieval = await loadJson('/api/roleplay/retrieval/state', state.roleplayRetrieval || null);
    await reloadRoleplaySourceBreakdowns();
    alert(`Approved ${result.approved_count ?? 0} canon candidate(s).`);
    render();
  } catch (error) { alert(error.message || 'Canon approval failed'); }
}

async function compileRoleplayNovelSourceFromUi(sourceId) {
  try {
    if (!sourceId) { alert('Select or save a source document first.'); return; }
    const promoteToCanon = !!document.getElementById('roleplay-novel-promote-canon')?.checked;
    const response = await fetch('/api/roleplay/novel/compile-source-document', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ source_id: sourceId, delete_existing: true, promote_to_memory: true, promote_to_canon: promoteToCanon }),
    });
    if (!response.ok) throw new Error('Source memory compile failed');
    const result = await response.json();
    state.roleplayLastNovelCompile = result;
    state.roleplayMemory = await loadJson('/api/roleplay/memory/state', state.roleplayMemory || null);
    state.roleplayRetrieval = await loadJson('/api/roleplay/retrieval/state', state.roleplayRetrieval || null);
    state.roleplayStudio = await loadJson('/api/roleplay/studio/state', state.roleplayStudio || null);
    alert(`Compiled ${result.chunk_count ?? 0} source chunk(s) into ${result.memory_fragment_count ?? 0} memory fragment(s).`);
    render();
  } catch (error) { alert(error.message || 'Source memory compile failed'); }
}

async function compileRoleplayAllNovelSourcesFromUi() {
  try {
    const projectId = document.getElementById('roleplay-studio-source-project')?.value || document.getElementById('roleplay-studio-project-select')?.value || '';
    const promoteToCanon = !!document.getElementById('roleplay-novel-promote-canon')?.checked;
    const response = await fetch('/api/roleplay/novel/compile-all-source-documents', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ project_id: projectId, delete_existing: true, promote_to_memory: true, promote_to_canon: promoteToCanon }),
    });
    if (!response.ok) throw new Error('Source memory compile failed');
    const result = await response.json();
    state.roleplayLastNovelCompile = result;
    state.roleplayMemory = await loadJson('/api/roleplay/memory/state', state.roleplayMemory || null);
    state.roleplayRetrieval = await loadJson('/api/roleplay/retrieval/state', state.roleplayRetrieval || null);
    state.roleplayStudio = await loadJson('/api/roleplay/studio/state', state.roleplayStudio || null);
    alert(`Compiled ${result.compiled_count ?? 0} source document(s), ${result.memory_fragment_count ?? 0} memory fragment(s).`);
    render();
  } catch (error) { alert(error.message || 'Source memory compile failed'); }
}

async function saveRoleplayStudioSourceFromUi() {
  const meta = {
    document_type: document.getElementById('roleplay-studio-source-type')?.value || 'text',
    order_index: document.getElementById('roleplay-studio-source-order')?.value || '1',
    chapter_number: document.getElementById('roleplay-studio-source-chapter')?.value || '1',
    scene_number: document.getElementById('roleplay-studio-source-scene')?.value || '0',
    draft_status: document.getElementById('roleplay-studio-source-status')?.value || 'draft',
    part_arc: document.getElementById('roleplay-studio-source-arc')?.value || '',
    pov: document.getElementById('roleplay-studio-source-pov')?.value || '',
    author_notes: document.getElementById('roleplay-studio-source-notes')?.value || '',
  };
  const payload = {
    project_id: document.getElementById('roleplay-studio-source-project')?.value || '',
    title: document.getElementById('roleplay-studio-source-title')?.value || 'Untitled Source',
    body: document.getElementById('roleplay-studio-source-body')?.value || '',
    source_type: meta.document_type || 'text',
    meta,
  };
  try {
    const response = await fetch('/api/roleplay/studio/source/save-text', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
    if (!response.ok) throw new Error('Studio source save failed');
    const result = await response.json();
    state.roleplayStudio = result.studio || await loadJson('/api/roleplay/studio/state', null);
    state.roleplayStudioActiveView = 'source';
    render();
  } catch (error) { console.warn(error); }
}

function roleplayStudioClearSourceDraft() {
  ['roleplay-studio-source-title','roleplay-studio-source-body','roleplay-studio-source-notes','roleplay-studio-source-arc','roleplay-studio-source-pov'].forEach((id) => {
    const node = document.getElementById(id);
    if (node) node.value = '';
  });
}

function renderRoleplayStudioPanels(columns, baseTab) {
  const studio = state.roleplayStudio || {};
  el.surfacePanels.classList.add('roleplay-v1-studio-workspace');
  columns.left.appendChild(panel('Studio', roleplayStudioShellHtml(studio), false, 'Studio lanes'));
  if (baseTab?.sections?.length && state.detailMode === 'expert') {
    columns.right.appendChild(panel('Project Links', roleplayProjectLinksHtml(), false, `${state.roleplayProjectLinks?.summary?.link_count || 0} links`));
    columns.right.appendChild(renderRoleplayFoundationPanel('Studio Setup', baseTab.sections.map((section) => `${section.section_id}: ${section.slot}`), 'Setup'));
  }
}



