function roleplayStoriesStatusBadge(status) {
  const clean = String(status || 'draft').toLowerCase().replace(/[^a-z0-9_-]+/g, '_');
  return `<span class="roleplay-story-status status-${escapeHtml(clean)}">${escapeHtml(status || 'Draft')}</span>`;
}

function roleplayStoriesCard(record, type = 'storyline') {
  const id = record.storyline_id || record.session_id || record.checkpoint_id || record.record_id || 'unsaved';
  const title = record.title || record.summary || record.premise || id;
  const meta = type === 'session'
    ? `${record.mode_lock || 'mode n/a'} · ${record.interaction_mode || 'roleplay'} · checkpoints ${record.checkpoint_count || 0}`
    : `${record.status || 'draft'} · ${id}`;
  const body = record.summary || record.premise || record.arc || record.storage_path || 'No summary yet.';
  const safeId = escapeAttr(id);
  const actions = type === 'checkpoint'
    ? `<div class="roleplay-story-card-actions"><button type="button" class="neo-btn admin-engine-btn small" onclick="restoreRoleplayStoryToSceneFromUi('checkpoint','${safeId}')">Restore to Scene</button><button type="button" class="neo-btn admin-engine-btn small" onclick="roleplayBranchCheckpointFromUi('${safeId}')">Branch</button><button type="button" class="neo-btn admin-engine-btn small" onclick="roleplaySelectCheckpointForDiff('${safeId}')">Diff</button></div>`
    : type === 'session'
      ? `<div class="roleplay-story-card-actions"><button type="button" class="neo-btn admin-engine-btn small" onclick="restoreRoleplayStoryToSceneFromUi('session','${safeId}')">Resume session</button></div>`
      : type === 'branch'
        ? `<div class="roleplay-story-card-actions"><button type="button" class="neo-btn admin-engine-btn small" onclick="restoreRoleplayStoryToSceneFromUi('session','${escapeAttr(record.session_id || '')}')">Resume branch</button><button type="button" class="neo-btn admin-engine-btn small" onclick="roleplaySelectCheckpointForDiff('${escapeAttr(record.source_checkpoint_id || '')}')">Diff source</button></div>`
        : '';
  return `<div class="roleplay-story-card status-${escapeHtml(String(record.status || 'draft').toLowerCase().replace(/[^a-z0-9_-]+/g, '_'))}">
    <strong>${escapeHtml(title)}</strong>
    <div class="roleplay-story-card-meta">${roleplayStoriesStatusBadge(record.status || 'draft')} <span>${escapeHtml(type)}</span></div>
    <p>${escapeHtml(meta)}</p>
    <small>${escapeHtml(body)}</small>
    ${actions}
  </div>`;
}

function roleplayStoriesListHtml(storylines) {
  const records = storylines || [];
  if (!records.length) return '<div class="roleplay-stories-empty">No storylines yet. Create one from Workspace or from the current Scene.</div>';
  return `<div class="roleplay-story-list">${records.map((record) => roleplayStoriesCard(record, 'storyline')).join('')}</div>`;
}

