function roleplayProvenanceNodeColor(type) {
  const colors = {
    entity: '#38bdf8',
    memory_fragment: '#a855f7',
    shared_memory: '#22c55e',
    continuity_row: '#f59e0b',
    turn_summary: '#0ea5e9',
    story_checkpoint: '#ec4899',
    retrieval_trace: '#6366f1',
    runtime_bundle: '#14b8a6',
    contradiction_report: '#f87171',
  };
  return colors[type] || '#94a3b8';
}

function roleplayProvenanceGraphLayout(nodes, edges) {
  const safeNodes = nodes.slice(0, 140);
  const index = new Map(safeNodes.map((node, idx) => [node.id, idx]));
  const degree = new Map(safeNodes.map((node) => [node.id, 0]));
  edges.forEach((edge) => {
    if (degree.has(edge.source)) degree.set(edge.source, degree.get(edge.source) + 1);
    if (degree.has(edge.target)) degree.set(edge.target, degree.get(edge.target) + 1);
  });
  const centerNodeId = safeNodes.slice().sort((a, b) => (degree.get(b.id) || 0) - (degree.get(a.id) || 0))[0]?.id || null;
  const types = [...new Set(safeNodes.map((node) => node.type || 'unknown'))];
  const typeIndex = new Map(types.map((type, idx) => [type, idx]));
  const laidOut = safeNodes.map((node, idx) => {
    if (node.id === centerNodeId) return { ...node, x: 0, y: 0, r: 24 + Math.min(16, (degree.get(node.id) || 0) * 3) };
    const ring = 1 + (typeIndex.get(node.type || 'unknown') % 4);
    const ringCount = Math.max(1, safeNodes.filter((candidate) => candidate.id !== centerNodeId && ((typeIndex.get(candidate.type || 'unknown') % 4) + 1) === ring).length);
    const ringPosition = safeNodes.slice(0, idx + 1).filter((candidate) => candidate.id !== centerNodeId && ((typeIndex.get(candidate.type || 'unknown') % 4) + 1) === ring).length - 1;
    const angle = (Math.PI * 2 * ringPosition / ringCount) + (ring * 0.37);
    const radius = 170 + ring * 135 + Math.min(110, (degree.get(node.id) || 0) * 12);
    return { ...node, x: Math.cos(angle) * radius, y: Math.sin(angle) * radius, r: 15 + Math.min(12, (degree.get(node.id) || 0) * 2) };
  });
  return { nodes: laidOut, nodeById: new Map(laidOut.map((node) => [node.id, node])) };
}

function roleplayProvenanceVisualGraphHtml(nodes, edges, trace) {
  const safeNodes = nodes.slice(0, 140);
  if (!safeNodes.length) {
    return '<div class="roleplay-provenance-canvas-empty">No graph nodes available yet. Create or sync Roleplay records, run Scene turns, compile runtime bundles, or save checkpoints.</div>';
  }
  const { nodes: laidOut, nodeById } = roleplayProvenanceGraphLayout(safeNodes, edges);
  const activeId = trace?.node_id || trace?.direct_node?.id || '';
  const relatedIds = new Set([activeId, ...(trace?.related_nodes || []).map((node) => node.id).filter(Boolean)]);
  const renderedEdges = edges.slice(0, 260).map((edge) => {
    const a = nodeById.get(edge.source);
    const b = nodeById.get(edge.target);
    if (!a || !b) return '';
    const active = edge.source === activeId || edge.target === activeId || (relatedIds.has(edge.source) && relatedIds.has(edge.target));
    const stroke = active ? '#fbbf24' : 'rgba(148, 163, 184, 0.34)';
    const width = active ? 2.6 : 1.25;
    const midX = (a.x + b.x) / 2;
    const midY = (a.y + b.y) / 2;
    return `<g class="roleplay-svg-edge ${active ? 'active' : ''}"><line x1="${a.x.toFixed(1)}" y1="${a.y.toFixed(1)}" x2="${b.x.toFixed(1)}" y2="${b.y.toFixed(1)}" stroke="${stroke}" stroke-width="${width}" marker-end="url(#roleplayGraphArrow)"/><text x="${midX.toFixed(1)}" y="${midY.toFixed(1)}">${escapeHtml(edge.type || '')}</text></g>`;
  }).join('');
  const renderedNodes = laidOut.map((node) => {
    const active = node.id === activeId;
    const related = relatedIds.has(node.id) && !active;
    const fill = roleplayProvenanceNodeColor(node.type || 'unknown');
    const label = String(node.label || node.source_id || node.id || '').slice(0, 26);
    return `<g class="roleplay-svg-node ${active ? 'active' : ''} ${related ? 'related' : ''}" transform="translate(${node.x.toFixed(1)} ${node.y.toFixed(1)})" onclick="roleplayTraceProvenanceNode(${escapeAttr(JSON.stringify(node.id || ''))})" role="button" tabindex="0">
      <circle r="${node.r.toFixed(1)}" fill="${fill}"/>
      <text y="${(node.r + 16).toFixed(1)}">${escapeHtml(label)}</text>
      <title>${escapeHtml(`${node.type || 'node'} · ${node.source_id || node.id || ''}`)}</title>
    </g>`;
  }).join('');
  const vb = roleplayProvenanceViewBox();
  return `<div class="roleplay-provenance-canvas-shell">
    <div class="roleplay-provenance-canvas-head"><strong>Visual graph canvas</strong><span>${safeNodes.length} nodes shown · ${edges.length} edges available</span></div>
    <svg class="roleplay-provenance-svg" viewBox="${vb.x} ${vb.y} ${vb.w} ${vb.h}" xmlns="http://www.w3.org/2000/svg" aria-label="Roleplay provenance visual graph">
      <defs><marker id="roleplayGraphArrow" markerWidth="8" markerHeight="8" refX="7" refY="3" orient="auto" markerUnits="strokeWidth"><path d="M0,0 L0,6 L7,3 z" fill="rgba(148, 163, 184, 0.72)"/></marker></defs>
      <rect x="${vb.x}" y="${vb.y}" width="${vb.w}" height="${vb.h}" rx="18" fill="rgba(2,6,23,.18)"/>
      ${renderedEdges}
      ${renderedNodes}
    </svg>
  </div>`;
}

