function roleplayStoriesInspectorHtml(stories) {
  const modResult = neoInvokeSurfaceModule('roleplay', 'roleplayStoriesInspectorHtml', { stories });
  if (modResult !== undefined) return modResult;
  const inspector = stories?.inspector || {};
  const view = roleplayStoriesInspectorView();
  const summary = inspector.summary || {};
  const continuity = inspector.continuity || {};
  const provenance = inspector.provenance || {};
  const summaryText = `Summary\nStorylines: ${summary.storyline_count ?? 0}\nSessions: ${summary.session_count ?? 0}\nCheckpoints: ${summary.checkpoint_count ?? 0}\nMemory fragments: ${summary.memory_rows?.fragments ?? 0}\nTurn summaries: ${summary.memory_rows?.turn_summaries ?? 0}\nActive storyline: ${summary.active_storyline_id || 'none'}\n${summary.message || 'Summary placeholder only.'}`;
  const continuityText = `Continuity\nRows: ${continuity.row_count ?? 0}\nChecks enabled: yes\n${continuity.message || 'Continuity rows are connected to the contradiction resolver.'}`;
  const provenanceText = `Provenance\nTraces: ${provenance.trace_count ?? 0}\nCheckpoint memory rows: ${provenance.checkpoint_memory_count ?? 0}\nTrace enabled: ${provenance.trace_enabled ? 'yes' : 'no'}\n${provenance.message || 'Full provenance graph UI is active.'}`;
  const body = view === 'provenance' ? provenanceText : view === 'continuity' ? continuityText : summaryText;
  return `<div class="roleplay-stories-card tall">
    <div class="roleplay-v1-row-between"><div><div class="roleplay-v1-eyebrow">Inspector</div><p>Summary, continuity, and provenance views for the selected storyline/session/checkpoint.</p></div><span class="badge">Inspector</span></div>
    <div class="roleplay-v1-tabbar inner">
      ${roleplayStoriesInspectorButton('summary', 'Summary')}
      ${roleplayStoriesInspectorButton('continuity', 'Continuity')}
      ${roleplayStoriesInspectorButton('provenance', 'Provenance')}
    </div>
    ${view === 'provenance' ? roleplayProvenanceGraphHtml() : `<pre class="roleplay-stories-pre">${escapeHtml(body)}</pre>`}
    ${view === 'continuity' ? roleplayContradictionReportsHtml() : ''}
  </div>`;
}

