async function roleplayStoriesResumePlaceholder() {
  if (await neoTryRoleplayAction('resumeRoleplayStoryFromSelection')) return;
  const stories = state.roleplayStories || {};
  const restore = stories.workspace?.restore_target || {};
  const checkpointId = restore.checkpoint_id || stories.active_checkpoint_id || '';
  const sessionId = restore.session_id || stories.active_session_id || '';
  await restoreRoleplayStoryToSceneFromUi(checkpointId ? 'checkpoint' : 'session', checkpointId || sessionId);
}

async function restoreRoleplayStoryToSceneFromUi(type, id) {
  if (await neoTryRoleplayAction('restoreRoleplayStoryToSceneFromUi', { type, id })) return;
  const cleanId = String(id || '').trim();
  if (!cleanId) {
    alert('No checkpoint/session selected to restore.');
    return;
  }
  const endpoint = type === 'checkpoint' ? '/api/roleplay/story-checkpoint/restore-snapshot' : '/api/roleplay/story-resume';
  const payload = {
    scene_id: state.roleplayScene?.scene_id || 'default',
    restore_mode: 'replace_scene',
  };
  if (type === 'checkpoint') payload.checkpoint_id = cleanId;
  else payload.session_id = cleanId;
  try {
    const response = await fetch(endpoint, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
    const result = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(result.detail || result.message || 'Story restore failed');
    state.roleplayScene = result.scene || await loadJson('/api/roleplay/scene/state', state.roleplayScene || null);
    state.roleplayStories = result.stories || await loadJson('/api/roleplay/stories/state', state.roleplayStories || null);
    state.roleplayStoriesActiveView = 'workspace';
    state.activeSubtab = 'scene';
    render();
  } catch (error) {
    alert(error.message || 'Story restore failed');
  }
}

