function assistantThreadScrollSnapshot() {
  const thread = document.querySelector('.assistant-thread');
  if (!thread) return null;
  const distanceFromBottom = thread.scrollHeight - thread.scrollTop - thread.clientHeight;
  return {
    scrollTop: thread.scrollTop,
    scrollHeight: thread.scrollHeight,
    clientHeight: thread.clientHeight,
    nearBottom: distanceFromBottom <= 96,
  };
}

function assistantRestoreThreadScroll(snapshot, options = {}) {
  const restore = () => {
    const thread = document.querySelector('.assistant-thread');
    if (!thread) return;
    const maxTop = Math.max(0, thread.scrollHeight - thread.clientHeight);
    if (options.stickToBottom || snapshot?.nearBottom || (!snapshot && options.preferBottom)) {
      thread.scrollTop = maxTop;
      return;
    }
    if (snapshot) thread.scrollTop = Math.min(snapshot.scrollTop, maxTop);
  };
  window.requestAnimationFrame?.(restore) || window.setTimeout(restore, 0);
  window.setTimeout(restore, 0);
}

function assistantRenderPreservingThreadScroll(options = {}) {
  const snapshot = assistantThreadScrollSnapshot();
  render();
  assistantRestoreThreadScroll(snapshot, options);
}

function assistantAttachmentUrl(attachment = {}) {
  return attachment.url || (attachment.attachment_id ? `/api/assistant/attachments/${encodeURIComponent(attachment.attachment_id)}` : '');
}

function assistantImageAttachmentThumbHtml(attachment = {}, removable = false) {
  const href = assistantAttachmentUrl(attachment);
  if (!href || attachment.kind !== 'image') return '';
  const name = attachment.filename || attachment.stored_filename || attachment.attachment_id || 'image attachment';
  const remove = removable ? `<button type="button" aria-label="Remove attachment" onclick="assistantRemovePendingAttachment('${escapeAttr(attachment.attachment_id || '')}')">×</button>` : '';
  return `<span class="assistant-attachment-thumb ${removable ? 'pending' : 'sent'}"><a href="${escapeAttr(href)}" target="_blank" rel="noopener"><img src="${escapeAttr(href)}" alt="${escapeAttr(name)}"><small>${escapeHtml(name)}</small></a>${remove}</span>`;
}

async function assistantReadEventStream(response, onEvent) {
  if (!response.ok) {
    let detail = '';
    try { detail = (await response.json()).detail || ''; } catch (_) { detail = await response.text().catch(() => ''); }
    throw new Error(detail || `Assistant stream failed (${response.status})`);
  }
  if (!response.body || typeof response.body.getReader !== 'function') {
    const text = await response.text();
    text.split(/\n\n+/).forEach((block) => {
      const dataLine = block.split('\n').find((line) => line.startsWith('data:'));
      if (!dataLine) return;
      try { onEvent(JSON.parse(dataLine.slice(5).trim())); } catch (_) {}
    });
    return;
  }
  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  let buffer = '';
  const flushBlock = (block) => {
    const lines = block.split(/\r?\n/);
    const data = lines.filter((line) => line.startsWith('data:')).map((line) => line.slice(5).trim()).join('\n');
    if (!data) return;
    try { onEvent(JSON.parse(data)); } catch (_) {}
  };
  while (true) {
    const { value, done } = await reader.read();
    if (done) break;
    buffer += decoder.decode(value, { stream: true });
    const parts = buffer.split(/\r?\n\r?\n/);
    buffer = parts.pop() || '';
    parts.forEach(flushBlock);
  }
  buffer += decoder.decode();
  if (buffer.trim()) flushBlock(buffer);
}

function assistantApplyStreamEvent(event) {
  const a = assistantState();
  const session = a.activeSession || (a.activeSession = { messages: [] });
  if (event.session) {
    a.activeSession = event.session;
    if (!Array.isArray(a.activeSession.messages)) a.activeSession.messages = [];
  }
  if (event.sessions) a.sessions = event.sessions;
  if (event.context_pack) a.contextPreview = event.context_pack;
  const active = a.activeSession || session;
  active.messages = Array.isArray(active.messages) ? active.messages : [];
  if (event.type === 'delta') {
    let streaming = active.messages.find((message) => message.message_id === a.streamingMessageId);
    if (!streaming) {
      streaming = { message_id: `stream_${event.run_id || Date.now()}`, role: 'assistant', text: '', created_at: new Date().toISOString(), status: 'streaming', streaming: true };
      a.streamingMessageId = streaming.message_id;
      active.messages.push(streaming);
    }
    streaming.text = `${streaming.text || ''}${event.text || event.token || ''}`;
    streaming.status = 'streaming';
    a.status = 'Assistant is streaming…';
    assistantRenderPreservingThreadScroll({ preferBottom: true });
    return;
  }
  if (event.type === 'start' || event.type === 'user_message') {
    a.status = 'Assistant stream started.';
    assistantRenderPreservingThreadScroll({ stickToBottom: true });
    return;
  }
  if (event.type === 'status') {
    a.status = event.message || event.status || 'Assistant stream running…';
    assistantRenderPreservingThreadScroll();
    return;
  }
  if (event.type === 'error') {
    a.status = event.message || event.error || 'Assistant stream failed.';
    assistantRenderPreservingThreadScroll();
    return;
  }
  if (event.type === 'done') {
    a.streaming = false;
    a.streamingMessageId = '';
    if (event.ok && event.session) {
      a.activeSession = event.session;
      a.sessions = event.sessions || a.sessions || [];
      a.contextPreview = event.context_pack || a.contextPreview || null;
      a.draft = '';
      a.pendingAttachments = [];
      a.status = 'Assistant streamed reply with context proof.';
    } else {
      a.status = event.message || event.error || 'Assistant stream ended with an error.';
    }
    assistantRenderPreservingThreadScroll({ preferBottom: true });
  }
}

function assistantPendingAttachmentChipsHtml() {
  const attachments = assistantState().pendingAttachments || [];
  if (!attachments.length) return `<div class="assistant-attachment-empty">No files attached.</div>`;
  return `<div class="assistant-attachment-chip-row">${attachments.map((attachment) => {
    if (attachment.kind === 'image') {
      const warning = !assistantBackendSupportsVision() ? '<em>backend cannot inspect images</em>' : '';
      return `${assistantImageAttachmentThumbHtml(attachment, true)}${warning}`;
    }
    return `<span class="assistant-attachment-chip ${escapeAttr(attachment.kind || 'file')}"><strong>Doc</strong>${escapeHtml(attachment.filename || attachment.stored_filename || attachment.attachment_id || 'attachment')}<button type="button" onclick="assistantRemovePendingAttachment('${escapeAttr(attachment.attachment_id || '')}')">×</button></span>`;
  }).join('')}</div>`;
}

function assistantMessageAttachmentsHtml(message = {}) {
  const attachments = Array.isArray(message.attachments) ? message.attachments : [];
  if (!attachments.length) return '';
  return `<div class="assistant-message-attachments">${attachments.map((attachment) => {
    if (attachment.kind === 'image') return assistantImageAttachmentThumbHtml(attachment, false);
    const label = 'Document';
    const name = attachment.filename || attachment.stored_filename || attachment.attachment_id || 'attachment';
    const href = assistantAttachmentUrl(attachment);
    const body = `<span>${escapeHtml(label)}</span><strong>${escapeHtml(name)}</strong>`;
    return href ? `<a href="${escapeAttr(href)}" target="_blank" rel="noopener">${body}</a>` : `<div>${body}</div>`;
  }).join('')}</div>`;
}

function assistantBackendSupportsVision() {
  const profile = typeof selectedBackendProfileForSurface === 'function' ? selectedBackendProfileForSurface('assistant') : null;
  const flags = profile?.capability_flags || {};
  const caps = profile?.runtime?.capabilities || {};
  const provider = String(profile?.provider_id || '').toLowerCase();
  const model = String(profile?.connection?.model || '').toLowerCase();
  if (flags.supports_vision || caps.supports_vision || caps.runtime_supports_vision) return true;
  if (provider.includes('vision') || model.includes('vision') || model.includes('llava') || model.includes('qwen-vl') || model.includes('qwen2vl') || model.includes('minicpm') || model.includes('mmproj')) return true;
  return false;
}

async function assistantUploadAttachments(input) {
  if (await neoTryAssistantAction('assistantUploadAttachments', { input })) return;
  const files = Array.from(input?.files || []);
  if (!files.length) return;
  const a = assistantState();
  if (!a.activeSession) await assistantCreateSession();
  const session = assistantState().activeSession || {};
  a.status = `Uploading ${files.length} Assistant attachment${files.length === 1 ? '' : 's'}...`;
  render();
  try {
    for (const file of files) {
      const data = new FormData();
      data.append('file', file);
      data.append('session_id', session.session_id || '');
      data.append('project_id', a.selectedProjectId || session.project_id || 'general');
      data.append('kind', file.type && file.type.startsWith('image/') ? 'image' : 'auto');
      const payload = await assistantFetchJson('/api/assistant/attachments/upload', { method: 'POST', body: data });
      if (payload.attachment) {
        const existing = new Set((a.pendingAttachments || []).map((item) => item.attachment_id));
        if (!existing.has(payload.attachment.attachment_id)) a.pendingAttachments.push(payload.attachment);
      }
    }
    a.status = `${a.pendingAttachments.length} attachment${a.pendingAttachments.length === 1 ? '' : 's'} ready for next message.`;
  } catch (error) {
    a.status = `Assistant attachment upload failed: ${error.message}`;
  } finally {
    if (input) input.value = '';
    render();
  }
}

async function assistantRemovePendingAttachment(attachmentId) {
  if (await neoTryAssistantAction('assistantRemovePendingAttachment', { attachmentId })) return;
  const a = assistantState();
  a.pendingAttachments = (a.pendingAttachments || []).filter((attachment) => attachment.attachment_id !== attachmentId);
  a.status = 'Attachment removed from pending message.';
  render();
}

function assistantMessageCards() {
  const session = assistantState().activeSession;
  const messages = Array.isArray(session?.messages) ? session.messages : [];
  if (!messages.length) {
    return `<div class="assistant-thread-empty"><div class="assistant-empty-orb">✦</div><h4>No messages yet</h4><p>Start with a client reply, implementation plan, tab guide, or messy brain dump. Neo will build context before replying.</p></div>`;
  }
  return messages.map((message) => {
    const role = String(message.role || 'user').toLowerCase();
    const when = message.created_at ? `<time>${escapeHtml(message.created_at)}</time>` : '';
    const label = role === 'assistant' ? 'Neo Assistant' : role === 'system' ? 'System' : 'You';
    const avatar = role === 'assistant' ? 'N' : role === 'system' ? '⚙' : 'Y';
    return `<article class="assistant-message ${escapeAttr(role)}">
      <div class="assistant-avatar" aria-hidden="true">${escapeHtml(avatar)}</div>
      <div class="assistant-message-bubble">
        <div class="assistant-message-head"><strong>${escapeHtml(label)}</strong>${when}</div>
        <p>${escapeHtml(message.text || '')}</p>
        ${message.streaming ? '<small class="assistant-streaming-chip">Streaming…</small>' : ''}
        ${assistantMessageAttachmentsHtml(message)}
        ${assistantMessageGroundingHtml(message)}
      </div>
    </article>`;
  }).join('');
}

function assistantSessionListHtml() {
  const a = assistantState();
  const query = String(a.searchQuery || '').toLowerCase();
  const sessions = (a.sessions || []).filter((session) => {
    const haystack = `${session.title || ''} ${session.preview || ''} ${session.mode || ''} ${session.project_id || ''}`.toLowerCase();
    return !query || haystack.includes(query);
  });
  if (!sessions.length) return `<div class="assistant-mini-empty">No chats match yet.</div>`;
  return sessions.map((session) => {
    const active = session.session_id === a.activeSession?.session_id ? ' active' : '';
    const count = session.message_count ?? (Array.isArray(session.messages) ? session.messages.length : 0);
    return `<button class="assistant-chat-card${active}" type="button" onclick="assistantLoadSession('${escapeAttr(session.session_id || '')}')">
      <span class="assistant-chat-card-top"><strong>${escapeHtml(session.title || 'New assistant chat')}</strong><em>${escapeHtml(session.mode || 'chat')}</em></span>
      <span>${count} messages · ${escapeHtml(session.project_id || 'general')}</span>
      <small>${escapeHtml(session.preview || 'No preview yet.')}</small>
    </button>`;
  }).join('');
}

function assistantStarterCardsHtml() {
  const a = assistantState();
  const projectId = String(a.selectedProjectId || a.activeSession?.project_id || 'general');
  const surface = typeof assistantProjectSurface === 'function' ? assistantProjectSurface() : projectId;
  const imageCards = [
    ['🧭', 'Help with this tab', 'Explain this Image tab screen and what I should do next.'],
    ['⚙️', 'Suggest image settings', 'Look at my current Image setup and suggest practical settings.'],
    ['✨', 'Write image prompt', 'Help me write a clean image prompt for the selected workflow.'],
    ['🧾', 'Read output metadata', 'Summarize the selected Image output metadata and what settings worked.'],
    ['🖼️', 'Explain attached image', 'Review the attached image and suggest an edit prompt.'],
    ['🧹', 'Organize my mess', 'Turn my rough notes into a clean Image workflow.'],
  ];
  const defaultCards = [
    ['✉️', 'Write client reply', 'Write a clear client response in my style.'],
    ['🎬', 'Write caption', 'Turn this idea into a short, punchy caption.'],
    ['🧭', 'Help with this tab', 'Explain this screen and what I should do next.'],
    ['⚙️', 'Suggest settings', 'Look at the current workspace setup and suggest better settings.'],
    ['🛠️', 'Fix an issue', 'Explain this problem and turn it into a fix plan.'],
    ['🧹', 'Organize notes', 'Turn this messy note dump into clear next steps.'],
  ];
  const cards = surface === 'image' || projectId === 'image_workspace' ? imageCards : defaultCards;
  return `<div class="assistant-starter-grid">${cards.map(([icon, title, prompt]) => `<button type="button" class="assistant-starter" onclick="assistantUseStarter(${escapeAttr(JSON.stringify(prompt))})"><span>${escapeHtml(icon)}</span><strong>${escapeHtml(title)}</strong><small>${escapeHtml(prompt)}</small></button>`).join('')}</div>`;
}

function assistantCanContinueResponse(session = null) {
  const active = session || assistantState().activeSession || {};
  const messages = Array.isArray(active.messages) ? active.messages : [];
  return !![...messages].reverse().find((message) => message && message.role === 'assistant' && String(message.text || '').trim());
}


