async function assistantSendLocalMessage() {
  if (await neoTryAssistantAction('assistantSendLocalMessage')) return;
  const a = assistantState();
  if (a.streaming) return;
  const draftEl = document.getElementById('assistant-composer-text');
  const text = (draftEl?.value || a.draft || '').trim();
  const pendingAttachmentIds = (a.pendingAttachments || []).map((attachment) => attachment.attachment_id).filter(Boolean);
  if (!text && !pendingAttachmentIds.length) return;
  const messageText = text || 'Please review the attached file(s).';
  if (!a.activeSession) await assistantCreateSession();
  const session = assistantState().activeSession || {};
  a.status = 'Starting Assistant stream…';
  a.streaming = true;
  a.streamingMessageId = '';
  assistantRenderPreservingThreadScroll({ stickToBottom: true });
  try {
    const payload = {
      session_id: session.session_id || '',
      project_id: a.selectedProjectId || session.project_id || 'general',
      message: messageText,
      retrieval_profile: a.profile?.retrieval_profile || 'smart',
      source_grounded: !!a.groundedMode,
      attachments: pendingAttachmentIds,
    };
    if (typeof selectedBackendProfileForSurface === 'function') payload.profile_id = selectedBackendProfileForSurface('assistant')?.profile_id || '';
    if (typeof assistantProjectSurface === 'function') {
      payload.active_surface = assistantProjectSurface();
      if (typeof assistantSurfaceProjectSnapshot === 'function') payload.surface_context_snapshot = assistantSurfaceProjectSnapshot(payload.active_surface);
    }
    const response = await fetch('/api/assistant/chat-run-stream', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
    await assistantReadEventStream(response, assistantApplyStreamEvent);
  } catch (error) {
    a.streaming = false;
    a.streamingMessageId = '';
    a.status = `Assistant send failed: ${error.message}`;
    assistantRenderPreservingThreadScroll();
  }
}

async function assistantContinueResponse() {
  if (await neoTryAssistantAction('assistantContinueResponse')) return;
  const a = assistantState();
  if (a.streaming) return;
  if (!assistantCanContinueResponse()) {
    a.status = 'No assistant response to continue yet.';
    render();
    return;
  }
  const session = a.activeSession || {};
  a.status = 'Continuing Assistant response…';
  a.streaming = true;
  a.streamingMessageId = '';
  assistantRenderPreservingThreadScroll({ stickToBottom: true });
  try {
    const payload = {
      session_id: session.session_id || '',
      project_id: a.selectedProjectId || session.project_id || 'general',
      message: 'Continue the previous Assistant response from where it stopped.',
      mode: 'continue_response',
      continue_response: true,
      retrieval_profile: a.profile?.retrieval_profile || 'smart',
      source_grounded: !!a.groundedMode,
    };
    if (typeof selectedBackendProfileForSurface === 'function') payload.profile_id = selectedBackendProfileForSurface('assistant')?.profile_id || '';
    if (typeof assistantProjectSurface === 'function') {
      payload.active_surface = assistantProjectSurface();
      if (typeof assistantSurfaceProjectSnapshot === 'function') payload.surface_context_snapshot = assistantSurfaceProjectSnapshot(payload.active_surface);
    }
    const response = await fetch('/api/assistant/chat-run-stream', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
    await assistantReadEventStream(response, assistantApplyStreamEvent);
  } catch (error) {
    a.streaming = false;
    a.streamingMessageId = '';
    a.status = `Assistant continue failed: ${error.message}`;
    assistantRenderPreservingThreadScroll();
  }
}


