async function assistantPlanActionReview() {
  if (await neoTryAssistantAction('assistantPlanActionReview')) return;
  const a = assistantState();
  const draftEl = document.getElementById('assistant-composer-text');
  const text = (draftEl?.value || a.draft || '').trim();
  if (!text) { a.status = 'Add a command before reviewing actions.'; render(); return; }
  a.status = 'Planning safe actions through Neo Operator...';
  render();
  try {
    if (!a.actionReview?.status) await assistantLoadActionReviewStatus();
    const payload = await assistantFetchJson('/api/assistant/action-review/plan', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ command: text, retrieval_profile: a.profile?.retrieval_profile || 'smart', limit: 8 }),
    });
    a.actionReview = { ...(a.actionReview || {}), plan: payload, run: null, command: text };
    const summary = payload.action_summary || {};
    a.status = `Action plan ready: ${summary.read_only_count || 0} read-only, ${summary.confirmation_required_count || 0} confirmation, ${summary.blocked_count || 0} blocked.`;
  } catch (error) {
    a.status = `Action review failed: ${error.message}`;
  }
  render();
}

async function assistantRunActionReview(executeConfirmed = false) {
  if (await neoTryAssistantAction('assistantRunActionReview', { executeConfirmed })) return;
  const a = assistantState();
  const draftEl = document.getElementById('assistant-composer-text');
  const command = (a.actionReview?.command || draftEl?.value || a.draft || '').trim();
  if (!command) { a.status = 'Plan an action first.'; render(); return; }
  if (executeConfirmed && !window.confirm('Run confirmation-required Operator actions? Read the action plan first.')) return;
  a.status = executeConfirmed ? 'Running confirmed Operator actions...' : 'Running safe read-only Operator actions...';
  render();
  try {
    const payload = await assistantFetchJson('/api/assistant/action-review/run', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ command, retrieval_profile: a.profile?.retrieval_profile || 'smart', execute_confirmed: !!executeConfirmed, limit: 8 }),
    });
    a.actionReview = { ...(a.actionReview || {}), run: payload, command };
    const blocked = (payload.blocked_actions || []).length;
    const executed = (payload.executed_actions || []).length;
    a.status = `Operator run complete: ${executed} executed, ${blocked} blocked/gated.`;
  } catch (error) {
    a.status = `Operator run failed: ${error.message}`;
  }
  render();
}

