function currentSurfaceContextSnapshot() {
  const surface = state.activeSurfaceId || state.activeSurface || 'assistant';
  const subtab = state.activeSubtabId || state.activeSubtab || '';
  const a = assistantState();
  const payload = { detail_mode: state.detailMode || 'guided' };
  if (surface === 'prompt_captioning') {
    const pc = state.promptCaptioning || {};
    payload.mode = pc.activeMode || pc.mode || 'prompt_builder';
    payload.prompt_source = pc.promptBuilder?.sourceText || '';
    payload.prompt_output = pc.promptBuilder?.outputText || '';
    payload.caption_output = pc.captioning?.outputText || '';
  } else if (surface === 'roleplay') {
    payload.roleplay_view = state.roleplayStoriesActiveView || state.roleplayActiveView || '';
  } else if (surface === 'image') {
    payload.prompt = state.imageDraft?.prompt || state.imageDraft?.positive_prompt || '';
    payload.negative_prompt = state.imageDraft?.negative_prompt || '';
  }
  return {
    surface,
    subtab,
    project_id: a.selectedProjectId || 'general',
    session_id: a.activeSession?.session_id || '',
    title: `Snapshot from ${surface}${subtab ? ` / ${subtab}` : ''}`,
    summary: `User asked Assistant to inspect current ${surface}${subtab ? `/${subtab}` : ''} context.`,
    suggested_action: 'guide',
    payload,
  };
}

