  document.getElementById('videoUpscaleTargetPreset')?.addEventListener('change', (event) => { state.videoDraft.upscale_target_preset = event.target.value || 'hd_1080'; if (state.videoDraft.upscale_target_preset === 'custom') state.videoDraft.upscale_advanced_open = true; saveUiState(); render(); });
