  const kept = session.boxes.filter((box) => box && box.selected !== false && box.ignored !== true);
  const positiveSep = kept.map((box) => String(box.positive_prompt || '').trim()).filter(Boolean).join(' [SEP] ');
  const negativeSep = kept.map((box) => String(box.negative_prompt || '').trim()).filter(Boolean).join(' [SEP] ');
  const patch = { target_mode: 'manual_boxes', manual_boxes: nextText };
  if (positiveSep) patch.positive_prompt = positiveSep;
  if (negativeSep) patch.negative_prompt = negativeSep;
  updateAdetailerPass(passIndex, patch);
  updateAdetailerSettings({ enabled: true, canvas_snapshot: adetailerCanvasSnapshot() });
  const textNode = document.querySelector(`[data-adetailer-pass-index="${passIndex}"][data-adetailer-pass-field="manual_boxes"]`);
