    params.aspect_ratio = draft.aspect_ratio || defaults.aspect_ratio || '1:1';
    params.resolution = draft.resolution || defaults.resolution || '1k';
    params.n = Number(draft.n || draft.image_count || defaults.n || params.batch_count || 1);
    params.response_format = defaults.response_format || 'b64_json';
