function sceneDirectorV054OutputInspectorSourceStack(regions, sceneGraph, metadata = {}) {
  const cleanRegions = Array.isArray(regions) ? regions : [];
  const graph = sceneGraph && typeof sceneGraph === 'object' ? sceneGraph : {};
  return {
    releaseStage: 'ready',
    legacy_phase_anchor: 'SD-V054-16',
    schema: 'neo.extension.source_stack.scene_director.v054.v1',
    scene_graph_json: graph,
    mask_outputs: ['subject_masks', 'detail_masks', 'background_masks', 'control_masks', 'inpaint_masks'],
    prompt_blocks: ['global_prompt', 'negative_prompt', 'compiled_prompt_blocks'],
    region_branch_actions: cleanRegions.map((region) => ({
      region_id: region && region.id ? region.id : '',
      role: region && (region.role || region.type) ? (region.role || region.type) : 'custom',
      actions: ['replay_region', 'use_as_source', 'branch_from_region', 'open_region_in_inpaint']
    })),
    latent_policy: 'compatible_route_only',
    source_image_policy: 'reusable_across_providers',
    mask_policy: 'requires_size_match',
    metadata
  };
}

function sceneDirectorV054OutputInspectorActions(region) {
  const role = region && (region.role || region.type) ? (region.role || region.type) : 'custom';
  const actions = ['Replay full Scene Director setup', 'Use output as source', 'Branch from this region'];
  if (region && region.inpaint && region.inpaint.enabled) actions.push('Open selected region in Inpaint');
  if (role === 'text') actions.push('Edit Text Plate');
  if (region && region.edit_intent) actions.push('Replace one region / preserve all other regions');
  return actions;
}
